            font-weight: bold;
            transition: background 0.3s;
            margin-left: 10px;
        }

        .auth-buttons button:hover {
            background-color: #f0f0f0;
        }

        /* --- HERO SECTION --- */
        .hero {
            background: linear-gradient(rgba(160, 82, 45, 0.7), rgba(160, 82, 45, 0.7)), url('https://images.unsplash.com/photo-1451187580459-43490279c0fa?ixlib=rb-1.2.1&auto=format&fit=crop&w=1352&q=80');
            background-size: cover;
