            { id: 8, title: "Leisure & Vacation", icon: "fa-umbrella-beach", desc: "Exclusive resort packages.", type: "leisure" }
        ];

        let orders = [
            { id: 'ORD-101', service: 'Travel - Beach Resort', date: '2023-10-20', status: 'Confirmed' },
            { id: 'ORD-102', service: 'Online Shopping - Electronics', date: '2023-10-22', status: 'Shipped' }
        ];

        let isLoggedIn = false;

        // --- INIT ---
        document.addEventListener('DOMContentLoaded', () => {
            renderServices();
            renderOrders();
        });

        // --- NAVIGATION ---
        function showSection(sectionId) {
            // Hide all sections
            document.querySelectorAll('.section').forEach(sec => {
                sec.classList.remove('active');
            });
            // Show target section
            document.getElementById(sectionId).classList.add('active');
            window.scrollTo(0, 0);

            // Guard for dashboard
            if (sectionId === 'dashboard' && !isLoggedIn) {
                alert("Please login to view dashboard.");
                openModal('loginModal');
                showSection('home');
            }
        }

        // --- SERVICE RENDERING ---
        function renderServices() {
            const container = document.getElementById('service-list');
            container.innerHTML = servicesData.map(service => `
                <div class="service-card">
                    <div class="card-img">
                        <i class="fas ${service.icon}"></i>
                    </div>
                    <div class="card-content">
                        <h3>${service.title}</h3>
                        <p>${service.desc}</p>
                        <button class="btn" onclick="bookService('${service.title}')">Book / View</button>
                    </div>
                </div>
            `).join('');
        }

        function bookService(serviceName) {
            if (!isLoggedIn) {
                alert("Please login to book a service.");
                openModal('loginModal');
            } else {
                const confirmBooking = confirm(`Do you want to create a booking for: ${serviceName}?`);
                if(confirmBooking) {
                    // Add to orders
                    const newOrder = {
                        id: `ORD-${Math.floor(Math.random() * 1000) + 100}`,
                        service: serviceName,
                        date: new Date().toISOString().split('T')[0],
                        status: 'Pending'
                    };
                    orders.unshift(newOrder); // Add to beginning
                    renderOrders();
                    alert("Booking request submitted! Check your dashboard.");
                    showSection('dashboard');
                    switchDashTab('orders');
                }
            }
        }

        // --- DASHBOARD LOGIC ---
        function switchDashTab(tabName) {
            // Reset Active classes
            document.querySelectorAll('.dash-nav li').forEach(li => li.classList.remove('active'));
            document.getElementById(`tab-${tabName}`).classList.add('active');

            // Hide all content divs
            document.getElementById('dash-profile').style.display = 'none';
            document.getElementById('dash-orders').style.display = 'none';
            document.getElementById('dash-records').style.display = 'none';

            // Show target
            document.getElementById(`dash-${tabName}`).style.display = 'block';
        }

        function renderOrders() {
            const tbody = document.getElementById('orders-table-body');
            tbody.innerHTML = orders.map(order => `
                <tr>
                    <td>${order.id}</td>
                    <td>${order.service}</td>
                    <td>${order.date}</td>
                    <td><span style="color: ${getStatusColor(order.status)}">${order.status}</span></td>
                    <td>
                        <button style="padding: 5px 10px; cursor: pointer;" onclick="alert('Viewing details for ${order.id}')">Details</button>
                    </td>
                </tr>
            `).join('');
        }

        function getStatusColor(status) {
            if(status === 'Confirmed') return 'green';
            if(status === 'Pending') return 'orange';
            return 'blue';
        }

        // --- MODAL & AUTH ---
        function openModal(modalId) {
            document.getElementById(modalId).style.display = "flex";
        }

        function closeModal(modalId) {
            document.getElementById(modalId).style.display = "none";
        }

        // Close modal if clicked outside
        window.onclick = function(event) {
            if (event.target.classList.contains('modal')) {
                event.target.style.display = "none";
            }
        }

        function handleLogin(e) {
            e.preventDefault();
            // Simulate API call
            setTimeout(() => {
                isLoggedIn = true;
                closeModal('loginModal');
                closeModal('registerModal');
                updateAuthUI();
                alert("Logged in successfully!");
            }, 500);
        }

        function logout() {
            isLoggedIn = false;
            updateAuthUI();
            showSection('home');
            alert("Logged out.");
        }

        function updateAuthUI() {
            const authBtns = document.getElementById('auth-buttons');
            const userMenu = document.getElementById('user-menu');

            if (isLoggedIn) {
                authBtns.style.display = 'none';
                userMenu.style.display = 'block';
            } else {
                authBtns.style.display = 'block';
                userMenu.style.display = 'none';
            }
        }

    </script>
</body>
</html>
