        }

        function filterProducts() {
            const filter = document.getElementById('category-filter').value;
            renderProducts(filter);
        }

        // --- CART ---
        function addToCart(id) {
            const product = products.find(p => p.id === id);
            cart.push(product);
            updateCartCount();
            showToast(`${product.name} added to cart!`);
        }

        function updateCartCount() {
            document.getElementById('cart-count').innerText = cart.length;
        }

        function renderCart() {
            const container = document.getElementById('cart-items');
            const totalEl = document.getElementById('cart-total');
            const formContainer = document.getElementById('checkout-form-container');

            if (cart.length === 0) {
                container.innerHTML = '<p>Your basket is empty. Go browse some fresh items!</p>';
                totalEl.innerText = '0.00';
                formContainer.style.display = 'none';
                return;
            }

            container.innerHTML = '';
            let total = 0;

            // Consolidate items
            const counts = {};
            cart.forEach(item => { counts[item.id] = (counts[item.id] || 0) + 1; });

            // Render unique items with counts
            const uniqueIds = [...new Set(cart.map(item => item.id))];

            uniqueIds.forEach(id => {
                const item = products.find(p => p.id === id);
                const qty = counts[id];
                const itemTotal = item.price * qty;
                total += itemTotal;

                container.innerHTML += `
                    <div class="cart-item">
                        <div>${item.name} x ${qty}</div>
                        <div>$${itemTotal.toFixed(2)}</div>
                    </div>
                `;
            });

            totalEl.innerText = total.toFixed(2);
            formContainer.style.display = 'flex';
        }

        // --- CHECKOUT & ORDERS ---
        function processPayment() {
            if (!currentUser) {
                showToast("Please login to place an order!");
                openLoginModal();
                return;
            }

            const address = document.getElementById('address').value;
            const card = document.getElementById('card').value;

            if (!address || !card) {
                alert("Please fill in payment details.");
                return;
            }

            // Simulate Payment Processing
            const btn = document.querySelector('.checkout-form button');
            const originalText = btn.innerText;
            btn.innerText = "Processing...";
            btn.disabled = true;

            setTimeout(() => {
                const orderId = 'ORD-' + Math.floor(Math.random() * 10000);
                const orderTotal = document.getElementById('cart-total').innerText;

                const newOrder = {
                    id: orderId,
                    date: new Date().toLocaleDateString(),
                    total: orderTotal,
                    items: cart.length,
                    status: "Packing" // Initial status
                };

                orders.unshift(newOrder); // Add to beginning

                // Clear cart
                cart = [];
                updateCartCount();
                renderCart();

                // Reset Form
                document.getElementById('address').value = '';
                document.getElementById('card').value = '';
                btn.innerText = originalText;
                btn.disabled = false;

                showToast("Order Placed Successfully!");
                showSection('orders');

                // Simulate status update
                setTimeout(() => updateOrderStatus(orderId, "Out for Delivery"), 5000);
                setTimeout(() => updateOrderStatus(orderId, "Delivered"), 10000);

            }, 1500);
        }

        function updateOrderStatus(orderId, status) {
            const order = orders.find(o => o.id === orderId);
            if(order) {
                order.status = status;
                if(document.getElementById('orders').classList.contains('active')){
                    renderOrders(); // Re-render if looking at page
                }
            }
        }

        function renderOrders() {
            const container = document.getElementById('order-history-list');

            if (!currentUser) {
                container.innerHTML = '<p>Please log in to view your orders.</p>';
                return;
            }

            if (orders.length === 0) {
                container.innerHTML = '<p>No past orders found.</p>';
                return;
            }

            container.innerHTML = '';
            orders.forEach(order => {
                container.innerHTML += `
                    <div class="order-card">
                        <div style="display:flex; justify-content:space-between; align-items:center;">
                            <h3>${order.id}</h3>
                            <span class="status-badge">${order.status}</span>
                        </div>
                        <p>Date: ${order.date}</p>
                        <p>Items: ${order.items} | Total: $${order.total}</p>
                    </div>
                `;
            });
        }

        // --- UTILS ---
        function showToast(message) {
            const x = document.getElementById("toast");
            x.innerText = message;
            x.className = "show";
            setTimeout(function(){ x.className = x.className.replace("show", ""); }, 3000);
        }

        // --- INIT ---
        window.onload = function() {
            renderProducts();
        };

    </script>
</body>
</html>
