    <script>
        // --- Data Models ---

        // Mock Data for Available Demands (Posted by users)
        const availableDemands = [
            { id: 101, from: "Central Warehouse", to: "Zone B Retail", cargo: "Perishables", weight: "2.5 Tons", price: "$120" },
            { id: 102, from: "Manufacturing Plant", to: "Port Terminal", cargo: "Steel Coils", weight: "8.0 Tons", price: "$350" },
            { id: 103, from: "Logistic Hub", to: "City Center", cargo: "Parcel Mix", weight: "1.2 Tons", price: "$90" }
        ];

        // State for Active Orders accepted by driver
        let myOrders = [
            { id: 901, from: "South Depot", to: "East Mall", cargo: "Furniture", status: "loading" }
        ];

        // --- Functions ---

        // Login Logic
        function handleLogin() {
            const driverId = document.getElementById('driver-id').value;
            if(driverId) {
                document.getElementById('login-overlay').style.display = 'none';
                document.getElementById('profile-id').innerText = driverId;
                updateDashboard();
            } else {
                alert("Please enter a Driver ID");
            }
        }

        function handleLogout() {
            document.getElementById('login-overlay').style.display = 'flex';
            // Reset to home view behind the modal
            showSection('home');
        }

        // Navigation Logic
        function showSection(sectionId) {
            // Hide all sections
            document.querySelectorAll('.section').forEach(sec => sec.classList.remove('active'));
            // Remove active class from nav buttons
            document.querySelectorAll('.nav-links button').forEach(btn => btn.classList.remove('active'));

            // Show selected section
            document.getElementById(sectionId).classList.add('active');
            // Highlight nav button
            document.getElementById('nav-' + sectionId).classList.add('active');

            if(sectionId === 'home') renderAvailableDemands();
            if(sectionId === 'orders') renderMyOrders();
        }

        // Render Homepage: Available Demands
        function renderAvailableDemands() {
            const container = document.getElementById('available-demands-container');
            container.innerHTML = '';

            availableDemands.forEach(demand => {
                const card = document.createElement('div');
                card.className = 'card';
                card.innerHTML = `
                    <div class="card-header">
                        <h4>Order #${demand.id}</h4>
                        <span style="color: var(--primary-color); font-weight: bold; font-size: 1.2rem;">${demand.price}</span>
                    </div>
                    <div class="card-details">
                        <p><strong>Route:</strong> ${demand.from} &rarr; ${demand.to}</p>
                        <p><strong>Cargo:</strong> ${demand.cargo} (${demand.weight})</p>
                    </div>
                    <button class="btn" onclick="acceptOrder(${demand.id})">Accept Order</button>
                `;
                container.appendChild(card);
            });

            updateStats();
        }

        // Action: Accept Order
        function acceptOrder(id) {
            // Find in available
            const index = availableDemands.findIndex(d => d.id === id);
            if (index > -1) {
                const demand = availableDemands[index];
                // Remove from available
                availableDemands.splice(index, 1);
                // Add to my orders with initial status
                myOrders.push({
                    id: demand.id,
                    from: demand.from,
                    to: demand.to,
                    cargo: demand.cargo,
                    status: 'pending' // pending -> loading -> transit -> delivered
                });

                alert(`Order #${id} Accepted! Go to Order Management to view.`);
                renderAvailableDemands();
                updateStats();
            }
        }

        // Render Order Management: My Orders
        function renderMyOrders() {
            const container = document.getElementById('my-orders-container');
            const noOrdersMsg = document.getElementById('no-orders-msg');
            container.innerHTML = '';

            if (myOrders.length === 0) {
                noOrdersMsg.style.display = 'block';
                return;
            } else {
                noOrdersMsg.style.display = 'none';
            }

            myOrders.forEach(order => {
                const card = document.createElement('div');
                card.className = 'card';

                // Determine status badge color
                let badgeClass = 'status-pending';
                if(order.status === 'loading') badgeClass = 'status-loading';
                if(order.status === 'transit') badgeClass = 'status-transit';

                card.innerHTML = `
                    <div class="card-header">
                        <h4>Order #${order.id}</h4>
                        <span class="status-badge ${badgeClass}">${order.status.toUpperCase()}</span>
                    </div>
                    <div class="card-details">
                        <p><strong>Route:</strong> ${order.from} &rarr; ${order.to}</p>
                        <p><strong>Cargo:</strong> ${order.cargo}</p>
                    </div>
                    <div class="action-row">
                        <label>Update Status:</label>
                        <select class="status-dropdown" onchange="updateOrderStatus(${order.id}, this.value)">
                            <option value="pending" ${order.status === 'pending' ? 'selected' : ''}>Pending</option>
                            <option value="loading" ${order.status === 'loading' ? 'selected' : ''}>Loading</option>
                            <option value="transit" ${order.status === 'transit' ? 'selected' : ''}>In Transit</option>
                            <option value="delivered">Delivered (Complete)</option>
                        </select>
                        <button class="btn" style="background-color: #d9534f;" onclick="cancelOrder(${order.id})">Cancel</button>
                    </div>
                `;
                container.appendChild(card);
            });
        }

        // Action: Update Status
        function updateOrderStatus(id, newStatus) {
            if (newStatus === 'delivered') {
                if(confirm("Mark order as delivered and complete? It will move to history.")) {
                    // Remove from active orders
                    myOrders = myOrders.filter(o => o.id !== id);
                    // In a real app, this would post to history database
                    // Increment history counter for demo
                    let completedCount = parseInt(document.getElementById('stat-completed').innerText);
                    document.getElementById('stat-completed').innerText = completedCount + 1;
                    renderMyOrders();
                } else {
                    renderMyOrders(); // Reset dropdown
                }
            } else {
                const order = myOrders.find(o => o.id === id);
                if (order) {
                    order.status = newStatus;
                    renderMyOrders(); // Re-render to update badge colors
                }
            }
            updateStats();
        }

        // Action: Cancel Order
        function cancelOrder(id) {
            if(confirm("Are you sure you want to cancel this order?")) {
                 const orderIndex = myOrders.findIndex(o => o.id === id);
                 if(orderIndex > -1) {
                     const order = myOrders[orderIndex];
                     // Move back to available demands for demo purposes
                     availableDemands.push({
                         id: order.id,
                         from: order.from,
                         to: order.to,
                         cargo: order.cargo,
                         weight: "Unknown", // Data lost in simple transition
                         price: "$TBD" 
                     });
                     myOrders.splice(orderIndex, 1);
                     renderMyOrders();
                     updateStats();
                 }
            }
        }

        // Helper: Update Dashboard Stats
        function updateStats() {
            document.getElementById('stat-active').innerText = myOrders.length;
        }

        function updateDashboard() {
            renderAvailableDemands();
            updateStats();
        }

        // --- Initialization ---
        // Run once on load
        updateDashboard();

    </script>
</body>
</html>
