        // --- Dynamic Content Logic ---
        function updatePayloadTemplate() {
            const method = document.getElementById('service-method').value;
            let template = {};

            switch(method) {
                case 'user.getUserData':
                    template = { "userId": 1024, "includeMetadata": true };
                    break;
                case 'payment.processTransaction':
                    template = { "amount": 99.99, "currency": "USD", "recipient": "Acme Corp" };
                    break;
                case 'system.healthCheck':
                    template = { "verbose": false };
                    break;
                case 'data.simulateError':
                    template = { "forceFail": true };
                    break;
            }
            payloadInput.value = JSON.stringify(template, null, 4);
        }

        // --- Core RPC Functionality ---
        function handleRpcCall(e) {
            e.preventDefault();

            if (state.isProcessing) return;

            // 1. Validation
            const method = document.getElementById('service-method').value;
            let payloadData;

            try {
                payloadData = JSON.parse(payloadInput.value);
            } catch (err) {
                showToast('Invalid JSON Payload', 'error');
                log('JSON Parse Error: Invalid syntax', 'error');
                return;
            }

            // 2. UI Updates (Loading State)
            state.isProcessing = true;
            sendBtn.innerHTML = `Processing <span class="loader"></span>`;
            sendBtn.style.opacity = "0.8";
            log(`Sending request to [${method}]...`, 'info');

            // 3. Simulate Network Delay & Processing
            const delay = Math.floor(Math.random() * 1500) + 500; // 0.5s to 2s

            setTimeout(() => {
                const response = mockServerResponse(method, payloadData);

                // 4. Handle Response
                if (response.status === 'success') {
                    log(`Response Received: ${JSON.stringify(response.data)}`, 'info');
                    showToast('Data Transmitted Successfully', 'success');
                    addToHistory(method, 'Success', new Date().toLocaleTimeString());
                } else {
                    log(`RPC Error: ${response.message} (Code: ${response.code})`, 'error');
                    showToast('Remote Call Failed', 'error');
                    addToHistory(method, 'Failed', new Date().toLocaleTimeString());
                }

                // 5. Reset UI
                sendBtn.innerHTML = `<span>Send Request</span>`;
                sendBtn.style.opacity = "1";
                state.isProcessing = false;

            }, delay);
        }

        // --- Mock Server Logic ---
        function mockServerResponse(method, data) {
            // Simulate random network jitter/failure occasionally
            if (Math.random() > 0.9) {
                return { status: 'error', code: 503, message: 'Service Unavailable' };
            }

            if (method === 'data.simulateError') {
                return { status: 'error', code: 400, message: 'Simulated Logic Failure' };
            }

            // Success responses based on method
            if (method === 'user.getUserData') {
                return { status: 'success', data: { id: data.userId, name: "Alice Green", role: "Admin" }};
            }

            if (method === 'payment.processTransaction') {
                return { status: 'success', data: { txId: "TX-" + Math.floor(Math.random() * 100000), status: "Cleared" }};
            }

            return { status: 'success', data: { ack: true, timestamp: Date.now() }};
        }

        // --- Logging System ---
        function log(message, type) {
            const time = new Date().toLocaleTimeString();
            const entry = document.createElement('div');
            entry.className = 'log-entry';
            entry.innerHTML = `<span class="log-time">[${time}]</span> <span class="log-type ${type}">${type.toUpperCase()}:</span> ${message}`;

            consoleOutput.appendChild(entry);
            consoleOutput.scrollTop = consoleOutput.scrollHeight; // Auto scroll to bottom
        }

        // --- Toast Notification System ---
        function showToast(msg, type) {
            toastElement.textContent = msg;
            toastElement.className = `toast show ${type}`;

            setTimeout(() => {
                toastElement.className = 'toast';
            }, 3000);
        }

        // --- History Management ---
        function addToHistory(method, result, time) {
            state.history.unshift({ method, result, time });
        }

        function updateHistoryView() {
            if (state.history.length === 0) {
                historyList.innerHTML = '<p style="color: #888; font-style: italic;">No history available yet.</p>';
                return;
            }

            let html = '';
            state.history.forEach(item => {
                const color = item.result === 'Success' ? 'var(--success-color)' : 'var(--error-color)';
                html += `
                    <div style="background: #f9f9f9; padding: 10px; margin-bottom: 8px; border-left: 4px solid ${color}; border-radius: 4px;">
                        <strong>${item.method}</strong><br>
                        <small>${item.time} - <span style="color:${color}">${item.result}</span></small>
                    </div>
                `;
            });
            historyList.innerHTML = html;
        }

