    </div>

    <!-- The Write-Ahead Log (WAL) Visualization -->
    <div class="log-container">
        <div class="log-header">
            <span>Write-Ahead Log (WAL)</span>
            <span style="font-size: 0.8rem; opacity: 0.7;">Persisted</span>
        </div>
        <div class="console-window" id="logConsole">
            <!-- Log entries appear here -->
            <div style="color: #666;">// System initialized...</div>
            <div style="color: #666;">// Waiting for input...</div>
        </div>
    </div>

    <!-- The Actual State (Replayed from Log) -->
    <div class="data-table-container">
        <table>
            <thead>
                <tr>
                    <th colspan="2">Current State (In-Memory)</th>
                </tr>
                <tr>
                    <th>Key</th>
                    <th>Value</th>
                </tr>
            </thead>
            <tbody id="dataTableBody">
                <!-- Data rows appear here -->
                <tr><td colspan="2" style="text-align:center; color:#999;">Database Empty</td></tr>
            </tbody>
        </table>
    </div>
