<script>
    /**
     * DATABASE ENGINE LOGIC
     * Uses a Log-Structured approach.
     * 1. All writes are appended to an array (The Log).
     * 2. The "Database" is built by replaying the log from start to finish.
     */

    // State Variables
    let transactionLog = []; // The persistent storage (simulated)
    let memoryStore = {};    // The resulting hash map

    // DOM Elements
    const logConsole = document.getElementById('logConsole');
    const tableBody = document.getElementById('dataTableBody');
    const cmdSelect = document.getElementById('commandSelect');
    const keyInput = document.getElementById('keyInput');
    const valInput = document.getElementById('valueInput');
    const statusMsg = document.getElementById('statusMessage');

    // Initialize
    window.onload = () => {
        // Check for existing data in LocalStorage to simulate persistence
        const savedLog = localStorage.getItem('kv_db_log');
        if (savedLog) {
            transactionLog = JSON.parse(savedLog);
            replayLog();
        }
        toggleInputs();
    };

    // UI Logic: Show/Hide Value input based on command
    function toggleInputs() {
        const cmd = cmdSelect.value;
        if (cmd === 'GET' || cmd === 'DELETE') {
            valInput.style.display = 'none';
        } else {
            valInput.style.display = 'block';
        }
        statusMsg.innerHTML = '';
    }

    // Core Function: Execute Command
    function executeCommand() {
        const cmd = cmdSelect.value;
        const key = keyInput.value.trim();
        const val = valInput.value.trim();

        if (!key) {
            showStatus('Error: Key is required', 'error');
            return;
        }

        if (cmd === 'SET') {
            if (!val) {
                showStatus('Error: Value is required for SET', 'error');
                return;
            }
            appendLog('SET', key, val);
            showStatus(`OK. Stored [${key}]`, 'success');
        } 
        else if (cmd === 'GET') {
            // Retrieve directly from memoryStore (which is the result of log replay)
            const result = memoryStore[key];
            if (result !== undefined) {
                showStatus(`VALUE: ${result}`, 'success');
                // Even GETs are often logged in debug modes, but usually not in WAL. 
                // We will just log to console for UI effect.
                writeToConsole(`GET ${key} -> FOUND`, true);
            } else {
                showStatus('MISS: Key not found', 'error');
                writeToConsole(`GET ${key} -> MISS`, true);
            }
        } 
        else if (cmd === 'DELETE') {
            if (memoryStore[key] !== undefined) {
                appendLog('DELETE', key, null);
                showStatus(`DELETED [${key}]`, 'success');
            } else {
                showStatus('NOT_FOUND', 'error');
            }
        }

        // Clear inputs
        keyInput.value = '';
        valInput.value = '';
        keyInput.focus();
    }

    // Mechanism: Append to Log and Persist
    function appendLog(command, key, value) {
        const entry = {
            timestamp: new Date().toISOString(),
            command: command,
            key: key,
            value: value
        };

        transactionLog.push(entry);

        // Simulate disk write
        localStorage.setItem('kv_db_log', JSON.stringify(transactionLog));

        // Update Visualization
        addLogEntryToConsole(entry);

        // Replay specific entry (optimization) or full replay
        // For strict log-replay purity, we replay the log to build state.
        replayLog();
    }

    // Mechanism: Replay Log to build State (MemoryStore)
    function replayLog() {
        memoryStore = {}; // Reset state

        // Clear console visual to rebuild or just append? 
        // For this UI, we will clear table and rebuild table.
        // We won't clear console history to show history.

        transactionLog.forEach(entry => {
            if (entry.command === 'SET') {
                memoryStore[entry.key] = entry.value;
            } else if (entry.command === 'DELETE') {
                delete memoryStore[entry.key];
            }
        });

        renderTable();
    }

    // UI: Render the In-Memory Table
    function renderTable() {
        tableBody.innerHTML = '';
        const keys = Object.keys(memoryStore);

        if (keys.length === 0) {
            tableBody.innerHTML = '<tr><td colspan="2" style="text-align:center; color:#999;">Database Empty</td></tr>';
            return;
        }

        keys.forEach(k => {
            const row = document.createElement('tr');
            row.innerHTML = `
                <td style="font-weight:bold;">${escapeHtml(k)}</td>
                <td>${escapeHtml(memoryStore[k])}</td>
            `;
            tableBody.appendChild(row);
        });
    }

    // UI: Add entry to the dark console window
    function addLogEntryToConsole(entry) {
        const div = document.createElement('div');
        div.className = 'log-entry';

        const time = new Date(entry.timestamp).toLocaleTimeString();

        let html = `<span class="log-timestamp">[${time}]</span>`;
        html += `<span class="log-cmd">${entry.command}</span> `;
        html += `<span class="log-key">${escapeHtml(entry.key)}</span>`;

        if (entry.value) {
            // Truncate long values for log view
            let displayVal = entry.value.length > 20 ? entry.value.substring(0, 20) + '...' : entry.value;
            html += ` <span class="log-val">"${escapeHtml(displayVal)}"</span>`;
        }

        div.innerHTML = html;
        logConsole.appendChild(div);
        logConsole.scrollTop = logConsole.scrollHeight; // Auto scroll
    }

    // Helper: Write non-persistent messages to console (like GET requests)
    function writeToConsole(msg, isSystem = false) {
        const div = document.createElement('div');
        div.className = 'log-entry';
        div.style.borderBottom = "none";
        if(isSystem) div.style.color = "#888";
        div.textContent = `> ${msg}`;
        logConsole.appendChild(div);
        logConsole.scrollTop = logConsole.scrollHeight;
    }

    // Helper: Clear Data
    function clearDatabase() {
        if(confirm("Are you sure you want to flush all data?")) {
            transactionLog = [];
            memoryStore = {};
            localStorage.removeItem('kv_db_log');
            replayLog();
            logConsole.innerHTML = '<div style="color: #ff5555;">// DATABASE FLUSHED</div>';
            showStatus('Database Flushed', 'info');
        }
    }

    // Helper: Status Messages
    function showStatus(msg, type) {
        statusMsg.textContent = msg;
        statusMsg.className = type;

        // Clear error messages after 3 seconds
        if (type !== 'info') {
            setTimeout(() => {
                statusMsg.textContent = '';
                statusMsg.className = '';
            }, 3000);
        }
    }

    // Security: Escape HTML to prevent XSS in the demo
    function escapeHtml(text) {
        if (typeof text !== 'string') return text;
        return text
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&#039;");
    }

    // Initial load of logs to console if they exist
    if(transactionLog.length > 0) {
        logConsole.innerHTML = '';
        transactionLog.forEach(entry => addLogEntryToConsole(entry));
    }

</script>

</body>
</html>
