            <span>Connected</span>
        </div>
    </header>

    <main>
        <!-- Operation Panel -->
        <div class="panel">
            <h2>Command Center</h2>

            <div class="form-group">
                <label for="operation-select">Select Operation</label>
                <select id="operation-select" onchange="toggleInputs()">
                    <option value="SET">SET (Create/Update)</option>
                    <option value="GET">GET (Read)</option>
                    <option value="DEL">DEL (Delete)</option>
                    <option value="FLUSHDB">FLUSHDB (Clear All)</option>
                </select>
            </div>

            <div class="form-group" id="key-group">
                <label for="redis-key">Key</label>
                <input type="text" id="redis-key" placeholder="e.g., user:1001:name">
            </div>

            <div class="form-group" id="value-group">
                <label for="redis-value">Value</label>
                <textarea id="redis-value" rows="3" placeholder="e.g., John Doe"></textarea>
            </div>

            <button class="btn-primary" id="execute-btn" onclick="executeCommand()">Execute Command</button>
        </div>

        <!-- Details Panel -->
        <div class="panel">
            <h2>Inspector</h2>
            <div id="inspector-content" style="color: #666; font-style: italic;">
                Select a key from the visualization below or run a GET command to inspect data details here.
            </div>
            <div id="inspector-actions" style="display:none; margin-top:1rem;">
                <div class="btn-group">
                    <button class="btn-primary" onclick="loadIntoForm()">Edit</button>
                    <button class="btn-danger" onclick="deleteCurrentInspectorKey()">Delete</button>
                </div>
            </div>
        </div>

        <!-- Terminal Output -->
        <div class="terminal-container">
            <div style="display: flex; justify-content: space-between; align-items:flex-end; margin-bottom: 5px;">
                <label style="margin-left: 2rem;">Log / Terminal Output</label>
                <button style="background:none; color:#666; padding:0; border:none; text-decoration:underline; font-size:0.8rem;" onclick="clearTerminal()">Clear Log</button>
            </div>
            <div id="terminal">
                <div class="log-entry">> Redis Simulator v1.0.0 initialized...</div>
                <div class="log-entry">> Ready to accept commands.</div>
            </div>
        </div>

        <!-- Visual Keys -->
        <div class="panel" style="grid-column: 1 / -1; background: white; border: none;">
            <h2>Stored Keys <span style="font-size:0.8rem; font-weight:normal;">(Click to Inspect)</span></h2>
            <div id="data-viz">
                <!-- Dynamic Keys will appear here -->
            </div>
        </div>
    </main>
</div>

<div id="notification">Action Successful</div>

<script>
    /**
     * REDIS SIMULATOR LOGIC
     * Using localStorage to persist data across reloads, mimicking a database.
     */

    // Initialize storage if empty
    if(!localStorage.getItem('redis_data')) {
        localStorage.setItem('redis_data', JSON.stringify({}));
    }

    // DOM Elements
    const keyInput = document.getElementById('redis-key');
    const valueInput = document.getElementById('redis-value');
    const opSelect = document.getElementById('operation-select');
    const terminal = document.getElementById('terminal');
    const dataViz = document.getElementById('data-viz');
    const inspectorContent = document.getElementById('inspector-content');
    const inspectorActions = document.getElementById('inspector-actions');
    const notification = document.getElementById('notification');

    // Currently inspected key tracker
    let currentInspectorKey = null;

    // --- UI Logic ---

    function toggleInputs() {
        const op = opSelect.value;
        const keyGroup = document.getElementById('key-group');
        const valueGroup = document.getElementById('value-group');
        const executeBtn = document.getElementById('execute-btn');

        // Reset styles
        keyGroup.style.display = 'flex';
        valueGroup.style.display = 'flex';
        executeBtn.className = 'btn-primary';

        if (op === 'GET' || op === 'DEL') {
            valueGroup.style.display = 'none';
        } 
        else if (op === 'FLUSHDB') {
            keyGroup.style.display = 'none';
            valueGroup.style.display = 'none';
            executeBtn.className = 'btn-danger';
        }
    }

    // --- Core Redis Operations ---

    function getStore() {
        return JSON.parse(localStorage.getItem('redis_data'));
    }

    function saveStore(data) {
        localStorage.setItem('redis_data', JSON.stringify(data));
        renderKeys();
    }

    function executeCommand() {
        const op = opSelect.value;
        const key = keyInput.value.trim();
        const val = valueInput.value;
        const store = getStore();

        if (op !== 'FLUSHDB' && !key) {
            showNotification('Error: Key is required', 'error');
            log(`ERROR: Key missing for ${op}`);
            return;
        }

        switch (op) {
            case 'SET':
                store[key] = val;
                saveStore(store);
                log(`OK`, 'SET', key, val);
                showNotification('Key Set Successfully', 'success');
                inspectKey(key); // Auto inspect
                break;

            case 'GET':
                if (store.hasOwnProperty(key)) {
                    log(store[key], 'GET', key);
                    inspectKey(key);
                } else {
                    log('(nil)', 'GET', key);
                    inspectorContent.innerHTML = `<span style="color:var(--error-color)">Key does not exist.</span>`;
                    inspectorActions.style.display = 'none';
                }
                break;

            case 'DEL':
                if (store.hasOwnProperty(key)) {
                    delete store[key];
                    saveStore(store);
                    log('(integer) 1', 'DEL', key);
                    showNotification('Key Deleted', 'success');
                    inspectorContent.innerHTML = 'Item deleted.';
                    inspectorActions.style.display = 'none';
                } else {
                    log('(integer) 0', 'DEL', key);
                }
                break;

            case 'FLUSHDB':
                if(confirm("Are you sure you want to delete ALL data?")) {
                    saveStore({});
                    log('OK', 'FLUSHDB');
                    showNotification('Database Flushed', 'success');
                    inspectorContent.innerHTML = 'Database cleared.';
                    inspectorActions.style.display = 'none';
                }
                break;
        }

        // Clear inputs after SET
        if (op === 'SET') {
            keyInput.value = '';
            valueInput.value = '';
        }
    }

    // --- Visualization & Inspection ---

    function renderKeys() {
        const store = getStore();
        dataViz.innerHTML = '';
        const keys = Object.keys(store);

        if (keys.length === 0) {
            dataViz.innerHTML = '<span style="color:#999; font-size: 0.9rem;">Database is empty.</span>';
            return;
        }

        keys.forEach(key => {
            const pill = document.createElement('div');
            pill.className = 'key-capsule';
            pill.innerHTML = `
                <span onclick="inspectKey('${key}')">${key}</span>
                <span class="key-delete-x" onclick="quickDelete('${key}')">&times;</span>
            `;
            dataViz.appendChild(pill);
        });
    }

    function inspectKey(key) {
        const store = getStore();
        if(store.hasOwnProperty(key)) {
            currentInspectorKey = key;
            inspectorContent.innerHTML = `
                <div style="margin-bottom:0.5rem"><strong>Key:</strong> <span style="color:var(--control-color)">${key}</span></div>
                <div><strong>Value:</strong> <br><pre style="background:#eee; padding:0.5rem; border-radius:4px; margin-top:0.25rem; white-space:pre-wrap;">${store[key]}</pre></div>
                <div style="margin-top:0.5rem; font-size:0.8rem; color:#888;">Type: string</div>
            `;
            inspectorActions.style.display = 'block';
        }
    }

    function loadIntoForm() {
        if(!currentInspectorKey) return;
        const store = getStore();

        opSelect.value = 'SET';
        toggleInputs();

        keyInput.value = currentInspectorKey;
        valueInput.value = store[currentInspectorKey];

        // Scroll to top
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }

    function deleteCurrentInspectorKey() {
        if(!currentInspectorKey) return;

        opSelect.value = 'DEL';
        keyInput.value = currentInspectorKey;
        executeCommand(); // This handles the logic and UI updates
    }

    function quickDelete(key) {
        // Bypass form, direct delete
        const store = getStore();
        delete store[key];
        saveStore(store);
        log('(integer) 1', 'DEL', key);
        showNotification(`Deleted ${key}`, 'success');

        if(currentInspectorKey === key) {
            inspectorContent.innerHTML = 'Item deleted.';
            inspectorActions.style.display = 'none';
        }
    }

    // --- Utilities ---

    function log(message, cmd = '', key = '', val = '') {
        const time = new Date().toLocaleTimeString();
        const cmdSpan = cmd ? `<span class="log-cmd">${cmd}</span>` : '';
        const keySpan = key ? `<span class="log-key">${key}</span>` : '';
        // Truncate val if too long for log
        let cleanVal = val;
        if (cleanVal.length > 20) cleanVal = cleanVal.substring(0, 20) + '...';
        const valSpan = val ? `<span class="log-val">"${cleanVal}"</span>` : '';

        const entry = document.createElement('div');
        entry.className = 'log-entry';
        entry.innerHTML = `<span class="log-timestamp">[${time}]</span> ${cmdSpan} ${keySpan} ${valSpan} -> ${message}`;

        terminal.appendChild(entry);
        terminal.scrollTop = terminal.scrollHeight; // Auto scroll to bottom
    }

    function clearTerminal() {
        terminal.innerHTML = '';
        const entry = document.createElement('div');
        entry.className = 'log-entry';
        entry.innerHTML = `> Log cleared.`;
        terminal.appendChild(entry);
    }

    function showNotification(msg, type) {
        notification.textContent = msg;
        notification.style.backgroundColor = type === 'error' ? 'var(--error-color)' : 'var(--success-color)';
        notification.style.opacity = '1';
        setTimeout(() => {
            notification.style.opacity = '0';
        }, 2000);
    }

    // Initial load
    renderKeys();
    toggleInputs(); // Ensure correct inputs show on load

</script>

</body>
</html>
