<body>

    <div id="app-container">
        <!-- Header -->
        <header>
            <h1 id="header-title">Guestbook</h1>
            <div class="dropdown">
                <button onclick="toggleMenu()" class="menu-btn">⋮</button>
                <div id="myDropdown" class="dropdown-content">
                    <a href="#" onclick="showFeed()">Refresh Feed</a>
                    <a href="#" onclick="clearAllData()">Reset Demo</a>
                    <a href="#" onclick="logout()">Logout</a>
                </div>
            </div>
        </header>

        <!-- Main Content -->
        <main>
            <!-- Login View -->
            <div id="login-screen">
                <h2 style="color: var(--primary-teal); margin-bottom: 20px;">Welcome</h2>
                <div class="input-group">
                    <input type="text" id="username-input" placeholder="Enter your name to join..." maxlength="15">
                </div>
                <button class="btn" onclick="login()">Enter Guestbook</button>
                <p style="font-size: 0.8rem; margin-top: 20px; color: var(--dark-teal);">
                    (Background: Ice Blue | Elements: Teal)
                </p>
            </div>

            <!-- Feed View -->
            <div id="feed-screen">
                <div id="messages-container">
                    <!-- Dynamic Messages will load here -->
                </div>
                <div style="height: 20px;"></div> <!-- Spacer -->
            </div>
        </main>

        <!-- Sticky Input Area -->
        <div id="input-area">
            <div class="input-wrapper">
                <textarea id="message-input" placeholder="Leave a message..."></textarea>
                <button id="send-btn" class="btn" onclick="postMessage()">Send</button>
            </div>
        </div>

        <!-- Reply Modal -->
        <div id="reply-modal">
            <div class="modal-content">
                <h3>Reply to message</h3>
                <br>
                <textarea id="reply-input" rows="3" placeholder="Write your reply..."></textarea>
                <button class="btn" onclick="submitReply()" style="margin-top:10px;">Reply</button>
                <button class="btn cancel-btn" onclick="closeReplyModal()">Cancel</button>
            </div>
        </div>
    </div>

    <script>
        // --- STATE MANAGEMENT ---
        let currentUser = null;
        let messages = [];
        let replyingToId = null;

        // --- INITIALIZATION ---
        window.onload = function() {
            // Check LocalStorage for data persistence
            const storedMessages = localStorage.getItem('gb_messages');
            if (storedMessages) {
                messages = JSON.parse(storedMessages);
            }

            const storedUser = localStorage.getItem('gb_user');
            if (storedUser) {
                currentUser = storedUser;
                showFeed();
            }
        };

        // --- AUTHENTICATION ---
        function login() {
            const input = document.getElementById('username-input');
            const name = input.value.trim();

            if (name.length > 0) {
                currentUser = name;
                localStorage.setItem('gb_user', currentUser);

                // Animation transition
                document.getElementById('login-screen').style.opacity = '0';
                setTimeout(() => {
                    showFeed();
                }, 300);
            } else {
                alert("Please enter a name.");
            }
        }

        function logout() {
            localStorage.removeItem('gb_user');
            currentUser = null;
            location.reload();
        }

        // --- NAVIGATION & UI ---
        function showFeed() {
            document.getElementById('login-screen').style.display = 'none';
            document.getElementById('feed-screen').style.display = 'block';
            document.getElementById('input-area').style.display = 'block';
            document.getElementById('header-title').innerText = `Hi, ${currentUser}`;
            renderMessages();
            closeMenu();
        }

        function toggleMenu() {
            document.getElementById("myDropdown").classList.toggle("show");
        }

        function closeMenu() {
            document.getElementById("myDropdown").classList.remove("show");
        }

        // Close dropdown if clicked outside
        window.onclick = function(event) {
            if (!event.target.matches('.menu-btn')) {
                var dropdowns = document.getElementsByClassName("dropdown-content");
                for (var i = 0; i < dropdowns.length; i++) {
                    var openDropdown = dropdowns[i];
                    if (openDropdown.classList.contains('show')) {
                        openDropdown.classList.remove('show');
                    }
                }
            }
        }

        // --- MESSAGE LOGIC ---
        function postMessage() {
            const input = document.getElementById('message-input');
            const content = input.value.trim();

            if (content.length === 0) return;

            const newMessage = {
                id: Date.now(),
                user: currentUser,
                content: content,
                timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                replies: []
            };

            messages.unshift(newMessage); // Add to top
            saveData();
            renderMessages();
            input.value = ''; // Clear input
        }

        function deleteMessage(id) {
            if(confirm("Are you sure you want to delete this message?")) {
                messages = messages.filter(msg => msg.id !== id);
                saveData();
                renderMessages();
            }
        }

        // --- REPLY LOGIC ---
        function openReplyModal(id) {
            replyingToId = id;
            document.getElementById('reply-modal').style.display = 'flex';
            document.getElementById('reply-input').focus();
        }

        function closeReplyModal() {
            document.getElementById('reply-modal').style.display = 'none';
            document.getElementById('reply-input').value = '';
            replyingToId = null;
        }

        function submitReply() {
            const content = document.getElementById('reply-input').value.trim();
            if (content.length === 0) return;

            const msgIndex = messages.findIndex(m => m.id === replyingToId);
            if (msgIndex !== -1) {
                messages[msgIndex].replies.push({
                    user: currentUser,
                    content: content
                });
                saveData();
                renderMessages();
                closeReplyModal();
            }
        }

        // --- RENDERING ---
        function renderMessages() {
            const container = document.getElementById('messages-container');
            container.innerHTML = '';

            if (messages.length === 0) {
                container.innerHTML = '<p style="text-align:center; color: #666; margin-top: 50px;">No messages yet. Be the first!</p>';
                return;
            }

            messages.forEach(msg => {
                const card = document.createElement('div');
                card.className = 'message-card';

                // Check if the current user owns this message
                const isOwner = msg.user === currentUser;

                // Build HTML for replies
                let repliesHtml = '';
                if (msg.replies && msg.replies.length > 0) {
                    repliesHtml = `<div class="replies-container">`;
                    msg.replies.forEach(reply => {
                        repliesHtml += `
                            <div class="reply-card">
                                <strong>${reply.user}:</strong> ${reply.content}
                            </div>
                        `;
                    });
                    repliesHtml += `</div>`;
                }

                // Delete button logic
                const deleteBtn = isOwner ? `<button class="action-btn delete" onclick="deleteMessage(${msg.id})">Delete</button>` : '';

                card.innerHTML = `
                    <div class="msg-header">
                        <span>${msg.user}</span>
                        <span>${msg.timestamp}</span>
                    </div>
                    <div class="msg-content">${msg.content}</div>
                    <div class="msg-actions">
                        <button class="action-btn" onclick="openReplyModal(${msg.id})">Reply</button>
                        ${deleteBtn}
                    </div>
                    ${repliesHtml}
                `;

                container.appendChild(card);
            });
        }

        // --- DATA UTILS ---
        function saveData() {
            localStorage.setItem('gb_messages', JSON.stringify(messages));
        }

        function clearAllData() {
            if(confirm("Reset entire demo? This clears all messages and logout.")) {
                localStorage.clear();
                location.reload();
            }
        }
    </script>
</body>
</html>
