            --text-color: #ffffff;
            --accent-color: #00adb5;
            --input-bg: #4b5d67;
            --shadow: 0 4px 6px rgba(0,0,0,0.3);
            --font-main: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        body {
            font-family: var(--font-main);
            background-color: var(--bg-color);
            color: var(--component-color);
            transition: background-color 0.3s ease;
            min-height: 100vh;
            display: flex;
            flex-direction: column;
        }

        /* --- LAYOUT --- */
        header {
            background-color: var(--component-color);
            color: var(--text-color);
            padding: 1rem 2rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
            box-shadow: var(--shadow);
        }

        .logo {
            font-size: 1.5rem;
            font-weight: bold;
            display: flex;
            align-items: center;
            gap: 10px;
        }

        .status-dot {
            height: 10px;
            width: 10px;
            background-color: #ff5252;
            border-radius: 50%;
            display: inline-block;
            box-shadow: 0 0 5px #ff5252;
            transition: background-color 0.3s;
        }

        .status-dot.online {
            background-color: #00e676;
            box-shadow: 0 0 5px #00e676;
        }

        main {
            flex: 1;
            padding: 2rem;
            max-width: 1200px;
            margin: 0 auto;
            width: 100%;
            display: grid;
            grid-template-columns: 1fr;
            gap: 2rem;
        }

        @media (min-width: 768px) {
            main {
                grid-template-columns: 300px 1fr;
            }
        }

        /* --- COMPONENTS --- */
        .card {
            background-color: var(--component-color);
            color: var(--text-color);
            border-radius: 8px;
            padding: 1.5rem;
            box-shadow: var(--shadow);
            margin-bottom: 1.5rem;
            transition: transform 0.2s;
        }

        .card:hover {
            transform: translateY(-2px);
        }

        h2 {
            margin-bottom: 1rem;
            border-bottom: 2px solid var(--accent-color);
            padding-bottom: 0.5rem;
            font-size: 1.2rem;
        }

        /* --- FORMS & INPUTS --- */
        input, textarea, select {
            width: 100%;
            padding: 10px;
            margin-bottom: 10px;
            border: none;
            border-radius: 4px;
            background-color: var(--input-bg);
            color: var(--text-color);
            font-family: inherit;
        }

        input:focus, textarea:focus {
            outline: 2px solid var(--accent-color);
        }

        button {
            padding: 10px 20px;
            background-color: var(--accent-color);
            color: white;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: bold;
            transition: opacity 0.2s;
        }

        button:hover {
            opacity: 0.9;
        }

        button:disabled {
            background-color: #666;
            cursor: not-allowed;
        }

        /* --- LOGIN SECTION --- */
        #login-overlay {
            position: fixed;
            top: 0; left: 0; width: 100%; height: 100%;
            background: rgba(0,0,0,0.8);
            display: flex;
            justify-content: center;
            align-items: center;
            z-index: 1000;
        }

        #login-box {
            background: var(--component-color);
            padding: 2rem;
            border-radius: 8px;
            color: white;
            width: 300px;
            text-align: center;
        }

        .hidden {
            display: none !important;
        }

        /* --- MESSAGE BOARD --- */
        #message-list {
            max-height: 400px;
            overflow-y: auto;
            display: flex;
            flex-direction: column;
            gap: 10px;
            margin-bottom: 1rem;
            padding-right: 5px;
        }

        /* Scrollbar styling */
        #message-list::-webkit-scrollbar {
            width: 8px;
        }
        #message-list::-webkit-scrollbar-track {
            background: var(--input-bg); 
        }
        #message-list::-webkit-scrollbar-thumb {
            background: var(--accent-color); 
            border-radius: 4px;
        }

        .msg-item {
            background-color: rgba(255,255,255,0.1);
            padding: 10px;
            border-radius: 4px;
            animation: fadeIn 0.3s ease-in;
        }

        .msg-meta {
            font-size: 0.8rem;
            color: #ccc;
            margin-bottom: 4px;
            display: flex;
            justify-content: space-between;
        }

        .msg-content {
            word-break: break-word;
        }

        /* --- DATA GRABBER --- */
        #data-display {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(120px, 1fr));
            gap: 10px;
            margin-top: 10px;
        }

        .data-item {
            background: var(--input-bg);
            padding: 10px;
            border-radius: 4px;
            text-align: center;
            font-size: 0.9rem;
        }

        .loader {
            border: 4px solid #f3f3f3;
            border-top: 4px solid var(--accent-color);
            border-radius: 50%;
            width: 30px;
            height: 30px;
            animation: spin 1s linear infinite;
            margin: 10px auto;
            display: none;
        }

        /* --- DROPDOWN MENU --- */
        .dropdown {
            position: relative;
            display: inline-block;
        }

        .dropbtn {
            background-color: transparent;
            border: 1px solid var(--text-color);
        }

        .dropdown-content {
            display: none;
            position: absolute;
            right: 0;
            background-color: #f9f9f9;
            min-width: 160px;
            box-shadow: 0px 8px 16px 0px rgba(0,0,0,0.2);
            z-index: 1;
            border-radius: 4px;
        }

        .dropdown-content a {
            color: black;
            padding: 12px 16px;
            text-decoration: none;
            display: block;
        }

        .dropdown-content a:hover {background-color: #f1f1f1;}
        .dropdown:hover .dropdown-content {display: block;}

        /* --- ANIMATIONS --- */
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(10px); }
            to { opacity: 1; transform: translateY(0); }
        }

        @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }
    </style>
</head>
<body>

    <!-- LOGIN MODAL -->
    <div id="login-overlay">
        <div id="login-box">
            <h2>System Access</h2>
            <p style="margin-bottom: 15px; font-size: 0.9rem; color: #ccc;">Enter any username to demo.</p>
            <input type="text" id="username-input" placeholder="Username" autocomplete="off">
            <input type="password" id="password-input" placeholder="Password">
            <button onclick="app.login()">Login</button>
            <p id="login-error" style="color: #ff5252; margin-top: 10px; display: none;">Please enter a username.</p>
        </div>
    </div>

    <!-- MAIN INTERFACE -->
    <header>
        <div class="logo">
            <span id="connection-status" class="status-dot"></span>
            AJAX Dashboard
        </div>
        <div class="user-controls">
            <span id="welcome-msg" style="margin-right: 15px;">Welcome, Guest</span>
            <div class="dropdown">
                <button class="dropbtn">Options ▼</button>
                <div class="dropdown-content">
                    <a href="#" onclick="app.toggleTheme()">Toggle Theme</a>
                    <a href="#" onclick="app.clearData()">Clear Local Data</a>
                    <a href="#" onclick="app.logout()">Logout</a>
                </div>
            </div>
        </div>
    </header>

    <main>
        <!-- SIDEBAR: DATA GRABBER -->
        <aside>
            <div class="card">
                <h2>External Data Grabber</h2>
                <p style="font-size: 0.9rem; margin-bottom: 10px; color: #ccc;">Fetches user data via AJAX from JSONPlaceholder API.</p>
                <button onclick="app.fetchExternalData()" id="fetch-btn">Grab Data</button>
                <div class="loader" id="data-loader"></div>
                <div id="data-display">
                    <!-- Fetched items go here -->
                </div>
            </div>

            <div class="card">
                <h2>System Stats</h2>
                <div id="clock" style="font-size: 2rem; font-weight: bold; text-align: center; margin: 10px 0;">00:00:00</div>
                <p style="text-align: center; color: #00e676;">Server Active</p>
            </div>
        </aside>

        <!-- CONTENT: MESSAGE BOARD -->
        <section>
            <div class="card">
                <h2>Real-time Message Board</h2>
                <div id="message-list">
                    <!-- Messages go here -->
                    <div class="msg-item" style="text-align: center; color: #ccc;">No messages yet. Start the conversation!</div>
                </div>

                <div class="message-input-area">
                    <textarea id="msg-input" rows="3" placeholder="Type your message here..."></textarea>
                    <div style="display: flex; justify-content: flex-end;">
                        <button onclick="app.postMessage()">Send Message</button>
                    </div>
                </div>
            </div>
        </section>
