    <script>
        /**
         * The App Logic
         * Encapsulated to avoid global scope pollution
         */
        const app = {
            currentUser: null,
            pollingInterval: null,

            // Simulation of a server database
            mockDatabase: [
                { id: 1, user: 'System', text: 'Welcome to the secure channel.', timestamp: new Date().toLocaleTimeString() }
            ],

            init: function() {
                this.updateClock();
                setInterval(() => this.updateClock(), 1000);

                // Check if user session exists in mock storage
                const storedUser = localStorage.getItem('ajaxAppUser');
                if (storedUser) {
                    this.currentUser = storedUser;
                    this.completeLoginSetup();
                }

                // Setup listener for Enter key on inputs
                document.getElementById('password-input').addEventListener('keypress', (e) => {
                    if (e.key === 'Enter') this.login();
                });
            },

            // --- AUTHENTICATION ---
            login: function() {
                const username = document.getElementById('username-input').value.trim();
                const errorMsg = document.getElementById('login-error');

                if (username) {
                    // Simulate AJAX Login Request
                    const btn = document.querySelector('#login-box button');
                    btn.textContent = 'Authenticating...';
                    btn.disabled = true;

                    setTimeout(() => { // Artificial delay
                        this.currentUser = username;
                        localStorage.setItem('ajaxAppUser', username);
                        this.completeLoginSetup();

                        // Reset login box for next time
                        btn.textContent = 'Login';
                        btn.disabled = false;
                        document.getElementById('username-input').value = '';
                        document.getElementById('password-input').value = '';
                        errorMsg.style.display = 'none';
                    }, 800);
                } else {
                    errorMsg.style.display = 'block';
                }
            },

            completeLoginSetup: function() {
                document.getElementById('login-overlay').classList.add('hidden');
                document.getElementById('welcome-msg').textContent = `Welcome, ${this.currentUser}`;
                document.getElementById('connection-status').classList.add('online');

                // Start "Real-time" polling
                this.refreshMessages(); // Initial load
                this.pollingInterval = setInterval(() => this.pollForUpdates(), 3000);
            },

            logout: function() {
                this.currentUser = null;
                localStorage.removeItem('ajaxAppUser');
                document.getElementById('login-overlay').classList.remove('hidden');
                document.getElementById('connection-status').classList.remove('online');
                clearInterval(this.pollingInterval);
            },

            // --- MESSAGE BOARD (AJAX SIMULATION) ---
            postMessage: function() {
                const input = document.getElementById('msg-input');
                const text = input.value.trim();

                if (!text) return;

                // Create message object
                const newMessage = {
                    id: Date.now(),
                    user: this.currentUser,
                    text: text,
                    timestamp: new Date().toLocaleTimeString()
                };

                // 1. Simulate sending data to server (AJAX POST)
                // In a real app, this would be fetch('/api/messages', { method: 'POST'... })

                // Optimistic UI update (optional, but we'll wait for "server" response here)
                const sendBtn = document.querySelector('.message-input-area button');
                const originalText = sendBtn.textContent;
                sendBtn.textContent = 'Sending...';
                sendBtn.disabled = true;

                setTimeout(() => {
                    this.mockDatabase.push(newMessage);
                    input.value = ''; // Clear input
                    this.refreshMessages(); // Re-render list

                    sendBtn.textContent = originalText;
                    sendBtn.disabled = false;
                }, 400); // 400ms network latency simulation
            },

            pollForUpdates: function() {
                // Periodically asks server for new data
                // In reality: GET /api/messages
                this.refreshMessages();
            },

            refreshMessages: function() {
                const list = document.getElementById('message-list');

                // Only redraw if necessary (simple diffing logic omitted for brevity, usually VDOM handles this)
                // Here we just rebuild the HTML string for the demo
                let html = '';

                // Show latest messages at the bottom
                this.mockDatabase.forEach(msg => {
                    const isMe = msg.user === this.currentUser;
                    const style = isMe ? 'border-left: 3px solid var(--accent-color);' : '';

                    html += `
                        <div class="msg-item" style="${style}">
                            <div class="msg-meta">
                                <strong>${msg.user}</strong>
                                <span>${msg.timestamp}</span>
                            </div>
                            <div class="msg-content">${this.escapeHtml(msg.text)}</div>
                        </div>
                    `;
                });

                list.innerHTML = html;
                // Auto scroll to bottom
                list.scrollTop = list.scrollHeight;
            },

            // --- DATA GRABBER (REAL EXTERNAL AJAX) ---
            fetchExternalData: function() {
                const display = document.getElementById('data-display');
                const loader = document.getElementById('data-loader');
                const btn = document.getElementById('fetch-btn');

                loader.style.display = 'block';
                display.innerHTML = '';
                btn.disabled = true;

                // Using XMLHttpRequest for traditional AJAX demonstration, 
                // though Fetch API is more modern.
                const xhr = new XMLHttpRequest();
                xhr.open('GET', 'https://jsonplaceholder.typicode.com/users', true);

                xhr.onload = function() {
                    if (this.status === 200) {
                        const users = JSON.parse(this.responseText);

                        // Limit to 6 for space
                        const slicedUsers = users.slice(0, 6);

                        let html = '';
                        slicedUsers.forEach(user => {
                            html += `
                                <div class="data-item">
                                    <strong>${user.username}</strong><br>
                                    <span style="font-size:0.7em; opacity:0.7">${user.email}</span>
                                </div>
                            `;
                        });
                        display.innerHTML = html;
                    } else {
                        display.innerHTML = '<p style="color:red">Error fetching data</p>';
                    }
                    loader.style.display = 'none';
                    btn.disabled = false;
                };

                xhr.onerror = function() {
                    display.innerHTML = '<p style="color:red">Network Error</p>';
                    loader.style.display = 'none';
                    btn.disabled = false;
                };

                xhr.send();
            },

            // --- UTILITIES ---
            updateClock: function() {
                const now = new Date();
                document.getElementById('clock').textContent = now.toLocaleTimeString();
            },

            toggleTheme: function() {
                const root = document.documentElement;
                const currentBg = getComputedStyle(root).getPropertyValue('--bg-color').trim();

                if (currentBg === '#8f9ea8') {
                    // Dark Mode
                    root.style.setProperty('--bg-color', '#222831');
                    root.style.setProperty('--component-color', '#393e46');
                } else {
                    // Default Mode (Cool Gray / Charcoal)
                    root.style.setProperty('--bg-color', '#8f9ea8');
                    root.style.setProperty('--component-color', '#36454F');
                }
            },

            clearData: function() {
                this.mockDatabase = [{ id: 1, user: 'System', text: 'Chat history cleared.', timestamp: new Date().toLocaleTimeString() }];
                this.refreshMessages();
                document.getElementById('data-display').innerHTML = '';
            },

            escapeHtml: function(text) {
                const map = {
                    '&': '&amp;',
                    '<': '&lt;',
                    '>': '&gt;',
                    '"': '&quot;',
                    "'": '&#039;'
                };
                return text.replace(/[&<>"']/g, function(m) { return map[m]; });
            }
        };

        // Initialize the application when DOM is ready
        document.addEventListener('DOMContentLoaded', () => {
            app.init();
        });

    </script>
</body>
</html>
