    <script>
        /* --- JAVASCRIPT LOGIC --- */

        // Sample Data: Initial Reviews
        let reviews = [
            {
                id: 1,
                name: "SakuraLover",
                rating: 5,
                text: "Absolutely stunning animation! The final episode made me cry. Highly recommended for fans of magical girl genres.",
                date: new Date("2023-10-25").getTime()
            },
            {
                id: 2,
                name: "CritiqueMaster",
                rating: 3,
                text: "The art style is beautiful, but the pacing felt a bit slow in the middle arc. Worth a watch, but requires patience.",
                date: new Date("2023-11-02").getTime()
            },
            {
                id: 3,
                name: "AnimeNewbie",
                rating: 4,
                text: "Great character development. Yuna is such a relatable protagonist.",
                date: new Date("2023-11-05").getTime()
            }
        ];

        const reviewsListElement = document.getElementById('reviewsList');
        const reviewCountElement = document.getElementById('reviewCount');
        const modal = document.getElementById('reviewModal');

        // Initialize Page
        document.addEventListener('DOMContentLoaded', () => {
            renderReviews();
            updateAverageRating();
        });

        // Function to render stars string based on number
        function getStars(rating) {
            let stars = '';
            for(let i=1; i<=5; i++) {
                stars += i <= rating ? '★' : '☆';
            }
            return stars;
        }

        // Render Reviews to DOM
        function renderReviews() {
            reviewsListElement.innerHTML = '';

            reviews.forEach(review => {
                const dateObj = new Date(review.date);
                const formattedDate = dateObj.toLocaleDateString() + ' ' + dateObj.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

                const card = document.createElement('div');
                card.className = 'review-card';
                card.innerHTML = `
                    <div class="review-user">
                        <span class="user-name">${review.name}</span>
                        <span class="review-stars">${getStars(review.rating)}</span>
                    </div>
                    <p>${review.text}</p>
                    <div class="review-date" style="margin-top: 10px; text-align: right;">${formattedDate}</div>
                `;
                reviewsListElement.appendChild(card);
            });

            reviewCountElement.innerText = reviews.length;
        }

        // Modal Functions
        function openModal() {
            modal.style.display = 'flex';
        }

        function closeModal() {
            modal.style.display = 'none';
        }

        // Close modal if clicking outside
        window.onclick = function(event) {
            if (event.target == modal) {
                closeModal();
            }
        }

        // Submit New Review
        function submitReview(e) {
            e.preventDefault();

            const nameInput = document.getElementById('username').value;
            const textInput = document.getElementById('comment').value;

            // Get selected rating
            const ratingInputs = document.getElementsByName('rating');
            let selectedRating = 0;
            for(const input of ratingInputs){
                if(input.checked) selectedRating = parseInt(input.value);
            }

            const newReview = {
                id: Date.now(),
                name: nameInput,
                rating: selectedRating,
                text: textInput,
                date: Date.now()
            };

            reviews.unshift(newReview); // Add to beginning

            // Reset Form
            document.getElementById('reviewForm').reset();
            closeModal();

            // Re-render
            renderReviews();
            updateAverageRating();

            // Reset sort dropdown to Newest
            document.getElementById('sortFilter').value = 'newest';
        }

        // Sorting Logic
        function sortReviews() {
            const criteria = document.getElementById('sortFilter').value;

            if (criteria === 'newest') {
                reviews.sort((a, b) => b.date - a.date);
            } else if (criteria === 'oldest') {
                reviews.sort((a, b) => a.date - b.date);
            } else if (criteria === 'highest') {
                reviews.sort((a, b) => b.rating - a.rating);
            } else if (criteria === 'lowest') {
                reviews.sort((a, b) => a.rating - b.rating);
            }

            renderReviews();
        }

        // Calculate and Update Global Rating
        function updateAverageRating() {
            if (reviews.length === 0) return;

            const total = reviews.reduce((acc, curr) => acc + curr.rating, 0);
            const average = (total / reviews.length).toFixed(1);

            // Convert 5 star scale to 10 point scale visual
            const tenPointScale = (average * 2).toFixed(1);

            let starDisplay = '';
            for(let i=1; i<=5; i++) {
                if (i <= Math.round(average)) {
                    starDisplay += '★';
                } else {
                    starDisplay += '☆';
                }
            }

            document.getElementById('averageRatingDisplay').innerHTML = 
                `${starDisplay} <span class="rating-score">${tenPointScale}/10</span>`;
        }
    </script>
</body>
</html>
