            <ul>
                <li><a href="#upload">Upload</a></li>
                <li><a href="#editor">Editor</a></li>
                <li><a href="#convert">Convert</a></li>
            </ul>
        </nav>
    </header>

    <div class="container">

        <!-- Upload Section -->
        <section id="upload" class="card">
            <h2 class="section-header">1. Upload CSV File</h2>
            <div class="upload-area" id="dropZone">
