    <script>
        // --- State Management ---
        let rawData = []; // Array of objects or arrays
        let headers = [];
        let originalFileName = "data";

        // --- DOM Elements ---
        const dropZone = document.getElementById('dropZone');
        const fileInput = document.getElementById('fileInput');
        const statusMsg = document.getElementById('statusMsg');
        const editorSection = document.getElementById('editor');
        const convertSection = document.getElementById('convert');
        const tableHeader = document.getElementById('tableHeader');
        const tableBody = document.getElementById('tableBody');
        const rowCountSpan = document.getElementById('rowCount');
        const previewArea = document.getElementById('previewArea');
        const loader = document.getElementById('loader');

        // --- Event Listeners for Upload ---
        dropZone.addEventListener('dragover', (e) => {
            e.preventDefault();
            dropZone.classList.add('drag-over');
        });

        dropZone.addEventListener('dragleave', () => {
            dropZone.classList.remove('drag-over');
        });

        dropZone.addEventListener('drop', (e) => {
            e.preventDefault();
            dropZone.classList.remove('drag-over');
            const files = e.dataTransfer.files;
            if (files.length) handleFile(files[0]);
        });

        fileInput.addEventListener('change', (e) => {
            if (e.target.files.length) handleFile(e.target.files[0]);
        });

        // --- File Handling Functions ---
        function handleFile(file) {
            if (file.type !== "text/csv" && !file.name.endsWith('.csv')) {
                showStatus("Please upload a valid .csv file", "error");
                return;
            }

            originalFileName = file.name.replace('.csv', '');
            showLoader(true);
            showStatus("Parsing file...", "success");

            const reader = new FileReader();
            reader.onload = function(e) {
                const text = e.target.result;
                parseCSV(text);
                showLoader(false);
                editorSection.style.display = 'block';
                convertSection.style.display = 'block';
                // Scroll to editor
                setTimeout(() => editorSection.scrollIntoView({behavior: "smooth"}), 100);
            };
            reader.readAsText(file);
        }

        function showStatus(msg, type) {
            statusMsg.textContent = msg;
            statusMsg.className = type;
            statusMsg.style.display = 'block';
        }

        function showLoader(show) {
            loader.style.display = show ? 'block' : 'none';
        }

        // --- CSV Parsing (Simple Implementation) ---
        function parseCSV(text) {
            // Basic CSV parser handling quoted fields
            const rows = [];
            let currentRow = [];
            let currentField = '';
            let inQuotes = false;

            for (let i = 0; i < text.length; i++) {
                const char = text[i];
                const nextChar = text[i + 1];

                if (inQuotes) {
                    if (char === '"' && nextChar === '"') {
                        currentField += '"';
                        i++; // skip next quote
                    } else if (char === '"') {
                        inQuotes = false;
                    } else {
                        currentField += char;
                    }
                } else {
                    if (char === '"') {
                        inQuotes = true;
                    } else if (char === ',') {
                        currentRow.push(currentField);
                        currentField = '';
                    } else if (char === '\n' || char === '\r') {
                        if (currentField || currentRow.length > 0) {
                            currentRow.push(currentField);
                            rows.push(currentRow);
                        }
                        currentRow = [];
                        currentField = '';
                        if (char === '\r' && nextChar === '\n') i++; // Handle CRLF
                    } else {
                        currentField += char;
                    }
                }
            }
            if (currentField || currentRow.length > 0) {
                currentRow.push(currentField);
                rows.push(currentRow);
            }

            // Assume first row is header
            if(rows.length > 0) {
                headers = rows[0];
                rawData = rows.slice(1).filter(row => row.length === headers.length); // Filter mismatched rows
                renderTable();
            } else {
                showStatus("File is empty", "error");
            }
        }

        // --- Table Rendering & Editing ---
        function renderTable() {
            tableHeader.innerHTML = '';
            tableBody.innerHTML = '';

            // Render Headers
            headers.forEach(header => {
                const th = document.createElement('th');
                th.textContent = header;
                tableHeader.appendChild(th);
            });

            // Render Rows
            rawData.forEach((row, rowIndex) => {
                const tr = document.createElement('tr');
                row.forEach((cellData, colIndex) => {
                    const td = document.createElement('td');
                    td.textContent = cellData;
                    td.contentEditable = "true";
                    // Save data on blur (focus lost)
                    td.addEventListener('blur', function() {
                        updateData(rowIndex, colIndex, this.textContent);
                    });
                    tr.appendChild(td);
                });
                tableBody.appendChild(tr);
            });

            rowCountSpan.textContent = rawData.length;
        }

        function updateData(rowIndex, colIndex, value) {
            rawData[rowIndex][colIndex] = value;
        }

        function addRow() {
            const emptyRow = new Array(headers.length).fill("");
            rawData.push(emptyRow);
            renderTable();
            // Scroll to bottom of table wrapper
            const wrapper = document.querySelector('.table-wrapper');
            wrapper.scrollTop = wrapper.scrollHeight;
        }

        function resetData() {
            if(confirm("Are you sure? This will reload the file from the initial upload state.")) {
                // Trigger file reload logic if needed, or just clear edits
                // For this demo, we'll just clear the table
                alert("To reset completely, please re-upload the file.");
                location.reload();
            }
        }

        // --- Conversion Logic ---
        function generateOutputString(format) {
            if (format === 'json') {
                const jsonOutput = rawData.map(row => {
                    let obj = {};
                    headers.forEach((h, i) => {
                        obj[h] = row[i];
                    });
                    return obj;
                });
                return JSON.stringify(jsonOutput, null, 2);
            }

            let delimiter = ',';
            if (format === 'tsv') delimiter = '\t';
            if (format === 'scsv') delimiter = ';';

            const processRow = (row) => row.map(val => {
                // Escape quotes and wrap in quotes if delimiter exists in content
                const stringVal = String(val);
                if (stringVal.includes(delimiter) || stringVal.includes('"') || stringVal.includes('\n')) {
                    return `"${stringVal.replace(/"/g, '""')}"`;
                }
                return stringVal;
            }).join(delimiter);

            const headerStr = processRow(headers);
            const rowsStr = rawData.map(processRow).join('\n');

            return `${headerStr}\n${rowsStr}`;
        }

        function previewConversion() {
            const format = document.getElementById('formatSelect').value;
            const output = generateOutputString(format);
            previewArea.style.display = 'block';

            // Truncate for preview if too long
            if(output.length > 5000) {
                previewArea.textContent = output.substring(0, 5000) + "\n... (Preview truncated)";
            } else {
                previewArea.textContent = output;
            }
        }

        function downloadFile() {
            const format = document.getElementById('formatSelect').value;
            const output = generateOutputString(format);
            const blob = new Blob([output], { type: 'text/plain' });
            const url = URL.createObjectURL(blob);

            const a = document.createElement('a');
            a.href = url;
            a.download = `${originalFileName}_converted.${format}`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }

    </script>
</body>
</html>
