    <!-- JavaScript Logic -->
    <script>
        // DOM Elements
        const fileInput = document.getElementById('fileInput');
        const dropZone = document.getElementById('dropZone');
        const originalPreview = document.getElementById('originalPreview');
        const uploadPlaceholder = document.getElementById('uploadPlaceholder');
        const generateBtn = document.getElementById('generateBtn');
        const scanningOverlay = document.getElementById('scanningOverlay');
        const aiStatus = document.getElementById('aiStatus');
        const finalCanvas = document.getElementById('finalCanvas');
        const downloadLink = document.getElementById('downloadLink');
        const bgColorSelect = document.getElementById('bgColorSelect');

        // Status Indicators
        const featFace = document.getElementById('feat-face').querySelector('span');
        const featBg = document.getElementById('feat-bg').querySelector('span');
        const featLight = document.getElementById('feat-light').querySelector('span');

        // State
        let uploadedImage = null;
        let selectedWidth = 295; // Default 1 inch approx pixels at 300dpi
        let selectedHeight = 413;

        // --- Event Listeners ---

        // File Upload Handling
        fileInput.addEventListener('change', handleFileSelect);

        // Drag and Drop
        dropZone.addEventListener('dragover', (e) => {
            e.preventDefault();
            dropZone.style.backgroundColor = '#e0e0e0';
        });

        dropZone.addEventListener('dragleave', (e) => {
            e.preventDefault();
            dropZone.style.backgroundColor = '#fafafa';
        });

        dropZone.addEventListener('drop', (e) => {
            e.preventDefault();
            dropZone.style.backgroundColor = '#fafafa';
            const files = e.dataTransfer.files;
            if (files.length > 0) {
                fileInput.files = files;
                handleFileSelect({ target: { files: files } });
            }
        });

        function handleFileSelect(event) {
            const file = event.target.files[0];
            if (file) {
                const reader = new FileReader();
                reader.onload = function(e) {
                    uploadedImage = new Image();
                    uploadedImage.onload = () => {
                        originalPreview.src = e.target.result;
                        originalPreview.style.display = 'block';
                        uploadPlaceholder.style.display = 'none';
                        generateBtn.disabled = false;
                        resetStatus();
                    };
                    uploadedImage.src = e.target.result;
                }
                reader.readAsDataURL(file);
            }
        }

        // Size Selection
        function selectSize(btn) {
            // Remove active class from all
            document.querySelectorAll('.size-btn').forEach(b => b.classList.remove('active'));
            // Add active to clicked
            btn.classList.add('active');
            // Update state
            selectedWidth = parseInt(btn.getAttribute('data-w'));
            selectedHeight = parseInt(btn.getAttribute('data-h'));
        }

        function resetStatus() {
            featFace.innerText = "Waiting...";
            featFace.style.color = "#999";
            featBg.innerText = "Waiting...";
            featBg.style.color = "#999";
            featLight.innerText = "Waiting...";
            featLight.style.color = "#999";
            finalCanvas.style.display = 'none';
            downloadLink.style.display = 'none';
        }

        // --- AI Process Simulation ---
        function startAIProcess() {
            if (!uploadedImage) return;

            // Show Overlay
            scanningOverlay.style.display = 'flex';
            generateBtn.disabled = true;
            generateBtn.innerText = "Processing...";

            // Simulate steps with timeouts
            updateAIStatus("Detecting Facial Landmarks...", 800, () => {
                featFace.innerText = "Detected (Confidence: 99%)";
                featFace.style.color = "green";
            });

            setTimeout(() => {
                updateAIStatus("Segmenting Background...", 0, () => {
                    featBg.innerText = "Removed Successfully";
                    featBg.style.color = "green";
                });
            }, 1800);

            setTimeout(() => {
                updateAIStatus("Adjusting Lighting Curve...", 0, () => {
                    featLight.innerText = "Optimized";
                    featLight.style.color = "green";
                });
            }, 3000);

            setTimeout(() => {
                scanningOverlay.style.display = 'none';
                generateIDPhoto();
                generateBtn.innerText = "✨ Generate AI Photo";
                generateBtn.disabled = false;
            }, 4000);
        }

        function updateAIStatus(text, delay, callback) {
            aiStatus.innerText = text;
            if(callback) callback();
        }

        // --- Canvas Generation ---
        function generateIDPhoto() {
            const ctx = finalCanvas.getContext('2d');

            // Set canvas size based on selection
            finalCanvas.width = selectedWidth;
            finalCanvas.height = selectedHeight;
            finalCanvas.style.display = 'block';

            // 1. Fill Background
            ctx.fillStyle = bgColorSelect.value;
            ctx.fillRect(0, 0, finalCanvas.width, finalCanvas.height);

            // 2. Calculate aspect ratio to "Crop" intelligently (Center Crop)
            const imgAspect = uploadedImage.width / uploadedImage.height;
            const canvasAspect = finalCanvas.width / finalCanvas.height;

            let drawWidth, drawHeight, offsetX, offsetY;

            if (imgAspect > canvasAspect) {
                // Image is wider than canvas
                drawHeight = finalCanvas.height;
                drawWidth = finalCanvas.height * imgAspect;
                offsetY = 0;
                offsetX = (finalCanvas.width - drawWidth) / 2;
            } else {
                // Image is taller than canvas
                drawWidth = finalCanvas.width;
                drawHeight = finalCanvas.width / imgAspect;
                offsetX = 0;
                offsetY = (finalCanvas.height - drawHeight) / 2; // Center vertically
                // For ID photos, usually shift slightly up for face centering
                offsetY += 10; 
            }

            // Draw image on canvas
            ctx.drawImage(uploadedImage, offsetX, offsetY, drawWidth, drawHeight);

            // 3. Apply a subtle "AI Enhancement" filter (Brightness/Contrast simulation)
            // Note: Real brightness manipulation requires pixel manipulation, keeping it simple here
            ctx.globalCompositeOperation = 'overlay';
            ctx.fillStyle = 'rgba(255,255,255,0.1)'; // Lighten slightly
            ctx.fillRect(0,0, finalCanvas.width, finalCanvas.height);
            ctx.globalCompositeOperation = 'source-over'; // Reset

            // Setup Download
            const dataURL = finalCanvas.toDataURL('image/png');
            downloadLink.href = dataURL;
            downloadLink.style.display = 'block';
            downloadLink.innerText = "⬇️ Download Result";
        }
    </script>
</body>
</html>
