<body>

    <header>
        <h1>Form to JSON Converter</h1>
        <p class="subtitle">Build a form on the left, get JSON on the right.</p>
    </header>

    <div class="container">
        <!-- LEFT PANEL: Form Builder & Preview -->
        <div class="panel">
            <h2>1. Form Builder</h2>

            <!-- Builder Controls -->
            <div class="builder-controls">
                <div class="input-group">
                    <label for="field-type">Type</label>
                    <select id="field-type">
                        <option value="text">Text Input</option>
                        <option value="number">Number Input</option>
                        <option value="email">Email Input</option>
                        <option value="textarea">Text Area</option>
                        <option value="checkbox">Checkbox</option>
                        <option value="select">Dropdown (Yes/No/Maybe)</option>
                        <option value="date">Date Picker</option>
                    </select>
                </div>

                <div class="input-group">
                    <label for="field-label">Label (Display Name)</label>
                    <input type="text" id="field-label" placeholder="e.g. First Name">
                </div>

                <div class="input-group">
                    <label for="field-key">JSON Key (Variable Name)</label>
                    <input type="text" id="field-key" placeholder="e.g. firstName">
                </div>

                <button class="btn-add" onclick="addField()">+ Add Field</button>
            </div>

            <!-- The Generated Form -->
            <form id="dynamic-form" onsubmit="event.preventDefault(); convertToJSON();">
                <div class="empty-state" id="empty-msg">
                    No fields added yet. Use the builder above to start.
                </div>
                <!-- Fields will be injected here -->
            </form>

            <button class="btn-generate" onclick="convertToJSON()">Convert to JSON Object</button>
        </div>

        <!-- RIGHT PANEL: JSON Output -->
        <div class="panel">
            <h2>2. JSON Output</h2>
            <textarea id="json-output" readonly placeholder="JSON result will appear here..."></textarea>
            <button class="copy-btn" onclick="copyToClipboard()">Copy JSON</button>
        </div>
    </div>

    <script>
        /**
         * Application State
         * Stores the definition of fields added by the user.
         */
        let formFields = [];

        /**
         * Adds a field to the form UI and state array based on user input.
         */
        function addField() {
            const type = document.getElementById('field-type').value;
            const label = document.getElementById('field-label').value.trim();
            const key = document.getElementById('field-key').value.trim();

            // Validation
            if (!label || !key) {
                alert("Please provide both a Label and a JSON Key.");
                return;
            }

            // Check for duplicate keys
            if (formFields.some(field => field.key === key)) {
                alert("This JSON Key already exists. Please use a unique key.");
                return;
            }

            const fieldConfig = {
                id: 'field-' + Date.now(), // unique ID for DOM
                type: type,
                label: label,
                key: key
            };

            formFields.push(fieldConfig);
            renderField(fieldConfig);

            // Clear inputs
            document.getElementById('field-label').value = '';
            document.getElementById('field-key').value = '';

            // Remove empty state message
            const emptyMsg = document.getElementById('empty-msg');
            if (emptyMsg) emptyMsg.style.display = 'none';
        }

        /**
         * Renders the HTML for a single field configuration.
         */
        function renderField(field) {
            const formContainer = document.getElementById('dynamic-form');

            const wrapper = document.createElement('div');
            wrapper.className = 'form-element-wrapper';
            wrapper.id = `wrapper-${field.id}`;

            let inputHTML = '';

            // Generate HTML based on input type
            switch (field.type) {
                case 'textarea':
                    inputHTML = `<textarea id="${field.id}" name="${field.key}" rows="3"></textarea>`;
                    break;
                case 'select':
                    inputHTML = `
                        <select id="${field.id}" name="${field.key}">
                            <option value="">-- Select --</option>
                            <option value="Yes">Yes</option>
                            <option value="No">No</option>
                            <option value="Maybe">Maybe</option>
                        </select>`;
                    break;
                case 'checkbox':
                    // Checkboxes need different wrapping for alignment
                    inputHTML = `
                        <div class="checkbox-wrapper">
                            <input type="checkbox" id="${field.id}" name="${field.key}">
                            <span>${field.label}</span>
                        </div>
                    `;
                    break;
                default: // text, number, email, date
                    inputHTML = `<input type="${field.type}" id="${field.id}" name="${field.key}">`;
            }

            // Construct the internal HTML structure
            let innerContent = '';
            if (field.type === 'checkbox') {
                 innerContent = `
                    <div class="form-field-container">
                        ${inputHTML}
                        <small style="color:#666; font-size:0.8em">Key: ${field.key}</small>
                    </div>
                `;
            } else {
                innerContent = `
                    <div class="form-field-container">
                        <label for="${field.id}">${field.label}</label>
                        ${inputHTML}
                        <small style="color:#666; font-size:0.8em">Key: ${field.key}</small>
                    </div>
                `;
            }

            wrapper.innerHTML = `
                ${innerContent}
                <button type="button" class="btn-remove" onclick="removeField('${field.id}')" title="Remove Field">&times;</button>
            `;

            formContainer.appendChild(wrapper);
        }

        /**
         * Removes a field from the DOM and state array.
         */
        function removeField(id) {
            // Remove from DOM
            const element = document.getElementById(`wrapper-${id}`);
            if (element) {
                element.remove();
            }

            // Remove from State
            formFields = formFields.filter(f => f.id !== id);

            // Check if empty
            if (formFields.length === 0) {
                document.getElementById('empty-msg').style.display = 'block';
            }
        }

        /**
         * Iterates over the defined fields, grabs their values, and creates a JSON object.
         */
        function convertToJSON() {
            if (formFields.length === 0) {
                document.getElementById('json-output').value = "{}";
                return;
            }

            const resultObject = {};

            formFields.forEach(field => {
                const domElement = document.getElementById(field.id);

                if (domElement) {
                    if (field.type === 'checkbox') {
                        resultObject[field.key] = domElement.checked;
                    } else if (field.type === 'number') {
                        // Attempt to parse number, fallback to string if empty or invalid
                        const val = domElement.value;
                        resultObject[field.key] = val === "" ? null : Number(val);
                    } else {
                        resultObject[field.key] = domElement.value;
                    }
                }
            });

            // Format JSON nicely with 4-space indentation
            const jsonString = JSON.stringify(resultObject, null, 4);
            document.getElementById('json-output').value = jsonString;
        }

        /**
         * Helper to copy JSON output to clipboard.
         */
        function copyToClipboard() {
            const copyText = document.getElementById("json-output");
            copyText.select();
            copyText.setSelectionRange(0, 99999); // For mobile devices
            navigator.clipboard.writeText(copyText.value).then(() => {
                alert("JSON copied to clipboard!");
            });
        }
    </script>
</body>
</html>
