    <script>
        // --- 1. SNOW BACKGROUND EFFECT ---
        function createSnow() {
            const container = document.getElementById('snow-container');
            const particleCount = 50;

            for (let i = 0; i < particleCount; i++) {
                const snowflake = document.createElement('div');
                snowflake.classList.add('snowflake');

                // Randomize properties
                const size = Math.random() * 5 + 2 + 'px';
                snowflake.style.width = size;
                snowflake.style.height = size;
                snowflake.style.left = Math.random() * 100 + 'vw';
                snowflake.style.animationDuration = Math.random() * 3 + 2 + 's';
                snowflake.style.animationDelay = Math.random() * 5 + 's';

                // Dim gray color variance for depth
                snowflake.style.backgroundColor = Math.random() > 0.8 ? '#DCDCDC' : '#fff';

                container.appendChild(snowflake);
            }
        }

        // --- 2. DYNAMIC TYPING TEXT ---
        const phrases = ["Don't worry about losing data.", "We save as you type.", "Pick up where you left off."];
        let phraseIndex = 0;
        let charIndex = 0;
        let isDeleting = false;
        const typeSpeed = 100;
        const deleteSpeed = 50;
        const pauseTime = 2000;

        function typeEffect() {
            const currentPhrase = phrases[phraseIndex];
            const textElement = document.getElementById('dynamic-text');

            if (isDeleting) {
                textElement.textContent = currentPhrase.substring(0, charIndex - 1);
                charIndex--;
            } else {
                textElement.textContent = currentPhrase.substring(0, charIndex + 1);
                charIndex++;
            }

            let nextSpeed = isDeleting ? deleteSpeed : typeSpeed;

            if (!isDeleting && charIndex === currentPhrase.length) {
                isDeleting = true;
                nextSpeed = pauseTime; // Pause at end
            } else if (isDeleting && charIndex === 0) {
                isDeleting = false;
                phraseIndex = (phraseIndex + 1) % phrases.length;
                nextSpeed = 500;
            }

            setTimeout(typeEffect, nextSpeed);
        }

        // --- 3. FORM STORAGE LOGIC ---
        const STORAGE_KEY = 'snowfall_form_data';
        const form = document.getElementById('autoSaveForm');
        const statusSpan = document.getElementById('save-status');
        const jsonDisplay = document.getElementById('json-display');

        // Load saved data on page load
        function loadSavedData() {
            const savedData = localStorage.getItem(STORAGE_KEY);

            if (savedData) {
                const data = JSON.parse(savedData);

                // Populate fields
                Object.keys(data).forEach(key => {
                    const field = form.elements[key];
                    if (field) {
                        field.value = data[key];
                    }
                });

                statusSpan.textContent = "✓ Loaded previously saved session";
                statusSpan.style.color = "var(--success-color)";
                updateJsonDisplay(data);
            }
        }

        // Save data to local storage
        function saveData() {
            const formData = new FormData(form);
            const data = {};

            formData.forEach((value, key) => {
                data[key] = value;
            });

            localStorage.setItem(STORAGE_KEY, JSON.stringify(data));

            // Update UI indicators
            statusSpan.innerHTML = "<i>Saving...</i>";
            setTimeout(() => {
                statusSpan.textContent = "✓ All changes saved";
                statusSpan.style.color = "var(--success-color)";
            }, 500);

            updateJsonDisplay(data);
        }

        // Update the JSON viewer panel
        function updateJsonDisplay(data) {
            jsonDisplay.textContent = JSON.stringify(data, null, 4);
        }

        // --- 4. EVENT LISTENERS ---

        // Listen for any input change in the form
        form.addEventListener('input', (e) => {
            saveData();
        });

        // Prevent actual submission for this demo
        form.addEventListener('submit', (e) => {
            e.preventDefault();
            alert('Form Submitted Successfully! (In a real app, this would send data to a server).');
            clearStorage();
        });

        // Clear storage function
        function clearStorage() {
            if(confirm("Are you sure you want to clear your saved progress?")) {
                localStorage.removeItem(STORAGE_KEY);
                form.reset();
                statusSpan.textContent = "Data cleared.";
                statusSpan.style.color = "var(--accent-color)";
                updateJsonDisplay({});
            }
        }

        // Toggle visibility of raw data panel
        function toggleDataView() {
            const panel = document.getElementById('data-panel');
            panel.style.display = panel.style.display === 'block' ? 'none' : 'block';
            window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
        }

        function scrollToTop() {
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        // --- INITIALIZATION ---
        document.addEventListener('DOMContentLoaded', () => {
            createSnow();
            typeEffect();
            loadSavedData();
        });

    </script>
</body>
</html>
