<body>

    <div class="container">
        <header>
            <h1>😎 Emoji Moji</h1>
            <p class="subtitle">Convert feelings to pixels and back again.</p>
        </header>

        <div class="controls">
            <div class="dropdown-wrapper">
                <label for="modeSelect" style="display:none;">Select Mode</label>
                <select id="modeSelect" onchange="updateUI()">
                    <option value="textToEmoji">Text to Emoji (e.g., "cat" -> 🐱)</option>
                    <option value="emojiToText">Emoji to Text (e.g., 🐱 -> :cat:)</option>
                </select>
            </div>
        </div>

        <div class="workspace">
            <div class="input-group">
                <label for="inputText" id="inputLabel">Enter text to convert:</label>
                <textarea id="inputText" placeholder="Type here..."></textarea>
            </div>

            <div class="actions">
                <button class="btn-primary" onclick="performConversion()">✨ Convert</button>
                <button class="btn-secondary" onclick="clearAll()">🗑️ Clear</button>
            </div>

            <label>Result:</label>
            <div class="result-area" id="resultBox">
                <button class="copy-btn" onclick="copyResult()">Copy</button>
                <div id="outputContent" class="result-text">
                    <div class="placeholder-text">Result will appear here...</div>
                </div>
            </div>
        </div>
    </div>

    <div id="toast" class="notification">Copied to clipboard!</div>

    <script>
        // JAVASCRIPT LOGIC

        // A basic dictionary for mapping text to emojis and vice versa
        // In a production app, this would be a much larger JSON object or an API call.
        const emojiMap = {
            "smile": "😊", "happy": "😊",
            "sad": "😢", "cry": "😢",
            "angry": "😠", "mad": "😠",
            "heart": "❤️", "love": "❤️",
            "cat": "🐱", "kitten": "🐱",
            "dog": "🐶", "puppy": "🐶",
            "fire": "🔥", "hot": "🔥",
            "cool": "😎", "sunglasses": "😎",
            "thumbsup": "👍", "yes": "👍",
            "thumbsdown": "👎", "no": "👎",
            "poop": "💩",
            "pizza": "🍕",
            "rocket": "🚀",
            "star": "⭐",
            "sun": "☀️",
            "moon": "🌙",
            "check": "✅",
            "cross": "❌",
            "robot": "🤖",
            "ghost": "👻",
            "party": "🎉",
            "beer": "🍺",
            "coffee": "☕"
        };

        // Create reverse map for Emoji to Text (Emoji -> :shortcode:)
        const reverseMap = {};
        for (const [key, value] of Object.entries(emojiMap)) {
            // We prioritize the first keyword found for the emoji
            if (!reverseMap[value]) {
                reverseMap[value] = `:${key}:`;
            }
        }

        // --- Functions ---

        function updateUI() {
            const mode = document.getElementById('modeSelect').value;
            const inputLabel = document.getElementById('inputLabel');
            const textarea = document.getElementById('inputText');

            if (mode === 'textToEmoji') {
                inputLabel.textContent = "Enter text (try 'cat', 'fire', 'pizza'):";
                textarea.placeholder = "I love pizza and cats...";
            } else {
                inputLabel.textContent = "Enter Emojis to describe:";
                textarea.placeholder = "🐱 🔥 🍕...";
            }
        }

        function performConversion() {
            const mode = document.getElementById('modeSelect').value;
            const input = document.getElementById('inputText').value;
            const outputDiv = document.getElementById('outputContent');

            if (!input.trim()) {
                outputDiv.innerHTML = '<div class="placeholder-text">Please enter some text above!</div>';
                return;
            }

            let result = "";

            if (mode === 'textToEmoji') {
                // Split by spaces to find words, preserving basic punctuation
                // Note: This is a simple regex approach.
                result = input.replace(/\b(\w+)\b/g, (match) => {
                    const lowerKey = match.toLowerCase();
                    return emojiMap[lowerKey] ? emojiMap[lowerKey] : match;
                });
            } else {
                // Emoji to Text
                // We iterate through the string and replace known emojis
                // Using Array.from to handle surrogate pairs (emojis) correctly
                const chars = Array.from(input); 
                result = chars.map(char => {
                    return reverseMap[char] ? reverseMap[char] : char;
                }).join('');
            }

            // Update DOM with animation effect
            outputDiv.style.opacity = 0;
            setTimeout(() => {
                outputDiv.textContent = result;
                outputDiv.style.opacity = 1;
            }, 200);
        }

        function clearAll() {
            document.getElementById('inputText').value = "";
            document.getElementById('outputContent').innerHTML = '<div class="placeholder-text">Result will appear here...</div>';
            showToast("Cleared!");
        }

        function copyResult() {
            const outputText = document.getElementById('outputContent').textContent;

            // Check if it's the placeholder text
            if(outputText.includes("Result will appear here...")) return;

            navigator.clipboard.writeText(outputText).then(() => {
                showToast("Copied to clipboard!");
            }).catch(err => {
                console.error('Failed to copy: ', err);
                showToast("Failed to copy");
            });
        }

        function showToast(message) {
            const toast = document.getElementById('toast');
            toast.textContent = message;
            toast.classList.add('show');

            setTimeout(() => {
                toast.classList.remove('show');
            }, 2000);
        }

        // Initialize UI on load
        window.onload = updateUI;

    </script>
</body>
