    <!-- JAVASCRIPT LOGIC -->
    <script>
        // --- DOM Elements ---
        const dropZone = document.getElementById('dropZone');
        const fileInput = document.getElementById('fileInput');
        const fileListDisplay = document.getElementById('fileList');
        const processBtn = document.getElementById('processBtn');
        const resultsSection = document.getElementById('resultsSection');
        const logConsole = document.getElementById('logConsole');
        const processingOverlay = document.getElementById('processingOverlay');
        const downloadBtn = document.getElementById('downloadBtn');
        const outputFormatSelect = document.getElementById('outputFormat');

        // --- State ---
        let filesQueue = [];

        // --- Event Listeners for Drag & Drop ---
        dropZone.addEventListener('dragover', (e) => {
            e.preventDefault();
            dropZone.classList.add('dragover');
        });

        dropZone.addEventListener('dragleave', () => {
            dropZone.classList.remove('dragover');
        });

        dropZone.addEventListener('drop', (e) => {
            e.preventDefault();
            dropZone.classList.remove('dragover');
            handleFiles(e.dataTransfer.files);
        });

        fileInput.addEventListener('change', (e) => {
            handleFiles(e.target.files);
        });

        // --- File Handling Functions ---
        function handleFiles(files) {
            if (files.length === 0) return;

            // Convert FileList to Array and add to queue
            const newFiles = Array.from(files);
            filesQueue = [...filesQueue, ...newFiles];

            updateFileListUI();
            updateProcessButton();
        }

        function updateFileListUI() {
            fileListDisplay.innerHTML = '';

            filesQueue.forEach((file, index) => {
                const item = document.createElement('div');
                item.className = 'file-item';

                // Determine icon based on type
                let icon = '📄';
                if(file.name.includes('.xls')) icon = '📊';
                if(file.name.includes('.csv')) icon = '📝';

                item.innerHTML = `
                    <div style="display: flex; align-items: center; gap: 10px;">
                        <span>${icon}</span>
                        <strong>${file.name}</strong>
                        <span style="color: #666; font-size: 0.8rem;">(${(file.size / 1024).toFixed(1)} KB)</span>
                    </div>
                    <div>
                        <span class="file-status status-ready">Pending</span>
                        <button class="btn-secondary" style="border: none; padding: 5px; font-size: 1.2rem; color: #888;" onclick="removeFile(${index})">&times;</button>
                    </div>
                `;
                fileListDisplay.appendChild(item);
            });
        }

        // Exposed globally for the inline onclick handler
        window.removeFile = function(index) {
            filesQueue.splice(index, 1);
            updateFileListUI();
            updateProcessButton();
        };

        function updateProcessButton() {
            if (filesQueue.length > 0) {
                processBtn.disabled = false;
                processBtn.innerText = `Process ${filesQueue.length} Files`;
            } else {
                processBtn.disabled = true;
                processBtn.innerText = 'Process Files';
            }
        }

        // --- Processing Logic ---
        processBtn.addEventListener('click', () => {
            // Show Overlay
            processingOverlay.style.display = 'flex';

            // Log Helper
            const log = (msg) => {
                const entry = document.createElement('div');
                const time = new Date().toLocaleTimeString();
                entry.textContent = `[${time}] ${msg}`;
                logConsole.appendChild(entry);
                logConsole.scrollTop = logConsole.scrollHeight;
            };

            // Reset UI for results
            resultsSection.style.display = 'block';
            logConsole.innerHTML = '> Initializing Engine...<br>';

            // Simulate processing with timeouts
            let processedCount = 0;
            const targetFormat = outputFormatSelect.value.toUpperCase();

            // Simulate parsing steps
            setTimeout(() => {
                log(`Batch job started. Format: ${targetFormat}`);

                filesQueue.forEach((file, index) => {
                    // Random delay for each file to simulate work
                    const delay = (index + 1) * 800;

                    setTimeout(() => {
                        log(`Parsing ${file.name}...`);

                        // Update status in list to "Processing"
                        const fileItems = document.querySelectorAll('.file-item');
                        if(fileItems[index]) {
                            const statusSpan = fileItems[index].querySelector('.file-status');
                            statusSpan.className = 'file-status status-processing';
                            statusSpan.innerText = 'Parsing...';
                        }
                    }, delay - 400);

                    setTimeout(() => {
                        log(`Converting ${file.name} to ${targetFormat}... Success.`);

                        // Update status to "Done"
                        const fileItems = document.querySelectorAll('.file-item');
                        if(fileItems[index]) {
                            const statusSpan = fileItems[index].querySelector('.file-status');
                            statusSpan.className = 'file-status status-done';
                            statusSpan.innerText = 'Converted';
                        }

                        processedCount++;

                        // Check if all done
                        if (processedCount === filesQueue.length) {
                            finishProcessing();
                        }
                    }, delay);
                });
            }, 1000);

            function finishProcessing() {
                setTimeout(() => {
                    processingOverlay.style.display = 'none';
                    log(`All files processed successfully.`);
                    log(`Ready for download.`);

                    // Scroll to bottom
                    window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
                }, 500);
            }
        });

        // --- Download Logic (Simulation) ---
        downloadBtn.addEventListener('click', () => {
            alert("This is a demo. In a production environment, this would initiate a download of a ZIP file containing your " + outputFormatSelect.value.toUpperCase() + " files.");
        });

        // --- Reset Logic ---
        window.resetApp = function() {
            filesQueue = [];
            updateFileListUI();
            updateProcessButton();
            resultsSection.style.display = 'none';
            logConsole.innerHTML = '';
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

    </script>
</body>
