            let result = '';
            for (let i = 0; i < text.length; i++) {
                const char = text[i];
                const index = sourceChars.indexOf(char);
                if (index !== -1) {
                    result += targetChars[index];
                } else {
                    result += char;
                }
            }
            return result;
