        convertBtn.addEventListener('click', performConversion);

        // Swap functionality
        swapBtn.addEventListener('click', () => {
            const currentInput = inputTextArea.value;
            const currentOutput = outputTextArea.value;

            // Swap values
            inputTextArea.value = currentOutput;
            outputTextArea.value = currentInput; // Optional: Usually you might want to clear output or re-convert

            // Toggle dropdown mode
            if (conversionMode.value === 's2t') {
                conversionMode.value = 't2s';
            } else {
                conversionMode.value = 's2t';
            }

            // Trigger conversion immediately after swap
            performConversion();
        });

        // Clear functionality
        clearBtn.addEventListener('click', () => {
            inputTextArea.value = '';
            outputTextArea.value = '';
            inputTextArea.focus();
        });

        // Copy functionality
        copyBtn.addEventListener('click', () => {
            if (!outputTextArea.value) return;

            outputTextArea.select();
            outputTextArea.setSelectionRange(0, 99999); /* For mobile devices */

            navigator.clipboard.writeText(outputTextArea.value).then(() => {
                showFeedback();
            });
        });

        function showFeedback() {
            feedbackMsg.classList.add('show');
            setTimeout(() => {
                feedbackMsg.classList.remove('show');
