            if (id) {
                // Edit existing
                const index = medications.findIndex(m => m.id === parseInt(id));
                if (index !== -1) {
                    // Cancel old reminder if time changed
                    if(medications[index].time !== time) {
                        clearReminder(medications[index].id);
                    }
                    medications[index] = { ...medications[index], name, dosage, usage, time };
                    setReminder(medications[index]); // Reset reminder
                    showToast('Medication updated!');
                }
            } else {
                // Add new
                const newMed = {
                    id: Date.now(),
                    name,
                    dosage,
                    usage,
                    time
                };
                medications.push(newMed);
                setReminder(newMed);
                showToast('Medication added!');
            }

            renderMedications();
            closeModal();
        }

        function deleteMedication(id) {
            if(confirm("Are you sure you want to delete this medication?")) {
                medications = medications.filter(m => m.id !== id);
                clearReminder(id);
                renderMedications();
                showToast('Medication deleted.');
            }
        }

        // --- Rendering ---
        function renderMedications() {
            const list = document.getElementById('medicationList');
            const emptyState = document.getElementById('emptyState');
            list.innerHTML = '';

            if (medications.length === 0) {
                emptyState.style.display = 'block';
            } else {
                emptyState.style.display = 'none';
                medications.forEach(med => {
                    const li = document.createElement('li');
                    li.className = 'med-card';
                    li.innerHTML = `
                        <div class="med-header">
                            <span class="med-name">${med.name}</span>
                            <span class="med-time">⏰ ${convertTo12Hour(med.time)}</span>
                        </div>
                        <div class="med-details">
                            <p><strong>Dosage:</strong> ${med.dosage}</p>
                            <p><strong>Usage:</strong> ${med.usage}</p>
                        </div>
                        <div class="med-actions">
                            <button class="action-btn edit-btn" onclick="openEditModal(${med.id})">Edit</button>
                            <button class="action-btn delete-btn" onclick="deleteMedication(${med.id})">Delete</button>
                        </div>
                    `;
                    list.appendChild(li);
                });
            }
        }

        // --- Reminder System ---
        function setReminder(med) {
            // Clear existing if setting up again
            clearReminder(med.id);

            // Simple checker that runs every 30 seconds to see if it matches current time
            // In a real app, we might use Push Notifications or more complex Date calculations
            const intervalId = setInterval(() => {
                const now = new Date();
                const currentTime = now.toTimeString().substring(0, 5); // HH:MM format

                if (currentTime === med.time) {
                    // Check if we already alerted in this minute to prevent spamming
                    // (Simple implementation assumes alert runs once per minute match)
                    if(now.getSeconds() < 2) { 
                        triggerAlert(med);
                    }
                }
            }, 1000); // Check every second to be precise

            reminderIntervals[med.id] = intervalId;
        }

        function clearReminder(id) {
            if (reminderIntervals[id]) {
                clearInterval(reminderIntervals[id]);
                delete reminderIntervals[id];
            }
        }

        function triggerAlert(med) {
            // Play Sound
            document.getElementById('alertSound').play().catch(e => console.log("Audio play blocked"));

            // Show Native Alert (Simple mechanism)
            setTimeout(() => {
                alert(`🔔 REMINDER TIME!\n\nTake: ${med.name}\nDosage: ${med.dosage}\nNote: ${med.usage}`);
            }, 100);
        }

        // --- Utilities ---
        function showToast(msg) {
            const toast = document.getElementById('toast');
            toast.innerText = msg;
            toast.classList.add('show');
            setTimeout(() => {
                toast.classList.remove('show');
            }, 3000);
        }

        function convertTo12Hour(time24) {
            const [hours, minutes] = time24.split(':');
            const h = parseInt(hours);
            const ampm = h >= 12 ? 'PM' : 'AM';
            const h12 = h % 12 || 12;
            return `${h12}:${minutes} ${ampm}`;
        }

        function loadMedications() {
            // Initial seed data for demonstration
            if(medications.length === 0) {
                medications = [
                    { id: 1, name: 'Aspirin', dosage: '100mg', usage: 'After breakfast', time: '08:00' },
                    { id: 2, name: 'Vitamin C', dosage: '500mg', usage: 'With water', time: '13:00' }
                ];
                medications.forEach(m => setReminder(m));
            }
            renderMedications();
        }

    </script>
</body>
</html>
