                    iterations: 1
                });
            }
        }

        /**
         * Starts the comparison process
         */
        function initiateComparison() {
            const section = document.getElementById('comparison-section');
            section.style.display = 'block';

            // Scroll to results smoothly
            section.scrollIntoView({ behavior: 'smooth' });

            // Setup the slider visualizer
            const baseImg = document.getElementById('base-img');
            const overlayImg = document.getElementById('overlay-img');

            baseImg.src = img1Src;
            overlayImg.src = img2Src;

            // Wait for images to load in the DOM to get dimensions, then init slider and calculation
            let loadedCount = 0;
            const onImgLoad = () => {
                loadedCount++;
                if (loadedCount === 2) {
                    initComparisons();
                    calculateSimilarity();
                }
            };

            // Reset loads just in case
            baseImg.onload = onImgLoad;
            overlayImg.onload = onImgLoad;

            // Handle cached images immediately
            if(baseImg.complete && overlayImg.complete) {
                initComparisons();
                calculateSimilarity();
            }
        }

        /**
         * Image Slider Logic (W3Schools inspired logic adapted)
         */
        function initComparisons() {
            const overlay = document.querySelector(".img-comp-overlay");
            const container = document.getElementById("comp-container");
            const img = overlay.querySelector("img");

            // Remove existing slider if resetting
            const existingSlider = document.querySelector(".img-comp-slider");
            if(existingSlider) existingSlider.remove();

            let slider, clicked = 0, w, h;

            // Set overlay width to 50% initially
            w = container.offsetWidth;
            h = container.offsetHeight;

            overlay.style.width = (w / 2) + "px";

            // Create slider
            slider = document.createElement("DIV");
            slider.setAttribute("class", "img-comp-slider");
            slider.innerHTML = "&#8660;"; // Arrows

            overlay.parentElement.insertBefore(slider, overlay);

            // Center slider vertically
            slider.style.top = (h / 2) - (slider.offsetHeight / 2) + "px";
            slider.style.left = (w / 2) - (slider.offsetWidth / 2) + "px";

            // Event Listeners for drag
            slider.addEventListener("mousedown", slideReady);
            window.addEventListener("mouseup", slideFinish);
            slider.addEventListener("touchstart", slideReady);
            window.addEventListener("touchend", slideFinish);

            function slideReady(e) {
                e.preventDefault();
                clicked = 1;
                window.addEventListener("mousemove", slideMove);
                window.addEventListener("touchmove", slideMove);
            }

            function slideFinish() {
                clicked = 0;
            }

            function slideMove(e) {
                let pos;
                if (clicked == 0) return false;
                pos = getCursorPos(e);
                if (pos < 0) pos = 0;
                if (pos > w) pos = w;
                slide(pos);
            }

            function getCursorPos(e) {
                let a, x = 0;
                e = (e.changedTouches) ? e.changedTouches[0] : e;
                a = overlay.getBoundingClientRect();
                x = e.pageX - a.left;
                x = x - window.pageXOffset;
                return x;
            }

            function slide(x) {
                overlay.style.width = x + "px";
                slider.style.left = overlay.offsetWidth - (slider.offsetWidth / 2) + "px";
            }
        }

        /**
         * Calculates pixel-based similarity (Simple implementation)
         * Resizes images to 100x100 for performance and comparison normalization
         */
        function calculateSimilarity() {
            const c1 = document.getElementById('canvas1');
            const c2 = document.getElementById('canvas2');
            const ctx1 = c1.getContext('2d');
            const ctx2 = c2.getContext('2d');

            const width = 100; // Small size for fast comparison
            const height = 100;

            c1.width = width;
            c1.height = height;
            c2.width = width;
            c2.height = height;

            const img1 = new Image();
            const img2 = new Image();

            img1.onload = function() {
                ctx1.drawImage(img1, 0, 0, width, height);
                img2.src = img2Src;
            };

            img2.onload = function() {
                ctx2.drawImage(img2, 0, 0, width, height);
                comparePixels(ctx1, ctx2, width, height);
            };

            img1.src = img1Src;
        }

        function comparePixels(ctx1, ctx2, w, h) {
            const data1 = ctx1.getImageData(0, 0, w, h).data;
            const data2 = ctx2.getImageData(0, 0, w, h).data;
            let diff = 0;

            // Loop through pixels (R, G, B, A)
            for (let i = 0; i < data1.length; i += 4) {
                // Convert to grayscale for simpler structural comparison
                const gray1 = (data1[i] + data1[i+1] + data1[i+2]) / 3;
                const gray2 = (data2[i] + data2[i+1] + data2[i+2]) / 3;

                diff += Math.abs(gray1 - gray2);
            }

            // Max possible difference: 255 * total pixels
            const maxDiff = 255 * (w * h);
            const percentage = 100 - ((diff / maxDiff) * 100);

            const scoreElement = document.getElementById('similarity-score');
            const msgElement = document.getElementById('analysis-text');

            // Animation for score
            let currentScore = 0;
            const targetScore = Math.round(percentage);
            const interval = setInterval(() => {
                if(currentScore >= targetScore) {
                    clearInterval(interval);
                    scoreElement.innerText = targetScore + "% Match";
                    determineFeedback(targetScore, msgElement);
                } else {
                    currentScore++;
                    scoreElement.innerText = currentScore + "%";
                }
            }, 20);
        }

        function determineFeedback(score, element) {
            if (score > 85) {
                element.innerText = "Excellent! The sketch aligns very closely with the photo.";
                element.style.color = "green";
            } else if (score > 60) {
                element.innerText = "Good job. The general structure is similar.";
                element.style.color = "#c71585";
            } else {
                element.innerText = "Significant differences detected. Ensure the sketch angle matches the photo.";
                element.style.color = "#b00";
            }
        }

        function resetApp() {
            // Reload page is simplest reset
            location.reload();
        }

    </script>
</body>
