         * We create a grid where the input and a hidden span overlap.
         * The span dictates the width based on content, and the input fills it.
         */
        .input-sizer::after,
        .input-sizer input,
        .input-sizer textarea {
            width: auto;
            min-width: 1em;
            grid-area: 1 / 2;
            font: inherit;
            padding: 0.25em;
            margin: 0;
            resize: none;
            background: none;
            appearance: none;
            border: none;
            color: #5d4037;
        }

        /* The hidden mirror element that pushes the grid width */
        .input-sizer::after {
            content: attr(data-value) " ";
            visibility: hidden;
            white-space: pre-wrap;
        }

        .input-sizer input:focus,
        .input-sizer textarea:focus,
        .input-sizer select:focus {
            outline: none;
            background-color: rgba(188, 143, 143, 0.1);
        }

        /* Dropdown specific styling */
        select.auto-width-select {
            border: 2px solid #a52a2a;
            border-radius: 6px;
            padding: 0.5rem;
            color: #5d4037;
            background-color: #fff;
