    <div class="form-wrapper">
        <h1>Dynamic Auto-Sizing Form</h1>

        <!-- Control Panel for Size Restriction -->
        <div class="control-panel">
            <span><strong>Size Restriction:</strong> Control max width of elements.</span>
            <select id="maxWidthSelector">
                <option value="none">No Restriction</option>
                <option value="200px">Narrow (200px)</option>
                <option value="350px">Medium (350px)</option>
                <option value="100%">Full Width</option>
            </select>
        </div>

        <form id="dynamicForm">

            <!-- Dynamic Text Input -->
            <div class="form-group">
                <label for="fullName">Full Name (Auto-expanding Text)</label>
                <div class="input-sizer restrictable">
                    <input type="text" id="fullName" oninput="this.parentNode.dataset.value = this.value" placeholder="Type name..." size="1">
                </div>
            </div>

            <!-- Dynamic Text Area -->
            <div class="form-group">
                <label for="bio">Biography (Auto-expanding Area)</label>
                <div class="input-sizer restrictable">
                    <textarea id="bio" rows="1" oninput="this.parentNode.dataset.value = this.value" placeholder="Type a bio..."></textarea>
                </div>
            </div>

            <!-- Dynamic Dropdown -->
            <div class="form-group">
                <label for="country">Country (Width matches selection)</label>
                <select id="country" class="auto-width-select restrictable">
                    <option value="Select">Select...</option>
                    <option value="US">United States of America</option>
                    <option value="UK">United Kingdom</option>
                    <option value="FR">France</option>
                    <option value="LI">Liechtenstein (Long Name Example)</option>
                    <option value="CN">China</option>
                </select>
            </div>

            <!-- Checkbox Group -->
            <div class="form-group">
                <label>Preferences</label>
                <div class="checkbox-group">
                    <input type="checkbox" id="newsletter" name="newsletter">
                    <label for="newsletter" style="margin:0; font-weight:normal;">Subscribe to newsletter</label>
                </div>
            </div>

            <button type="button" class="btn-submit" onclick="alert('Form Submitted! Content adjusted successfully.')">Submit Data</button>
        </form>
    </div>

    <script>
        /**
         * AUTO-RESIZING LOGIC
         * 1. Text Inputs/Textareas: Uses a CSS Grid trick. The input reflects text into a data-attribute 
         *    on the parent. The parent uses a pseudo-element (::after) to push the width of the grid.
         * 2. Selects: Calculates width based on the length of the selected option text.
         */

        // Initial setup for Select elements to resize on load
        document.addEventListener('DOMContentLoaded', () => {
            const selectElements = document.querySelectorAll('.auto-width-select');
            selectElements.forEach(select => {
                resizeSelect(select);
                select.addEventListener('change', (e) => resizeSelect(e.target));
            });
        });

        // Function to handle width calculation for Dropdown menus
        function resizeSelect(sel) {
            // Create a temporary span to measure text width
            let tempOption = document.createElement('span');
            tempOption.style.visibility = "hidden";
            tempOption.style.position = "absolute";
            tempOption.style.fontSize = window.getComputedStyle(sel).fontSize;
            tempOption.style.fontFamily = window.getComputedStyle(sel).fontFamily;
            tempOption.style.padding = "0.5rem"; // match padding of select

            // Get text of selected option
            let selectedText = sel.options[sel.selectedIndex].text;
            tempOption.innerText = selectedText;

            document.body.appendChild(tempOption);
            // Add some buffer for the arrow icon
            let width = tempOption.getBoundingClientRect().width + 40; 
            document.body.removeChild(tempOption);

            sel.style.width = `${width}px`;
        }


        /**
         * USER RESTRICTION LOGIC
         * Handles the "Size Restriction" dropdown at the top.
         */
        const maxSelector = document.getElementById('maxWidthSelector');
        const restrictableElements = document.querySelectorAll('.restrictable');

        maxSelector.addEventListener('change', function() {
            const selectedMax = this.value;

            restrictableElements.forEach(el => {
                if (selectedMax === 'none') {
                    el.style.maxWidth = 'none';
                    // If it's a select element specifically
                    if(el.tagName === 'SELECT') {
                         resizeSelect(el); // Recalculate natural width
                    }
                } else {
                    el.style.maxWidth = selectedMax;
                    // Ensure overflow is handled gracefully for restricted elements
                    el.style.overflow = 'hidden';
                    el.style.textOverflow = 'ellipsis';
                }
            });
        });

    </script>
</body>
</html>
