    <script>
        /* --- JAVASCRIPT LOGIC --- */

        // Simulated Dictionary (In a real app, this would be a large loaded JSON or TriE structure)
        const baseDictionary = new Set([
            "今天", "天气", "真好", "我", "想", "去", "公园", "散步", 
            "云计算", "人工智能", "机器学习", "深度学习", "自然语言处理",
            "测试", "效果", "非常", "不错", "中国", "科学", "技术", 
            "大学", "北京", "上海", "开发", "工程师", "高", "性能"
        ]);

        let customDictionary = new Set();

        // 1. Add Custom Words
        function addCustomWord() {
            const input = document.getElementById('custom-word-input');
            const word = input.value.trim();
            const display = document.getElementById('added-words-display');

            if (word) {
                customDictionary.add(word);
                input.value = '';

                // Update display
                const wordsArray = Array.from(customDictionary);
                display.innerText = wordsArray.join(', ');

                // Visual feedback
                input.style.borderColor = '#4caf50'; // Green flash
                setTimeout(() => input.style.borderColor = '#ddd', 500);
            }
        }

        // 2. Clear Inputs
        function clearAll() {
            document.getElementById('input-text').value = '';
            document.getElementById('result-display').innerHTML = '<span style="color: #999; width: 100%; text-align: center; margin-top: 70px;">Results will appear here...</span>';
            customDictionary.clear();
            document.getElementById('added-words-display').innerText = 'None';
        }

        // 3. Segmentation Logic (Forward Maximum Matching Algorithm Simulation)
        // Note: Real browser-based segmentation libraries like 'jieba-js' are heavy.
        // This function implements the core logic of FMM to demonstrate functionality.
        function segmentText(text, mode) {
            const combinedDict = new Set([...baseDictionary, ...customDictionary]);
            let result = [];
            let i = 0;
            const maxLen = 5; // Max word length to scan

            while (i < text.length) {
                let matched = false;

                // Try to match longest possible word starting at i
                for (let len = maxLen; len > 0; len--) {
                    if (i + len <= text.length) {
                        const sub = text.substr(i, len);

                        // Check if in dictionary OR if it's a single character (fallback)
                        if (combinedDict.has(sub)) {
                            result.push({ word: sub, type: 'word' });
                            i += len;
                            matched = true;
                            break;
                        }
                    }
                }

                // If no word matched in dictionary, treat current char as single token
                if (!matched) {
                    const char = text[i];
                    // Simple regex for punctuation
                    const isPunctuation = /[，。！？、；：“”‘’（）《》\s,.!?;:]/.test(char);
                    result.push({ 
                        word: char, 
                        type: isPunctuation ? 'punct' : 'unknown' 
                    });
                    i++;
                }
            }

            // Mode Logic Simulation
            if (mode === 'search') {
                // In search mode, split long words into smaller tokens too (simplified simulation)
                let expandedResult = [];
                result.forEach(token => {
                    expandedResult.push(token);
                    if (token.word.length > 2) {
                        for(let k=0; k<token.word.length-1; k++) {
                            expandedResult.push({ word: token.word.substr(k, 2), type: 'sub-word' });
                        }
                    }
                });
                return expandedResult;
            }

            return result;
        }

        // 4. Main Execution Function
        function performSegmentation() {
            const text = document.getElementById('input-text').value;
            const mode = document.getElementById('mode-select').value;
            const encoding = document.getElementById('encoding-select').value;
            const outputDiv = document.getElementById('result-display');

            if (!text.trim()) {
                alert("Please enter some text first.");
                return;
            }

            // Simulate Processing Delay for Realism/Performance feel
            outputDiv.innerHTML = '<div style="width:100%; text-align:center;">Processing...</div>';

            setTimeout(() => {
                const tokens = segmentText(text, mode);
                renderResults(tokens);

                // Log encoding (Simulating backend handling)
                console.log(`Processed as ${encoding} encoding in ${mode} mode.`);
            }, 300);
        }

        // 5. Render Results to DOM
        function renderResults(tokens) {
            const outputDiv = document.getElementById('result-display');
            outputDiv.innerHTML = ''; // Clear loading

            tokens.forEach(token => {
                const span = document.createElement('span');
                span.textContent = token.word;
                span.className = 'word-token';

                if (token.type === 'punct') {
                    span.classList.add('punctuation');
                    span.style.background = 'transparent';
                    span.style.color = '#333';
                    span.style.padding = '4px 2px';
                } else if (token.type === 'sub-word') {
                    span.style.opacity = '0.6';
                    span.style.fontSize = '0.8rem';
                }

                // Click to inspect
                span.onclick = function() {
                    alert(`Token: "${token.word}"\nType: ${token.type}`);
                };

                outputDiv.appendChild(span);
            });
        }
    </script>
</body>
