        </div>
        <div class="stat-card">
            <div class="stat-number">{{ totalComments }}</div>
            <div>Community Feedbacks</div>
        </div>
        <div class="stat-card">
            <div class="stat-number">{{ latestVersion }}</div>
            <div>Current Version</div>
        </div>
    </div>

    <!-- Controls -->
    <div class="controls">
        <select v-model="sortOrder">
            <option value="newest">Newest First</option>
            <option value="oldest">Oldest First</option>
        </select>
        <select v-model="typeFilter">
            <option value="all">All Types</option>
            <option value="Feature">Features</option>
            <option value="Bugfix">Bugfixes</option>
            <option value="Maintenance">Maintenance</option>
        </select>
    </div>

    <!-- Update Feed -->
    <div class="update-list">
        <div v-if="filteredUpdates.length === 0" style="text-align: center; color: #666; padding: 2rem;">
            No updates found matching your criteria.
        </div>

        <div class="update-card" v-for="update in filteredUpdates" :key="update.id">
            <div class="card-header">
                <div>
                    <span class="version-badge">{{ update.version }}</span>
                    <span class="date">{{ formatDate(update.date) }}</span>
