                {{ modalMode === 'create' ? 'Publish New Update' : 'Edit Update' }}
            </h2>

            <div class="form-group">
                <label>Update Title</label>
                <input type="text" class="form-control" v-model="form.title" placeholder="e.g. Major UI Overhaul">
            </div>

            <div class="form-group" style="display: flex; gap: 10px;">
