</div>

<script>
    const { createApp, ref, computed, reactive } = Vue;

    createApp({
        setup() {
            // --- State ---
            // Seed data
            const updates = ref([
                {
                    id: 1,
                    version: 'v2.1.0',
                    title: 'New Dashboard Analytics',
                    type: 'Feature',
                    date: '2023-10-25T10:00:00',
                    content: '• Added detailed graphs for user retention.\n• Improved loading speed by 20%.\n• Refreshed sidebar icons.',
                    likes: 12,
                    comments: [
                        { text: 'Great work on the speed!', date: '2023-10-25T12:00:00' }
                    ]
                },
                {
                    id: 2,
                    version: 'v2.0.5',
                    title: 'Login Bug Fix',
                    type: 'Bugfix',
                    date: '2023-10-20T14:30:00',
                    content: '• Fixed an issue where users could not reset passwords.\n• Minor security patches applied.',
                    likes: 5,
                    comments: []
                }
            ]);

            // UI State
            const showModal = ref(false);
            const modalMode = ref('create'); // 'create' or 'edit'
            const activeCommentSection = ref(null);
            const newCommentText = ref('');
            const sortOrder = ref('newest');
            const typeFilter = ref('all');

            // Form State
            const form = reactive({
                id: null,
                title: '',
                version: '',
                type: 'Feature',
                content: ''
            });

            // --- Computed Properties ---

            const filteredUpdates = computed(() => {
                let result = [...updates.value];

                // Filter
                if (typeFilter.value !== 'all') {
                    result = result.filter(u => u.type === typeFilter.value);
                }

                // Sort
                result.sort((a, b) => {
                    const dateA = new Date(a.date);
                    const dateB = new Date(b.date);
                    return sortOrder.value === 'newest' ? dateB - dateA : dateA - dateB;
                });

                return result;
            });

            const totalComments = computed(() => {
                return updates.value.reduce((acc, curr) => acc + curr.comments.length, 0);
            });

            const latestVersion = computed(() => {
                if(updates.value.length === 0) return 'N/A';
                // Simple logic assuming newest date is latest version, 
                // in real app use semver comparison
                const sorted = [...updates.value].sort((a,b) => new Date(b.date) - new Date(a.date));
                return sorted[0].version;
            });

            // --- Methods ---

            const formatDate = (dateString) => {
                const options = { year: 'numeric', month: 'short', day: 'numeric' };
                return new Date(dateString).toLocaleDateString(undefined, options);
            };

            const openModal = (mode, updateData = null) => {
                modalMode.value = mode;
                if (mode === 'edit' && updateData) {
                    form.id = updateData.id;
                    form.title = updateData.title;
                    form.version = updateData.version;
                    form.type = updateData.type;
                    form.content = updateData.content;
                } else {
                    // Reset form for create
                    form.id = null;
                    form.title = '';
                    form.version = '';
                    form.type = 'Feature';
                    form.content = '';
                }
                showModal.value = true;
            };

            const closeModal = () => {
                showModal.value = false;
            };

            const saveUpdate = () => {
                if (!form.title || !form.version || !form.content) {
                    alert("Please fill in all fields.");
                    return;
                }

                if (modalMode.value === 'create') {
                    const newUpdate = {
                        id: Date.now(),
                        title: form.title,
                        version: form.version,
                        type: form.type,
                        content: form.content,
                        date: new Date().toISOString(),
                        likes: 0,
                        comments: []
                    };
                    updates.value.unshift(newUpdate);
                } else {
                    const index = updates.value.findIndex(u => u.id === form.id);
                    if (index !== -1) {
                        updates.value[index] = {
                            ...updates.value[index],
                            title: form.title,
                            version: form.version,
                            type: form.type,
                            content: form.content
                        };
                    }
                }
                closeModal();
            };

            const deleteUpdate = (id) => {
                if(confirm("Are you sure you want to delete this update log?")) {
                    updates.value = updates.value.filter(u => u.id !== id);
                }
            };

            const toggleComments = (id) => {
                if (activeCommentSection.value === id) {
                    activeCommentSection.value = null;
                } else {
                    activeCommentSection.value = id;
                }
            };

            const addComment = (updateId) => {
                if (!newCommentText.value.trim()) return;

                const update = updates.value.find(u => u.id === updateId);
                if (update) {
                    update.comments.push({
                        text: newCommentText.value,
                        date: new Date().toISOString()
                    });
                    newCommentText.value = '';
                }
            };

            const likeUpdate = (update) => {
                update.likes = (update.likes || 0) + 1;
            };

            return {
                updates,
                filteredUpdates,
                totalComments,
                latestVersion,
                showModal,
                modalMode,
                form,
                activeCommentSection,
                newCommentText,
                sortOrder,
                typeFilter,
                formatDate,
                openModal,
                closeModal,
                saveUpdate,
                deleteUpdate,
                toggleComments,
                addComment,
                likeUpdate
            };
        }
    }).mount('#app');
</script>

</body>
</html>
