                category: "Legal",
                definition: "A document declaring the preliminary commitment of one party to do business with another."
            }
        ];

        // 2. State Management
        let favorites = JSON.parse(localStorage.getItem('propDefFavorites')) || [];
        let currentView = 'all'; // 'all' or 'favorites'

        // 3. Initialization
        document.addEventListener('DOMContentLoaded', () => {
            renderGrid(dictionaryData);
        });

        // 4. Core Functions

        function renderGrid(data) {
            const grid = document.getElementById('dictionaryGrid');
            const countSpan = document.getElementById('count');

            grid.innerHTML = ''; // Clear existing content
            countSpan.innerText = data.length;

            if (data.length === 0) {
                grid.innerHTML = `
                    <div class="no-results">
                        <h2>No terms found.</h2>
                        <p>Try adjusting your search or category filter.</p>
                    </div>`;
                return;
            }

            data.forEach(item => {
                const isFav = favorites.includes(item.id);
                const favClass = isFav ? 'favorited' : '';

                const card = document.createElement('div');
                card.className = 'card';
                card.innerHTML = `
                    <div class="card-header">
                        <span class="abbr">${item.abbr}</span>
                        <div>
                            <span class="category-tag">${item.category}</span>
                            <button class="fav-btn ${favClass}" onclick="toggleFavorite(${item.id})">
                                &#10084;
                            </button>
                        </div>
                    </div>
                    <div class="full-term">${item.term}</div>
                    <div class="definition">${item.definition}</div>
                `;
                grid.appendChild(card);
            });
        }

        function handleSearch() {
            const searchTerm = document.getElementById('searchInput').value.toLowerCase();
            const category = document.getElementById('categoryFilter').value;

            // Filter logic
            let filtered = dictionaryData.filter(item => {
                // Check Keyword/Abbreviation match
                const matchesSearch = 
                    item.abbr.toLowerCase().includes(searchTerm) || 
                    item.term.toLowerCase().includes(searchTerm) ||
                    item.definition.toLowerCase().includes(searchTerm);

                // Check Category match
                const matchesCategory = category === 'all' || item.category === category;

                // Check View (All vs Favorites)
                const matchesView = currentView === 'all' || favorites.includes(item.id);

                return matchesSearch && matchesCategory && matchesView;
            });

            // Optional: Highlight search term functionality could be added here
            renderGrid(filtered);
        }

        function filterView(viewType) {
            currentView = viewType;

            // Toggle active button styling
            const allBtn = document.getElementById('showAllBtn');
            const favBtn = document.getElementById('showFavBtn');

            if (viewType === 'favorites') {
                allBtn.classList.remove('active');
                favBtn.classList.add('active');
                document.getElementById('searchInput').placeholder = "Search within favorites...";
            } else {
                favBtn.classList.remove('active');
                allBtn.classList.add('active');
                document.getElementById('searchInput').placeholder = "Search abbreviation (e.g., 'ROI') or keyword...";
            }

            handleSearch(); // Re-run search/filter logic with new view constraint
        }

        function toggleFavorite(id) {
            if (favorites.includes(id)) {
                favorites = favorites.filter(favId => favId !== id);
            } else {
                favorites.push(id);
            }

            // Save to local storage for persistence
            localStorage.setItem('propDefFavorites', JSON.stringify(favorites));

            // Re-render to update UI (hearts and view)
            handleSearch(); 
        }

        function clearFilters() {
            document.getElementById('searchInput').value = '';
            document.getElementById('categoryFilter').value = 'all';
            handleSearch();
        }

    </script>
</body>
</html>
