        const newsElement = document.getElementById('dynamic-news');

        function rotateNews() {
            // Fade out
            newsElement.style.opacity = 0;

            setTimeout(() => {
                newsElement.textContent = newsItems[newsIndex];
                newsIndex = (newsIndex + 1) % newsItems.length;
                // Fade in
                newsElement.style.opacity = 1;
            }, 500);
        }

        // Initialize news rotation
        newsElement.style.transition = "opacity 0.5s";
        rotateNews(); // Initial call
        setInterval(rotateNews, 4000); // Rotate every 4 seconds

