            const searchText = document.getElementById('searchInput').value.toLowerCase();

            const filtered = aiTools.filter(tool => {
                const matchesSearch = tool.name.toLowerCase().includes(searchText) || 
                                      tool.description.toLowerCase().includes(searchText);
                const matchesCategory = currentActiveCategory === 'All' || tool.category === currentActiveCategory;

                return matchesSearch && matchesCategory;
            });

            renderTools(filtered);
        }

        function filterByCategory(category) {
            currentActiveCategory = category;

            // Update UI buttons
            const buttons = document.querySelectorAll('.cat-btn');
            buttons.forEach(btn => {
                if(btn.innerText === category || (category === 'Chatbot' && btn.innerText === 'Chatbots')) {
                    btn.classList.add('active');
                } else {
                    btn.classList.remove('active');
                }
            });

            filterTools(); // Re-run filter with new category
        }

        // 5. Modal & Interaction Logic
        function openReviewModal(id, name) {
            const modal = document.getElementById('reviewModal');
            document.getElementById('modalToolTitle').innerText = `Review ${name}`;
            document.getElementById('commentInput').value = ''; // Reset comment
            currentReviewId = id;
            currentRating = 0;
            updateStarVisuals(0);
            modal.style.display = "block";
        }

        function closeModal() {
            document.getElementById('reviewModal').style.display = "none";
        }

        // Close modal if clicking outside
        window.onclick = function(event) {
            const modal = document.getElementById('reviewModal');
            if (event.target == modal) {
                modal.style.display = "none";
            }
        }

        function setRating(rating) {
            currentRating = rating;
            updateStarVisuals(rating);
        }

        function updateStarVisuals(rating) {
            const stars = document.getElementById('modalStars').children;
            for (let i = 0; i < stars.length; i++) {
                if (i < rating) {
                    stars[i].style.color = "gold";
                } else {
                    stars[i].style.color = "#ccc";
                }
            }
        }

        function submitReview() {
            const comment = document.getElementById('commentInput').value;

            if (currentRating === 0) {
                alert("Please select a star rating.");
                return;
            }

            // In a real app, send this to backend
            console.log(`Submitted Review for Tool ID ${currentReviewId}:`);
            console.log(`Rating: ${currentRating}`);
            console.log(`Comment: ${comment}`);

            // Simulate UI update
            const toolIndex = aiTools.findIndex(t => t.id === currentReviewId);
            if(toolIndex !== -1) {
                // Simplified "new average" calculation for demo visual feedback
                aiTools[toolIndex].reviews += 1;
                alert("Thank you! Your review has been submitted.");
                renderTools(aiTools); // Re-render to show updated review count
            }

            closeModal();
        }

    </script>
