                    <img src="${item.image}" alt="${item.title}" loading="lazy">
                    <div class="card-content">
                        <h3>${item.title}</h3>
                        <p>${item.desc}</p>
                        ${actionButton}
                        <div class="social-share">
                            <button class="share-btn" onclick="shareContent('twitter', '${item.title}')">Tweet</button>
                            <button class="share-btn" onclick="shareContent('facebook', '${item.title}')">Share</button>
                        </div>
                    </div>
                </div>
            `;
        }

        // Initialize Content
        function loadContent(filter = null) {
            const articleGrid = document.getElementById('article-grid');
            const imageGrid = document.getElementById('image-grid');
            const videoGrid = document.getElementById('video-grid');

            // Clear current content
            articleGrid.innerHTML = '';
            imageGrid.innerHTML = '';
            videoGrid.innerHTML = '';

            const filteredData = filter 
                ? contentData.filter(item => 
                    item.title.toLowerCase().includes(filter.toLowerCase()) || 
                    item.category.toLowerCase().includes(filter.toLowerCase()) ||
                    item.desc.toLowerCase().includes(filter.toLowerCase())
                  )
                : contentData;

            if(filteredData.length === 0) {
                articleGrid.innerHTML = '<p>No results found. Try a different search term.</p>';
                return;
            }

            filteredData.forEach(item => {
                const cardHTML = createCard(item);
                if (item.type === 'article') {
                    articleGrid.innerHTML += cardHTML;
                } else if (item.type === 'image') {
                    imageGrid.innerHTML += cardHTML;
                } else if (item.type === 'video') {
                    videoGrid.innerHTML += cardHTML;
                }
            });
        }

        // Search Functionality
        function performSearch() {
            const query = document.getElementById('searchInput').value;
            loadContent(query);
            // Scroll to results
            document.getElementById('articles').scrollIntoView({ behavior: 'smooth' });
        }

        // Filter via Menu
        function filterContent(category) {
            document.getElementById('searchInput').value = category;
            performSearch();
        }

        // Dynamic Text Effect in Hero
        const words = ["Japan", "Tradition", "Innovation", "Nature", "Cuisine"];
        let i = 0;
        const textElement = document.getElementById("dynamic-text");

        setInterval(() => {
            i = (i + 1) % words.length;
            textElement.style.opacity = 0;
            setTimeout(() => {
                textElement.innerText = words[i];
                textElement.style.opacity = 1;
            }, 500); // Wait for fade out
        }, 3000);

        // Modal Functions
        const modal = document.getElementById("videoModal");

        function openModal(title, desc, source) {
            document.getElementById("modalTitle").innerText = title;
            document.getElementById("modalDesc").innerText = desc;
            document.getElementById("videoSource").innerText = source;
            modal.style.display = "flex";
        }

        function closeModal() {
            modal.style.display = "none";
        }

        // Close modal if clicking outside
        window.onclick = function(event) {
            if (event.target == modal) {
                closeModal();
            }
        }

        // Social Share Simulation
        function shareContent(platform, title) {
            const url = encodeURIComponent(window.location.href);
            const text = encodeURIComponent(`Check out ${title} on Japan Insight!`);
            let shareUrl = '';

            if (platform === 'twitter') {
                shareUrl = `https://twitter.com/intent/tweet?url=${url}&text=${text}`;
            } else if (platform === 'facebook') {
                shareUrl = `https://www.facebook.com/sharer/sharer.php?u=${url}`;
            }

            window.open(shareUrl, '_blank', 'width=600,height=400');
        }

        // Execute on Load
        document.addEventListener('DOMContentLoaded', () => {
            loadContent();
            // Add CSS transition for dynamic text
            textElement.style.transition = "opacity 0.5s ease-in-out";
        });

    </script>
</body>
</html>
