            // 1. Get Data
            const data = weatherDatabase[selectedCity];
            const cityDisplayName = citySelect.options[citySelect.selectedIndex].text;

            // 2. Update Header Info
            cityNameDisplay.innerText = cityDisplayName;
            cityInfo.classList.add('visible');
            wrapper.style.display = "block";

            // 3. Clear existing carousel content
            track.innerHTML = '';
            navContainer.innerHTML = '';

            // 4. Build Slides
            data.forEach((entry, index) => {
                // Create Slide Li
                const slide = document.createElement('li');
                slide.classList.add('carousel-slide');

                // Create Card Content
                slide.innerHTML = `
                    <div class="weather-card">
                        <div class="date">${entry.date}</div>
                        <div class="temp">${entry.temp}</div>
                        <div class="condition">${entry.condition}</div>
                        <div class="details">
                            <span>💧 Humidity: ${entry.humidity}</span>
                            <span>💨 Wind: ${entry.wind}</span>
                        </div>
                    </div>
                `;

                track.appendChild(slide);

                // Create Dot Indicator
                const dot = document.createElement('button');
                dot.classList.add('carousel-indicator');
                if (index === 0) dot.classList.add('current-slide');

                // Add click listener to dot for direct navigation
                dot.addEventListener('click', () => {
                    moveToSlide(index);
                });

                navContainer.appendChild(dot);
            });

            // 5. Re-initialize State
            slides = Array.from(track.children);
            dots = Array.from(navContainer.children);
            currentSlideIndex = 0;

            // Set initial position
            updateSlidePosition();
        }

        /**
         * FUNCTION: moveToSlide
         * Moves the track to show the target slide index.
         */
        function moveToSlide(targetIndex) {
            const slideWidth = slides[0].getBoundingClientRect().width;

            // Move Track
            track.style.transform = 'translateX(-' + (slideWidth * targetIndex) + 'px)';

            // Update Dots
            const currentDot = dots[currentSlideIndex];
            const targetDot = dots[targetIndex];
            currentDot.classList.remove('current-slide');
            targetDot.classList.add('current-slide');

            // Update Index State
            currentSlideIndex = targetIndex;
        }

        /**
         * FUNCTION: updateSlidePosition
         * Helper to reset position (useful on window resize or init).
         */
        function updateSlidePosition() {
            if(slides.length === 0) return;
            const slideWidth = slides[0].getBoundingClientRect().width;
            // Align slides side-by-side logic handled by flexbox, 
            // we just need to ensure transform is correct relative to current index
            track.style.transform = 'translateX(-' + (slideWidth * currentSlideIndex) + 'px)';
        }

        // --- Event Listeners for Carousel Controls ---

        nextButton.addEventListener('click', () => {
            if (slides.length === 0) return;
            let nextIndex = currentSlideIndex + 1;
            // Loop back to start
            if (nextIndex >= slides.length) {
                nextIndex = 0;
            }
            moveToSlide(nextIndex);
        });

        prevButton.addEventListener('click', () => {
            if (slides.length === 0) return;
            let prevIndex = currentSlideIndex - 1;
            // Loop to end
            if (prevIndex < 0) {
                prevIndex = slides.length - 1;
            }
            moveToSlide(prevIndex);
        });

        // Handle Window Resize to keep carousel aligned
        window.addEventListener('resize', () => {
            // Debounce or just simply call update
            updateSlidePosition();
        });

    </script>
