        .btn-sm {
            padding: 5px 10px;
            border: 1px solid var(--primary-color);
            background: transparent;
            color: var(--primary-color);
            border-radius: 4px;
            cursor: pointer;
            font-size: 0.8rem;
            transition: var(--transition);
        }

        .btn-sm:hover {
            background: var(--primary-color);
            color: var(--white);
        }

        .source-tag {
            background-color: var(--bg-color);
            color: var(--primary-color);
            padding: 2px 8px;
            border-radius: 10px;
            font-size: 0.75rem;
            font-weight: bold;
        }

        /* --- MODAL FOR IMAGE VIEWING --- */
        .modal {
            display: none; 
            position: fixed; 
            z-index: 200; 
            left: 0;
            top: 0;
            width: 100%; 
            height: 100%; 
            overflow: auto; 
            background-color: rgba(0,0,0,0.8);
            justify-content: center;
            align-items: center;
        }

        .modal-content {
            background-color: #fefefe;
            padding: 20px;
            border-radius: 10px;
            max-width: 80%;
            text-align: center;
            position: relative;
        }

        .modal-img {
            max-width: 100%;
            max-height: 70vh;
            border-radius: 5px;
        }

        .close {
