<body>

    <!-- Header -->
    <header>
        <div class="logo">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect><circle cx="8.5" cy="8.5" r="1.5"></circle><polyline points="21 15 16 10 5 21"></polyline></svg>
            Lumina
        </div>
        <nav>
            <ul>
                <li><a href="#" class="active" onclick="filterSource('all')">All</a></li>
                <li><a href="#" onclick="filterSource('bing')">Bing Daily</a></li>
                <li><a href="#" onclick="filterSource('github')">GitHub Archive</a></li>
            </ul>
        </nav>
    </header>

    <!-- Hero Section -->
    <div class="hero">
        <h1 id="hero-title">Discover the World Through Images</h1>
        <p>Explore daily wallpapers and open-source libraries.</p>
        <br>
        <div class="search-bar">
            <input type="text" id="searchInput" placeholder="Search for nature, space, animals...">
            <button onclick="performSearch()">Search</button>
        </div>
    </div>

    <!-- Controls -->
    <div class="controls">
        <div class="dropdown">
            <button class="dropbtn">Categories &#9662;</button>
            <div class="dropdown-content">
                <a href="#" onclick="filterCategory('Nature')">Nature</a>
                <a href="#" onclick="filterCategory('Architecture')">Architecture</a>
                <a href="#" onclick="filterCategory('Technology')">Technology</a>
                <a href="#" onclick="filterCategory('Abstract')">Abstract</a>
            </div>
        </div>

        <button class="dropbtn" onclick="resetGallery()">Reset Filters</button>
    </div>

    <!-- Main Content -->
    <div class="gallery-container">
        <div id="loader" class="loader"></div>
        <div id="imageGrid" class="grid">
            <!-- Images will be injected here via JavaScript -->
        </div>
    </div>

    <!-- Modal -->
    <div id="imageModal" class="modal">
        <div class="modal-content">
            <span class="close" onclick="closeModal()">&times;</span>
            <h3 id="modalTitle" style="margin-bottom: 10px; color: var(--primary-color);"></h3>
            <img id="modalImage" class="modal-img" src="" alt="Large View">
            <div id="resolutionControls" class="resolution-options">
                <!-- Resolution buttons will be injected here -->
            </div>
        </div>
    </div>

    <!-- Footer -->
    <footer>
        <p>&copy; 2023 Lumina Image Viewer. Powered by Unsplash API (simulated) and Bing.</p>
    </footer>

    <script>
        // --- DATA SIMULATION ---
        // Since we cannot make actual cross-origin requests to Bing/GitHub without a backend proxy due to CORS,
        // we will simulate the data structure that would return from these APIs.

        const mockBingData = [
            { id: 1, title: "Misty Mountain", category: "Nature", source: "Bing", url: "https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?w=500", fullUrl: "https://images.unsplash.com/photo-1464822759023-fed622ff2c3b" },
            { id: 2, title: "Urban Sunset", category: "Architecture", source: "Bing", url: "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=500", fullUrl: "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df" },
            { id: 3, title: "Arctic Fox", category: "Nature", source: "Bing", url: "https://images.unsplash.com/photo-1516934024742-b461fba47600?w=500", fullUrl: "https://images.unsplash.com/photo-1516934024742-b461fba47600" },
            { id: 4, title: "Spiral Staircase", category: "Architecture", source: "Bing", url: "https://images.unsplash.com/photo-1519011985187-444d62641929?w=500", fullUrl: "https://images.unsplash.com/photo-1519011985187-444d62641929" }
        ];

        // Simulating GitHub "awesome-wallpapers" repo data
        const mockGithubData = [
            { id: 5, title: "Code Matrix", category: "Technology", source: "GitHub", url: "https://images.unsplash.com/photo-1526374965328-7f61d4dc18c5?w=500", fullUrl: "https://images.unsplash.com/photo-1526374965328-7f61d4dc18c5" },
            { id: 6, title: "Liquid Colors", category: "Abstract", source: "GitHub", url: "https://images.unsplash.com/photo-1541701494587-cb58502866ab?w=500", fullUrl: "https://images.unsplash.com/photo-1541701494587-cb58502866ab" },
            { id: 7, title: "Cyber City", category: "Technology", source: "GitHub", url: "https://images.unsplash.com/photo-1515630278258-407f66498911?w=500", fullUrl: "https://images.unsplash.com/photo-1515630278258-407f66498911" },
            { id: 8, title: "Geometric Shapes", category: "Abstract", source: "GitHub", url: "https://images.unsplash.com/photo-1550684848-fac1c5b4e853?w=500", fullUrl: "https://images.unsplash.com/photo-1550684848-fac1c5b4e853" }
        ];

        let allImages = [...mockBingData, ...mockGithubData];
        let currentImages = [...allImages];

        // --- DOM ELEMENTS ---
        const grid = document.getElementById('imageGrid');
        const loader = document.getElementById('loader');
        const modal = document.getElementById('imageModal');
        const modalImg = document.getElementById('modalImage');
        const modalTitle = document.getElementById('modalTitle');
        const resControls = document.getElementById('resolutionControls');

        // --- FUNCTIONS ---

        // Initialize
        window.onload = () => {
            renderImages(allImages);
        };

        // Render Cards
        function renderImages(data) {
            grid.innerHTML = ''; // Clear existing

            if(data.length === 0) {
                grid.innerHTML = '<p style="grid-column: 1/-1; text-align: center; font-size: 1.2rem;">No images found matching your criteria.</p>';
                return;
            }

            // Simulate loading effect
            loader.style.display = 'block';
            grid.style.display = 'none';

            setTimeout(() => {
                loader.style.display = 'none';
                grid.style.display = 'grid';

                data.forEach(img => {
                    const card = document.createElement('div');
                    card.className = 'card';
                    card.innerHTML = `
                        <img src="${img.url}" alt="${img.title}" loading="lazy">
                        <div class="card-body">
                            <div style="display:flex; justify-content:space-between; align-items:center;">
                                <h3 class="card-title">${img.title}</h3>
                                <span class="source-tag">${img.source}</span>
                            </div>
                            <p class="card-info">Category: ${img.category}</p>
                            <div class="card-actions">
                                <button class="btn-sm" onclick="openModal(${img.id})">View HD</button>
                                <button class="btn-sm" onclick="alert('Image downloaded (Simulated)')">Download</button>
                            </div>
                        </div>
                    `;
                    grid.appendChild(card);
                });
            }, 500); // 500ms fake loading delay
        }

        // Filter by Source (Bing vs GitHub)
        function filterSource(source) {
            // Update active nav state
            document.querySelectorAll('nav a').forEach(el => el.classList.remove('active'));
            event.target.classList.add('active');

            if (source === 'all') {
                currentImages = allImages;
            } else if (source === 'bing') {
                currentImages = allImages.filter(img => img.source === 'Bing');
            } else {
                currentImages = allImages.filter(img => img.source === 'GitHub');
            }
            renderImages(currentImages);
        }

        // Filter by Category
        function filterCategory(category) {
            const filtered = currentImages.filter(img => img.category === category);
            renderImages(filtered);
            document.getElementById('hero-title').innerText = `Browsing: ${category}`;
        }

        // Search Functionality
        function performSearch() {
            const query = document.getElementById('searchInput').value.toLowerCase();
            const filtered = allImages.filter(img => 
                img.title.toLowerCase().includes(query) || 
                img.category.toLowerCase().includes(query)
            );
            renderImages(filtered);
            document.getElementById('hero-title').innerText = query ? `Search Results: "${query}"` : "Discover the World";
        }

        // Reset
        function resetGallery() {
            document.getElementById('searchInput').value = '';
            document.getElementById('hero-title').innerText = "Discover the World Through Images";
            currentImages = allImages;

            // Reset nav active state
            document.querySelectorAll('nav a').forEach(el => el.classList.remove('active'));
            document.querySelector('nav a:first-child').classList.add('active');

            renderImages(allImages);
        }

        // Modal Logic
        function openModal(id) {
            const imgObj = allImages.find(img => img.id === id);
            if (!imgObj) return;

            modal.style.display = "flex";
            modalTitle.innerText = imgObj.title;
            modalImg.src = imgObj.fullUrl + "?w=1080"; // Default to HD

            // Generate Resolution Buttons (Bing Feature Simulation)
            // In a real scenario, you would parse the Bing API URL structure (e.g., replace 1920x1080 with 1366x768)
            resControls.innerHTML = `
                <button class="btn-sm" onclick="changeRes('${imgObj.fullUrl}', 'small')">1366x768</button>
                <button class="btn-sm" onclick="changeRes('${imgObj.fullUrl}', 'medium')">1920x1080</button>
                <button class="btn-sm" onclick="changeRes('${imgObj.fullUrl}', 'large')">4K (UHD)</button>
            `;
        }

        function closeModal() {
            modal.style.display = "none";
        }

        // Close modal if clicking outside content
        window.onclick = function(event) {
            if (event.target == modal) {
                closeModal();
            }
        }

        // Change Resolution logic
        function changeRes(baseUrl, size) {
            // Unsplash allows resizing via query params, perfect for simulation
            let width;
            switch(size) {
                case 'small': width = 800; break;
                case 'medium': width = 1200; break;
                case 'large': width = 1920; break;
            }

            // Show loading state for modal
            modalImg.style.opacity = '0.5';
            const newSrc = `${baseUrl}?w=${width}`;

            // Preload image to prevent flickering
            const tempImg = new Image();
            tempImg.src = newSrc;
            tempImg.onload = () => {
                modalImg.src = newSrc;
                modalImg.style.opacity = '1';
            };
        }

        // Enter key for search
        document.getElementById("searchInput").addEventListener("keypress", function(event) {
            if (event.key === "Enter") {
                performSearch();
            }
        });

    </script>
</body>
</html>
