    <script>
        // =========================================
        // DYNAMIC TYPING EFFECT
        // =========================================
        const textElement = document.getElementById('dynamic-text');
        const phrases = ["Efficiency", "Security", "Scalability", "Elegance"];
        let phraseIndex = 0;
        let charIndex = 0;
        let isDeleting = false;
        let typeSpeed = 100;

        function typeEffect() {
            const currentPhrase = phrases[phraseIndex];

            if (isDeleting) {
                textElement.textContent = currentPhrase.substring(0, charIndex - 1);
                charIndex--;
                typeSpeed = 50;
            } else {
                textElement.textContent = currentPhrase.substring(0, charIndex + 1);
                charIndex++;
                typeSpeed = 150;
            }

            if (!isDeleting && charIndex === currentPhrase.length) {
                isDeleting = true;
                typeSpeed = 2000; // Pause at end
            } else if (isDeleting && charIndex === 0) {
                isDeleting = false;
                phraseIndex = (phraseIndex + 1) % phrases.length;
                typeSpeed = 500; // Pause before new word
            }

            setTimeout(typeEffect, typeSpeed);
        }

        // =========================================
        // SCROLL INTERACTION
        // =========================================
        // Intersection Observer for fade-in animations on scroll
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                }
            });
        }, { threshold: 0.1 });

        document.querySelectorAll('.content-panel').forEach(panel => {
            observer.observe(panel);
        });

        function scrollToSection(id) {
            const element = document.getElementById(id);
            if(element) {
                element.scrollIntoView({ behavior: 'smooth' });
            }
        }

        // =========================================
        // DYNAMIC CONTENT HANDLING
        // =========================================
        const detailView = document.getElementById('detail-view');
        const detailTitle = document.getElementById('detail-title');
        const detailText = document.getElementById('detail-text');

        function updateDetail(title, description) {
            // Apply a quick fade out/in effect
            detailView.style.opacity = '0';
            detailView.style.display = 'block';

            setTimeout(() => {
                detailTitle.textContent = title;
                detailText.textContent = description;
                detailView.style.transition = 'opacity 0.5s';
                detailView.style.opacity = '1';

                // Scroll slightly to ensure visibility if needed
                detailView.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            }, 100);
        }

        function closeDetail() {
            detailView.style.opacity = '0';
            setTimeout(() => {
                detailView.style.display = 'none';
            }, 300);
        }

        // Handles Dropdown menu clicks
        function showFeatureDetail(feature) {
            let desc = "";
            switch(feature) {
                case 'MVC Architecture':
                    desc = "Model-View-Controller separates your application logic from the presentation layer, making code cleaner and easier to maintain.";
                    break;
                case 'ORM':
                    desc = "Object-Relational Mapping allows you to interact with your database using objects instead of writing raw SQL queries.";
                    break;
                case 'Routing':
                    desc = "Advanced routing maps URL requests to specific controllers and actions, supporting RESTful API design.";
                    break;
            }
            // Navigate to concepts area and show detail
            scrollToSection('concepts');
            updateDetail(feature, desc);
        }

        // Initialize Typing Effect
        document.addEventListener('DOMContentLoaded', typeEffect);

    </script>
