        // --- RENDERING LOGIC ---
        function createCardHTML(item) {
            const isCollected = collection.includes(item.id);
            const btnText = isCollected ? 'Collected' : 'Collect';
            const btnClass = isCollected ? 'collected' : '';

            // Determine subtitle based on type
            let subtitle = "";
            if (item.type === 'work') subtitle = `By: ${item.creator}`;
            if (item.type === 'artist') subtitle = item.role;
            if (item.type === 'exhibition') subtitle = item.dates;

            // Determine tag based on era or location
            let tag = item.era || item.location || "General";

            return `
                <div class="card" data-id="${item.id}" data-type="${item.type}">
                    <div class="card-img-placeholder">
