        // --- SEARCH & FILTER ---
        function handleSearch() {
            const term = searchInput.value.toLowerCase();
            const filterEra = eraFilter.value;

            // Filter Works
            const filteredWorks = db.works.filter(item => {
                const matchesText = item.title.toLowerCase().includes(term) || item.creator.toLowerCase().includes(term);
                const matchesEra = filterEra === 'all' || item.era === filterEra;
                return matchesText && matchesEra;
            });
            renderGrid('works', filteredWorks);

            // Filter Artists
            const filteredArtists = db.artists.filter(item => {
                const matchesText = item.name.toLowerCase().includes(term);
                const matchesEra = filterEra === 'all' || item.era === filterEra;
                return matchesText && matchesEra;
            });
            renderGrid('artists', filteredArtists);

            // Filter Exhibitions (Ignore Era filter for exhibitions usually, but keeping text search)
            const filteredExhibitions = db.exhibitions.filter(item => {
                return item.title.toLowerCase().includes(term) || item.location.toLowerCase().includes(term);
