            else if (type === 'artist') item = db.artists.find(i => i.id === id);
            else if (type === 'exhibition') item = db.exhibitions.find(i => i.id === id);

            if (!item) return;

            const modalTitle = document.getElementById('modal-title');
            const modalBody = document.getElementById('modal-body');

            modalTitle.innerText = item.title || item.name;

            let htmlContent = ``;

            if (type === 'work') {
                htmlContent = `
