                // Remove
                collection.splice(index, 1);
                btnElement.classList.remove('collected');
                btnElement.innerHTML = '☆ Collect';

                // If we are on the collection page, remove the card immediately
                if(!document.getElementById('collection-section').classList.contains('hidden')){
