        };

        function updateCollectionCount() {
            collectionCountSpan.innerText = collection.length;
        }

        function renderCollection() {
            // Aggregate all items
            const allItems = [...db.works, ...db.artists, ...db.exhibitions];
            const collectedItems = allItems.filter(item => collection.includes(item.id));

            if (collectedItems.length === 0) {
                grids.collection.innerHTML = '';
                emptyCollectionMsg.style.display = 'block';
            } else {
                emptyCollectionMsg.style.display = 'none';
                grids.collection.innerHTML = collectedItems.map(item => createCardHTML(item)).join('');
            }
        }

        function syncButtons(id) {
            // Find all buttons for this ID across the page and update state
            const buttons = document.querySelectorAll(`.card[data-id="${id}"] .btn-collect`);
            const isCollected = collection.includes(id);

            buttons.forEach(btn => {
                if(isCollected) {
                    btn.classList.add('collected');
                    btn.innerHTML = '★ Collected';
                } else {
                    btn.classList.remove('collected');
                    btn.innerHTML = '☆ Collect';
                }
            });
        }

        // Run Init
        init();

    </script>
</body>
</html>
