    <script>
        /* --- JAVASCRIPT LOGIC --- */

        // Mock Data for "Database"
        const shikigamiDB = [
            { name: "Ibaraki Doji", clue: "Strongest / Arm", location: "Chapter 10" },
            { name: "Ootengu", clue: "Fan / Wings / Mask", location: "Chapter 15" },
            { name: "Yoto Hime", clue: "Blade / Sword", location: "Secret Zone" },
            { name: "Kusa", clue: "Dandelion / Heal", location: "Chapter 2" },
            { name: "Shuten Doji", clue: "Gourd / Drink", location: "Chapter 10" },
            { name: "Ubume", clue: "Umbrella / Crane", location: "Chapter 12" }
        ];

        // State Management
        let searchHistory = JSON.parse(localStorage.getItem('yys_history')) || [];

        // --- Navigation Logic ---
        function switchTab(tabId) {
            // Remove active class from all buttons and sections
            document.querySelectorAll('.tab-btn').forEach(btn => btn.classList.remove('active'));
            document.querySelectorAll('.section').forEach(sec => sec.classList.remove('active'));

            // Activate clicked button
            const clickedBtn = document.querySelector(`.tab-btn[onclick="switchTab('${tabId}')"]`);
            if(clickedBtn) clickedBtn.classList.add('active');

            // Activate corresponding section
            document.getElementById(tabId).classList.add('active');

            // Refresh history if opening history tab
            if(tabId === 'history') renderHistory();
        }

        // --- Search Logic ---
        function performSearch() {
            const input = document.getElementById('searchInput');
            const query = input.value.trim().toLowerCase();
            const resultArea = document.getElementById('searchResultArea');

            if (!query) return;

            // Add to history
            addToHistory(input.value.trim());

            // Filter "Database"
            const results = shikigamiDB.filter(demon => 
                demon.name.toLowerCase().includes(query) || 
                demon.clue.toLowerCase().includes(query)
            );

            // Render Results
            resultArea.innerHTML = '';
            if (results.length > 0) {
                results.forEach(demon => {
                    const card = document.createElement('div');
                    card.className = 'result-card';
                    card.innerHTML = `
                        <strong>${demon.name}</strong><br>
                        <small>Clues: ${demon.clue}</small><br>
                        <span style="color: var(--primary-teal)">Found in: ${demon.location}</span>
                    `;
                    resultArea.appendChild(card);
                });
            } else {
                resultArea.innerHTML = `<div class="result-card">No spirits found matching "${input.value}". Try a different clue.</div>`;
            }
        }

        function quickSearch(keyword) {
            // Switch to search tab
            switchTab('search');
            // Set value
            document.getElementById('searchInput').value = keyword;
            // Execute search
            performSearch();
        }

        // --- History Logic ---
        function addToHistory(term) {
            // Avoid duplicates at top
            searchHistory = searchHistory.filter(item => item !== term);
            searchHistory.unshift(term);

            // Limit to 10 items
            if (searchHistory.length > 10) searchHistory.pop();

            localStorage.setItem('yys_history', JSON.stringify(searchHistory));
        }

        function renderHistory() {
            const list = document.getElementById('historyList');
            list.innerHTML = '';

            if (searchHistory.length === 0) {
                list.innerHTML = '<li class="history-item" style="justify-content: center; color: #888;">No history yet.</li>';
                return;
            }

            searchHistory.forEach(term => {
                const li = document.createElement('li');
                li.className = 'history-item';

                const span = document.createElement('span');
                span.innerText = term;
                span.style.cursor = 'pointer';
                span.onclick = () => quickSearch(term); // Click history to search again

                const time = document.createElement('span');
                time.innerText = '↺';
                time.style.color = '#ccc';

                li.appendChild(span);
                li.appendChild(time);
                list.appendChild(li);
            });
        }

        function clearHistory() {
            searchHistory = [];
            localStorage.removeItem('yys_history');
            renderHistory();
        }

        // --- Feedback Logic ---
        function submitFeedback() {
            const text = document.getElementById('feedbackText').value;
            const msg = document.getElementById('feedbackMsg');

            if (!text) {
                alert("Please enter details before submitting.");
                return;
            }

            // Simulate API call
            const btn = document.querySelector('#feedback .action-btn');
            const originalText = btn.innerText;
            btn.innerText = "Sending...";
            btn.disabled = true;

            setTimeout(() => {
                btn.innerText = originalText;
                btn.disabled = false;
                document.getElementById('feedbackText').value = ''; // clear text

                // Show success message
                msg.style.opacity = 1;
                setTimeout(() => {
                    msg.style.opacity = 0;
                }, 3000);
            }, 1000);
        }

        // Allow "Enter" key to search
        document.getElementById('searchInput').addEventListener('keypress', function (e) {
            if (e.key === 'Enter') {
                performSearch();
            }
        });

    </script>
</body>
</html>
