            const secret = document.getElementById('secret-text');
            if (secret.style.display === 'none') {
                secret.style.display = 'block';
                // Simple fade in effect via opacity could be added here
            } else {
                secret.style.display = 'none';
            }
        }

        // --- Tab Functionality ---
        function openTab(evt, tabName) {
            let i, tabcontent, tablinks;

            // Hide all tab content
            tabcontent = document.getElementsByClassName("tab-content");
            for (i = 0; i < tabcontent.length; i++) {
                tabcontent[i].style.display = "none";
            }

            // Remove active class from buttons
            tablinks = document.getElementsByClassName("tab-btn");
            for (i = 0; i < tablinks.length; i++) {
                tablinks[i].className = tablinks[i].className.replace(" active", "");
            }

            // Show current tab and add active class
            document.getElementById(tabName).style.display = "block";
            evt.currentTarget.className += " active";
        }

        // --- Comment System ---
        function postComment() {
            const input = document.getElementById('userComment');
            const text = input.value.trim();
            const list = document.getElementById('commentList');

            if (text === "") {
                alert("Transmission empty. Please input text.");
                return;
            }

            const newItem = document.createElement('li');
            newItem.className = 'comment-item';

            // Generate random initial
            const initials = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
            const randomChar = initials.charAt(Math.floor(Math.random() * initials.length));

            newItem.innerHTML = `
                <div class="user-avatar">${randomChar}</div>
                <div class="comment-text">
                    <strong>Guest Porter:</strong> <br> ${text}
                </div>
            `;

            // Add animation class or simple prepend
            list.insertBefore(newItem, list.firstChild);
            input.value = ""; // Clear input

            // Simulate "Like" sound or feedback (console log for now)
            console.log("Keep on keeping on!");
        }

        // --- Search Functionality ---
        function performSearch() {
            const query = document.getElementById('searchInput').value.toLowerCase();
            const modal = document.getElementById('searchModal');
            const resultsDiv = document.getElementById('searchResults');

            if (!query) return;

            // Collect searchable content
            // We search through character cards (data-keywords) and tab content headers
            const characters = document.querySelectorAll('.searchable-item');
            const tabs = document.querySelectorAll('.tab-content h3');

            let hits = [];

            // Check Characters
            characters.forEach(char => {
                const keywords = char.getAttribute('data-keywords');
                const name = char.querySelector('h3').innerText;
                if (keywords.includes(query) || name.toLowerCase().includes(query)) {
                    hits.push(`Character: ${name}`);
                }
            });

            // Check Gameplay Tabs
            tabs.forEach(tab => {
                if (tab.innerText.toLowerCase().includes(query)) {
                    hits.push(`Guide: ${tab.innerText}`);
                }
            });

            // Display Results
            resultsDiv.innerHTML = "";
            if (hits.length > 0) {
                const ul = document.createElement('ul');
                hits.forEach(hit => {
                    const li = document.createElement('li');
                    li.innerText = hit;
                    li.style.padding = "5px 0";
                    li.style.borderBottom = "1px solid #ccc";
                    ul.appendChild(li);
                });
                resultsDiv.appendChild(ul);
            } else {
                resultsDiv.innerHTML = "<p>No data found in Chiral Network.</p>";
            }

            modal.style.display = "block";
        }

        function closeModal() {
            document.getElementById('searchModal').style.display = "none";
        }

        // Close modal when clicking outside
        window.onclick = function(event) {
            const modal = document.getElementById('searchModal');
            if (event.target == modal) {
                modal.style.display = "none";
            }
        }

        // Allow 'Enter' key to trigger search
        document.getElementById("searchInput").addEventListener("keypress", function(event) {
            if (event.key === "Enter") {
                event.preventDefault();
                performSearch();
            }
        });
    </script>
</body>
</html>
