            { id: 3, title: "Ming Dynasty Wall", category: "history", desc: "A fragment of the ancient city wall that survived modernization. Touched by centuries of rain and wind.", color: "#c19a6b" },
            { id: 4, title: "Bamboo Garden", category: "nature", desc: "A lush micro-forest in the middle of concrete buildings. Perfect for meditation and tea.", color: "#8fbc8f" },
            { id: 5, title: "Spicy Hot Pot Lane", category: "food", desc: "The smell hits you before you see it. Authentic Sichuan peppers and vibrant night life.", color: "#cd5c5c" },
            { id: 6, title: "Calligraphy Corner", category: "art", desc: "Watch masters practice their strokes on the pavement using just water and giant brushes.", color: "#deb887" },
