        });

        prevBtn.addEventListener('click', () => {
            if (currentScroll > 0) {
                currentScroll -= cardWidth;
                // Clamp to 0
                if(currentScroll < 0) currentScroll = 0;
                track.style.transform = `translateX(-${currentScroll}px)`;
            }
        });

        // --- CATEGORY LOGIC ---
        categoryBtns.forEach(btn => {
            btn.addEventListener('click', () => {
                // Remove active class from all
                categoryBtns.forEach(b => b.classList.remove('active'));
                // Add active to clicked
                btn.classList.add('active');

                activeFilter = btn.getAttribute('data-filter');
                renderCards(activeFilter, searchInput.value);
            });
        });

        // --- SEARCH LOGIC ---
        searchInput.addEventListener('input', (e) => {
            renderCards(activeFilter, e.target.value);
        });

        // --- MODAL LOGIC ---
        function openModal(item) {
            modalTitle.innerText = item.title;
            modalDesc.innerText = item.desc; // Full description
            modalCat.innerText = item.category;
            modalHeader.style.backgroundColor = item.color;
            modal.classList.add('open');
            document.body.style.overflow = 'hidden'; // Prevent background scrolling
        }

        closeModal.addEventListener('click', () => {
            modal.classList.remove('open');
            document.body.style.overflow = 'auto';
        });

        // Close modal if clicking outside the card
        modal.addEventListener('click', (e) => {
            if (e.target === modal) {
                modal.classList.remove('open');
                document.body.style.overflow = 'auto';
            }
        });

        // --- START ---
        // Initial render
        renderCards();

    </script>
</body>
</html>
