        /* --- JAVASCRIPT LOGIC --- */

        // Mock Data for hierarchical simulation
        const assetData = {
            'Stack': { voltage: '800 V', temp: '28°C', cycles: '120', soh: 98, status: 'Good' },
            'Cluster': { voltage: '200 V', temp: '26°C', cycles: '130', soh: 96, status: 'Good' },
            'Package': { voltage: '48 V', temp: '25°C', cycles: '135', soh: 94, status: 'Check' },
            'Core': { voltage: '3.2 V', temp: '24°C', cycles: '142', soh: 92, status: 'Optimal' }
        };

        // DOM Elements
        const levelSelect = document.getElementById('level-select');
        const assetList = document.getElementById('asset-list');
        const currentAssetName = document.getElementById('current-asset-name');
        const currentLevelBadge = document.getElementById('current-level-badge');
        const sohBar = document.getElementById('soh-bar');

        // Metric Elements
        const valVoltage = document.getElementById('val-voltage');
        const valTemp = document.getElementById('val-temp');
        const valCycles = document.getElementById('val-cycles');
        const valStatus = document.getElementById('val-status');
        const imgPreview = document.getElementById('imagePreview');

        // Initialize
        document.addEventListener('DOMContentLoaded', () => {
            updateDataDisplay('Core'); // Load default
        });

        // 1. Hierarchical Division Functionality
        function updateViewLevel() {
            const selectedLevel = levelSelect.value;

            // Update Badges
            currentLevelBadge.textContent = `Level: ${selectedLevel}`;

            // Update Sidebar List (Simulated hierarchy change)
            assetList.innerHTML = ''; // Clear list

            let count = 3;
            if(selectedLevel === 'Stack') count = 1;

            for(let i=1; i<=count; i++) {
                const li = document.createElement('li');
                li.textContent = `${selectedLevel}-00${i}`;
                if(i===1) li.classList.add('active'); // Default select first

                // Add click event closure
                li.onclick = function() { selectAsset(this, `${selectedLevel}-00${i}`); };

                assetList.appendChild(li);
            }

            // Reset Name and Update Data
            currentAssetName.textContent = `${selectedLevel}-001`;
            updateDataDisplay(selectedLevel);

            showNotification(`Switched hierarchy level to: ${selectedLevel}`);
        }

        // 2. Asset Selection Logic
        function selectAsset(element, name) {
            // Remove active class from all
            const items = document.querySelectorAll('.nav-tree li');
            items.forEach(item => item.classList.remove('active'));

            // Add to clicked
            element.classList.add('active');

            // Update Header
            currentAssetName.textContent = name;

            // Randomize data slightly to simulate different assets
            runDiagnostics(); 
        }

        // 3. Update Data / Assessment Results
        function updateDataDisplay(level) {
            const data = assetData[level];

            // Update Text Metrics
            valVoltage.textContent = data.voltage;
            valTemp.textContent = data.temp;
            valCycles.textContent = data.cycles;
            valStatus.textContent = data.status;

            // Color code status
            if(data.status === 'Check') valStatus.style.color = '#d9534f'; // Red
            else valStatus.style.color = 'green';

            // Animate Health Bar
            animateHealthBar(data.soh);
        }

        function animateHealthBar(percent) {
            sohBar.style.width = '0%';
            sohBar.textContent = '0%';

            setTimeout(() => {
                sohBar.style.width = percent + '%';
                sohBar.textContent = percent + '% SOH';

                // Color Logic for Bar
                if(percent > 90) sohBar.style.backgroundColor = 'var(--accent-color)';
                else if(percent > 75) sohBar.style.backgroundColor = '#f0ad4e';
                else sohBar.style.backgroundColor = '#d9534f';
            }, 100);
        }

        // 4. Run Diagnostics (Simulation Button)
        function runDiagnostics() {
            // Simulate processing
            valStatus.textContent = "Analyzing...";
            valStatus.style.color = "#999";

            setTimeout(() => {
                const level = levelSelect.value;
                const baseData = assetData[level];

                // Add slight randomization for realism
                const randomSOH = Math.floor(baseData.soh - (Math.random() * 5));

                valStatus.textContent = baseData.status;
                valStatus.style.color = baseData.status === 'Check' ? '#d9534f' : 'green';

                animateHealthBar(randomSOH);
                showNotification("Assessment Complete");
            }, 800);
        }

        // 5. Image Upload Functionality
        function handleImageUpload(event) {
            const file = event.target.files[0];
            if (file) {
                const reader = new FileReader();
                reader.onload = function(e) {
                    imgPreview.innerHTML = `<img src="${e.target.result}" alt="Asset Preview">`;
                    showNotification("Image Uploaded Successfully");
                }
                reader.readAsDataURL(file);
            }
        }

        // 6. Notification System
        function showNotification(message) {
            const notif = document.getElementById('notification');
            notif.textContent = message;
            notif.classList.add('show');

            setTimeout(() => {
                notif.classList.remove('show');
            }, 3000);
        }
    </script>
</body>
</html>
