            if(tabName === 'lottery') document.querySelectorAll('.nav-item')[1].classList.add('active');

            // Switch View
            views.collection.classList.remove('active');
            views.lottery.classList.remove('active');

            document.getElementById(`section-${tabName}`).classList.add('active');
