                card.className = `character-card ${char.locked ? 'locked' : ''}`;

                const btnText = char.locked ? "Get" : "Owned";
                const btnDisabled = char.locked ? "" : "disabled";
                const btnAction = char.locked ? `onclick="performTask(${char.id})"` : "";

                card.innerHTML = `
                    <span class="character-icon">${char.icon}</span>
                    <h3>${char.name}</h3>
                    <p style="font-size: 0.8rem; color: #777; margin: 5px 0;">${char.task}</p>
