                        ${btnText}
                    </button>
                `;
                views.grid.appendChild(card);
            });

            views.count.innerText = `${collectedCount}/${state.characters.length}`;

            // Update Lottery Button State
            if (collectedCount === state.characters.length) {
                views.lotteryBtn.disabled = false;
                views.lotteryBtn.innerText = "Start Lottery";
            } else {
                views.lotteryBtn.disabled = true;
                views.lotteryBtn.innerText = "Collect All to Unlock";
