            }

            if (char.id === 3) { // Wait 2 seconds
                const btn = event.target;
                btn.innerText = "Waiting...";
                btn.disabled = true;
                setTimeout(() => unlockCharacter(id), 2000);
            } else {
                unlockCharacter(id);
            }
        }

        function unlockCharacter(id) {
            const charIndex = state.characters.findIndex(c => c.id === id);
            state.characters[charIndex].locked = false;
            renderCharacters();
            showModal("Unlocked!", `You got ${state.characters[charIndex].name}!`);
        }

        // --- Lottery Logic ---
        function startLottery() {
            if (views.lotteryBtn.disabled) return;

            views.lotteryBtn.disabled = true;
            views.lotteryBtn.innerText = "Spinning...";

            let shuffleCount = 0;
            const prizes = ["10 Gold Coins", "Rare Wallpaper", "Try Again", "Grand Prize: Chocolate Box"];

            // Animation effect
            const interval = setInterval(() => {
                views.lotteryResult.innerText = prizes[Math.floor(Math.random() * prizes.length)];
                shuffleCount++;
                if (shuffleCount > 15) {
                    clearInterval(interval);
                    finalizeLottery(prizes);
                }
            }, 100);
        }

        function finalizeLottery(prizes) {
            // Determine winner (random)
            const winIndex = Math.floor(Math.random() * prizes.length);
            const prize = prizes[winIndex];

            views.lotteryResult.innerText = prize;
            views.lotteryBtn.innerText = "Play Again";
            views.lotteryBtn.disabled = false;

            // Add to records
            const date = new Date();
            const timeString = `${date.getHours()}:${date.getMinutes().toString().padStart(2, '0')}`;
            state.records.unshift({ time: timeString, prize: prize });
            renderRecords();

            showModal("Result", `You won: ${prize}`);
        }

        function renderRecords() {
            if (state.records.length === 0) {
                views.recordsList.innerHTML = '<li style="color: #999; justify-content: center;">No records yet</li>';
                return;
            }

            views.recordsList.innerHTML = '';
            state.records.forEach(rec => {
                const li = document.createElement('li');
                li.innerHTML = `<span>${rec.prize}</span> <span style="color:#888; font-size:0.8rem;">${rec.time}</span>`;
                views.recordsList.appendChild(li);
            });
        }

        // --- Modal Utility ---
        function showModal(title, msg) {
            views.modalTitle.innerText = title;
            views.modalMsg.innerText = msg;
            views.modal.style.display = 'flex';
        }

        function closeModal() {
            views.modal.style.display = 'none';
        }

        // Close modal when clicking outside
        window.onclick = function(event) {
            if (event.target == views.modal) {
                closeModal();
            }
        }

    </script>
</body>
</html>
