    <script>
        /* --- JAVASCRIPT LOGIC --- */

        // Game State
        let isPlaying = false;
        let score = 0;
        let timeLeft = 60;
        let timerInterval;
        const totalDiffs = 7;
        const foundDiffs = new Set(); // Store IDs of found differences

        // DOM Elements
        const timerDisplay = document.getElementById('timer');
        const scoreDisplay = document.getElementById('score');
        const startBtn = document.getElementById('startBtn');
        const giveUpBtn = document.getElementById('giveUpBtn');
        const gameArea = document.getElementById('gameArea');
        const img2Wrapper = document.getElementById('img2-wrapper');
        const img1Wrapper = document.getElementById('img1-wrapper');

        // Sounds (Simulated logic, no actual audio files linked to prevent errors)
        const playSound = (type) => {
            // In a real app, use: new Audio('path/to/sound.mp3').play();
            console.log(`Playing sound: ${type}`);
        };

        // 1. Start Game
        function startGame() {
            if (isPlaying) return;

            isPlaying = true;
            score = 0;
            timeLeft = 60;
            foundDiffs.clear();

            // Clear previous markers
            document.querySelectorAll('.found-circle').forEach(el => el.remove());

            // Update UI
            scoreDisplay.innerText = score;
            timerDisplay.innerText = timeLeft;
            startBtn.disabled = true;
            giveUpBtn.disabled = false;
            startBtn.innerText = "Game in Progress...";

            // Start Timer
            timerInterval = setInterval(() => {
                timeLeft--;
                timerDisplay.innerText = timeLeft;

                if (timeLeft <= 10) {
                    timerDisplay.style.color = '#b71c1c'; // Dark red warning
                }

                if (timeLeft <= 0) {
                    endGame(false);
                }
            }, 1000);

            // Enable Clicking on Zones
            enableInteraction();
        }

        // 2. Interaction Logic
        function enableInteraction() {
            const zones = document.querySelectorAll('.diff-zone');

            zones.forEach(zone => {
                zone.onclick = (e) => {
                    if (!isPlaying) return;

                    const id = zone.getAttribute('data-id');

                    if (foundDiffs.has(id)) return; // Already found

                    // Found a difference!
                    foundDiffs.add(id);
                    score++;
                    scoreDisplay.innerText = score;

                    // Mark it visually
                    createMarker(e.target, img2Wrapper); // Mark on Right

                    // Optional: Mark on Left too for symmetry
                    // createMarkerClone(e.target, img1Wrapper); 

                    if (score === totalDiffs) {
                        endGame(true);
                    }
                };
            });

            // Handle misses (clicking on background image)
            img2Wrapper.onclick = (e) => {
                if(!isPlaying) return;
                // If the target is the image itself (not a zone or a marker)
                if(e.target.tagName === 'IMG') {
                    showMissAnimation(e.clientX, e.clientY);
                }
            }
        }

        function createMarker(zoneElement, wrapper) {
            const rect = zoneElement.getBoundingClientRect();
            const wrapperRect = wrapper.getBoundingClientRect();

            const marker = document.createElement('div');
            marker.classList.add('found-circle');

            // Calculate relative position inside the wrapper
            marker.style.width = rect.width + 'px';
            marker.style.height = rect.height + 'px';
            marker.style.left = (rect.left - wrapperRect.left) + 'px';
            marker.style.top = (rect.top - wrapperRect.top) + 'px';

            wrapper.appendChild(marker);
        }

        function showMissAnimation(x, y) {
            const msg = document.createElement('div');
            msg.classList.add('error-msg');
            msg.innerText = "Oops!";
            msg.style.left = x + 'px';
            msg.style.top = y + 'px';
            document.body.appendChild(msg);

            setTimeout(() => { msg.remove(); }, 1000);

            // Penalize time slightly?
            timeLeft = Math.max(0, timeLeft - 2);
            timerDisplay.innerText = timeLeft;
        }

        // 3. End Game Logic
        function endGame(win) {
            isPlaying = false;
            clearInterval(timerInterval);
            startBtn.disabled = false;
            startBtn.innerText = "▶ Restart Game";
            giveUpBtn.disabled = true;

            const modal = document.getElementById('resultModal');
            const title = document.getElementById('resultTitle');
            const message = document.getElementById('resultMessage');

            modal.style.display = 'flex';

            if (win) {
                title.innerText = "Brilliant!";
                title.style.color = "#388E3C";
                message.innerHTML = `You found all 7 differences with <strong>${timeLeft}</strong> seconds left!<br>Mr. Bean is impressed.`;
            } else {
                title.innerText = "Oh no!";
                title.style.color = "#d32f2f";
                message.innerHTML = `Time's up! You found <strong>${score}</strong> out of 7.<br>Better luck next time, Teddy!`;
            }
        }

        // 4. Modal Controls
        function showRules() {
            document.getElementById('rulesModal').style.display = 'flex';
        }

        function closeModal(modalId) {
            document.getElementById(modalId).style.display = 'none';
        }

        // Close modal if clicking outside content
        window.onclick = function(event) {
            if (event.target.classList.contains('modal')) {
                event.target.style.display = "none";
            }
        }
    </script>
</body>
</html>
