            margin: 0;
            padding: 0;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        body {
            background-color: var(--bg-color);
            color: var(--text-dark);
            line-height: 1.6;
        }

        /* --- NAVIGATION --- */
        nav {
            background-color: var(--highlight-color);
            padding: 1rem 2rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
            box-shadow: var(--shadow);
            position: sticky;
            top: 0;
            z-index: 1000;
        }

        .logo {
            font-size: 1.5rem;
            font-weight: bold;
            color: var(--text-light);
            text-shadow: 1px 1px 2px rgba(0,0,0,0.2);
        }

        .nav-links {
            display: flex;
            gap: 20px;
        }

        .nav-btn {
            background: none;
            border: none;
            color: var(--text-light);
            font-weight: 600;
            cursor: pointer;
            transition: opacity 0.3s;
        }

        .nav-btn:hover {
            opacity: 0.8;
        }

        /* --- AUTH MODAL --- */
        .modal-overlay {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0,0,0,0.5);
            display: none;
            justify-content: center;
            align-items: center;
            z-index: 2000;
        }

        .modal {
            background: white;
            padding: 2rem;
            border-radius: 12px;
            width: 350px;
            text-align: center;
            box-shadow: var(--shadow);
            border: 4px solid var(--highlight-color);
        }

        .modal input {
            width: 100%;
            padding: 10px;
            margin: 10px 0;
            border: 1px solid #ccc;
            border-radius: 5px;
        }

        .modal button {
            width: 100%;
            padding: 10px;
            background-color: var(--highlight-color);
            color: white;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            font-weight: bold;
        }

        /* --- MAIN LAYOUT --- */
        .container {
            max-width: 1200px;
            margin: 2rem auto;
            padding: 0 1rem;
            display: grid;
            grid-template-columns: 1fr 3fr;
            gap: 2rem;
        }

        /* --- SIDEBAR (USER PROFILE) --- */
        .sidebar {
            background: var(--card-bg);
            padding: 1.5rem;
            border-radius: 12px;
            box-shadow: var(--shadow);
            height: fit-content;
            border-left: 5px solid var(--highlight-color);
        }

        .user-card {
            text-align: center;
        }

        .avatar {
            width: 80px;
            height: 80px;
            background-color: var(--highlight-color);
            border-radius: 50%;
            margin: 0 auto 10px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 2rem;
            color: white;
        }

        .stats {
            margin-top: 1rem;
            text-align: left;
            font-size: 0.9rem;
        }

        .stat-row {
            display: flex;
            justify-content: space-between;
            padding: 5px 0;
            border-bottom: 1px dashed #ccc;
        }

        /* --- CONTENT AREA --- */
        .main-content {
            display: flex;
            flex-direction: column;
            gap: 2rem;
        }

        /* --- HERO SECTION --- */
        .hero {
            background: linear-gradient(135deg, var(--highlight-color), #d99a6c);
            color: white;
            padding: 2rem;
            border-radius: 12px;
            box-shadow: var(--shadow);
            position: relative;
            overflow: hidden;
        }

        .hero h1 {
            font-size: 2.5rem;
            margin-bottom: 0.5rem;
        }

        /* --- TABS --- */
        .tabs {
            display: flex;
            gap: 10px;
            margin-bottom: 1rem;
        }

        .tab-btn {
            padding: 10px 20px;
            background: var(--card-bg);
            border: none;
            border-radius: 8px 8px 0 0;
            cursor: pointer;
            font-weight: bold;
            color: var(--text-dark);
        }

        .tab-btn.active {
            background: var(--highlight-color);
            color: white;
        }

        /* --- TASK LIST --- */
        .task-container {
            background: var(--card-bg);
            border-radius: 0 12px 12px 12px;
            padding: 1.5rem;
            box-shadow: var(--shadow);
        }

        .task-item {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 15px;
            border-bottom: 1px solid rgba(0,0,0,0.1);
            transition: background 0.2s;
        }

        .task-item:last-child {
            border-bottom: none;
        }

        .task-item:hover {
            background-color: #fffaf0;
        }

        .task-info h3 {
            margin-bottom: 5px;
        }

        .progress-bar-bg {
            width: 200px;
            height: 10px;
            background: #ddd;
            border-radius: 5px;
            overflow: hidden;
            margin-top: 5px;
        }

        .progress-bar-fill {
            height: 100%;
            background: var(--highlight-color);
            width: 0%;
            transition: width 0.5s ease-in-out;
        }

        .task-action button {
            padding: 8px 16px;
            background-color: var(--highlight-color);
            color: white;
            border: none;
            border-radius: 20px;
            cursor: pointer;
            font-weight: bold;
            transition: transform 0.1s;
        }

        .task-action button:hover {
            background-color: var(--btn-hover);
        }

        .task-action button:active {
            transform: scale(0.95);
        }

        .task-action button:disabled {
            background-color: #ccc;
            cursor: not-allowed;
        }

        .task-action button.claimed {
            background-color: var(--success-green);
            cursor: default;
        }

        /* --- RULES SECTION --- */
        .rules-section {
            margin-top: 2rem;
            padding: 1rem;
            background: rgba(255,255,255,0.5);
            border-radius: 8px;
            font-size: 0.9rem;
        }

        .rules-dropdown {
            cursor: pointer;
            font-weight: bold;
            display: flex;
            align-items: center;
            gap: 10px;
        }

        .rules-content {
            display: none;
            margin-top: 10px;
            padding-left: 20px;
        }

        .rules-content.show {
            display: block;
        }

        /* --- NOTIFICATIONS --- */
        .toast {
            position: fixed;
            bottom: 20px;
            right: 20px;
            background-color: var(--text-dark);
            color: white;
            padding: 12px 24px;
            border-radius: 8px;
            opacity: 0;
            transition: opacity 0.3s;
            pointer-events: none;
        }

        .toast.show {
            opacity: 1;
        }

        /* --- RESPONSIVE --- */
        @media (max-width: 768px) {
            .container {
                grid-template-columns: 1fr;
            }
            .progress-bar-bg {
                width: 100px;
            }
        }
    </style>
</head>
<body>

    <!-- Navigation -->
    <nav>
        <div class="logo">⚔️ Realm of Heroes</div>
        <div class="nav-links">
            <button id="loginBtn" class="nav-btn">Login</button>
            <button id="registerBtn" class="nav-btn">Register</button>
            <span id="welcomeUser" style="display:none; color: white; font-weight: bold;"></span>
            <button id="logoutBtn" class="nav-btn" style="display:none;">Logout</button>
        </div>
    </nav>

    <!-- Main Container -->
    <div class="container">

        <!-- Sidebar: User Profile (Hidden initially if not logged in) -->
        <aside class="sidebar">
            <div id="loggedOutMsg">
                <p>Please log in to track your progress.</p>
            </div>
            <div id="userProfile" class="user-card" style="display: none;">
                <div class="avatar">🦸‍♂️</div>
                <h2 id="profileName">Hero Name</h2>
                <div class="stats">
                    <div class="stat-row">
                        <span>Level:</span>
                        <span id="userLevel">12</span>
                    </div>
                    <div class="stat-row">
                        <span>Daily Points:</span>
                        <span id="dailyPoints">0</span>/100
                    </div>
                    <div class="stat-row">
                        <span>Tasks Done:</span>
                        <span id="tasksCompleted">0</span>/5
                    </div>
                </div>
            </div>
        </aside>

        <!-- Main Content -->
        <main class="main-content">

            <!-- Hero Section -->
            <section class="hero">
                <h1>Goblin Invasion Event</h1>
                <p>Complete daily tasks to drive back the goblins and earn "Sandy Gold"!</p>
                <div style="margin-top:10px; font-size: 0.9em; opacity: 0.9;">Time Remaining: <span id="timer">12:00:00</span></div>
            </section>

            <!-- Task Tabs -->
            <div>
                <div class="tabs">
                    <button class="tab-btn active" onclick="switchTab('daily')">Daily Tasks</button>
                    <button class="tab-btn" onclick="switchTab('weekly')">Weekly Challenges</button>
                </div>

                <div class="task-container" id="taskListContainer">
                    <!-- Tasks will be injected here via JS -->
                </div>
            </div>

            <!-- Rules Dropdown -->
            <section class="rules-section">
                <div class="rules-dropdown" onclick="toggleRules()">
                    <span>📜 Activity Rules & Regulations</span>
                    <span>▼</span>
                </div>
                <div class="rules-content" id="rulesContent">
                    <ul>
                        <li>Tasks reset every day at 00:00 server time.</li>
                        <li>Unclaimed rewards will be sent to your mailbox.</li>
                        <li>Completing all daily tasks grants a bonus chest.</li>
                        <li>Points accumulated contribute to the Weekly Pass.</li>
                    </ul>
                </div>
            </section>

        </main>
    </div>

    <!-- Login/Register Modal -->
    <div class="modal-overlay" id="authModal">
        <div class="modal">
            <h2 id="modalTitle">Login</h2>
            <input type="text" id="usernameInput" placeholder="Username">
            <input type="password" id="passwordInput" placeholder="Password">
            <button onclick="handleAuth()" id="authSubmitBtn">Login</button>
            <p style="margin-top: 10px; font-size: 0.8rem; cursor: pointer; color: var(--highlight-color);" onclick="closeModal()">Close</p>
        </div>
    </div>

    <!-- Toast Notification -->
    <div class="toast" id="toast">Reward Claimed!</div>

    <script>
        // --- DATA SIMULATION ---
        const dailyTasks = [
            { id: 1, title: "Defeat 5 Goblins", reward: "50 Gold", target: 5, current: 3, claimed: false },
            { id: 2, title: "Craft 1 Potion", reward: "10 Gems", target: 1, current: 0, claimed: false },
            { id: 3, title: "Log in", reward: "1 Stamina", target: 1, current: 1, claimed: false },
            { id: 4, title: "Help a Friend", reward: "20 Friendship", target: 1, current: 1, claimed: true }, // Already claimed example
            { id: 5, title: "Spend 100 Gold", reward: "20 EXP", target: 100, current: 45, claimed: false }
        ];

        const weeklyTasks = [
            { id: 6, title: "Clear Dungeon 5 Times", reward: "Rare Sword", target: 5, current: 2, claimed: false },
            { id: 7, title: "Win 3 Arena Matches", reward: "500 Gems", target: 3, current: 3, claimed: false }
        ];

        let currentUser = null;
        let currentTab = 'daily';

        // --- DOM ELEMENTS ---
        const authModal = document.getElementById('authModal');
        const modalTitle = document.getElementById('modalTitle');
        const authSubmitBtn = document.getElementById('authSubmitBtn');
        const loginBtn = document.getElementById('loginBtn');
        const registerBtn = document.getElementById('registerBtn');
        const logoutBtn = document.getElementById('logoutBtn');
        const welcomeUser = document.getElementById('welcomeUser');
        const userProfile = document.getElementById('userProfile');
        const loggedOutMsg = document.getElementById('loggedOutMsg');
        const taskListContainer = document.getElementById('taskListContainer');

        // --- AUTHENTICATION LOGIC ---
        loginBtn.addEventListener('click', () => openModal('Login'));
        registerBtn.addEventListener('click', () => openModal('Register'));
        logoutBtn.addEventListener('click', logout);

        function openModal(type) {
            authModal.style.display = 'flex';
            modalTitle.innerText = type;
            authSubmitBtn.innerText = type;
        }

        function closeModal() {
            authModal.style.display = 'none';
        }

        function handleAuth() {
            const username = document.getElementById('usernameInput').value;
            if(!username) return alert("Please enter a username");

            // Mock Login/Register success
            currentUser = {
                name: username,
                level: Math.floor(Math.random() * 50) + 1,
                points: 0,
                completed: 0
            };

            updateUIForLogin();
            closeModal();
            showToast(`Welcome, ${username}!`);
        }

        function logout() {
            currentUser = null;
            updateUIForLogout();
            showToast("Logged out successfully.");
        }

        function updateUIForLogin() {
            loginBtn.style.display = 'none';
            registerBtn.style.display = 'none';
            logoutBtn.style.display = 'inline-block';
            welcomeUser.style.display = 'inline-block';
            welcomeUser.innerText = `Hi, ${currentUser.name}`;

            loggedOutMsg.style.display = 'none';
            userProfile.style.display = 'block';
            document.getElementById('profileName').innerText = currentUser.name;
            document.getElementById('userLevel').innerText = currentUser.level;

            updateStats();
            renderTasks();
        }

        function updateUIForLogout() {
            loginBtn.style.display = 'inline-block';
            registerBtn.style.display = 'inline-block';
            logoutBtn.style.display = 'none';
            welcomeUser.style.display = 'none';

            loggedOutMsg.style.display = 'block';
            userProfile.style.display = 'none';

            // Reset task views to unclaimed state visually (though data persists in memory for this session)
            renderTasks();
        }

        function updateStats() {
            if (!currentUser) return;

            // Calculate stats based on 'dailyTasks' array state
            let points = 0;
            let done = 0;

            dailyTasks.forEach(task => {
                if(task.current >= task.target) {
                    done++;
                    points += 10; // Arbitrary points per task
                }
            });

            document.getElementById('dailyPoints').innerText = points;
            document.getElementById('tasksCompleted').innerText = done;
        }

        // --- TASK MANAGEMENT ---

        function switchTab(tab) {
            currentTab = tab;
            // Update Tab Styling
            const buttons = document.querySelectorAll('.tab-btn');
            buttons.forEach(btn => btn.classList.remove('active'));
            event.target.classList.add('active');

            renderTasks();
        }

        function renderTasks() {
            taskListContainer.innerHTML = '';
            const tasksToRender = currentTab === 'daily' ? dailyTasks : weeklyTasks;

            tasksToRender.forEach(task => {
                const percent = Math.min((task.current / task.target) * 100, 100);
                const isFinished = task.current >= task.target;

                let btnHTML = '';

                if (!currentUser) {
                     btnHTML = `<button disabled>Login to Claim</button>`;
                } else if (task.claimed) {
                    btnHTML = `<button class="claimed" disabled>Claimed</button>`;
                } else if (isFinished) {
                    btnHTML = `<button onclick="claimReward(${task.id})">Claim</button>`;
                } else {
                    btnHTML = `<button onclick="doTask(${task.id})">Go</button>`;
                }

                const html = `
                    <div class="task-item">
                        <div class="task-info">
                            <h3>${task.title} <span style="font-size:0.8em; color:gray;">(Reward: ${task.reward})</span></h3>
                            <div style="font-size: 0.9em;">Progress: ${task.current}/${task.target}</div>
                            <div class="progress-bar-bg">
                                <div class="progress-bar-fill" style="width: ${percent}%"></div>
                            </div>
                        </div>
                        <div class="task-action">
                            ${btnHTML}
                        </div>
                    </div>
                `;
                taskListContainer.innerHTML += html;
            });
        }

        function doTask(id) {
            // Simulation: Clicking "Go" instantly completes the task for demo purposes
            const list = currentTab === 'daily' ? dailyTasks : weeklyTasks;
            const task = list.find(t => t.id === id);

            if(task) {
                task.current = task.target; // Max out progress
                showToast(`Task "${task.title}" progress updated!`);
                renderTasks();
                updateStats();
            }
        }

        function claimReward(id) {
            const list = currentTab === 'daily' ? dailyTasks : weeklyTasks;
            const task = list.find(t => t.id === id);

            if(task && !task.claimed) {
                task.claimed = true;
                showToast(`Rewards received: ${task.reward}`);
                renderTasks();
            }
        }

        // --- UTILITIES ---

        function toggleRules() {
            const content = document.getElementById('rulesContent');
            content.classList.toggle('show');
        }

        function showToast(message) {
            const toast = document.getElementById('toast');
            toast.innerText = message;
            toast.classList.add('show');
            setTimeout(() => {
                toast.classList.remove('show');
            }, 3000);
        }

        // Countdown Timer Logic
        function startTimer() {
            const timerEl = document.getElementById('timer');
            // Set end time to end of day
            let hours = 12, minutes = 0, seconds = 0;

            setInterval(() => {
                if (seconds > 0) {
                    seconds--;
                } else {
                    if (minutes > 0) {
                        minutes--;
                        seconds = 59;
                    } else {
                        if (hours > 0) {
                            hours--;
                            minutes = 59;
                            seconds = 59;
                        }
                    }
                }

                timerEl.innerText = `${String(hours).padStart(2,'0')}:${String(minutes).padStart(2,'0')}:${String(seconds).padStart(2,'0')}`;
            }, 1000);
        }

        // --- INITIALIZATION ---
        startTimer();
        renderTasks();

    </script>
</body>
</html>
```

Here is a complete, one-page website implementation containing HTML, CSS, and JavaScript. This solution uses the popular **Chart.js** library (via CDN) to render high-quality, interactive charts without needing a complex backend.

Save the following code as an `.html` file (e.g., `messi_ronaldo_cl.html`) and open it in any modern web browser.

