<body>

    <header>
        <h1>GOAT Debate: UCL Edition</h1>
        <p class="subtitle">Interactive Analysis of Messi vs. Ronaldo in the Champions League</p>
    </header>

    <section class="controls">
        <div>
            <label for="chartFilter" style="color:white; margin-right: 10px;">Highlight Focus:</label>
            <select id="chartFilter" onchange="updateCharts()">
                <option value="all">Compare Both</option>
                <option value="Messi">Focus: Messi</option>
                <option value="Ronaldo">Focus: Ronaldo</option>
            </select>
        </div>
        <button class="primary-btn" onclick="showSummary()">📊 Generate Analysis Report</button>
        <button class="reset-btn" onclick="resetDashboard()">🔄 Reset Dashboard</button>
    </section>

    <div class="dashboard">
        <!-- Chart 1: Bar Chart (Total Goals) -->
        <div class="chart-card">
            <h3>Total Goals by Stage (Bar Chart)</h3>
            <canvas id="barChart"></canvas>
            <p style="text-align:center; font-size:0.8rem; color:#666;">Click bars to see exact figures.</p>
        </div>

        <!-- Chart 2: Radar Chart (Attribute Analysis) -->
        <div class="chart-card">
            <h3>Performance Attributes (Radar Chart)</h3>
            <canvas id="radarChart"></canvas>
        </div>

        <!-- Chart 3: Rose/Polar Area Chart (Goal Types) -->
        <div class="chart-card">
            <h3>Goal Scoring Methods (Rose Chart)</h3>
            <canvas id="roseChart"></canvas>
        </div>

