            const rRatio = (dataSet.ronaldo.totalGoals / dataSet.ronaldo.apps).toFixed(2);

            let winnerText = rRatio > mRatio ? "Cristiano Ronaldo" : "Lionel Messi";

            modalText.innerHTML = `Based on the current visualized datasets, here is the breakdown:`;
            statsDiv.innerHTML = `
