                        <p>Goals: ${dataSet.ronaldo.totalGoals}</p>
                        <p>Ratio: <span class="stat-highlight">${rRatio}</span></p>
                    </div>
                </div>
                <hr>
                <p><strong>Insight:</strong> While Ronaldo has more total goals due to more appearances, their goal-per-game ratios are incredibly close. Ronaldo dominates the Knockout stages (QF/SF), while Messi has historically high efficiency in group stages.</p>
            `;
        }

        // Function 3: Close Modal
        function closeModal() {
            document.getElementById('analysisModal').style.display = "none";
        }

        // Click outside modal to close
        window.onclick = function(event) {
            const modal = document.getElementById('analysisModal');
            if (event.target == modal) {
                modal.style.display = "none";
            }
        }

        // Function 4: Reset Dashboard
        function resetDashboard() {
            document.getElementById('chartFilter').value = 'all';
            updateCharts();

            // Add a subtle animation to indicate reset
            const cards = document.querySelectorAll('.chart-card');
            cards.forEach(card => {
                card.style.transform = "scale(0.98)";
                setTimeout(() => {
                    card.style.transform = "scale(1)";
                }, 200);
            });
        }

    </script>
</body>
</html>
