                <button class="secondary" onclick="prevStage(4)">&larr; Edit Details</button>
                <button onclick="window.print()">Print / Save PDF</button>
                <button onclick="location.reload()">Start Over</button>
            </div>
        </div>

    </main>

    <script>
        // --- STATE MANAGEMENT ---
        let currentStage = 1;
        const totalStages = 5;
        let userData = {
            topic: "",
            initialSelections: [],
            secondSelections: []
        };
        let myChart = null; // Chart instance

        // --- NAVIGATION FUNCTIONS ---
        function updateProgress() {
            // Update line fill
            const percentage = ((currentStage - 1) / (totalStages - 1)) * 100;
            document.getElementById('progressFill').style.width = percentage + "%";

            // Update circles
            document.querySelectorAll('.step-indicator').forEach(step => {
                const stepNum = parseInt(step.getAttribute('data-step'));
                if (stepNum < currentStage) {
                    step.classList.add('completed');
                    step.classList.remove('active');
                } else if (stepNum === currentStage) {
                    step.classList.add('active');
                    step.classList.remove('completed');
                } else {
                    step.classList.remove('active', 'completed');
                }
            });
        }

        function showStage(stageNum) {
            // Hide all stages
            document.querySelectorAll('.stage').forEach(el => el.classList.remove('active'));
            // Show target stage
            document.getElementById(`stage${stageNum}`).classList.add('active');

            currentStage = stageNum;
            updateProgress();
        }

        function nextStage(targetStage) {
            showStage(targetStage);
        }

        function prevStage(targetStage) {
            showStage(targetStage);
        }

        // --- STAGE 1 LOGIC: SEARCH ---
        function performSearch() {
            const query = document.getElementById('searchInput').value;
            const resultsDiv = document.getElementById('searchResults');
            const listDiv = document.getElementById('resultsList');
            const nextBtn = document.getElementById('btnStage1Next');

            if (query.trim() === "") {
                alert("Please enter a search term.");
                return;
            }

            // Simulate searching
            listDiv.innerHTML = `
                <div class="search-result" onclick="selectTopic('${query} Analysis')"><strong>${query} Analysis</strong> - Comprehensive breakdown of ${query}.</div>
                <div class="search-result" onclick="selectTopic('${query} Trends')"><strong>${query} Trends</strong> - Historical data regarding ${query}.</div>
                <div class="search-result" onclick="selectTopic('${query} Projections')"><strong>${query} Projections</strong> - Future outlook for ${query}.</div>
            `;

            resultsDiv.style.display = 'block';
            userData.topic = query; // Default fallback
        }

        function selectTopic(topicName) {
            userData.topic = topicName;
            // Highlight selection (visual feedback)
            const allResults = document.querySelectorAll('.search-result');
            allResults.forEach(r => r.style.backgroundColor = 'transparent');
            event.currentTarget.style.backgroundColor = '#d1c4e9'; // Light slate blue

            document.getElementById('btnStage1Next').style.display = 'inline-block';
        }

        // --- STAGE 2 & 3 LOGIC: ANALYTICS ---
        function generateAnalyticReport() {
            // Get checked items from Stage 2
            const checkboxes = document.querySelectorAll('#initialChecklist input[type="checkbox"]:checked');
            userData.initialSelections = Array.from(checkboxes).map(cb => cb.value);

            if (userData.initialSelections.length === 0) {
                alert("Please select at least one item from the checklist.");
                return;
            }

            // Populate Stage 3 text
            document.getElementById('analysisSummary').innerHTML = `
                <strong>Selected Topic:</strong> ${userData.topic}<br>
                <strong>Focus Areas:</strong> ${userData.initialSelections.join(", ")}.<br><br>
                Preliminary analysis indicates a positive correlation between selected metrics. The chart below visualizes the current standing versus industry benchmarks.
            `;

            // Render Chart
            renderChart(userData.initialSelections);
            nextStage(3);
        }

        function renderChart(labels) {
            const ctx = document.getElementById('analysisChart').getContext('2d');

            // Generate random data for demo purposes
            const dataPoints = labels.map(() => Math.floor(Math.random() * 50) + 50);

            if (myChart) {
                myChart.destroy(); // Destroy old chart if exists
            }

            myChart = new Chart(ctx, {
                type: 'bar',
                data: {
                    labels: labels,
                    datasets: [{
                        label: 'Current Score (0-100)',
                        data: dataPoints,
                        backgroundColor: 'rgba(106, 90, 205, 0.6)', // Slate blue transparent
                        borderColor: 'rgba(106, 90, 205, 1)',
                        borderWidth: 1
                    }]
                },
                options: {
                    responsive: true,
                    scales: {
                        y: {
                            beginAtZero: true,
                            max: 100
                        }
                    }
                }
            });
        }

        // --- STAGE 4 LOGIC: DYNAMIC CHECKLIST ---
        function prepareSecondChecklist() {
            const container = document.getElementById('secondaryChecklist');
            container.innerHTML = ''; // Clear previous

            // Create context-aware options based on Stage 2 selections
            userData.initialSelections.forEach(item => {
                // For every item picked in stage 2, give 2 detailed options
                const detail1 = `Detailed Report: ${item} (Q1-Q2)`;
                const detail2 = `Forecast: ${item} (Next Year)`;

                container.innerHTML += `
                    <label><input type="checkbox" value="${detail1}" checked> ${detail1}</label>
                    <label><input type="checkbox" value="${detail2}"> ${detail2}</label>
                `;
            });

            nextStage(4);
        }

        // --- STAGE 5 LOGIC: FINAL REPORT ---
        function generateFinalReport() {
            // Get checked items from Stage 4
            const checkboxes = document.querySelectorAll('#secondaryChecklist input[type="checkbox"]:checked');
            userData.secondSelections = Array.from(checkboxes).map(cb => cb.value);

            if (userData.secondSelections.length === 0) {
                alert("Please select at least one data point.");
                return;
            }

            const date = new Date().toLocaleDateString();

            let reportHTML = `
                <div style="text-align:center; border-bottom: 2px solid #333; margin-bottom: 20px;">
                    <h2>EXECUTIVE SUMMARY</h2>
                    <p>Generated on: ${date}</p>
                </div>
                <h3>1. Introduction</h3>
                <p>This report provides a comprehensive analysis of <strong>${userData.topic}</strong>. The objective was to assess key performance indicators and derive actionable insights.</p>

                <h3>2. Methodology</h3>
                <p>We analyzed the following primary vectors:</p>
                <ul>
                    ${userData.initialSelections.map(item => `<li>${item}</li>`).join('')}
                </ul>

                <h3>3. Detailed Findings</h3>
                <p>Based on the deep-dive selection, the following specific datasets have been compiled:</p>
                <div style="background:#f0f0f5; padding:15px; border-radius:5px;">
                    <ul>
                         ${userData.secondSelections.map(item => `<li><strong>${item}:</strong> Data indicates stability with a variance of +/- 5%.</li>`).join('')}
                    </ul>
                </div>

                <h3>4. Recommendations</h3>
                <p>It is recommended to focus resources on the high-performing metrics identified in the analytical chart. Specifically, attention should be given to sustaining growth in ${userData.initialSelections[0]}.</p>
            `;

            document.getElementById('finalReportContent').innerHTML = reportHTML;
            nextStage(5);
        }
    </script>
</body>
</html>
