        function processDataLoad(data, fields) {
            rawData = data;
            headers = fields;

            document.getElementById('loader').style.display = 'none';
            document.getElementById('file-info').style.display = 'block';
            document.getElementById('row-count').innerText = rawData.length;
            document.getElementById('col-count').innerText = headers.length;

            renderTable('preview-table', rawData.slice(0, 5), headers);
            enableTabs();
            populateSelectors();
            updateAnalysisStats();
        }

        // --- Rendering Helpers ---
        function renderTable(tableId, data, columns) {
            const table = document.getElementById(tableId);
            const thead = table.querySelector('thead');
            const tbody = table.querySelector('tbody');

            thead.innerHTML = '';
            tbody.innerHTML = '';

            // Header
            const trHead = document.createElement('tr');
            columns.forEach(col => {
                const th = document.createElement('th');
                th.innerText = col;
                trHead.appendChild(th);
            });
            thead.appendChild(trHead);

            // Body
            // Limit large tables rendering for performance in cleaning view
            const displayData = (tableId === 'cleaning-table' && data.length > 50) ? data.slice(0, 50) : data;

            displayData.forEach(row => {
                const tr = document.createElement('tr');
                columns.forEach(col => {
                    const td = document.createElement('td');
                    td.innerText = (row[col] === null || row[col] === undefined) ? '' : row[col];
                    tr.appendChild(td);
                });
                tbody.appendChild(tr);
            });
        }

        function populateSelectors() {
            const selectors = ['clean-col-select', 'drop-col-select', 'x-axis-select', 'y-axis-select'];

            selectors.forEach(selId => {
                const select = document.getElementById(selId);
                select.innerHTML = '';
                headers.forEach(header => {
                    const option = document.createElement('option');
                    option.value = header;
                    option.innerText = header;
                    select.appendChild(option);
                });
            });
        }

        // --- Data Cleaning Logic ---
        function removeDuplicates() {
            const initialLen = rawData.length;
            // Create a set of stringified objects to filter
            const seen = new Set();
            rawData = rawData.filter(el => {
                const duplicate = seen.has(JSON.stringify(el));
                seen.add(JSON.stringify(el));
                return !duplicate;
            });

            const removed = initialLen - rawData.length;
            refreshAfterUpdate(`Removed ${removed} duplicate rows.`);
        }

        function dropColumn() {
            const colToRemove = document.getElementById('drop-col-select').value;
            if(!colToRemove) return;

            headers = headers.filter(h => h !== colToRemove);
            rawData = rawData.map(row => {
                const newRow = { ...row };
                delete newRow[colToRemove];
                return newRow;
            });

            refreshAfterUpdate(`Column '${colToRemove}' dropped.`);
        }

        function handleMissing() {
            const col = document.getElementById('clean-col-select').value;
            const action = document.getElementById('missing-action').value;
            let count = 0;

            if (action === 'drop') {
                const initialLen = rawData.length;
                rawData = rawData.filter(row => row[col] !== null && row[col] !== undefined && row[col] !== "");
                count = initialLen - rawData.length;
            } else if (action === 'zero') {
                rawData.forEach(row => {
                    if (row[col] == null || row[col] === "") {
                        row[col] = (typeof row[col] === 'number') ? 0 : "Unknown";
                        count++;
                    }
                });
            } else if (action === 'mean') {
                // Calculate Mean
                const validValues = rawData.filter(r => typeof r[col] === 'number').map(r => r[col]);
                if(validValues.length === 0) {
                    showToast("Cannot calculate mean on non-numeric column");
                    return;
                }
                const sum = validValues.reduce((a, b) => a + b, 0);
                const mean = (sum / validValues.length).toFixed(2);

                rawData.forEach(row => {
                    if (typeof row[col] !== 'number') {
                        row[col] = parseFloat(mean);
                        count++;
                    }
                });
            } else if (action === 'mode') {
                // Calculate Mode
                const frequency = {};
                let maxFreq = 0;
                let mode = null;

                rawData.forEach(r => {
                    const val = r[col];
                    if(val) {
                        frequency[val] = (frequency[val] || 0) + 1;
                        if(frequency[val] > maxFreq) {
                            maxFreq = frequency[val];
                            mode = val;
                        }
                    }
                });

                if(mode) {
                    rawData.forEach(row => {
                        if (row[col] == null || row[col] === "") {
                            row[col] = mode;
                            count++;
                        }
                    });
                }
            }

            refreshAfterUpdate(`Handled ${count} missing values in '${col}'.`);
        }

        function refreshAfterUpdate(msg) {
            renderTable('cleaning-table', rawData, headers);
            populateSelectors();
            updateAnalysisStats();
            showToast(msg);
        }

        // --- Analysis & Visualization ---
        function updateAnalysisStats() {
            const container = document.getElementById('stats-container');
            container.innerHTML = '';

            // Numeric Columns Only
            const numericCols = headers.filter(h => typeof rawData[0][h] === 'number');

            if(numericCols.length === 0) {
                container.innerHTML = "<p>No numeric columns detected for automatic statistics.</p>";
                return;
            }

            numericCols.forEach(col => {
                const values = rawData.map(r => r[col]).filter(v => typeof v === 'number');
                const sum = values.reduce((a, b) => a + b, 0);
                const avg = (sum / values.length).toFixed(2);
                const min = Math.min(...values);
                const max = Math.max(...values);

                const div = document.createElement('div');
                div.className = 'stat-box';
                div.innerHTML = `
                    <h4>${col}</h4>
                    <div style="font-size: 0.9rem; text-align: left; margin-top: 10px;">
                        Avg: <strong>${avg}</strong><br>
                        Min: <strong>${min}</strong><br>
                        Max: <strong>${max}</strong>
                    </div>
                `;
                container.appendChild(div);
            });
        }

        function generateChart() {
            const type = document.getElementById('chart-type').value;
            const xCol = document.getElementById('x-axis-select').value;
            const yCol = document.getElementById('y-axis-select').value;

            if(!xCol || !yCol) {
                showToast("Please select both X and Y axes.");
                return;
            }

            // Prepare Data
            // Limit to top 20 for readability if there are too many unique X values
            let labels = rawData.map(r => r[xCol]);
            let data = rawData.map(r => r[yCol]);

            // Simple aggregation check (if X labels are duplicated, we should sum Y)
            // For simplicity in this demo, we will just take the first 50 rows if dataset is huge
            if(labels.length > 50) {
                labels = labels.slice(0, 50);
                data = data.slice(0, 50);
                showToast("Data truncated to first 50 rows for chart performance.");
            }

            const ctx = document.getElementById('myChart').getContext('2d');

            if (chartInstance) {
                chartInstance.destroy();
            }

            // Dynamic colors
            const bgColors = labels.map(() => `rgba(178, 34, 34, 0.7)`); // Firebrick with opacity
            const borderColors = labels.map(() => `rgba(178, 34, 34, 1)`);

            chartInstance = new Chart(ctx, {
                type: type,
                data: {
                    labels: labels,
                    datasets: [{
                        label: `${yCol} by ${xCol}`,
                        data: data,
                        backgroundColor: type === 'line' ? 'transparent' : bgColors,
                        borderColor: borderColors,
                        borderWidth: 2,
                        pointBackgroundColor: 'firebrick'
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                        y: {
                            beginAtZero: true
                        }
                    }
                }
            });
        }

        // --- Utilities ---
        function showToast(message) {
            const area = document.getElementById('notification-area');
            const toast = document.createElement('div');
            toast.className = 'toast show';
            toast.innerText = message;
            area.appendChild(toast);

            setTimeout(() => {
                toast.classList.remove('show');
                setTimeout(() => toast.remove(), 300);
            }, 3000);
        }

    </script>
</body>
</html>
