    <script>
        // --- Configuration & State ---
        const themeColor = 'royalblue';
        const themeBg = 'rgba(65, 105, 225, 0.2)'; // Light transparent royal blue

        // Store chart instances to update them later
        let charts = {};

        // --- Data Generation Helpers ---
        function generateRandomData(count, min, max) {
            return Array.from({length: count}, () => Math.floor(Math.random() * (max - min + 1)) + min);
        }

        // --- Chart Initialization ---
        document.addEventListener('DOMContentLoaded', function() {
            initCharts();
        });

        function initCharts() {
            // 1. Bar Chart (Revenue)
            const ctxBar = document.getElementById('barChart').getContext('2d');
            charts.bar = new Chart(ctxBar, {
                type: 'bar',
                data: {
                    labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
                    datasets: [{
                        label: 'Revenue ($)',
                        data: generateRandomData(7, 1000, 5000),
                        backgroundColor: themeColor,
                        borderRadius: 5,
                        borderWidth: 0
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    onClick: handleChartClick,
                    plugins: {
                        legend: { display: false }
                    }
                }
            });

            // 2. Line Chart (Growth)
            const ctxLine = document.getElementById('lineChart').getContext('2d');
            charts.line = new Chart(ctxLine, {
                type: 'line',
                data: {
                    labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
                    datasets: [{
                        label: 'Active Users',
                        data: generateRandomData(6, 500, 2000),
                        borderColor: themeColor,
                        backgroundColor: themeBg,
                        fill: true,
                        tension: 0.4
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    onClick: handleChartClick
                }
            });

            // 3. Pie Chart (Devices)
            const ctxPie = document.getElementById('pieChart').getContext('2d');
            charts.pie = new Chart(ctxPie, {
                type: 'doughnut',
                data: {
                    labels: ['Desktop', 'Mobile', 'Tablet'],
                    datasets: [{
                        data: [55, 30, 15],
                        backgroundColor: [
                            'royalblue', 
                            '#6495ED', // Cornflower Blue
                            '#B0C4DE'  // Light Steel Blue
                        ],
                        hoverOffset: 10
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    onClick: handleChartClick
                }
            });

            // 4. Radar Chart (Performance)
            const ctxRadar = document.getElementById('radarChart').getContext('2d');
            charts.radar = new Chart(ctxRadar, {
                type: 'radar',
                data: {
                    labels: ['Speed', 'Reliability', 'Comfort', 'Safety', 'Efficiency'],
                    datasets: [{
                        label: 'Product A',
                        data: generateRandomData(5, 1, 10),
                        fill: true,
                        backgroundColor: 'rgba(65, 105, 225, 0.2)',
                        borderColor: 'royalblue',
                        pointBackgroundColor: 'royalblue',
                        pointBorderColor: '#fff',
                        pointHoverBackgroundColor: '#fff',
                        pointHoverBorderColor: 'royalblue'
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    elements: {
                        line: { borderWidth: 3 }
                    },
                    scales: {
                        r: { ticks: { display: false } } // Hide numbers on radar
                    },
                    onClick: handleChartClick
                }
            });
        }

        // --- Interaction Functions ---

        /**
         * Simulates fetching new data based on the dropdown selection
         */
        function updateDashboard() {
            const range = document.getElementById('timeRangeSelector').value;
            const infoPanel = document.getElementById('info-panel');
            const infoContent = document.getElementById('info-content');

            // Show a notification
            infoPanel.style.display = 'block';
            infoContent.innerHTML = `<h3>Data Range Updated</h3><p>Now showing analytics for: <strong class="text-royalblue">${range.toUpperCase()}</strong>. Data has been refreshed.</p>`;

            randomizeData(); // Actually change the charts
        }

        /**
         * Randomizes the data for all charts to simulate live updates
         */
        function randomizeData() {
            // Update Bar
            charts.bar.data.datasets[0].data = generateRandomData(7, 1000, 5000);
            charts.bar.update();

            // Update Line
            charts.line.data.datasets[0].data = generateRandomData(6, 500, 2000);
            charts.line.update();

            // Update Pie
            const pieData = generateRandomData(3, 10, 100);
            charts.pie.data.datasets[0].data = pieData;
            charts.pie.update();

            // Update Radar
            charts.radar.data.datasets[0].data = generateRandomData(5, 1, 10);
            charts.radar.update();
        }

        /**
         * Switches a chart between 'bar' and 'line' types dynamically
         */
        function toggleChartType(canvasId, altType) {
            const chartInstance = Object.values(charts).find(c => c.canvas.id === canvasId);
            if (!chartInstance) return;

            const currentType = chartInstance.config.type;
            const newType = currentType === 'bar' ? altType : 'bar';

            // Destroy old chart and recreate with new config
            const ctx = document.getElementById(canvasId).getContext('2d');
            const data = chartInstance.data;
            const options = chartInstance.options;

            chartInstance.destroy();

            // Reassign based on logic (simplified for demo)
            if (canvasId === 'barChart') {
                charts.bar = new Chart(ctx, {
                    type: newType,
                    data: data,
                    options: options
                });
            }
        }

        /**
         * Handles clicking on chart elements to display specific details
         */
        function handleChartClick(evt, elements, chart) {
            if (!elements || elements.length === 0) return;

            const index = elements[0].index;
            const label = chart.data.labels[index];
            const value = chart.data.datasets[0].data[index];
            const datasetLabel = chart.data.datasets[0].label || 'Value';

            const infoPanel = document.getElementById('info-panel');
            const infoContent = document.getElementById('info-content');

            infoPanel.style.display = 'block';
            infoContent.innerHTML = `
                <h3>Detail View</h3>
                <p>You selected: <strong class="text-royalblue">${label}</strong></p>
                <p>${datasetLabel}: <strong>${value}</strong></p>
                <button class="btn" style="margin-top:10px; font-size: 0.8rem;" onclick="this.parentElement.parentElement.style.display='none'">Close Details</button>
            `;

            // Scroll to info panel smoothly
            infoPanel.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }

    </script>
</body>
</html>
