    <!-- JavaScript -->
    <script>
        document.addEventListener('DOMContentLoaded', () => {

            // 1. SIMULATE EXTERNAL SYSTEM RETRIEVAL
            // This function mimics an API call to get a dynamic link
            const fetchWebinarLink = () => {
                const linkContainer = document.getElementById('link-container');

                // Simulate network delay (2 seconds)
                setTimeout(() => {
                    // Generate a random "unique" ID for the user
                    const uniqueSessionId = Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
                    const dynamicUrl = `https://zoom.us/j/webinar?session=${uniqueSessionId}`;

                    // Clear the loader
                    linkContainer.innerHTML = '';

                    // Create the success message
                    const successMsg = document.createElement('p');
                    successMsg.textContent = "Your unique link is ready:";
                    successMsg.style.marginBottom = "15px";
                    successMsg.style.fontWeight = "bold";

                    // Create the button
                    const btn = document.createElement('a');
                    btn.href = dynamicUrl;
                    btn.className = 'btn-main';
                    btn.textContent = 'Enter Webinar Room';
                    btn.target = '_blank'; // Open in new tab

                    // Append elements
                    linkContainer.appendChild(successMsg);
                    linkContainer.appendChild(btn);

                    // Add a small animation to the container
                    linkContainer.style.backgroundColor = "#f0fff4"; // Light green tint
                    linkContainer.style.borderColor = "#28a745";
                }, 2000);
            };

            // Initiate the fetch
            fetchWebinarLink();


            // 2. ACCORDION FUNCTIONALITY
            const acc = document.getElementsByClassName("accordion");
            for (let i = 0; i < acc.length; i++) {
                acc[i].addEventListener("click", function() {
                    this.classList.toggle("active");
                    const panel = this.nextElementSibling;
                    if (panel.style.maxHeight) {
                        panel.style.maxHeight = null;
                    } else {
                        panel.style.maxHeight = panel.scrollHeight + "px";
                    } 
                });
            }


            // 3. COUNTDOWN TIMER LOGIC
            // Set the date we're counting down to (2 days from now for demo purposes)
            const countDownDate = new Date().getTime() + (2 * 24 * 60 * 60 * 1000);

            const timerInterval = setInterval(function() {
                const now = new Date().getTime();
                const distance = countDownDate - now;

                // Time calculations
                const days = Math.floor(distance / (1000 * 60 * 60 * 24));
                const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
                const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
                const seconds = Math.floor((distance % (1000 * 60)) / 1000);

                // Display results
                document.getElementById("days").innerHTML = days < 10 ? "0"+days : days;
                document.getElementById("hours").innerHTML = hours < 10 ? "0"+hours : hours;
                document.getElementById("minutes").innerHTML = minutes < 10 ? "0"+minutes : minutes;
                document.getElementById("seconds").innerHTML = seconds < 10 ? "0"+seconds : seconds;

                // If count down is finished
                if (distance < 0) {
                    clearInterval(timerInterval);
                    document.getElementById("countdown").innerHTML = "<h3 style='color:var(--primary-color)'>WE ARE LIVE!</h3>";
                }
            }, 1000);
        });
    </script>
</body>
</html>
