                    <button class="btn" onclick="updateScore('A', -1)">-</button>
                </div>
            </div>

            <!-- VS Divider -->
            <div class="vs-divider">VS</div>

            <!-- Team B -->
            <div class="team-card" id="teamB">
                <input type="text" class="team-name-input" id="nameB" value="GUEST">
                <div class="score-display" id="scoreB">0</div>
                <div class="controls">
                    <button class="btn" onclick="updateScore('B', 1)">+</button>
                    <button class="btn" onclick="updateScore('B', -1)">-</button>
                </div>
            </div>

        </section>

        <!-- Broadcasting Controls -->
        <section class="broadcast-panel">
            <h2>📢 Voice Broadcast Control</h2>
            <p>Current Status: <span id="matchStatus">Match Start</span></p>
            <br>
            <button class="btn" id="announceBtn" onclick="announceCurrentScore()">🎙️ Broadcast Score Now</button>
            <button class="btn btn-reset" onclick="resetAll()">🔄 Reset All</button>

            <div class="broadcast-log" id="logArea">
                <div class="log-entry">System ready...</div>
            </div>
