    <script>
        /* =========================================
           JAVASCRIPT LOGIC
           ========================================= */

        // State Variables
        let scoreA = 0;
        let scoreB = 0;
        let isSoundOn = true;

        // DOM Elements
        const elScoreA = document.getElementById('scoreA');
        const elScoreB = document.getElementById('scoreB');
        const elNameA = document.getElementById('nameA');
        const elNameB = document.getElementById('nameB');
        const elLog = document.getElementById('logArea');
        const elStatus = document.getElementById('matchStatus');

        /**
         * Update the score for a specific team
         * @param {string} team - 'A' or 'B'
         * @param {number} change - The amount to add or subtract
         */
        function updateScore(team, change) {
            if (team === 'A') {
                scoreA += change;
                if(scoreA < 0) scoreA = 0; // Prevent negative scores
                elScoreA.innerText = scoreA;
                animateScore(elScoreA);
            } else {
                scoreB += change;
                if(scoreB < 0) scoreB = 0;
                elScoreB.innerText = scoreB;
                animateScore(elScoreB);
            }

            updateStatus();
            addToLog(`Score Update: ${elNameA.value} ${scoreA} - ${scoreB} ${elNameB.value}`);
        }

        /**
         * Simple animation effect when score changes
         */
        function animateScore(element) {
            element.style.transform = "scale(1.2)";
            setTimeout(() => {
                element.style.transform = "scale(1)";
            }, 200);
        }

        /**
         * Updates the match status text based on scores
         */
        function updateStatus() {
            if (scoreA === scoreB) {
                elStatus.innerText = "It's a tie!";
            } else if (scoreA > scoreB) {
                elStatus.innerText = `${elNameA.value} is leading!`;
            } else {
                elStatus.innerText = `${elNameB.value} is leading!`;
            }
        }

        /**
         * Voice Broadcasting Function using Web Speech API
         */
        function announceCurrentScore() {
            const text = `The current score is. ${elNameA.value}, ${scoreA}. ${elNameB.value}, ${scoreB}.`;
            addToLog(`📢 Broadcasting: "${text}"`);

            if ('speechSynthesis' in window && isSoundOn) {
                // Cancel any currently speaking audio to prevent overlap
                window.speechSynthesis.cancel();

                const utterance = new SpeechSynthesisUtterance(text);

                // Settings for the voice
                utterance.pitch = 1;
                utterance.rate = 1;
                utterance.volume = 1;

                window.speechSynthesis.speak(utterance);
            } else if (!isSoundOn) {
                alert("Sound is currently muted via options.");
            } else {
                alert("Sorry, your browser does not support text-to-speech.");
            }
        }

        /**
         * Reset all scores to 0
         */
        function resetAll() {
            if(confirm("Are you sure you want to reset the match?")) {
                scoreA = 0;
                scoreB = 0;
                elScoreA.innerText = "0";
                elScoreB.innerText = "0";
                elStatus.innerText = "Match Start";
                addToLog("♻️ Match Reset");
            }
        }

        /**
         * Toggle Voice Sound capability
         */
        function toggleSound() {
            isSoundOn = !isSoundOn;
            addToLog(`🔊 Sound is now ${isSoundOn ? 'ON' : 'OFF'}`);
        }

        /**
         * Add entry to the visible log
         */
        function addToLog(message) {
            const time = new Date().toLocaleTimeString();
            const entry = document.createElement('div');
            entry.className = 'log-entry';
            entry.innerText = `[${time}] ${message}`;
            elLog.prepend(entry); // Add to top
        }

        /**
         * Show help alert
         */
        function showHelp() {
            alert("Instructions:\n1. Click + or - to change scores.\n2. Click the team name to rename them.\n3. Click 'Broadcast Score Now' to hear the score.");
        }

        // Initialize log
        addToLog("System Initialized. Ready to score.");

    </script>
</body>
