                <p id="mediaType">Type: --</p>
            </div>
            <div class="time-display">
                <span id="currentTime">00:00</span> / <span id="duration">00:00</span>
            </div>
        </div>

        <!-- Controls -->
        <div class="controls-wrapper">

            <!-- Progress Bar -->
            <div class="progress-container" id="progressContainer">
                <div class="progress-bar" id="progressBar"></div>
            </div>

            <!-- Main Buttons -->
            <div class="main-controls">
                <button class="btn" id="stopBtn" title="Stop">⏹</button>
                <button class="btn" id="rewindBtn" title="Rewind 10s">⏪</button>
                <button class="btn btn-large" id="playPauseBtn" title="Play/Pause">▶</button>
                <button class="btn" id="forwardBtn" title="Forward 10s">⏩</button>
            </div>

            <!-- Settings (Volume & Speed) -->
            <div class="settings-controls">
                <div class="setting-group">
                    <label for="volumeSlider">Volume</label>
                    <span id="volIcon">🔊</span>
                    <input type="range" id="volumeSlider" min="0" max="1" step="0.1" value="1">
                </div>

                <div class="setting-group">
                    <label for="speedSelect">Speed</label>
                    <select id="speedSelect">
                        <option value="0.5">0.5x</option>
                        <option value="1" selected>1.0x</option>
                        <option value="1.5">1.5x</option>
                        <option value="2">2.0x</option>
                    </select>
                </div>
            </div>
        </div>
    </div>

    <script>
        /* 
         * =========================================
         * JAVASCRIPT LOGIC
         * =========================================
         */

        // Element Selection
        const mediaContainer = document.getElementById('mediaContainer');
        const fileInput = document.getElementById('fileInput');
        const playPauseBtn = document.getElementById('playPauseBtn');
        const stopBtn = document.getElementById('stopBtn');
        const rewindBtn = document.getElementById('rewindBtn');
        const forwardBtn = document.getElementById('forwardBtn');
        const progressBar = document.getElementById('progressBar');
        const progressContainer = document.getElementById('progressContainer');
        const volumeSlider = document.getElementById('volumeSlider');
        const speedSelect = document.getElementById('speedSelect');
        const mediaTitle = document.getElementById('mediaTitle');
        const mediaTypeLabel = document.getElementById('mediaType');
        const currentTimeEl = document.getElementById('currentTime');
        const durationEl = document.getElementById('duration');
        const volIcon = document.getElementById('volIcon');

        // State Variables
        let mediaPlayer = null; // Will hold the Audio or Video object
        let isPlaying = false;

        // 1. Handle File Upload
        fileInput.addEventListener('change', function(e) {
            const file = e.target.files[0];
            if (!file) return;

            // Clean up previous player if exists
            if (mediaPlayer) {
                mediaPlayer.pause();
                mediaPlayer.src = "";
                mediaPlayer = null;
                mediaContainer.innerHTML = '';
            }

            // Determine file type
            const fileType = file.type;
            const fileURL = URL.createObjectURL(file);

            // Update Metadata UI
            mediaTitle.textContent = file.name;
            mediaTypeLabel.textContent = `Type: ${fileType}`;
            isPlaying = false;
            updatePlayButtonIcon();
            progressBar.style.width = '0%';
            currentTimeEl.textContent = '00:00';
            durationEl.textContent = '00:00';

            // Create appropriate element
            if (fileType.startsWith('video')) {
                mediaPlayer = document.createElement('video');
                mediaPlayer.src = fileURL;
                mediaContainer.appendChild(mediaPlayer);
                // Hide placeholder
                const placeholder = mediaContainer.querySelector('.placeholder-text');
                if(placeholder) placeholder.style.display = 'none';
            } else if (fileType.startsWith('audio')) {
                mediaPlayer = document.createElement('audio');
                mediaPlayer.src = fileURL;
                mediaContainer.appendChild(mediaPlayer);

                // Show a visualizer placeholder or icon for audio
                mediaContainer.innerHTML = '<div style="font-size: 5rem; color: #8B4513;">🎵</div>';
                mediaContainer.appendChild(mediaPlayer); // Re-append logic node
            } else {
                alert("Unsupported file format.");
                return;
            }

            // Initialize Player Settings
            mediaPlayer.volume = volumeSlider.value;
            mediaPlayer.playbackRate = parseFloat(speedSelect.value);

            // Attach Event Listeners to the new Media Player
            attachMediaEvents();
        });

        // 2. Core Media Functions
        function togglePlay() {
            if (!mediaPlayer) return;

            if (mediaPlayer.paused) {
                mediaPlayer.play();
                isPlaying = true;
            } else {
                mediaPlayer.pause();
                isPlaying = false;
            }
            updatePlayButtonIcon();
        }

        function stopMedia() {
            if (!mediaPlayer) return;
            mediaPlayer.pause();
            mediaPlayer.currentTime = 0;
            isPlaying = false;
            updatePlayButtonIcon();
        }

        function updatePlayButtonIcon() {
            playPauseBtn.textContent = isPlaying ? '⏸' : '▶';
        }

        function formatTime(seconds) {
            const mins = Math.floor(seconds / 60);
            const secs = Math.floor(seconds % 60);
            return `${mins < 10 ? '0' : ''}${mins}:${secs < 10 ? '0' : ''}${secs}`;
        }

        // 3. Attach Events to Media Object
        function attachMediaEvents() {
            // Update duration when metadata loads
            mediaPlayer.addEventListener('loadedmetadata', () => {
                durationEl.textContent = formatTime(mediaPlayer.duration);
            });

            // Update progress bar and time during playback
            mediaPlayer.addEventListener('timeupdate', () => {
                const percent = (mediaPlayer.currentTime / mediaPlayer.duration) * 100;
                progressBar.style.width = `${percent}%`;
                currentTimeEl.textContent = formatTime(mediaPlayer.currentTime);
            });

            // Reset when media ends
            mediaPlayer.addEventListener('ended', () => {
                isPlaying = false;
                updatePlayButtonIcon();
                progressBar.style.width = '0%';
            });
        }

        // 4. UI Control Event Listeners

        // Play/Pause Button
        playPauseBtn.addEventListener('click', togglePlay);

        // Stop Button
        stopBtn.addEventListener('click', stopMedia);

        // Rewind (10s)
        rewindBtn.addEventListener('click', () => {
            if (mediaPlayer) mediaPlayer.currentTime -= 10;
        });

        // Forward (10s)
        forwardBtn.addEventListener('click', () => {
            if (mediaPlayer) mediaPlayer.currentTime += 10;
        });

        // Progress Bar Click (Seek)
        progressContainer.addEventListener('click', (e) => {
            if (!mediaPlayer) return;
            const width = progressContainer.clientWidth;
            const clickX = e.offsetX;
            const duration = mediaPlayer.duration;
            mediaPlayer.currentTime = (clickX / width) * duration;
        });

        // Volume Control
        volumeSlider.addEventListener('input', (e) => {
            if (mediaPlayer) {
                mediaPlayer.volume = e.target.value;
            }
            // Update Icon based on level
            if(e.target.value == 0) volIcon.textContent = '🔇';
            else if(e.target.value < 0.5) volIcon.textContent = '🔉';
            else volIcon.textContent = '🔊';
        });

        // Speed Control
        speedSelect.addEventListener('change', (e) => {
            if (mediaPlayer) {
                mediaPlayer.playbackRate = parseFloat(e.target.value);
            }
        });

    </script>
</body>
</html>
```

Here is a complete, single-file HTML solution. It uses **Three.js**, the industry-standard library for WebGL, to render the 3D content directly in the browser without plugins.

I have set up a scene with a generated geometry (a Torus Knot) so you can immediately see a result without needing to upload an external file.

### Complete Source Code (`index.html`)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Interactive 3D Viewer</title>

    <!-- Load Three.js from a CDN -->
    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
    <!-- Load OrbitControls for mouse interaction -->
    <script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js"></script>

    <style>
        /* CSS RESET & BASIC SETUP */
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        body {
            /* Requirement: Powder Blue Background */
            background-color: #B0E0E6; 
            color: #333;
            overflow: hidden; /* Prevent scrolling, canvas takes full screen */
        }

        /* UI OVERLAY CONTAINER */
        #ui-container {
            position: absolute;
            top: 20px;
            left: 20px;
            z-index: 10; /* Ensure UI sits above the 3D canvas */
            background: rgba(255, 255, 255, 0.85);
            padding: 20px;
            border-radius: 12px;
            box-shadow: 0 4px 15px rgba(0,0,0,0.1);
            width: 300px;
            backdrop-filter: blur(5px);
            border: 1px solid #ffffff;
        }

        /* HEADER STYLING */
        h1 {
            /* Requirement: Royal Blue Components */
            color: #4169E1; 
            font-size: 1.5rem;
            margin-bottom: 10px;
            text-transform: uppercase;
            letter-spacing: 1px;
            border-bottom: 2px solid #4169E1;
            padding-bottom: 5px;
        }

        p {
            font-size: 0.9rem;
            color: #555;
            margin-bottom: 15px;
            line-height: 1.4;
        }

        /* CONTROLS SECTION */
        .control-group {
            margin-bottom: 15px;
        }

        label {
            display: block;
            font-weight: 600;
            color: #4169E1;
            margin-bottom: 5px;
            font-size: 0.9rem;
        }

        /* CUSTOM SELECT DROPDOWN */
        select {
            width: 100%;
            padding: 10px;
            border: 2px solid #4169E1;
            border-radius: 6px;
            background-color: white;
            color: #333;
