        }

        select:focus {
            outline: none;
            box-shadow: 0 0 0 3px rgba(65, 105, 225, 0.3);
        }

        /* BUTTON STYLING */
        button {
            width: 100%;
            padding: 12px;
            background-color: #4169E1; /* Royal Blue */
            color: white;
            border: none;
            border-radius: 6px;
            font-size: 1rem;
            font-weight: bold;
            cursor: pointer;
            transition: transform 0.1s ease, background-color 0.3s ease;
            margin-top: 5px;
        }

        button:hover {
            background-color: #3152b5;
        }

        button:active {
            transform: scale(0.98);
        }

        /* INSTRUCTION TAGS */
        .instructions {
            margin-top: 20px;
            font-size: 0.8rem;
            color: #666;
            background: #e6f2ff;
            padding: 10px;
            border-radius: 6px;
            border-left: 3px solid #4169E1;
