</head>
<body>

    <!-- UI Overlay -->
    <div id="ui-container">
        <h1>3D Model Viewer</h1>
        <p>Explore the geometry in real-time. Use the controls below to change the object or reset the view.</p>

        <div class="control-group">
            <label for="geometry-select">Select Model:</label>
            <select id="geometry-select">
                <option value="torusKnot">Torus Knot</option>
                <option value="cube">Cube</option>
                <option value="sphere">Sphere</option>
                <option value="icosahedron">Icosahedron</option>
            </select>
        </div>

        <div class="control-group">
            <label for="material-select">Material Type:</label>
            <select id="material-select">
                <option value="standard">Standard (Shiny)</option>
                <option value="normal">Normal Map (Rainbow)</option>
                <option value="wireframe">Wireframe</option>
            </select>
        </div>

        <div class="control-group">
            <button id="toggle-spin">Pause Rotation</button>
            <button id="reset-cam" style="margin-top:10px; background-color: white; color: #4169E1; border: 2px solid #4169E1;">Reset Camera</button>
        </div>

        <div class="instructions">
            <strong>Controls:</strong><br>
            • Left Click + Drag to Rotate<br>
            • Right Click + Drag to Pan<br>
            • Scroll to Zoom
        </div>
    </div>

    <!-- Loading Text -->
    <div id="loader">Loading...</div>

    <!-- 3D Canvas Container -->
    <div id="canvas-container"></div>

    <script>
        /**
         * 3D VIEWER APPLICATION
         * Using Three.js
         */

        // --- 1. Variables & Initialization ---
        let scene, camera, renderer, controls, mesh;
        let isSpinning = true;
        const container = document.getElementById('canvas-container');

        // Configuration
        const config = {
            bgColor: 0xB0E0E6, // Powder Blue
            objectColor: 0x4169E1 // Royal Blue
        };

        // --- 2. Setup Scene, Camera, Renderer ---
        function init() {
            // Scene
            scene = new THREE.Scene();
            scene.background = new THREE.Color(config.bgColor);
            // Add some fog for depth
            scene.fog = new THREE.Fog(config.bgColor, 10, 50);

            // Camera
            camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 1000);
            camera.position.set(0, 0, 15);

            // Renderer
            renderer = new THREE.WebGLRenderer({ antialias: true });
            renderer.setSize(window.innerWidth, window.innerHeight);
            renderer.setPixelRatio(window.devicePixelRatio);
            renderer.shadowMap.enabled = true; // Enable shadows
            container.appendChild(renderer.domElement);

            // Lighting
            setupLighting();

            // Controls (OrbitControls)
            controls = new THREE.OrbitControls(camera, renderer.domElement);
            controls.enableDamping = true; // Smooth motion
            controls.dampingFactor = 0.05;
            controls.screenSpacePanning = false;
            controls.minDistance = 5;
            controls.maxDistance = 50;

            // Initial Object
            createObject('torusKnot', 'standard');

            // Event Listeners
            window.addEventListener('resize', onWindowResize);
            setupUIListeners();

            // Start Loop
            animate();
        }

        // --- 3. Lighting Setup ---
        function setupLighting() {
            // Ambient Light (soft overall light)
            const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
            scene.add(ambientLight);

            // Directional Light (Sun-like)
            const dirLight = new THREE.DirectionalLight(0xffffff, 0.8);
            dirLight.position.set(10, 20, 10);
            dirLight.castShadow = true;
            dirLight.shadow.mapSize.width = 1024;
            dirLight.shadow.mapSize.height = 1024;
            scene.add(dirLight);

            // Point Light (fill light from other side)
            const pointLight = new THREE.PointLight(0xff9900, 0.5);
            pointLight.position.set(-10, -10, -5);
            scene.add(pointLight);
        }

        // --- 4. Object Creation Logic ---
        function createObject(type, materialType) {
            // Remove existing mesh if present
            if (mesh) {
                scene.remove(mesh);
                mesh.geometry.dispose();
                mesh.material.dispose();
            }

            let geometry;

            // Geometry Switcher
            switch (type) {
                case 'cube':
                    geometry = new THREE.BoxGeometry(4, 4, 4);
                    break;
                case 'sphere':
                    geometry = new THREE.SphereGeometry(3, 32, 32);
                    break;
                case 'icosahedron':
                    geometry = new THREE.IcosahedronGeometry(3, 0);
                    break;
                case 'torusKnot':
                default:
                    geometry = new THREE.TorusKnotGeometry(2.5, 0.8, 100, 16);
                    break;
            }

            let material;

            // Material Switcher
            switch(materialType) {
                case 'normal':
                    material = new THREE.MeshNormalMaterial();
                    break;
                case 'wireframe':
                    material = new THREE.MeshBasicMaterial({ color: config.objectColor, wireframe: true });
                    break;
                case 'standard':
                default:
                    material = new THREE.MeshStandardMaterial({
                        color: config.objectColor,
                        roughness: 0.3,
                        metalness: 0.2,
                    });
                    break;
            }

            mesh = new THREE.Mesh(geometry, material);
            mesh.castShadow = true;
            mesh.receiveShadow = true;
            scene.add(mesh);
        }

        // --- 5. UI Interaction Logic ---
        function setupUIListeners() {
            // Dropdown: Change Shape
            document.getElementById('geometry-select').addEventListener('change', (e) => {
                const matType = document.getElementById('material-select').value;
                createObject(e.target.value, matType);
            });

            // Dropdown: Change Material
            document.getElementById('material-select').addEventListener('change', (e) => {
                const geoType = document.getElementById('geometry-select').value;
                createObject(geoType, e.target.value);
            });

            // Button: Toggle Spin
            const spinBtn = document.getElementById('toggle-spin');
            spinBtn.addEventListener('click', () => {
                isSpinning = !isSpinning;
                spinBtn.innerText = isSpinning ? "Pause Rotation" : "Resume Rotation";
                spinBtn.style.backgroundColor = isSpinning ? "#4169E1" : "#666";
            });

            // Button: Reset Camera
            document.getElementById('reset-cam').addEventListener('click', () => {
                controls.reset();
                camera.position.set(0, 0, 15);
            });
        }

        // --- 6. Resize Handling ---
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        // --- 7. Animation Loop ---
        function animate() {
            requestAnimationFrame(animate);

            // Auto-rotation logic
            if (isSpinning && mesh) {
                mesh.rotation.x += 0.005;
                mesh.rotation.y += 0.005;
            }

            // Update controls damping
            controls.update();

            // Render scene
            renderer.render(scene, camera);
        }

        // Initialize App
        init();

    </script>
</body>
</html>
```

### Key Features of this Code:

1.  **Technology Stack**:
    *   **Three.js**: Used for the 3D rendering engine.
    *   **OrbitControls**: A Three.js add-on included via CDN that allows for the intuitive "Click & Drag" to rotate, "Right Click" to pan, and "Scroll" to zoom functionality.

2.  **Color Requirements**:
    *   **Background**: Set to Powder Blue (`#B0E0E6`) via CSS on the body and initialized in the WebGL scene.
    *   **Components**: UI elements (Headers, buttons, borders) and the 3D model itself default to Royal Blue (`#4169E1`).

3.  **Interactive Elements**:
    *   **Dropdowns**: Users can switch between 4 different geometries (Torus Knot, Cube, Sphere, Icosahedron) and 3 different material styles (Standard, Rainbow/Normal, Wireframe).
    *   **Buttons**: A toggle button to stop/start the automatic rotation and a reset button to snap the camera back to the starting position.
    *   **Mouse/Touch**: The entire canvas supports touch gestures and mouse interactions natively.

4.  **Performance & Responsiveness**:
    *   The `resize` event listener ensures the 3D canvas always fills the screen correctly if the browser window changes size.
    *   `requestAnimationFrame` is used for the render loop to ensure smooth 60fps performance without draining the battery unnecessarily.
    *   `OrbitControls` has damping enabled (`enableDamping: true`), which gives the rotation a heavy, physical feel rather than stopping instantly when you let go of the mouse.

5.  **Code Structure**:
    *   **CSS**: Separated into clear sections (Layout, UI, Typography).
    *   **JavaScript**: Modularized into functions (`init`, `createObject`, `animate`, `setupUIListeners`) making it easy to read and modify. Extensive comments explain what each section does.

### How to use:
Simply save the code above as an `.html` file (e.g., `3d-viewer.html`) and open it in any modern web browser (Chrome, Firefox, Safari, Edge). It requires an internet connection to load the Three.js library from the CDN.

