                meta: "Animation • 2008 • Blender Foundation",
                desc: "Big Buck Bunny is a short computer-animated comedy film by the Blender Institute, part of the Blender Foundation. It features a giant rabbit with a heart bigger than his body.",
                type: "Video"
            },
            {
                title: "Mountain Expedition",
                meta: "Photography • 2022 • High Altitude",
                desc: "Capturing the rugged beauty of mountain peaks. This photograph was taken at an altitude of 12,000 feet, showcasing the raw power of nature and the solitude of the climb.",
                type: "Image"
            },
            {
                title: "Elephants Dream",
                meta: "Sci-Fi • 2006 • Open Movie",
                desc: "Elephants Dream is the world's first open movie, made entirely with open source graphics software such as Blender. It tells the story of two characters exploring a strange machine world.",
                type: "Video"
            }
        ];

        // --- DOM Elements ---
        const slides = document.querySelectorAll('.slide');
        const prevBtn = document.getElementById('prevBtn');
        const nextBtn = document.getElementById('nextBtn');
        const playPauseBtn = document.getElementById('playPauseBtn');
        const infoTitle = document.getElementById('mediaTitle');
        const infoMeta = document.getElementById('mediaMeta');
        const infoDesc = document.getElementById('mediaDesc');

        let currentSlideIndex = 0;
        let isPlaying = false;
        let slideInterval; // For auto-sliding images

        // --- Functions ---

        // Update the textual content below the slider
        function updateInfo(index) {
            const data = mediaData[index];
            infoTitle.innerHTML = `${data.title} <span class="dynamic-badge">${data.type}</span>`;
            infoMeta.textContent = data.meta;
            infoDesc.textContent = data.desc;
        }

        // Handle Play/Pause Logic
        function togglePlayPause() {
            const currentSlide = slides[currentSlideIndex];
            const type = currentSlide.getAttribute('data-type');
            const video = currentSlide.querySelector('video');

            if (isPlaying) {
                // Pause action
                isPlaying = false;
                playPauseBtn.innerHTML = '&#9658;'; // Play symbol

                if (type === 'video' && video) {
                    video.pause();
                } else {
                    clearInterval(slideInterval); // Stop auto-slide for images
                }
            } else {
                // Play action
                isPlaying = true;
                playPauseBtn.innerHTML = '&#10074;&#10074;'; // Pause symbol

                if (type === 'video' && video) {
                    video.play();
                } else {
                    // For images, "Play" means start slideshow
                    slideInterval = setInterval(nextSlide, 3000);
                }
            }
        }

        // Show a specific slide
        function showSlide(index) {
            // Stop any currently playing media from the OLD slide
            const oldSlide = slides[currentSlideIndex];
            const oldVideo = oldSlide.querySelector('video');
            if (oldVideo) {
                oldVideo.pause();
                oldVideo.currentTime = 0; // Reset video
            }

            // Remove active class from all
            slides.forEach(slide => slide.classList.remove('active'));

            // Update Index handling wrap-around
            if (index >= slides.length) {
                currentSlideIndex = 0;
            } else if (index < 0) {
                currentSlideIndex = slides.length - 1;
            } else {
                currentSlideIndex = index;
            }

            // Show new slide
            const newSlide = slides[currentSlideIndex];
            newSlide.classList.add('active');
            updateInfo(currentSlideIndex);

            // Reset Play state visually and logic-wise when changing slides manually
            // (Unless it was an auto-slide, handled below)
            isPlaying = false;
            playPauseBtn.innerHTML = '&#9658;'; 
            clearInterval(slideInterval);
        }

        function nextSlide() {
            showSlide(currentSlideIndex + 1);
        }

        function prevSlide() {
            showSlide(currentSlideIndex - 1);
        }

        // --- Event Listeners ---

        nextBtn.addEventListener('click', nextSlide);
        prevBtn.addEventListener('click', prevSlide);
        playPauseBtn.addEventListener('click', togglePlayPause);

        // Add keyboard navigation
        document.addEventListener('keydown', (e) => {
            if (e.key === 'ArrowRight') nextSlide();
            if (e.key === 'ArrowLeft') prevSlide();
            if (e.key === ' ') {
                e.preventDefault(); // Prevent scrolling
                togglePlayPause();
            }
        });

        // Initialize
        updateInfo(0);
    </script>
</body>
