<body>

    <!-- Header Navigation -->
    <header>
        <div class="logo">ScrollSage</div>
        <div class="controls-top">
            <select id="chapterSelect" title="Select Chapter">
                <!-- Chapters injected via JS -->
            </select>
            <button class="btn" id="toggleAutoScrollBtn">Start Auto-Scroll</button>
        </div>
    </header>

    <!-- Main Content Area -->
    <main>
        <div class="scroll-indicator" id="scrollIndicator"></div>

        <div class="info-bar">
            <span id="chapterTitle">Chapter 1</span> - Page <span id="pageNumber">1</span>
        </div>

        <div class="comic-viewport" id="viewport">
            <img src="" alt="Comic Page" class="comic-image" id="comicImage">
            <!-- Placeholder for loading state -->
            <div id="loadingText" style="display:none; text-align:center;">Loading...</div>
        </div>

        <div class="controls-bottom">
            <button class="btn" id="prevBtn">&laquo; Prev Page</button>
            <button class="btn" id="nextBtn">Next Page &raquo;</button>
        </div>
    </main>

    <!-- Toast Notification -->
    <div class="toast" id="toast">Message here</div>

    <script>
        // --- DATA SIMULATION ---
        // In a real app, this would come from an API or database.
        // Using placeholder images for demonstration.
        const comicData = [
            {
                id: 1,
                title: "Chapter 1: The Beginning",
                pages: [
                    "https://placehold.co/600x800/FFDEAD/3e2723?text=Chapter+1+Page+1",
                    "https://placehold.co/600x800/FFDEAD/3e2723?text=Chapter+1+Page+2",
                    "https://placehold.co/600x800/FFDEAD/3e2723?text=Chapter+1+Page+3"
                ]
            },
            {
                id: 2,
                title: "Chapter 2: The Journey",
                pages: [
                    "https://placehold.co/600x800/D2B48C/3e2723?text=Chapter+2+Page+1",
                    "https://placehold.co/600x800/D2B48C/3e2723?text=Chapter+2+Page+2",
                    "https://placehold.co/600x800/D2B48C/3e2723?text=Chapter+2+Page+3",
                    "https://placehold.co/600x800/D2B48C/3e2723?text=Chapter+2+Page+4"
                ]
            },
            {
                id: 3,
                title: "Chapter 3: The Climax",
                pages: [
                    "https://placehold.co/600x800/C19A6B/3e2723?text=Chapter+3+Page+1",
                    "https://placehold.co/600x800/C19A6B/3e2723?text=Chapter+3+Page+2"
                ]
            }
        ];

        // --- STATE VARIABLES ---
        let currentChapterIndex = 0;
        let currentPageIndex = 0;
        let isAutoScrolling = false;
        let autoScrollInterval;
        let scrollSpeed = 50; // Milliseconds per pixel (lower is faster)

        // --- DOM ELEMENTS ---
        const chapterSelect = document.getElementById('chapterSelect');
        const comicImage = document.getElementById('comicImage');
        const chapterTitleEl = document.getElementById('chapterTitle');
        const pageNumberEl = document.getElementById('pageNumber');
        const prevBtn = document.getElementById('prevBtn');
        const nextBtn = document.getElementById('nextBtn');
        const toggleAutoScrollBtn = document.getElementById('toggleAutoScrollBtn');
        const viewport = document.getElementById('viewport');
        const loadingText = document.getElementById('loadingText');
        const toast = document.getElementById('toast');
        const scrollIndicator = document.getElementById('scrollIndicator');

        // --- INITIALIZATION ---
        function init() {
            populateChapters();
            loadPage(0, 0); // Load Chapter 1, Page 1
            setupEventListeners();
        }

        // --- FUNCTIONS ---

        function populateChapters() {
            comicData.forEach((chapter, index) => {
                const option = document.createElement('option');
                option.value = index;
                option.textContent = chapter.title;
                chapterSelect.appendChild(option);
            });
        }

        function loadPage(chapterIdx, pageIdx) {
            // Validate bounds
            if (chapterIdx < 0 || chapterIdx >= comicData.length) return;
            const chapter = comicData[chapterIdx];
            if (pageIdx < 0 || pageIdx >= chapter.pages.length) return;

            // Update State
            currentChapterIndex = chapterIdx;
            currentPageIndex = pageIdx;

            // UI Feedback: Loading
            comicImage.classList.remove('loaded');
            comicImage.style.display = 'none';
            loadingText.style.display = 'block';

            // Set Image Source
            const newImg = new Image();
            newImg.src = chapter.pages[pageIdx];

            newImg.onload = () => {
                comicImage.src = newImg.src;
                comicImage.style.display = 'block';
                loadingText.style.display = 'none';
                // Trigger reflow for transition
                void comicImage.offsetWidth; 
                comicImage.classList.add('loaded');

                // Reset scroll position to top
                viewport.scrollTop = 0;
                // If auto scrolling, ensure we continue from top
                if(isAutoScrolling) {
                    resetScrollIndicator();
                }
            };

            // Update Info Text
            chapterTitleEl.textContent = chapter.title;
            pageNumberEl.textContent = pageIdx + 1;

            // Sync Dropdown
            chapterSelect.value = chapterIdx;

            // Button States
            updateButtonStates();
        }

        function updateButtonStates() {
            const chapter = comicData[currentChapterIndex];

            // Prev Logic
            prevBtn.disabled = (currentChapterIndex === 0 && currentPageIndex === 0);
            prevBtn.style.opacity = prevBtn.disabled ? '0.5' : '1';

            // Next Logic
            const isLastChapter = currentChapterIndex === comicData.length - 1;
            const isLastPage = currentPageIndex === chapter.pages.length - 1;
            nextBtn.disabled = (isLastChapter && isLastPage);
            nextBtn.style.opacity = nextBtn.disabled ? '0.5' : '1';
        }

        function navigateNext() {
            const chapter = comicData[currentChapterIndex];

            if (currentPageIndex < chapter.pages.length - 1) {
                // Next page in same chapter
                loadPage(currentChapterIndex, currentPageIndex + 1);
            } else if (currentChapterIndex < comicData.length - 1) {
                // Next chapter, first page
                showToast(`Starting ${comicData[currentChapterIndex + 1].title}`);
                loadPage(currentChapterIndex + 1, 0);
            } else {
                showToast("You've reached the end!");
                stopAutoScroll();
            }
        }

        function navigatePrev() {
            if (currentPageIndex > 0) {
                // Prev page in same chapter
                loadPage(currentChapterIndex, currentPageIndex - 1);
            } else if (currentChapterIndex > 0) {
                // Prev chapter, last page
                const prevChapIdx = currentChapterIndex - 1;
                const lastPageOfPrev = comicData[prevChapIdx].pages.length - 1;
                showToast(`Back to ${comicData[prevChapIdx].title}`);
                loadPage(prevChapIdx, lastPageOfPrev);
            }
        }

        // --- AUTO SCROLL LOGIC ---

        function toggleAutoScroll() {
            if (isAutoScrolling) {
                stopAutoScroll();
            } else {
                startAutoScroll();
            }
        }

        function startAutoScroll() {
            isAutoScrolling = true;
            toggleAutoScrollBtn.textContent = "Stop Auto-Scroll";
            toggleAutoScrollBtn.classList.add('active-mode');
            showToast("Auto-Scroll Enabled");

            // Determine scroll increment
            const scrollStep = 1; // pixel
            const intervalTime = 20; // ms

            autoScrollInterval = setInterval(() => {
                // Current scroll position + height of viewport
                const currentBottom = viewport.scrollTop + viewport.clientHeight;
                const totalHeight = viewport.scrollHeight;

                if (currentBottom < totalHeight) {
                    viewport.scrollTop += scrollStep;
                    updateScrollIndicator(viewport.scrollTop, totalHeight - viewport.clientHeight);
                } else {
                    // Reached bottom, go to next page
                    // Small delay before switching
                    clearInterval(autoScrollInterval);
                    setTimeout(() => {
                        if(isAutoScrolling) {
                            navigateNext();
                            // Restart interval if we successfully moved (navigateNext handles stop if end)
                            // If navigateNext stopped it (end of comic), isAutoScrolling will be false
                            if(isAutoScrolling) startAutoScroll(); 
                        }
                    }, 1000);
                }
            }, intervalTime);
        }

        function stopAutoScroll() {
            isAutoScrolling = false;
            clearInterval(autoScrollInterval);
            toggleAutoScrollBtn.textContent = "Start Auto-Scroll";
            toggleAutoScrollBtn.classList.remove('active-mode');
            resetScrollIndicator();
            showToast("Auto-Scroll Paused");
        }

        function updateScrollIndicator(current, max) {
            const percentage = (current / max) * 100;
            scrollIndicator.style.width = `${percentage}%`;
        }

        function resetScrollIndicator() {
            scrollIndicator.style.width = '0%';
        }

        // --- UTILS ---
        function showToast(message) {
            toast.textContent = message;
            toast.classList.add('show');
            setTimeout(() => {
                toast.classList.remove('show');
            }, 2000);
        }

        // --- EVENT LISTENERS ---
        function setupEventListeners() {
            // Chapter Dropdown
            chapterSelect.addEventListener('change', (e) => {
                loadPage(parseInt(e.target.value), 0);
            });

            // Buttons
            nextBtn.addEventListener('click', () => {
                stopAutoScroll(); // Manual nav stops auto
                navigateNext();
            });

            prevBtn.addEventListener('click', () => {
                stopAutoScroll(); // Manual nav stops auto
                navigatePrev();
            });

            // Auto Scroll
            toggleAutoScrollBtn.addEventListener('click', toggleAutoScroll);

            // Keyboard Navigation
            document.addEventListener('keydown', (e) => {
                if (e.key === 'ArrowRight') {
                    stopAutoScroll();
                    navigateNext();
                } else if (e.key === 'ArrowLeft') {
                    stopAutoScroll();
                    navigatePrev();
                } else if (e.key === ' ') { // Spacebar
                    e.preventDefault(); // prevent page down
                    toggleAutoScroll();
                }
            });
        }

        // Start the app
        init();

    </script>
