                { name: "Zhao Yun", title: "Dragon of Changshan", desc: "Expert in spear techniques. High mobility and rapid combos.", stat: "Speed", val: "90%" },
                { name: "Diao Chan", title: "Lotus Dancer", desc: "Uses twin daggers. Specialized in evasion and critical hits.", stat: "Agility", val: "88%" },
                { name: "Lu Bu", title: "Peerless Warrior", desc: "The strongest warrior. Massive AOE damage but requires rage management.", stat: "Power", val: "100%" }
            ],
            weapons: [
                { name: "Crescent Blade", type: "Polearm", desc: "Heavy cleaving attacks. Breaks enemy guards easily.", stat: "Weight", val: "80%" },
                { name: "Twin Maces", type: "Blunt", desc: "Stuns enemies on impact. Short range but devastating.", stat: "Impact", val: "92%" },
                { name: "Feather Fan", type: "Magic", desc: "Casts elemental spells (Wind/Fire). Long range zoning.", stat: "Range", val: "95%" },
                { name: "Serpent Spear", type: "Polearm", desc: "Thrusting attacks that cause bleeding damage over time.", stat: "Sharpness", val: "85%" }
            ],
            spirits: [
                { name: "Vermilion Bird", type: "Fire", desc: "Summons a rain of fire over the battlefield.", stat: "AOE", val: "90%" },
                { name: "White Tiger", type: "Metal", desc: "Grants super armor and increased attack for 20s.", stat: "Buff", val: "75%" },
                { name: "Azure Dragon", type: "Lightning", desc: "Strikes a single target with massive lightning damage.", stat: "Burst", val: "95%" },
                { name: "Black Tortoise", type: "Water", desc: "Creates a shield that absorbs damage and heals nearby allies.", stat: "Defense", val: "100%" }
            ]
        };

        // --- RENDER FUNCTION ---
        const grid = document.getElementById('content-grid');
        const tabBtns = document.querySelectorAll('.tab-btn');

        function renderCards(category) {
            grid.innerHTML = ''; // Clear current
            const items = gameData[category];

            items.forEach((item, index) => {
                // Determine icon based on category for placeholder
                let icon = category === 'characters' ? '👤' : category === 'weapons' ? '⚔️' : '🐉';

                const card = document.createElement('div');
                card.className = 'card';
                card.innerHTML = `
                    <div class="card-img-placeholder">${icon}</div>
                    <div class="card-content">
                        <h3>${item.name}</h3>
                        <p style="font-size: 0.9rem; font-weight: bold; color: #2e8b57;">${item.type || item.title}</p>
                        <p style="margin-top: 10px; font-size: 0.9rem;">${item.desc}</p>
                        <div style="margin-top: 15px;">
                            <span style="font-size: 0.8rem; font-weight: bold;">${item.stat}</span>
                            <div class="stat-bar">
                                <div class="stat-fill" style="width: ${item.val}"></div>
                            </div>
                        </div>
                    </div>
                `;
                // Add staggered animation
                setTimeout(() => {
                    grid.appendChild(card);
                }, index * 100);
            });
        }

        function filterContent(category) {
            // Update buttons
            tabBtns.forEach(btn => btn.classList.remove('active'));
            event.target.classList.add('active');

            // Render
            renderCards(category);
        }

        // --- INITIAL LOAD ---
        window.addEventListener('DOMContentLoaded', () => {
            renderCards('characters');
        });

        // --- MODAL & AUTH LOGIC ---
        const modal = document.getElementById('authModal');
        const modalTitle = document.getElementById('modalTitle');
        const modalSubmitBtn = document.getElementById('modalSubmitBtn');
        const toggleAuth = document.getElementById('toggleAuth');
        let isLoginMode = true;

        function openModal(mode) {
            modal.style.display = 'flex';
            isLoginMode = mode === 'Login';
            updateModalUI();
        }

        function closeModal() {
            modal.style.display = 'none';
        }

        function toggleAuthMode() {
            isLoginMode = !isLoginMode;
            updateModalUI();
        }

        function updateModalUI() {
            if (isLoginMode) {
                modalTitle.textContent = "Login";
                modalSubmitBtn.textContent = "Login";
                toggleAuth.textContent = "Don't have an account? Register";
            } else {
                modalTitle.textContent = "Register";
                modalSubmitBtn.textContent = "Join the Fight";
                toggleAuth.textContent = "Already have an account? Login";
            }
        }

        function handleAuth(e) {
            e.preventDefault();
            const username = document.getElementById('username').value;
            alert(`${isLoginMode ? 'Welcome back' : 'Welcome to the army'}, General ${username}!`);
            closeModal();
        }

        // Close modal if clicking outside
        window.onclick = function(event) {
            if (event.target == modal) {
                closeModal();
            }
        }
    </script>
