                    <a href="#" onclick="changeSpeed(0.5)">0.5x Slower</a>
                    <a href="#" onclick="changeSpeed(1.0)">1.0x Normal</a>
                    <a href="#" onclick="changeSpeed(1.5)">1.5x Faster</a>
                    <a href="#" onclick="changeSpeed(2.0)">2.0x Fast</a>
                </div>
            </div>
        </div>
    </div>

    <script>
        /**
         * Universal Media Player Logic
         * Handles file reading, DOM manipulation for media elements, 
         * and control event listeners.
         */

        // Element Selection
        const fileInput = document.getElementById('file-input');
        const mediaWrapper = document.getElementById('media-wrapper');
        const fileNameDisplay = document.getElementById('file-name-display');

        // Control Elements
        const btnPlay = document.getElementById('btn-play');
        const btnPause = document.getElementById('btn-pause');
        const btnStop = document.getElementById('btn-stop');
        const seekBar = document.getElementById('seek-bar');
        const volumeBar = document.getElementById('volume-bar');
        const currentTimeEl = document.getElementById('current-time');
        const durationEl = document.getElementById('duration');

        let currentMedia = null; // Stores the current audio or video object
        let isDragging = false; // For seek bar interaction

        // 1. File Upload Handling
        fileInput.addEventListener('change', function(e) {
            const file = e.target.files[0];
            if (file) {
                loadMedia(file);
            }
        });

        function loadMedia(file) {
            // Reset previous media
            if (currentMedia) {
                currentMedia.pause();
                currentMedia.src = "";
                mediaWrapper.innerHTML = '';
            }

            const fileURL = URL.createObjectURL(file);
            const fileType = file.type;
            fileNameDisplay.textContent = `Playing: ${file.name}`;

            // Determine if Video or Audio
            if (fileType.startsWith('video/')) {
                currentMedia = document.createElement('video');
                currentMedia.style.width = "100%";
                currentMedia.style.height = "100%";
            } else if (fileType.startsWith('audio/')) {
                currentMedia = document.createElement('audio');
                // visual placeholder for audio
                const icon = document.createElement('div');
                icon.className = 'audio-icon';
                icon.innerHTML = '🎵'; 
                mediaWrapper.appendChild(icon);
            } else {
                alert('Unsupported file format.');
                return;
            }

            // Common attributes
            currentMedia.src = fileURL;
            currentMedia.volume = volumeBar.value;

            // If it's a video element, append it directly
            if (fileType.startsWith('video/')) {
                mediaWrapper.appendChild(currentMedia);
            } else {
                // Audio is appended but invisible inside wrapper (visualizer placeholder used above)
                mediaWrapper.appendChild(currentMedia);
            }

            // Enable Controls
            btnPlay.disabled = false;
            btnPause.disabled = false;
            btnStop.disabled = false;
            seekBar.disabled = false;

            // Setup Media Event Listeners
            setupMediaEvents();
        }

        // 2. Media Event Listeners (Update UI based on playback)
        function setupMediaEvents() {
            // When metadata is loaded (duration is known)
            currentMedia.addEventListener('loadedmetadata', () => {
                seekBar.max = currentMedia.duration;
                durationEl.textContent = formatTime(currentMedia.duration);
            });

            // Update progress bar as time updates
            currentMedia.addEventListener('timeupdate', () => {
                if (!isDragging) {
                    seekBar.value = currentMedia.currentTime;
                    currentTimeEl.textContent = formatTime(currentMedia.currentTime);
                }
            });

            // Reset when media ends
            currentMedia.addEventListener('ended', () => {
                btnPlay.style.backgroundColor = 'transparent';
                btnPlay.style.color = 'var(--white)';
                seekBar.value = 0;
            });
        }

        // 3. Control Functions
        btnPlay.addEventListener('click', () => {
            if (currentMedia) {
                currentMedia.play();
                highlightActiveButton(btnPlay);
            }
        });

        btnPause.addEventListener('click', () => {
            if (currentMedia) {
                currentMedia.pause();
                highlightActiveButton(btnPause);
            }
        });

        btnStop.addEventListener('click', () => {
            if (currentMedia) {
                currentMedia.pause();
                currentMedia.currentTime = 0;
                seekBar.value = 0;
                highlightActiveButton(btnStop);
                // Reset active highlight after a moment for stop
                setTimeout(() => removeHighlights(), 200);
            }
        });

        // Seek Bar Interactions
        seekBar.addEventListener('input', () => {
            isDragging = true;
            currentTimeEl.textContent = formatTime(seekBar.value);
        });

        seekBar.addEventListener('change', () => {
            if (currentMedia) {
                currentMedia.currentTime = seekBar.value;
                isDragging = false;
            }
        });

        // Volume Control
        volumeBar.addEventListener('input', (e) => {
            if (currentMedia) {
                currentMedia.volume = e.target.value;
            }
        });

        // 4. Helper Functions

        // Time Formatting (MM:SS)
        function formatTime(seconds) {
            const minutes = Math.floor(seconds / 60);
            let secs = Math.floor(seconds % 60);
            if (secs < 10) secs = "0" + secs;
            return `${minutes}:${secs}`;
        }

        // UI Highlights
        function highlightActiveButton(btn) {
            removeHighlights();
            btn.style.backgroundColor = 'var(--white)';
            btn.style.color = 'var(--primary-color)';
        }

        function removeHighlights() {
            [btnPlay, btnPause, btnStop].forEach(btn => {
                btn.style.backgroundColor = 'transparent';
                btn.style.color = 'var(--white)';
            });
        }

        // Dropdown Logic
        function toggleDropdown() {
            document.getElementById("speed-dropdown").classList.toggle("show");
        }

        function changeSpeed(speed) {
            if (currentMedia) {
                currentMedia.playbackRate = speed;
                document.getElementById('settings-btn').innerText = `Speed ${speed}x ▼`;
            }
            // Close dropdown
            document.getElementById("speed-dropdown").classList.remove("show");
        }

        // Close the dropdown if the user clicks outside of it
        window.onclick = function(event) {
            if (!event.target.matches('#settings-btn')) {
                var dropdowns = document.getElementsByClassName("dropdown-content");
                for (var i = 0; i < dropdowns.length; i++) {
                    var openDropdown = dropdowns[i];
                    if (openDropdown.classList.contains('show')) {
                        openDropdown.classList.remove('show');
                    }
                }
            }
        }
    </script>
</body>
</html>
