        document.addEventListener('DOMContentLoaded', () => {
            const dropZone = document.getElementById('dropZone');
            const fileInput = document.getElementById('fileInput');
            const controls = document.getElementById('controls');
            const fileNameDisplay = document.getElementById('fileName');
            const convertBtn = document.getElementById('convertBtn');
            const progressContainer = document.getElementById('progressContainer');
            const progressBar = document.getElementById('progressBar');
            const statusText = document.getElementById('statusText');
            const downloadArea = document.getElementById('downloadArea');
            const downloadBtn = document.getElementById('downloadBtn');
            const formatSelect = document.getElementById('formatSelect');

            let currentFile = null;

            // --- Event Listeners for Upload ---

            // Click to upload
            dropZone.addEventListener('click', () => fileInput.click());

            // Drag and Drop Visual Feedback
            dropZone.addEventListener('dragover', (e) => {
                e.preventDefault();
                dropZone.classList.add('dragover');
            });

            dropZone.addEventListener('dragleave', () => {
                dropZone.classList.remove('dragover');
            });

            // Handle Dropped File
            dropZone.addEventListener('drop', (e) => {
                e.preventDefault();
                dropZone.classList.remove('dragover');
                if (e.dataTransfer.files.length) {
                    handleFileSelection(e.dataTransfer.files[0]);
                }
            });

            // Handle Selected File
            fileInput.addEventListener('change', () => {
                if (fileInput.files.length) {
                    handleFileSelection(fileInput.files[0]);
                }
            });

            // --- Logic Functions ---

            function handleFileSelection(file) {
                currentFile = file;
                fileNameDisplay.textContent = file.name;

                // Intelligent format suggestion
                if(file.type.includes('audio')) {
                    formatSelect.value = 'mp3';
                } else {
                    formatSelect.value = 'mp4';
                }

                // UI Transitions
                dropZone.style.display = 'none';
                controls.style.display = 'block';
            }

            // --- Conversion Simulation ---
            convertBtn.addEventListener('click', () => {
                // Disable button
                convertBtn.disabled = true;
                convertBtn.textContent = 'Processing...';

                // Show Progress
                progressContainer.style.display = 'block';

                let progress = 0;
                const totalDuration = 3000; // Simulated 3 seconds
                const intervalTime = 50;
                const increment = 100 / (totalDuration / intervalTime);

                const interval = setInterval(() => {
                    progress += increment;

                    // Update width
                    progressBar.style.width = Math.min(progress, 100) + '%';

                    // Update Text based on percentage
                    if (progress < 30) {
                        statusText.textContent = 'Uploading...';
                    } else if (progress < 70) {
                        statusText.textContent = `Converting to ${formatSelect.value.toUpperCase()}...`;
                    } else {
                        statusText.textContent = 'Finalizing...';
                    }

                    if (progress >= 100) {
                        clearInterval(interval);
                        finishConversion();
                    }
                }, intervalTime);
            });

            function finishConversion() {
                setTimeout(() => {
                    controls.style.display = 'none';
                    progressContainer.style.display = 'none';
                    downloadArea.style.display = 'block';

                    // Update download button text with new extension
                    const targetFormat = formatSelect.value;
                    downloadBtn.textContent = `Download .${targetFormat}`;
                }, 500);
            }

            // --- Download Simulation ---
            downloadBtn.addEventListener('click', () => {
                if (!currentFile) return;

                // Create a fake download link
                const originalName = currentFile.name.substring(0, currentFile.name.lastIndexOf('.')) || currentFile.name;
                const newFileName = `${originalName}_converted.${formatSelect.value}`;

                // For demonstration, we create a dummy text file blob, 
                // but in a real app, this would be the URL from the server.
                const blob = new Blob(["This is a placeholder for the converted multimedia file content."], { type: 'text/plain' });
                const url = window.URL.createObjectURL(blob);

                const a = document.createElement('a');
                a.style.display = 'none';
                a.href = url;
                a.download = newFileName;

                document.body.appendChild(a);
                a.click();

                window.URL.revokeObjectURL(url);
                document.body.removeChild(a);

                alert(`Simulated download of: ${newFileName}`);
            });
        });
    </script>
