                id: 2,
                category: 'company',
                date: 'September 15, 2023',
                title: 'New Vision VR Wins "Innovator of the Year"',
                snippet: 'We are humbled to receive this prestigious award at the Global Tech Summit.'
            },
            {
                id: 3,
                category: 'product',
                date: 'August 10, 2023',
                title: 'Introducing Nexus Cloud Collaboration',
                snippet: 'Teams can now meet in virtual spaces from anywhere in the world with zero lag.'
            }
        ];

        const newsContainer = document.getElementById('news-container');

        function renderNews(filter) {
            newsContainer.innerHTML = '';

            const filteredData = filter === 'all' 
                ? newsData 
                : newsData.filter(item => item.category === filter);

            filteredData.forEach(item => {
                const newsHTML = `
                    <div class="news-item">
                        <div>
                            <div class="news-date">${item.date} | <span style="text-transform: capitalize; color: saddlebrown;">${item.category}</span></div>
                            <h4>${item.title}</h4>
                            <p>${item.snippet}</p>
                        </div>
                        <a href="#" class="read-more">Read &rarr;</a>
                    </div>
                `;
                newsContainer.innerHTML += newsHTML;
            });
        }

        function filterNews(category) {
            // Update active button state
            const buttons = document.querySelectorAll('.filter-btn');
            buttons.forEach(btn => btn.classList.remove('active'));
            event.target.classList.add('active');

            // Render content
            renderNews(category);
        }

        // Initial Render
        renderNews('all');

    </script>
