    <script>
        // Toggle Mobile Menu
        function toggleMenu() {
            const navLinks = document.getElementById('nav-links');
            navLinks.classList.toggle('active');
        }

        // Animated Counters
        const counters = document.querySelectorAll('.stat-number');
        const speed = 200;

        const animateCounters = () => {
            counters.forEach(counter => {
                const updateCount = () => {
                    const target = +counter.getAttribute('data-target');
                    const count = +counter.innerText;
                    const inc = target / speed;

                    if (count < target) {
                        counter.innerText = Math.ceil(count + inc);
                        setTimeout(updateCount, 20);
                    } else {
                        counter.innerText = target + (target === 98 ? '%' : '+');
                    }
                };
                updateCount();
            });
        };

        // Trigger animation when About section is in view
        let animated = false;
        window.addEventListener('scroll', () => {
            const aboutSection = document.getElementById('about');
            const position = aboutSection.getBoundingClientRect();
            if (position.top < window.innerHeight && position.bottom >= 0 && !animated) {
                animateCounters();
                animated = true;
            }
        });

        // Tab Functionality
        function openTab(evt, tabName) {
            var i, tabcontent, tablinks;
            tabcontent = document.getElementsByClassName("tab-content");
            for (i = 0; i < tabcontent.length; i++) {
                tabcontent[i].style.display = "none";
                tabcontent[i].classList.remove("active");
            }
            tablinks = document.getElementsByClassName("tab-btn");
            for (i = 0; i < tablinks.length; i++) {
                tablinks[i].className = tablinks[i].className.replace(" active", "");
            }
            document.getElementById(tabName).style.display = "block";
            document.getElementById(tabName).classList.add("active");
            evt.currentTarget.className += " active";
        }

        // Calculator Logic
        function calculateSavings() {
            const volume = parseFloat(document.getElementById('flow-rate').value);
            const efficiency = parseFloat(document.getElementById('tech-type').value);
            const cost = parseFloat(document.getElementById('water-cost').value);
            const resultBox = document.getElementById('calc-result');

            if (isNaN(volume) || isNaN(cost)) {
                resultBox.style.display = 'block';
                resultBox.style.color = 'red';
                resultBox.innerHTML = "Please enter valid numbers.";
                return;
            }

            const recoveredWater = volume * efficiency;
            const dailySavings = recoveredWater * cost;
            const yearlySavings = dailySavings * 365;

            resultBox.style.display = 'block';
            resultBox.style.color = 'var(--primary-dark)';
            resultBox.innerHTML = `
                Water Recovered: ${recoveredWater.toFixed(1)} m³/day<br>
                Estimated Daily Savings: $${dailySavings.toFixed(2)}<br>
                <strong>Estimated Yearly Savings: $${yearlySavings.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</strong>
            `;
        }

        // Simulation Functions
        function openModal(productName) {
            alert(`You requested detailed specifications for: ${productName}. \n\nA sales representative will contact you shortly.`);
        }

        function downloadFile(filename) {
            alert(`Starting download for: ${filename}...\n\n(This is a simulation. In a real site, the file would download.)`);
        }

        function submitForm(e) {
            e.preventDefault();
            const btn = e.target.querySelector('button');
            const originalText = btn.innerText;

            btn.innerText = "Sending...";
            btn.disabled = true;

            setTimeout(() => {
                alert("Thank you for your inquiry! We have received your message.");
                e.target.reset();
                btn.innerText = originalText;
                btn.disabled = false;
            }, 1500);
        }
    </script>
</body>
