    <!-- Main Container -->
    <div class="container">
        <header>
            <h1>Join the <span class="dynamic-text" id="dynamicRole">Community</span></h1>
            <p class="subtitle">Complete the form below to register your account.</p>
        </header>

        <!-- Form Element -->
        <form id="registrationForm" novalidate>

            <!-- Username Field -->
            <div class="form-group">
                <label for="username">Username</label>
                <input type="text" id="username" placeholder="Enter your username" autocomplete="off">
                <small class="error-message">Username must be at least 3 characters.</small>
            </div>

            <!-- Email Field -->
            <div class="form-group">
                <label for="email">Email Address</label>
                <input type="email" id="email" placeholder="name@example.com" autocomplete="off">
                <small class="error-message">Please enter a valid email address.</small>
            </div>

            <!-- Dropdown Menu -->
            <div class="form-group">
                <label for="role">Select Your Role</label>
                <select id="role">
                    <option value="" disabled selected>-- Choose an option --</option>
                    <option value="Developer">Developer</option>
                    <option value="Designer">Designer</option>
                    <option value="Manager">Manager</option>
                    <option value="Student">Student</option>
                </select>
                <small class="error-message">Please select a role.</small>
            </div>

            <!-- Password Field -->
            <div class="form-group">
                <label for="password">Password</label>
                <input type="password" id="password" placeholder="Create a secure password">
                <small class="error-message">Password needs 8+ chars, 1 number, 1 special char.</small>
            </div>

            <!-- Confirm Password Field -->
            <div class="form-group">
                <label for="confirmPassword">Confirm Password</label>
                <input type="password" id="confirmPassword" placeholder="Repeat password">
                <small class="error-message">Passwords do not match.</small>
            </div>

            <!-- Submit Button -->
            <button type="submit" class="btn" id="submitBtn">
                <span>Register Now</span>
                <div class="spinner" id="loadingSpinner"></div>
            </button>
        </form>
    </div>

    <!-- Toast Notification (Hidden by default) -->
    <div class="toast" id="toastNotification">
        <div class="toast-content">
            <h3 id="toastTitle">Notification</h3>
            <p id="toastMessage">Message content goes here.</p>
        </div>
    </div>

    <script>
        /**
         * JAVASCRIPT LOGIC
         * Handles form validation, DOM manipulation, and user feedback.
         */

        document.addEventListener('DOMContentLoaded', () => {
            const form = document.getElementById('registrationForm');
            const username = document.getElementById('username');
            const email = document.getElementById('email');
            const role = document.getElementById('role');
            const password = document.getElementById('password');
            const confirmPassword = document.getElementById('confirmPassword');
            const dynamicRoleText = document.getElementById('dynamicRole');
            const submitBtn = document.getElementById('submitBtn');
            const spinner = document.getElementById('loadingSpinner');

            // --- Dynamic Text Update ---
            // Updates the header text based on the dropdown selection
            role.addEventListener('change', (e) => {
                const selectedRole = e.target.value;
                dynamicRoleText.innerHTML = `<span>${selectedRole}s</span>`;
            });

            // --- Form Submission Event ---
            form.addEventListener('submit', (e) => {
                e.preventDefault(); // Prevent actual server submission

                // Run validation
                if (validateInputs()) {
                    simulateServerProcessing();
                }
            });

            // --- Real-time Validation Listeners ---
            // Removes error styles as soon as user starts typing/correcting
            const inputs = [username, email, role, password, confirmPassword];
            inputs.forEach(input => {
                input.addEventListener('input', () => {
                    setSuccess(input); // Clear error state on input
                });
            });

            /**
             * Core Validation Function
             * Checks all fields and returns boolean status
             */
            function validateInputs() {
                const usernameValue = username.value.trim();
                const emailValue = email.value.trim();
                const roleValue = role.value;
                const passwordValue = password.value.trim();
                const confirmPasswordValue = confirmPassword.value.trim();
                let isValid = true;

                // Username Check
                if (usernameValue === '') {
                    setError(username, 'Username is required');
                    isValid = false;
                } else if (usernameValue.length < 3) {
                    setError(username, 'Username must be at least 3 characters');
                    isValid = false;
                } else {
                    setSuccess(username);
                }

                // Email Check
                if (emailValue === '') {
                    setError(email, 'Email is required');
                    isValid = false;
                } else if (!isValidEmail(emailValue)) {
                    setError(email, 'Provide a valid email address');
                    isValid = false;
                } else {
                    setSuccess(email);
                }

                // Role Check
                if (roleValue === '') {
                    setError(role, 'Please select a role from the list');
                    isValid = false;
                } else {
                    setSuccess(role);
                }

                // Password Check (Regex: 8 chars, 1 letter, 1 number, 1 special)
                const passwordRegex = /^(?=.*[A-Za-z])(?=.*\d)(?=.*[@$!%*#?&])[A-Za-z\d@$!%*#?&]{8,}$/;
                if (passwordValue === '') {
                    setError(password, 'Password is required');
                    isValid = false;
                } else if (!passwordRegex.test(passwordValue)) {
                    setError(password, 'Password must be 8+ chars, incl number & special char');
                    isValid = false;
                } else {
                    setSuccess(password);
                }

                // Confirm Password Check
                if (confirmPasswordValue === '') {
                    setError(confirmPassword, 'Please confirm your password');
                    isValid = false;
                } else if (confirmPasswordValue !== passwordValue) {
                    setError(confirmPassword, "Passwords doesn't match");
                    isValid = false;
                } else {
                    setSuccess(confirmPassword);
                }

                if (!isValid) {
                    showToast('Validation Error', 'Please correct the highlighted fields.', 'error');
                }

                return isValid;
            }

            /**
             * Helper: Set Error State
             */
            function setError(element, message) {
                const formGroup = element.parentElement;
                const errorDisplay = formGroup.querySelector('.error-message');

                errorDisplay.innerText = message;
                formGroup.classList.add('error');
                formGroup.classList.remove('success');
            }

            /**
             * Helper: Set Success State
             */
            function setSuccess(element) {
                const formGroup = element.parentElement;
                formGroup.classList.add('success');
                formGroup.classList.remove('error');
            }

            /**
             * Helper: Email Regex Validator
             */
            function isValidEmail(email) {
                const re = /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
                return re.test(String(email).toLowerCase());
            }

            /**
             * Simulates an Async Server Request
             */
            function simulateServerProcessing() {
                // UI Loading State
                const btnText = submitBtn.querySelector('span');
                btnText.innerText = "Processing...";
                spinner.style.display = "inline-block";
                submitBtn.disabled = true;
                submitBtn.style.opacity = "0.7";

                // Simulate 2 second delay
                setTimeout(() => {
                    // Reset UI
                    btnText.innerText = "Register Now";
                    spinner.style.display = "none";
                    submitBtn.disabled = false;
                    submitBtn.style.opacity = "1";

                    // Show Success
                    showToast('Success!', 'Your account has been successfully created.', 'success');

                    // Reset Form
                    form.reset();
                    // Clear visual success indicators
                    document.querySelectorAll('.form-group').forEach(group => group.classList.remove('success'));
                    dynamicRoleText.innerHTML = "<span>Community</span>";

                }, 2000);
            }

            /**
             * Toast Notification System
             */
            function showToast(title, message, type) {
                const toast = document.getElementById('toastNotification');
                const toastTitle = document.getElementById('toastTitle');
                const toastMsg = document.getElementById('toastMessage');

                // Set content
                toastTitle.innerText = title;
                toastMsg.innerText = message;

                // Reset classes
                toast.className = 'toast'; 
                toast.classList.add(type); // 'success' or 'error'

                // Show toast
                setTimeout(() => {
                    toast.classList.add('show');
                }, 100);

                // Hide after 3.5 seconds
                setTimeout(() => {
                    toast.classList.remove('show');
                }, 3500);
            }
        });
    </script>
</body>
</html>
