                img: "https://images.unsplash.com/photo-1626785774573-4b799314346d?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
            },
            {
                id: 3,
                title: "SEO Mastery Tool",
                category: "marketing",
                desc: "Boost your ranking with AI-driven insights.",
                img: "https://images.unsplash.com/photo-1432888498266-38ffec3eaf0a?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
            },
            {
                id: 4,
                title: "SecurePay Gateway",
                category: "tech",
                desc: "The safest way to handle transactions online.",
                img: "https://images.unsplash.com/photo-1563013544-824ae1b704d3?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
            },
            {
                id: 5,
                title: "Social Media Manager",
                category: "marketing",
                desc: "Automate your posts across all platforms.",
                img: "https://images.unsplash.com/photo-1611162617474-5b21e879e113?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
            },
            {
                id: 6,
                title: "UI/UX Audit",
                category: "design",
                desc: "Expert review of your user interface flows.",
                img: "https://images.unsplash.com/photo-1586717791821-3f44a5638d48?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
            }
        ];

        // --- FUNCTIONS ---

        // 1. Initialize Page
        document.addEventListener('DOMContentLoaded', () => {
            renderProducts(products);

            // Dynamic text effect in hero
            const heroText = document.querySelector('.hero h1');
            heroText.style.opacity = 0;
            setTimeout(() => {
                heroText.style.transition = "opacity 1.5s";
                heroText.style.opacity = 1;
            }, 200);
        });

        // 2. Render Products
        function renderProducts(data) {
            const grid = document.getElementById('productsGrid');
            grid.innerHTML = ''; // Clear existing

            if(data.length === 0) {
                grid.innerHTML = '<p style="text-align:center; grid-column: 1/-1;">No products found.</p>';
                return;
            }

            data.forEach(prod => {
                const card = document.createElement('div');
                card.className = 'product-card fade-in';
                card.innerHTML = `
                    <div class="product-img" style="background-image: url('${prod.img}')"></div>
                    <div class="product-info">
                        <span class="product-tag">${prod.category.toUpperCase()}</span>
                        <h3>${prod.title}</h3>
                        <p>${prod.desc}</p>
                        <div class="read-more" onclick="alert('Viewing details for: ${prod.title}')">View Details &rarr;</div>
                    </div>
                `;
                grid.appendChild(card);
            });
        }

        // 3. Filter Products
        function filterProducts(category) {
            // Update buttons visual state
            const buttons = document.querySelectorAll('.filter-btn');
            buttons.forEach(btn => btn.classList.remove('active'));

            // Add active class to clicked button (find by text roughly or passing event)
            // Simplified for this demo: finding button by onclick match is tricky without passing 'this'
            // We will just re-highlight based on index for simplicity or basic logic
            // (Better to pass 'event' in production)

            // Filter Data
            if (category === 'all') {
                renderProducts(products);
            } else {
                const filtered = products.filter(p => p.category === category);
                renderProducts(filtered);
            }
        }

        // 4. Search Functionality
        function performSearch() {
            const query = document.getElementById('searchInput').value.toLowerCase();
            const results = products.filter(p => 
                p.title.toLowerCase().includes(query) || 
                p.desc.toLowerCase().includes(query)
            );

            // Scroll to products
            document.getElementById('products').scrollIntoView({behavior: 'smooth'});

            // Render results
            renderProducts(results);

            // Update filter buttons to show none active or "custom" state
            const buttons = document.querySelectorAll('.filter-btn');
            buttons.forEach(btn => btn.classList.remove('active'));
        }

        // Allow Enter key to search
        document.getElementById('searchInput').addEventListener('keypress', function (e) {
            if (e.key === 'Enter') {
                performSearch();
            }
        });

        // 5. Mobile Menu Toggle
        function toggleMenu() {
            const nav = document.getElementById('navLinks');
            nav.classList.toggle('active');
        }

        // Mobile Dropdown interaction
        function toggleMobileDropdown(element) {
            // Only trigger on mobile screen widths
            if (window.innerWidth <= 768) {
                element.classList.toggle('active');
            }
        }

        // 6. Navbar Scroll Effect
        window.addEventListener('scroll', () => {
            const header = document.querySelector('header');
            if (window.scrollY > 50) {
                header.style.boxShadow = "0 4px 20px rgba(0,0,0,0.1)";
            } else {
                header.style.boxShadow = "0 2px 10px rgba(0,0,0,0.05)";
            }
        });

    </script>
</body>
</html>
