            if (window.innerWidth <= 768) {
                navList.classList.remove('active');
            }
        }

        // Dynamic Text Interaction (Our Philosophy)
        const valueBtns = document.querySelectorAll('.value-btn');
        const dynamicText = document.getElementById('dynamic-text-area');

        valueBtns.forEach(btn => {
            btn.addEventListener('click', function() {
                // Update text
                dynamicText.textContent = this.getAttribute('data-text');

                // Visual feedback on buttons
                valueBtns.forEach(b => b.style.backgroundColor = 'var(--primary-color)');
                valueBtns.forEach(b => b.style.color = 'white');

                this.style.backgroundColor = 'transparent';
                this.style.color = 'var(--primary-color)';
            });
        });

        // Contact Form Submission (Simulation)
        const contactForm = document.getElementById('contactForm');
        const modal = document.getElementById('successModal');
        const closeBtn = document.querySelector('.close-btn');

        contactForm.addEventListener('submit', function(e) {
            e.preventDefault();
            // Simulate sending data...

            // Show Modal
            modal.style.display = "block";

            // Reset Form
            contactForm.reset();
        });

        // Close Modal Logic
        closeBtn.onclick = function() {
            modal.style.display = "none";
        }

        window.onclick = function(event) {
            if (event.target == modal) {
                modal.style.display = "none";
            }
        }

        // Scroll Reveal Animation (Simple intersection observer)
        const observerOptions = {
            threshold: 0.2
        };

        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.style.opacity = "1";
                    entry.target.style.transform = "translateY(0)";
                }
            });
        }, observerOptions);

        const scrollElements = document.querySelectorAll('.service-card, .about-content');

        scrollElements.forEach(el => {
            el.style.opacity = "0";
            el.style.transform = "translateY(20px)";
            el.style.transition = "all 0.6s ease-out";
            observer.observe(el);
        });

    </script>
