        <p style="margin-bottom: 2rem;">Join 10,000+ companies optimizing their workflow today.</p>

        <div class="form-container">
            <form onsubmit="handleFormSubmit(event)">
                <div class="input-group">
                    <input type="email" placeholder="Enter your email address" required>
                </div>
                <button type="submit" class="submit-btn">Get Started Now</button>
            </form>
            <p id="success-message" style="display:none; margin-top:1rem; color: white; font-weight:bold;">Thanks! We'll be in touch.</p>
        </div>
    </section>

    <footer>
        <p>&copy; 2023 EcoSprint Technologies. All rights reserved.</p>
    </footer>

    <!-- JavaScript for Interactivity -->
    <script>
        // 1. Dynamic Text (Typewriter Effect)
        const textElement = document.getElementById('typewriter');
        const words = ["Fast.", "Sustainable.", "Reliable.", "EcoSprint."];
        let wordIndex = 0;
        let charIndex = 0;
        let isDeleting = false;

        function type() {
            const currentWord = words[wordIndex];

            if (isDeleting) {
                textElement.textContent = currentWord.substring(0, charIndex - 1);
                charIndex--;
            } else {
                textElement.textContent = currentWord.substring(0, charIndex + 1);
                charIndex++;
            }

            if (!isDeleting && charIndex === currentWord.length) {
                isDeleting = true;
                setTimeout(type, 2000); // Wait before deleting
            } else if (isDeleting && charIndex === 0) {
                isDeleting = false;
                wordIndex = (wordIndex + 1) % words.length;
                setTimeout(type, 500); // Wait before typing next word
            } else {
                setTimeout(type, isDeleting ? 100 : 200);
            }
        }

        // Initialize typewriter
        document.addEventListener('DOMContentLoaded', type);

        // 2. Benefits Tabs Logic
        function openBenefit(evt, benefitId) {
            // Hide all content panes
            const contentPanes = document.getElementsByClassName("content-pane");
            for (let i = 0; i < contentPanes.length; i++) {
                contentPanes[i].classList.remove("active");
            }

            // Remove active class from all buttons
            const buttons = document.getElementsByClassName("benefit-btn");
            for (let i = 0; i < buttons.length; i++) {
                buttons[i].classList.remove("active");
            }

            // Show current content and add active class to clicked button
            document.getElementById(benefitId).classList.add("active");
            evt.currentTarget.classList.add("active");
        }

        // 3. Smooth Scroll to CTA
        function scrollToCTA() {
            document.getElementById('cta').scrollIntoView({ behavior: 'smooth' });
        }

        // 4. Form Handling
        function handleFormSubmit(e) {
            e.preventDefault();
            const btn = document.querySelector('.submit-btn');
            const msg = document.getElementById('success-message');

            // Simulate loading state
            btn.innerHTML = "Processing...";
            btn.style.opacity = "0.7";

            setTimeout(() => {
                btn.innerHTML = "Submitted!";
                btn.style.backgroundColor = "#228B22"; // Darker green
                btn.style.color = "white";
                msg.style.display = "block";
            }, 1500);
        }
    </script>
</body>
</html>
