<script>
    /**
     * Logic for the Accordion Dropdown
     */
    const acc = document.getElementsByClassName("accordion");
    for (let i = 0; i < acc.length; i++) {
        acc[i].addEventListener("click", function() {
            this.classList.toggle("active");
            const panel = this.nextElementSibling;
            if (panel.style.maxHeight) {
                panel.style.maxHeight = null;
            } else {
                panel.style.maxHeight = panel.scrollHeight + "px";
            }
        });
    }

    /**
     * Helper to format dates from YYYY-MM-DD to YYYY/MM/DD for meta tags
     */
    function formatDate(dateString) {
        if (!dateString) return "";
        return dateString.replace(/-/g, '/');
    }

    /**
     * Main Function to Generate Meta Tags
     */
    function generateMetaTags() {
        const form = document.getElementById('metadataForm');
        let outputHTML = '<!-- Standard SEO Metadata -->\n';

        // 1. Process Standard Fields
        const standardFields = ['description', 'keywords', 'robots', 'author'];

        standardFields.forEach(field => {
            const value = form.elements[field].value;
            if(value) {
                outputHTML += `<meta name="${field}" content="${value}">\n`;
            }
        });

        outputHTML += '\n<!-- Academic Metadata -->\n';

        // 2. Process Academic Fields
        // Map form IDs to citation_names
        const academicFields = [
            'citation_title', 'citation_journal_title', 'citation_book_title', 
            'citation_conference_title', 'citation_abstract_html_url', 
            'citation_fulltext_html_url', 'citation_pdf_url', 'citation_doi', 
            'citation_issn', 'citation_isbn', 'citation_volume', 'citation_issue', 
            'citation_firstpage', 'citation_lastpage', 'citation_publisher', 
            'citation_language'
        ];

        academicFields.forEach(name => {
            const value = form.elements[name].value;
            if(value) {
                outputHTML += `<meta name="${name}" content="${value}">\n`;
            }
        });

        // 3. Process Dates (Special formatting)
        const dateFields = ['citation_date', 'citation_publication_date', 'citation_online_date'];

        dateFields.forEach(name => {
            const value = form.elements[name].value;
            if(value) {
                const formattedDate = formatDate(value);
                outputHTML += `<meta name="${name}" content="${formattedDate}">\n`;
            }
        });

        // Display Results
        const resultContainer = document.getElementById('result-container');
        const outputArea = document.getElementById('output-area');

        outputArea.textContent = outputHTML;
        outputArea.style.display = 'block';
        resultContainer.style.display = 'block';

        // Scroll to results
        resultContainer.scrollIntoView({behavior: "smooth"});
    }

    /**
     * Function to Reset Form
     */
    function resetForm() {
        document.getElementById('metadataForm').reset();
        document.getElementById('result-container').style.display = 'none';
    }

    /**
     * Function to Copy to Clipboard
     */
    function copyToClipboard() {
        const codeText = document.getElementById('output-area').textContent;
        navigator.clipboard.writeText(codeText).then(() => {
            const msg = document.getElementById('copy-msg');
            msg.style.display = 'block';
            setTimeout(() => {
                msg.style.display = 'none';
            }, 3000);
        });
    }
</script>

