    <script>
        /**
         * Application Logic
         * Encapsulated in an object to keep global namespace clean
         */
        const app = {
            // Simulated Database
            novels: [
                {
                    id: 1,
                    title: "The Golden Sunset",
                    author: "Eleanor Vance",
                    genre: "Romance",
                    status: "Completed",
                    chapters: 45,
                    rating: 4.8,
                    description: "In a world where the sun never sets, a young painter finds love in the most unexpected shade of burnt sienna.",
                    lastUpdated: "2023-10-15"
                },
                {
                    id: 2,
                    title: "Blade of Champagne",
                    author: "J.R. Sterling",
                    genre: "Fantasy",
                    status: "Ongoing",
                    chapters: 128,
                    rating: 4.5,
                    description: "A disgraced knight must wield a magical blade forged from liquid starlight to save his kingdom from eternal darkness.",
                    lastUpdated: "2023-10-27"
                },
                {
                    id: 3,
                    title: "Cyber Dust",
                    author: "Neo Anderson",
                    genre: "Sci-Fi",
                    status: "Ongoing",
                    chapters: 210,
                    rating: 4.2,
                    description: "In the year 3042, the barren wastelands of Earth hold a secret that could reboot humanity, but the corporations want it buried.",
                    lastUpdated: "2023-10-26"
                },
                {
                    id: 4,
                    title: "Shadows of the Manor",
                    author: "Agatha B.",
                    genre: "Mystery",
                    status: "Completed",
                    chapters: 12,
                    rating: 4.9,
                    description: "A locked room mystery set in a Victorian manor where every guest has a motive and the butler is already dead.",
                    lastUpdated: "2022-05-10"
                },
                {
                    id: 5,
                    title: "Heavenly Demon Arts",
                    author: "Dragon Ink",
                    genre: "Wuxia",
                    status: "Ongoing",
                    chapters: 850,
                    rating: 4.6,
                    description: "Cultivating the forbidden arts, Jiang Chen seeks revenge against the orthodox sects that destroyed his clan.",
                    lastUpdated: "2023-10-28"
                },
                {
                    id: 6,
                    title: "The Clockwork Heart",
                    author: "Steampunk Sally",
                    genre: "Fantasy",
                    status: "Hiatus",
                    chapters: 60,
                    rating: 3.9,
                    description: "Can a machine learn to love? A tale of gears, steam, and a heart that beats with a ticking rhythm.",
                    lastUpdated: "2023-01-15"
                }
            ],

            // State
            currentFilter: 'All',

            // Initialize
            init: function() {
                this.renderGrid(this.novels);

                // Add enter key listener for search
                document.getElementById('searchInput').addEventListener('keypress', function (e) {
                    if (e.key === 'Enter') {
                        app.searchNovels();
                    }
                });
            },

            // Render the Grid
            renderGrid: function(data) {
                const grid = document.getElementById('novelGrid');
                const noResults = document.getElementById('noResults');

                grid.innerHTML = ''; // Clear existing

                if (data.length === 0) {
                    noResults.style.display = 'block';
                    return;
                } else {
                    noResults.style.display = 'none';
                }

                data.forEach(novel => {
                    const card = document.createElement('div');
                    card.className = 'novel-card';
                    card.innerHTML = `
                        <div class="card-content">
                            <h3 class="card-title">${novel.title}</h3>
                            <div class="card-meta">
                                <span>${novel.author}</span>
                                <span class="tag">${novel.genre}</span>
                            </div>
                            <p class="card-desc">${novel.description}</p>
                            <div style="margin-top: 10px; font-size: 0.8rem; color: #888;">
                                <span>Status: ${novel.status}</span> | 
                                <span>Chapters: ${novel.chapters}</span>
                            </div>
                        </div>
                        <div class="card-footer">
                            <button class="btn read-btn" onclick="app.openDetailModal(${novel.id})">Read Now</button>
                        </div>
                    `;
                    grid.appendChild(card);
                });
            },

            // Filter by Category/Genre
            filterByGenre: function(genre) {
                this.currentFilter = genre;
                const searchVal = document.getElementById('searchInput').value.toLowerCase();

                let filtered = this.novels;

                // Apply Genre Filter
                if (genre !== 'All') {
                    filtered = filtered.filter(n => n.genre === genre);
                }

                // Apply Search Filter (if exists)
                if (searchVal) {
                    filtered = filtered.filter(n => 
                        n.title.toLowerCase().includes(searchVal) || 
                        n.author.toLowerCase().includes(searchVal)
                    );
                }

                this.renderGrid(filtered);
                this.showNotification(`Filtered by: ${genre}`);
            },

            // Search Functionality
            searchNovels: function() {
                const query = document.getElementById('searchInput').value.toLowerCase();

                let filtered = this.novels.filter(n => 
                    n.title.toLowerCase().includes(query) || 
                    n.author.toLowerCase().includes(query)
                );

                // Respect current category filter
                if (this.currentFilter !== 'All') {
                    filtered = filtered.filter(n => n.genre === this.currentFilter);
                }

                this.renderGrid(filtered);
            },

            // Reset view
            renderHome: function() {
                document.getElementById('searchInput').value = '';
                this.currentFilter = 'All';
                this.renderGrid(this.novels);
            },

            // Open Detail Modal
            openDetailModal: function(id) {
                const novel = this.novels.find(n => n.id === id);
                if(!novel) return;

                const modalBody = document.getElementById('modalBody');

                // Simulate chapters
                let chapterHtml = '';
                for(let i=1; i <= Math.min(novel.chapters, 5); i++) {
                    chapterHtml += `
                        <div class="chapter-item">
                            <span>Chapter ${novel.chapters - i + 1}: The Journey Part ${novel.chapters - i + 1}</span>
                            <span style="color:#888; font-size:0.8rem;">Free</span>
                        </div>
                    `;
                }

                modalBody.innerHTML = `
                    <div class="modal-header">
                        <h2 class="modal-title">${novel.title}</h2>
                        <span class="tag" style="font-size: 1rem; margin-top:5px; display:inline-block;">${novel.genre}</span>
                    </div>

                    <div class="stats-grid">
                        <div class="stat-item">
                            <h4>Author</h4>
                            <p>${novel.author}</p>
                        </div>
                        <div class="stat-item">
                            <h4>Status</h4>
                            <p>${novel.status}</p>
                        </div>
                        <div class="stat-item">
                            <h4>Chapters</h4>
                            <p>${novel.chapters}</p>
                        </div>
                        <div class="stat-item">
                            <h4>Rating</h4>
                            <p>★ ${novel.rating}/5.0</p>
                        </div>
                    </div>

                    <p style="font-size: 1.1rem; color: #444;">${novel.description}</p>

                    <div style="margin-top: 1.5rem;">
                        <button class="btn" onclick="app.showNotification('Added to Library!')">Add to Library</button>
                        <button class="btn" style="background-color: var(--text-dark); margin-left: 10px;" onclick="app.showNotification('Reading Chapter 1...')">Start Reading</button>
                    </div>

                    <h3 style="margin-top: 2rem; color: var(--color-burnt-sienna);">Latest Chapters</h3>
                    <div class="chapter-list">
                        ${chapterHtml}
                        <div class="chapter-item" style="justify-content:center; color: var(--color-burnt-sienna); font-weight:bold;">View All Chapters</div>
                    </div>
                `;

                document.getElementById('detailModal').style.display = 'block';
            },

            // Open Add Modal
            openAddModal: function() {
                document.getElementById('addForm').reset();
                document.getElementById('addModal').style.display = 'block';
            },

            // Close Modals
            closeModal: function(modalId) {
                document.getElementById(modalId).style.display = 'none';
            },

            // Handle New Novel Submission (Data Management)
            handleAddSubmit: function(e) {
                e.preventDefault();

                const title = document.getElementById('newTitle').value;
                const author = document.getElementById('newAuthor').value;
                const genre = document.getElementById('newGenre').value;
                const desc = document.getElementById('newDesc').value;
                const status = document.getElementById('newStatus').value;

                const newNovel = {
                    id: this.novels.length + 1,
                    title: title,
                    author: author,
                    genre: genre,
                    status: status,
                    chapters: 1, // Default
                    rating: 0, // Default
                    description: desc,
                    lastUpdated: new Date().toISOString().split('T')[0]
                };

                this.novels.unshift(newNovel); // Add to beginning of array
                this.renderGrid(this.novels);
                this.closeModal('addModal');
                this.showNotification('Novel successfully published!');
            },

            // Toast Notification System
            showNotification: function(message) {
                const toast = document.getElementById('notification');
                toast.innerText = message;
                toast.classList.add('show');
                setTimeout(() => {
                    toast.classList.remove('show');
                }, 3000);
            }
        };

        // Window click to close modals when clicking outside
        window.onclick = function(event) {
            if (event.target.classList.contains('modal')) {
                event.target.style.display = "none";
            }
        }

        // Run App
        app.init();
    </script>
</body>
</html>
```

Here is a complete, single-file HTML solution containing CSS and JavaScript to create a Machine Translation Comparison tool.

### Features Included:
1.  **Responsive Design:** Works on desktop and mobile.
2.  **Color Scheme:** Uses the requested Sky Blue background and Steel Blue components.
3.  **Simulated Backend:** Since real translation APIs (Google, DeepL, Bing) require paid keys and server-side proxies to avoid CORS errors, I have implemented a robust **mock translation engine** in JavaScript. It simulates network latency and generates plausible-looking "translations" based on logic (or lorem ipsum for demonstration) to show how the UI works.
4.  **Interactive Elements:**
    *   Dropdown for source/target languages.
    *   Multi-select for engines.
    *   Loading states with spinners.
    *   Result cards showing text, speed (ms), and a randomized "Confidence Score" (Accuracy).
5.  **Copy to Clipboard:** Functionality for every result.

