            <input type="checkbox" id="engine2" class="engine-checkbox" value="DeepL" checked>
            <label for="engine2" class="engine-label">DeepL</label>

            <input type="checkbox" id="engine3" class="engine-checkbox" value="Bing Microsoft" checked>
            <label for="engine3" class="engine-label">Bing Microsoft</label>

            <input type="checkbox" id="engine4" class="engine-checkbox" value="Yandex">
            <label for="engine4" class="engine-label">Yandex</label>

            <input type="checkbox" id="engine5" class="engine-checkbox" value="Baidu">
            <label for="engine5" class="engine-label">Baidu</label>
        </div>
    </section>

    <!-- Input Section -->
    <section class="input-area">
        <textarea id="inputText" placeholder="Enter text to translate here..."></textarea>
        <button class="action-btn" onclick="performTranslation()">Translate & Compare</button>
    </section>

    <!-- Results Section -->
    <div id="resultsGrid" class="results-container">
        <!-- Results will be injected here via JavaScript -->
        <div style="grid-column: 1 / -1; text-align: center; color: #777; padding: 2rem;">
            Select engines and input text to see comparisons.
        </div>
    </div>
</div>

<script>
    /* --- JAVASCRIPT LOGIC --- */

    /**
     * Simulates translation logic. 
     * In a production app, this would call real APIs (Google Cloud, DeepL API, etc.).
     * Since we cannot expose API keys in a client-side demo, we simulate the results.
     */
    const simulateTranslation = (text, targetLang, engineName) => {
        return new Promise((resolve) => {
            // Simulate network latency (random between 300ms and 1500ms)
            const latency = Math.floor(Math.random() * 1200) + 300;

            // Simulate Accuracy/Confidence (random between 85% and 99%)
            const accuracy = (Math.random() * (99.9 - 85.0) + 85.0).toFixed(1);

            setTimeout(() => {
                let translatedText = "";

                // Simple pseudo-translation logic for demonstration visuals
                if (text.trim() === "") {
                    translatedText = "[Empty Input]";
                } else {
                    // Create slightly different variations per engine to show comparison utility
                    const prefix = `[${engineName} Result]: `;

                    if(targetLang === 'es') translatedText = prefix + "Este es un ejemplo simulado de traducción para el texto ingresado.";
                    else if(targetLang === 'fr') translatedText = prefix + "Ceci est un exemple simulé de traduction pour le texte saisi.";
                    else if(targetLang === 'de') translatedText = prefix + "Dies ist ein simuliertes Übersetzungsbeispiel für den eingegebenen Text.";
                    else if(targetLang === 'zh') translatedText = prefix + "这是输入文本的模拟翻译示例。";
                    else if(targetLang === 'ja') translatedText = prefix + "これは、入力されたテキストの模擬翻訳例です。";
                    else translatedText = prefix + "This is a simulated translation example for the input text.";

                    // Append part of original text to make it look length-appropriate
                    translatedText += ` (${text.substring(0, 20)}...)`;
                }

                resolve({
                    engine: engineName,
                    text: translatedText,
                    speed: latency,
                    accuracy: accuracy
                });
            }, latency);
        });
    };

    async function performTranslation() {
        const inputText = document.getElementById('inputText').value;
        const targetLang = document.getElementById('targetLang').value;
        const resultsGrid = document.getElementById('resultsGrid');

        // Get selected engines
        const checkboxes = document.querySelectorAll('.engine-checkbox:checked');
        const selectedEngines = Array.from(checkboxes).map(cb => cb.value);

        // Validation
        if (!inputText.trim()) {
            alert("Please enter some text to translate.");
            return;
        }
        if (selectedEngines.length === 0) {
            alert("Please select at least one translation engine.");
            return;
        }

        // Clear previous results and show loaders
        resultsGrid.innerHTML = '';

        // Create placeholders with spinners
        selectedEngines.forEach(engine => {
            const card = document.createElement('div');
            card.className = 'result-card';
            card.id = `card-${engine.replace(/\s/g, '')}`;
            card.innerHTML = `
                <div class="card-header">
                    <span class="engine-name">${engine}</span>
                    <div class="metrics">Processing...</div>
                </div>
                <div class="spinner"></div>
            `;
            resultsGrid.appendChild(card);
        });

        // Trigger simulations for all selected engines in parallel
        const promises = selectedEngines.map(engine => 
            simulateTranslation(inputText, targetLang, engine).then(result => {
                updateResultCard(result);
            })
        );

        await Promise.all(promises);
    }

    function updateResultCard(result) {
        const cardId = `card-${result.engine.replace(/\s/g, '')}`;
        const card = document.getElementById(cardId);

        if (card) {
            // Determine color for accuracy badge
            let accuracyColor = '#28a745'; // green
            if(result.accuracy < 90) accuracyColor = '#ffc107'; // yellow
            if(result.accuracy < 80) accuracyColor = '#dc3545'; // red

            card.innerHTML = `
                <div class="card-header">
                    <span class="engine-name">${result.engine}</span>
                    <div class="metrics">
                        <span class="metric-badge">⚡ ${result.speed}ms</span>
                        <span class="metric-badge" style="border-color: ${accuracyColor}; color:${accuracyColor}">🎯 ${result.accuracy}%</span>
                    </div>
                </div>
                <div class="translation-text" id="text-${cardId}">${result.text}</div>
                <button class="copy-btn" onclick="copyToClipboard('text-${cardId}')">Copy Result</button>
            `;
        }
    }

    function copyToClipboard(elementId) {
        const text = document.getElementById(elementId).innerText;
        navigator.clipboard.writeText(text).then(() => {
            // Simple visual feedback
            const btn = document.querySelector(`button[onclick="copyToClipboard('${elementId}')"]`);
            const originalText = btn.innerText;
            btn.innerText = "Copied!";
            btn.style.backgroundColor = "var(--primary-color)";
            btn.style.color = "white";

            setTimeout(() => {
                btn.innerText = originalText;
                btn.style.backgroundColor = "transparent";
                btn.style.color = "var(--primary-color)";
            }, 2000);
        });
    }

    // Initialize logic to handle source/target language conflicts
    document.getElementById('sourceLang').addEventListener('change', function() {
        const target = document.getElementById('targetLang');
        if(this.value === target.value) {
            // Swap or shift target to avoid same language translation
            target.selectedIndex = (target.selectedIndex + 1) % target.options.length;
        }
    });
</script>

</body>
</html>
