<script>
    /**
     * Application Logic
     * Manages state, UI rendering, and user interactions.
     */
    const app = {
        // Mock Data
        data: [
            { id: 1, name: "Welcome Email", category: "Marketing", content: "<h1 style='color:blue'>Welcome!</h1><p>Thanks for joining us.</p>" },
            { id: 2, name: "Monthly Report", category: "Technical", content: "<h3>Monthly Stats</h3><ul><li>Users: 100</li><li>Sales: $500</li></ul>" },
            { id: 3, name: "Reset Password", category: "Personal", content: "<p>Click <b>here</b> to reset your password.</p>" }
        ],
        currentUser: null,

        // --- Initialization ---
        init: function() {
            this.cacheDOM();
            this.bindEvents();
            this.render();
        },

        cacheDOM: function() {
            this.loginView = document.getElementById('login-view');
            this.dashboardView = document.getElementById('dashboard-view');
            this.loginForm = document.getElementById('login-form');
            this.templateList = document.getElementById('template-list');
            this.templateModal = document.getElementById('template-modal');
            this.previewModal = document.getElementById('preview-modal');
            this.templateForm = document.getElementById('template-form');
            this.totalCountSpan = document.getElementById('total-count');
        },

        bindEvents: function() {
            this.loginForm.addEventListener('submit', (e) => this.handleLogin(e));
            this.templateForm.addEventListener('submit', (e) => this.handleSaveTemplate(e));
        },

        // --- Auth Functions ---
        handleLogin: function(e) {
            e.preventDefault();
            const u = document.getElementById('username').value;
            const p = document.getElementById('password').value;

            // Simple mock validation
            if(u === 'admin' && p === 'password') {
                this.currentUser = u;
                document.getElementById('welcome-msg').textContent = `Hello, ${u}`;
                this.switchView('dashboard');
                this.renderTemplates();
            } else {
                const err = document.getElementById('login-error');
                err.style.display = 'block';
                setTimeout(() => err.style.display = 'none', 3000);
            }
        },

        logout: function() {
            this.currentUser = null;
            document.getElementById('username').value = '';
            document.getElementById('password').value = '';
            this.switchView('login');
        },

        switchView: function(viewName) {
            document.querySelectorAll('.view').forEach(el => el.classList.remove('active'));
            if(viewName === 'login') this.loginView.classList.add('active');
            if(viewName === 'dashboard') this.dashboardView.classList.add('active');
        },

        // --- Template Management (CRUD) ---
        renderTemplates: function() {
            this.templateList.innerHTML = '';
            this.totalCountSpan.textContent = this.data.length;

            if (this.data.length === 0) {
                this.templateList.innerHTML = '<p style="grid-column: 1/-1; text-align: center;">No templates found. Create one!</p>';
                return;
            }

            this.data.forEach(t => {
                const card = document.createElement('div');
                card.className = 'template-card';
                card.innerHTML = `
                    <div style="display:flex; justify-content:space-between;">
                        <h3>${t.name}</h3>
                        <span style="background:peachpuff; padding:2px 8px; border-radius:10px; font-size:0.7rem;">${t.category}</span>
                    </div>
                    <p>${t.content.replace(/<[^>]*>?/gm, '').substring(0, 50)}...</p>
                    <div class="card-actions">
                        <button class="btn-sm btn-primary" onclick="app.previewTemplate(${t.id})">Preview</button>
                        <button class="btn-sm btn-secondary" onclick="app.editTemplate(${t.id})">Edit</button>
                        <button class="btn-sm btn-danger" onclick="app.deleteTemplate(${t.id})">Delete</button>
                    </div>
                `;
                this.templateList.appendChild(card);
            });
        },

        openModal: function(type) {
            if(type === 'add') {
                document.getElementById('modal-title').textContent = "Add New Template";
                document.getElementById('edit-id').value = '';
                this.templateForm.reset();
                this.templateModal.classList.add('open');
            }
        },

        closeModal: function(modalId) {
            document.getElementById(modalId).classList.remove('open');
        },

        handleSaveTemplate: function(e) {
            e.preventDefault();
            const id = document.getElementById('edit-id').value;
            const name = document.getElementById('t-name').value;
            const category = document.getElementById('t-category').value;
            const content = document.getElementById('t-content').value;

            if(id) {
                // Edit existing
                const index = this.data.findIndex(x => x.id == id);
                if(index !== -1) {
                    this.data[index] = { id: parseInt(id), name, category, content };
                }
            } else {
                // Add new
                const newId = this.data.length > 0 ? Math.max(...this.data.map(t => t.id)) + 1 : 1;
                this.data.push({ id: newId, name, category, content });
            }

            this.closeModal('template-modal');
            this.renderTemplates();
        },

        editTemplate: function(id) {
            const t = this.data.find(x => x.id === id);
            if(!t) return;

            document.getElementById('modal-title').textContent = "Edit Template";
            document.getElementById('edit-id').value = t.id;
            document.getElementById('t-name').value = t.name;
            document.getElementById('t-category').value = t.category;
            document.getElementById('t-content').value = t.content;

            this.templateModal.classList.add('open');
        },

        deleteTemplate: function(id) {
            if(confirm('Are you sure you want to delete this template?')) {
                this.data = this.data.filter(t => t.id !== id);
                this.renderTemplates();
            }
        },

        previewTemplate: function(id) {
            const t = this.data.find(x => x.id === id);
            if(!t) return;

            document.getElementById('preview-title').textContent = t.name;
            document.getElementById('preview-frame').innerHTML = t.content;
            this.previewModal.classList.add('open');
        },

        render: function() {
            // Initial view state is handled by HTML class 'active' on login view
        }
    };

    // Initialize the app when DOM is ready
    document.addEventListener('DOMContentLoaded', () => {
        app.init();
    });

</script>

</body>
</html>
