    <script>
        // Use strict mode for cleaner code
        'use strict';

        function startWriting() {
            // 1. Gather Data
            const name = $('#name').val() || "Anonymous";
            const role = $('#role').val();
            const skills = $('#skills').val() || "None listed";
            const bio = $('#bio').val() || "No bio provided.";

            // 2. Prepare text to type
            // using HTML line breaks for the output styling
            const textToType = `RESUME\n\nName: ${name}\nRole: ${role}\n\nKey Skills:\n${skills}\n\nAbout Me:\n${bio}`;

            // 3. Reset display area
            const $contentSpan = $('#typed-content');
            const $pen = $('#pen-icon');
            $contentSpan.html(''); // clear previous text
            $pen.show();

            // Disable button during animation
            $('button').prop('disabled', true).css('opacity', '0.6');

            // 4. Start Typing Animation Logic
            let i = 0;
            const speed = 50; // typing speed in ms

            function typeWriter() {
                if (i < textToType.length) {
                    let char = textToType.charAt(i);

                    // Handle new lines visually
                    if (char === '\n') {
                        char = '<br>';
                    }

                    // Append character
                    $contentSpan.append(char);

                    // Move pen to the position of the cursor (roughly)
                    movePenToCursor();

                    // Add wiggle effect to pen
                    $pen.addClass('writing-active');

                    i++;
                    setTimeout(typeWriter, speed);
                } else {
                    // Animation Finished
                    $pen.removeClass('writing-active');
                    $pen.fadeOut();
                    finishAnimation();
                }
            }

            // Start the recursive typing
            typeWriter();
        }

        function movePenToCursor() {
            const $cursor = $('.cursor');
            const $pen = $('#pen-icon');

            // Get position of the blinking cursor relative to the paper container
            const position = $cursor.position();

            if(position) {
                // Offset pen slightly so the tip touches the text
                $pen.css({
                    top: position.top - 25, 
                    left: position.left + 5
                });
            }
        }

        function finishAnimation() {
            // Re-enable button
            $('button').prop('disabled', false).css('opacity', '1');

            // Show Thank You message after a short delay
            setTimeout(() => {
                $('#thank-you').addClass('show');
            }, 800);
        }

        function resetForm() {
            // Clear inputs
            $('#name').val('');
            $('#skills').val('');
            $('#bio').val('');
            $('#typed-content').html('');

            // Hide modal
            $('#thank-you').removeClass('show');
        }

        // CSS3 Animation triggering via jQuery hover on title
        $(document).ready(function() {
            $('h1').hover(
                function() {
                    $(this).css({
                        'transform': 'scale(1.1) rotate(2deg)',
                        'transition': '0.3s'
                    });
                }, function() {
                    $(this).css({
                        'transform': 'scale(1) rotate(0deg)'
                    });
                }
            );
        });
    </script>
</body>
</html>
