        // --- DOM ELEMENTS ---
        const sections = document.querySelectorAll('section');
        const navButtons = document.querySelectorAll('.nav-btn');
        const premiumMenu = document.getElementById('premium-menu');
        const premiumItems = document.querySelectorAll('.hidden-nav-item');
        const unlockMsg = document.getElementById('unlock-message');

        // --- NAVIGATION LOGIC ---
        function showSection(sectionId) {
            // Hide all sections
            sections.forEach(sec => sec.classList.remove('active'));

            // Show target section
            const target = document.getElementById(sectionId);
            if (target) {
                target.classList.add('active');
            }

            // Update active state in sidebar
            navButtons.forEach(btn => {
                btn.classList.remove('active');
                // Simple heuristic to highlight button based on click handler string
                if(btn.getAttribute('onclick').includes(sectionId)) {
                    btn.classList.add('active');
                }
            });
        }

        // --- PASSWORD SYSTEM LOGIC ---

        // 1. Check Cache on Load
        function checkCache() {
            const isUnlocked = localStorage.getItem(UNLOCK_KEY);
            if (isUnlocked === 'true') {
                revealPremiumContent();
            }
        }

        // 2. Form Submission Handler
        function checkPassword() {
            const input = document.getElementById('passcode-input');
            const val = input.value;

            if (val === PASSWORD) {
                // Success
                localStorage.setItem(UNLOCK_KEY, 'true'); // Cache the success
                revealPremiumContent();

                unlockMsg.style.color = 'var(--success-color)';
                unlockMsg.textContent = "Access Granted! Menu updated.";
                input.value = '';

                // Redirect to first premium guide after short delay
                setTimeout(() => {
                    showSection('guide-adv-js');
                }, 1000);
            } else {
                // Failure
                unlockMsg.style.color = 'var(--lock-color)';
                unlockMsg.textContent = "Incorrect password. Try 'snowy'.";
                input.classList.add('shake');
                setTimeout(() => input.classList.remove('shake'), 500);
            }
        }

        // 3. UI Update Helper
        function revealPremiumContent() {
            // Change the lock icon or text if desired (optional)
            // Display the hidden menu items
            premiumItems.forEach(item => {
                item.style.display = 'block';
                // Trigger reflow for animation
                item.offsetHeight; 
                item.style.opacity = '1';
            });
        }

        // --- INITIALIZATION ---
        window.onload = checkCache;

    </script>
