    // Updates the text in the header based on user interaction
    function updateStatus(text) {
        const statusEl = document.getElementById('status-message');
        statusEl.textContent = text;
        statusEl.style.opacity = '1';
    }

    // --- 2. Image Enlargement Logic (Modal) ---
    const modal = document.getElementById("myModal");
    const modalImg = document.getElementById("img01");
    const captionText = document.getElementById("caption");

    function openModal(element) {
        // Find the sibling image element within the wrapper
        const wrapper = element.parentElement;
        const thumbnail = wrapper.querySelector('img');

        // Get the full resolution URL from data attribute and alt text
        const fullResSrc = thumbnail.getAttribute('data-full');
        const altText = thumbnail.alt;

        modal.style.display = "block";
        modalImg.src = fullResSrc;
        captionText.innerHTML = altText;

        // Prevent body scrolling when modal is open
        document.body.style.overflow = "hidden";
        updateStatus(`Enlarged view: ${altText}`);
    }

    // Close Modal via Button
    function closeModalBtn() {
        modal.style.display = "none";
        document.body.style.overflow = "auto";
        updateStatus("Gallery View");
    }

    // Close Modal via Background Click
    function closeModal(event) {
        if (event.target === modal) {
            closeModalBtn();
        }
    }

    // Close on Escape Key
    document.addEventListener('keydown', function(event) {
        if (event.key === "Escape" && modal.style.display === "block") {
            closeModalBtn();
