        // Apply Rosy Brown highlight border
        randomCard.style.border = "4px solid rosybrown";

        // Scroll to view if needed (smooth)
        randomCard.scrollIntoView({behavior: "smooth", block: "center"});
        updateStatus("Random image highlighted!");
