    <script>
        // --- 1. Dynamic Typing Effect for Hero Section ---
        const textElement = document.getElementById('typing-text');
        const phrases = ["PLC Programming", "SCADA Systems", "Industrial Robotics", "Process Control"];
        let phraseIndex = 0;
        let charIndex = 0;
        let isDeleting = false;

        function typeEffect() {
            const currentPhrase = phrases[phraseIndex];

            if (isDeleting) {
                textElement.textContent = currentPhrase.substring(0, charIndex - 1);
                charIndex--;
            } else {
                textElement.textContent = currentPhrase.substring(0, charIndex + 1);
                charIndex++;
            }

            if (!isDeleting && charIndex === currentPhrase.length) {
                isDeleting = true;
                setTimeout(typeEffect, 1500); // Pause at end of word
            } else if (isDeleting && charIndex === 0) {
                isDeleting = false;
                phraseIndex = (phraseIndex + 1) % phrases.length;
                setTimeout(typeEffect, 500); // Pause before next word
            } else {
                const speed = isDeleting ? 50 : 100;
                setTimeout(typeEffect, speed);
            }
        }

        // --- 2. Project Data and Rendering ---
        const projects = [
            {
                id: 1,
                title: "Automated Bottling Line",
