        const jobListElement = document.getElementById('jobList');
        const cityFilterElement = document.getElementById('cityFilter');
        const noResultsElement = document.getElementById('noResults');

        function renderJobs(data) {
            jobListElement.innerHTML = ''; // Clear current list

            if (data.length === 0) {
                noResultsElement.style.display = 'block';
                return;
            } else {
                noResultsElement.style.display = 'none';
            }

            data.forEach(job => {
                const card = document.createElement('div');
                card.className = 'job-card';

                // Create tags HTML
                const tagsHtml = job.skills.map(skill => `<span class="tag">${skill}</span>`).join('');

                card.innerHTML = `
