                        <div class="tags">
                            ${tagsHtml}
                        </div>
                    </div>
                    <button class="view-btn" onclick="openModal(${job.id})">View Details</button>
                `;
                jobListElement.appendChild(card);
            });
        }

        function populateCityFilter() {
            // Extract unique cities
            const cities = [...new Set(jobs.map(job => job.city))];

            cities.forEach(city => {
                const option = document.createElement('option');
                option.value = city;
                option.textContent = city;
                cityFilterElement.appendChild(option);
            });
        }

        // --- 4. Filter Logic ---
        function filterJobs() {
            const searchText = document.getElementById('searchInput').value.toLowerCase();
            const selectedCity = cityFilterElement.value;

            const filtered = jobs.filter(job => {
                // Check text match (title or skills)
                const textMatch = job.title.toLowerCase().includes(searchText) || 
                                  job.skills.some(skill => skill.toLowerCase().includes(searchText));

                // Check city match
                const cityMatch = selectedCity === 'All' || job.city === selectedCity;

                return textMatch && cityMatch;
            });

            renderJobs(filtered);
        }

        // Add event listener for "Enter" key in search box
        document.getElementById('searchInput').addEventListener('keypress', function (e) {
            if (e.key === 'Enter') {
                filterJobs();
            }
        });

        // --- 5. Modal Logic ---
        const modal = document.getElementById('jobModal');

        function openModal(id) {
            const job = jobs.find(j => j.id === id);
            if (!job) return;

            document.getElementById('modalTitle').textContent = job.title;
            document.getElementById('modalCompany').textContent = job.company;
            document.getElementById('modalCity').textContent = job.city;
            document.getElementById('modalSalary').textContent = job.salary;
            document.getElementById('modalSkills').textContent = job.skills.join(', ');
            // In a real app, description would likely be unique per job object
            // document.getElementById('modalDesc').textContent = job.description;

            modal.style.display = "block";
        }

        function closeModal() {
            modal.style.display = "none";
        }

        // Close modal if clicking outside the content
        window.onclick = function(event) {
            if (event.target == modal) {
                closeModal();
            }
        }
    </script>
