                <label for="layout-select">Layout Mode</label>
                <select id="layout-select" onchange="updateLayout()">
                    <option value="list">List View</option>
                    <option value="grid">Grid View</option>
                    <option value="card">Card View</option>
                </select>
            </div>
        </aside>

        <!-- Main Content: Feed Display -->
        <main class="content-area">
            <h2>Live Feed Preview</h2>

            <!-- View Controls -->
            <div class="display-controls">
                <label class="toggle-switch">
                    <input type="checkbox" id="show-title" checked onchange="updateVisibility()"> 
                    Show Title
                </label>
                <label class="toggle-switch">
                    <input type="checkbox" id="show-summary" checked onchange="updateVisibility()"> 
                    Show Summary
                </label>
                <label class="toggle-switch">
                    <input type="checkbox" id="show-date" checked onchange="updateVisibility()"> 
                    Show Date
                </label>
            </div>

            <!-- The Feed Container -->
            <div id="feed-container" class="layout-list">
                <p style="text-align: center; color: #777;">Add a source on the left to load articles.</p>
            </div>
        </main>
    </div>

    <script>
        /* --- JAVASCRIPT LOGIC --- */

        // State Management
        let sources = [
            // Pre-populated with dummy data for demonstration
            { name: "Tech News Demo", url: "mock-url-1" },
            { name: "Design Daily Demo", url: "mock-url-2" }
        ];

        // Mock Data Generator (Since we can't fetch real RSS without a CORS proxy in a static file)
        function getMockArticles(sourceName) {
            const date = new Date();
            return [
                {
                    title: `Big Update Coming to ${sourceName}`,
                    link: "#",
                    date: date.toDateString(),
                    summary: "Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua."
                },
                {
                    title: `Why ${sourceName} is Changing the Industry`,
                    link: "#",
                    date: new Date(date.setDate(date.getDate() - 1)).toDateString(),
                    summary: "Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat."
                },
                {
                    title: `Top 10 Tips for ${sourceName} Users`,
                    link: "#",
                    date: new Date(date.setDate(date.getDate() - 2)).toDateString(),
                    summary: "Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur."
                }
            ];
        }

        // --- DOM Elements ---
        const nameInput = document.getElementById('rss-name');
        const urlInput = document.getElementById('rss-url');
        const editIndexInput = document.getElementById('edit-index');
        const saveBtn = document.getElementById('save-btn');
        const cancelBtn = document.getElementById('cancel-btn');
        const sourceListEl = document.getElementById('source-list-el');
        const feedContainer = document.getElementById('feed-container');
        const layoutSelect = document.getElementById('layout-select');

        // --- Core Functions ---

        function renderSources() {
            sourceListEl.innerHTML = '';
            sources.forEach((source, index) => {
                const li = document.createElement('li');
                li.className = 'source-item';
                li.innerHTML = `
                    <span title="${source.url}">${source.name}</span>
                    <div class="action-icons">
                        <span onclick="editSource(${index})">✎</span>
                        <span onclick="deleteSource(${index})">🗑</span>
                    </div>
                `;
                sourceListEl.appendChild(li);
            });
            renderFeed();
        }

        function renderFeed() {
            feedContainer.innerHTML = '';

            if(sources.length === 0) {
                feedContainer.innerHTML = '<p style="text-align: center; color: #777;">No sources configured.</p>';
                return;
            }

            // Aggregate articles from all sources
            let allArticles = [];
            sources.forEach(source => {
                const articles = getMockArticles(source.name);
                allArticles = [...allArticles, ...articles];
            });

            // Render articles
            allArticles.forEach(article => {
                const articleEl = document.createElement('article');
                articleEl.className = 'feed-item';

                articleEl.innerHTML = `
                    <h3 class="article-title"><a href="${article.link}">${article.title}</a></h3>
                    <span class="feed-meta article-date">${article.date}</span>
                    <p class="feed-summary article-summary">${article.summary}</p>
                `;
                feedContainer.appendChild(articleEl);
            });

            // Apply current visibility settings
            updateVisibility();
        }

        // --- Source Management ---

        function saveSource() {
            const name = nameInput.value.trim();
            const url = urlInput.value.trim();
            const index = parseInt(editIndexInput.value);

            if (!name || !url) {
                alert("Please fill in both Name and URL.");
                return;
            }

            if (index === -1) {
                // Add new
                sources.push({ name, url });
            } else {
                // Edit existing
                sources[index] = { name, url };
            }

            resetForm();
            renderSources();
        }

        function deleteSource(index) {
            if(confirm('Are you sure you want to delete this source?')) {
                sources.splice(index, 1);
                renderSources();
            }
        }

        function editSource(index) {
            const source = sources[index];
            nameInput.value = source.name;
            urlInput.value = source.url;
            editIndexInput.value = index;
            saveBtn.textContent = "Update Source";
            cancelBtn.style.display = "block";
        }

        function resetForm() {
            nameInput.value = '';
            urlInput.value = '';
            editIndexInput.value = '-1';
            saveBtn.textContent = "Add Source";
            cancelBtn.style.display = "none";
        }

        // --- Display Configuration ---

        function updateLayout() {
            const layout = layoutSelect.value;
            // Remove existing layout classes
            feedContainer.classList.remove('layout-list', 'layout-grid', 'layout-card');
            // Add new layout class
            feedContainer.classList.add(`layout-${layout}`);
        }

        function updateVisibility() {
            const showTitle = document.getElementById('show-title').checked;
            const showSummary = document.getElementById('show-summary').checked;
            const showDate = document.getElementById('show-date').checked;

            const titles = document.querySelectorAll('.article-title');
            const summaries = document.querySelectorAll('.article-summary');
            const dates = document.querySelectorAll('.article-date');

            titles.forEach(el => showTitle ? el.classList.remove('hidden') : el.classList.add('hidden'));
            summaries.forEach(el => showSummary ? el.classList.remove('hidden') : el.classList.add('hidden'));
            dates.forEach(el => showDate ? el.classList.remove('hidden') : el.classList.add('hidden'));
        }

        // --- Initialization ---
        window.onload = function() {
            renderSources();
        };

    </script>
</body>
</html>
