<body>

    <!-- Sidebar: Subscription Management -->
    <aside>
        <h1>QuickRead RSS</h1>

        <div class="controls">
            <input type="text" id="newFeedUrl" placeholder="Enter RSS/Atom URL...">
            <button class="btn-primary" onclick="addFeed()">+ Add Subscription</button>
        </div>

        <h4 style="margin-bottom:10px; border-bottom: 1px solid rgba(255,255,255,0.5); padding-bottom:5px;">My Sources</h4>
        <ul class="feed-list" id="feedList">
            <!-- Feed items will be injected here via JS -->
        </ul>
    </aside>

    <!-- Main Content: Reading Area -->
    <main>
        <header>
            <h2 id="currentViewTitle">All News</h2>
            <div class="filter-bar">
                <input type="text" id="searchInput" placeholder="Search by keyword..." onkeyup="filterArticles()">
                <select id="categoryFilter" onchange="filterArticles()">
                    <option value="all">All Sources</option>
                    <!-- Options populated dynamically -->
                </select>
            </div>
        </header>

        <div class="news-container" id="newsContainer">
            <div class="loading">Loading your news...</div>
        </div>
    </main>

    <script>
        /* --- JAVASCRIPT LOGIC --- */

        // Default feeds to populate if storage is empty
        const defaultFeeds = [
            { name: "BBC Top Stories", url: "http://feeds.bbci.co.uk/news/rss.xml" },
            { name: "NYT Technology", url: "https://rss.nytimes.com/services/xml/rss/nyt/Technology.xml" },
            { name: "NASA Breaking", url: "https://www.nasa.gov/rss/dyn/breaking_news.rss" }
        ];

        let feeds = JSON.parse(localStorage.getItem('rssFeeds')) || defaultFeeds;
        let allArticles = []; // Store fetched articles globally for filtering

        // Helper: use rss2json proxy to bypass CORS restrictions
        const RSS_TO_JSON_API = "https://api.rss2json.com/v1/api.json?rss_url=";

        document.addEventListener('DOMContentLoaded', () => {
            renderFeedList();
            fetchAllFeeds();
            populateCategoryDropdown();
        });

        // --- Feed Management Functions ---

        function renderFeedList() {
            const list = document.getElementById('feedList');
            list.innerHTML = '';

            feeds.forEach((feed, index) => {
                const li = document.createElement('li');
                li.className = 'feed-item';
                li.innerHTML = `
                    <span onclick="filterBySource('${feed.name}')">${feed.name}</span>
                    <button class="btn-delete" onclick="removeFeed(${index})">&times;</button>
                `;
                list.appendChild(li);
            });
            localStorage.setItem('rssFeeds', JSON.stringify(feeds));
            populateCategoryDropdown();
        }

        async function addFeed() {
            const urlInput = document.getElementById('newFeedUrl');
            const url = urlInput.value.trim();

            if (!url) return alert("Please enter a URL.");

            // Validate URL format simply
            try {
                new URL(url);
            } catch (_) {
                return alert("Invalid URL format.");
            }

            // Verify feed validity via API
            try {
                const response = await fetch(RSS_TO_JSON_API + encodeURIComponent(url));
                const data = await response.json();

                if (data.status === 'ok') {
                    const feedName = data.feed.title || "New Feed";
                    feeds.push({ name: feedName, url: url });
                    urlInput.value = '';
                    renderFeedList();
                    fetchAllFeeds(); // Refresh content
                } else {
                    alert("Could not validate RSS feed. Please check the URL.");
                }
            } catch (error) {
                alert("Network error while validating feed.");
            }
        }

        function removeFeed(index) {
            if(confirm("Remove this subscription?")) {
                feeds.splice(index, 1);
                renderFeedList();
                fetchAllFeeds();
            }
        }

        // --- Content Fetching & Rendering ---

        async function fetchAllFeeds() {
            const container = document.getElementById('newsContainer');
            container.innerHTML = '<div class="loading">Fetching latest news...</div>';
            allArticles = [];

            const fetchPromises = feeds.map(feed => 
                fetch(RSS_TO_JSON_API + encodeURIComponent(feed.url))
                    .then(res => res.json())
                    .then(data => {
                        if (data.status === 'ok') {
                            // Add source name to each item for filtering
                            return data.items.map(item => ({...item, source: feed.name})); 
                        }
                        return [];
                    })
                    .catch(err => {
                        console.error(`Error fetching ${feed.name}:`, err);
                        return [];
                    })
            );

            try {
                const results = await Promise.all(fetchPromises);
                // Flatten array
                allArticles = results.flat();

                // Sort by date (newest first)
                allArticles.sort((a, b) => new Date(b.pubDate) - new Date(a.pubDate));

                displayArticles(allArticles);
            } catch (err) {
                container.innerHTML = '<div class="error">Failed to load news feeds.</div>';
            }
        }

        function displayArticles(articles) {
            const container = document.getElementById('newsContainer');
            container.innerHTML = '';

            if (articles.length === 0) {
                container.innerHTML = '<div class="error">No articles found.</div>';
                return;
            }

            articles.forEach(article => {
                // Strip HTML tags from description for clean preview
                const cleanDesc = article.description.replace(/<[^>]*>?/gm, '').substring(0, 150) + '...';
                const date = new Date(article.pubDate).toLocaleDateString();

                const card = document.createElement('div');
                card.className = 'article-card';
                card.innerHTML = `
                    <div class="article-meta">
                        <span class="badge">${article.source}</span>
                        <span>${date}</span>
                    </div>
                    <h3>${article.title}</h3>
                    <p>${cleanDesc}</p>
                    <a href="${article.link}" target="_blank" class="read-more">Read Full Article</a>
                `;
                container.appendChild(card);
            });
        }

        // --- Filtering Logic ---

        function populateCategoryDropdown() {
            const select = document.getElementById('categoryFilter');
            // Keep the "All" option
            select.innerHTML = '<option value="all">All Sources</option>';

            feeds.forEach(feed => {
                const option = document.createElement('option');
                option.value = feed.name;
                option.textContent = feed.name;
                select.appendChild(option);
            });
        }

        function filterBySource(sourceName) {
            // Update dropdown UI to match click
            const select = document.getElementById('categoryFilter');
            select.value = sourceName;
            filterArticles();
        }

        function filterArticles() {
            const keyword = document.getElementById('searchInput').value.toLowerCase();
            const sourceFilter = document.getElementById('categoryFilter').value;
            const titleElement = document.getElementById('currentViewTitle');

            let filtered = allArticles;

            // Filter by Source
            if (sourceFilter !== 'all') {
                filtered = filtered.filter(a => a.source === sourceFilter);
                titleElement.textContent = sourceFilter;
            } else {
                titleElement.textContent = "All News";
            }

            // Filter by Keyword
            if (keyword) {
                filtered = filtered.filter(a => 
                    a.title.toLowerCase().includes(keyword) || 
                    (a.description && a.description.toLowerCase().includes(keyword))
                );
            }

            displayArticles(filtered);
        }

    </script>
</body>
</html>
