    <script>
        /* JAVASCRIPT LOGIC */

        // Data Simulation
        const users = [
            { name: "Alice Dev", handle: "@alicedev", avatar: "AD" },
            { name: "Bob Design", handle: "@bob_ux", avatar: "BD" },
            { name: "Charlie Eco", handle: "@green_charlie", avatar: "CE" },
            { name: "Daily News", handle: "@dailynews", avatar: "DN" },
            { name: "Sarah Tech", handle: "@sarah_js", avatar: "ST" }
        ];

        const hashtags = ['tech', 'design', 'nature', 'news'];

        const contentTemplates = [
            "Just saw the latest updates in {hashtag}. Absolutely mind-blowing! 🤯",
            "Why doesn't everyone talk more about {hashtag}? It's the future.",
            "Spending my Sunday reading about {hashtag}. Best way to relax.",
            "Does anyone have resources for learning more about {hashtag}?",
            "Breaking: Huge changes coming to the world of {hashtag} next week!"
        ];

        let currentFilter = 'all';
        let tweetIdCounter = 0;

        // Initialize Feed
        document.addEventListener('DOMContentLoaded', () => {
            // Load initial batch
            for(let i=0; i<5; i++) {
                addTweetToFeed(generateTweet(), false);
            }

            // Simulate live updates every 5 seconds
            setInterval(() => {
                const newTweet = generateTweet();
                // Only add if it matches current filter
                if(currentFilter === 'all' || newTweet.tag === currentFilter) {
                    addTweetToFeed(newTweet, true);
                }
            }, 5000);
        });

        // Generate a random tweet object
        function generateTweet() {
            const user = users[Math.floor(Math.random() * users.length)];
            const tag = hashtags[Math.floor(Math.random() * hashtags.length)];
            const template = contentTemplates[Math.floor(Math.random() * contentTemplates.length)];
            const content = template.replace("{hashtag}", `<span class="hashtag">#${tag}</span>`);

            return {
                id: tweetIdCounter++,
                user: user,
                tag: tag,
                content: content,
                timestamp: new Date(),
                likes: Math.floor(Math.random() * 500),
                retweets: Math.floor(Math.random() * 100)
            };
        }

        // Add tweet to DOM
        function addTweetToFeed(tweet, isNew) {
            const feed = document.getElementById('tweetFeed');
            const tweetElement = document.createElement('div');

            tweetElement.className = 'tweet';
            tweetElement.setAttribute('data-tag', tweet.tag);
            tweetElement.onclick = () => openModal(tweet);

            // Format time
            const timeString = tweet.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

            tweetElement.innerHTML = `
                <div class="tweet-header">
                    <div class="avatar">${tweet.user.avatar}</div>
                    <div class="user-info">
                        <div>
                            <span class="username">${tweet.user.name}</span>
                            <span class="handle">${tweet.user.handle}</span>
                        </div>
                        <small style="color:#888">${timeString}</small>
                    </div>
                    ${isNew ? '<span class="new-badge">New</span>' : ''}
                </div>
                <div class="tweet-content">
                    ${tweet.content}
                </div>
                <div class="tweet-footer">
                    <button class="action-btn" onclick="event.stopPropagation(); likeTweet(this)">❤️ ${tweet.likes}</button>
                    <button class="action-btn" onclick="event.stopPropagation()">🔁 ${tweet.retweets}</button>
                    <button class="action-btn" onclick="event.stopPropagation()">💬 Reply</button>
                </div>
            `;

            if (isNew) {
                feed.prepend(tweetElement);
                // Remove "New" badge after animation
                setTimeout(() => {
                    const badge = tweetElement.querySelector('.new-badge');
                    if(badge) badge.remove();
                }, 3000);
            } else {
                feed.appendChild(tweetElement);
            }

            // Limit feed size for performance
            if (feed.children.length > 50) {
                feed.removeChild(feed.lastChild);
            }
        }

        // Dropdown Logic
        function toggleDropdown() {
            document.getElementById("hashtagDropdown").classList.toggle("show");
        }

        // Close dropdown if clicked outside
        window.onclick = function(event) {
            if (!event.target.matches('.dropdown-btn')) {
                var dropdowns = document.getElementsByClassName("dropdown-content");
                for (var i = 0; i < dropdowns.length; i++) {
                    var openDropdown = dropdowns[i];
                    if (openDropdown.classList.contains('show')) {
                        openDropdown.classList.remove('show');
                    }
                }
            }
            // Close modal if clicked outside
            const modal = document.getElementById('tweetModal');
            if (event.target == modal) {
                closeModal();
            }
        }

        // Filter Logic
        function filterTweets(tag) {
            currentFilter = tag;
            const feed = document.getElementById('tweetFeed');
            feed.innerHTML = ''; // Clear feed

            // Change button text
            document.querySelector('.dropdown-btn').textContent = 
                tag === 'all' ? 'Filter Hashtags ▼' : `Filter: #${tag} ▼`;

            // Load initial set for this filter
            for(let i=0; i<5; i++) {
                let tweet = generateTweet();
                // Force the tag if filtering
                if(tag !== 'all') {
                    while(tweet.tag !== tag) {
                        tweet = generateTweet();
                    }
                }
                addTweetToFeed(tweet, false);
            }
        }

        // Load More Logic
        function loadMoreTweets() {
            const btn = document.querySelector('.load-more-btn');
            const originalText = btn.textContent;
            btn.textContent = "Loading...";

            setTimeout(() => {
                for(let i=0; i<3; i++) {
                    let tweet = generateTweet();
                    if(currentFilter !== 'all') {
                         while(tweet.tag !== currentFilter) {
                            tweet = generateTweet();
                        }
                    }
                    addTweetToFeed(tweet, false);
                }
                btn.textContent = originalText;
                // Scroll to bottom slightly to show new content
                window.scrollBy({top: 200, behavior: 'smooth'});
            }, 800);
        }

        // Modal Logic
        function openModal(tweet) {
            const modal = document.getElementById('tweetModal');
            const modalBody = document.getElementById('modalBody');

            modalBody.innerHTML = `
                <div style="text-align: center; margin-bottom: 20px;">
                    <div style="width: 80px; height: 80px; background: var(--primary-color); border-radius: 50%; color: white; font-size: 2rem; display: flex; align-items: center; justify-content: center; margin: 0 auto;">${tweet.user.avatar}</div>
                    <h2 style="margin-top: 10px;">${tweet.user.name}</h2>
                    <p style="color: #666;">${tweet.user.handle}</p>
                </div>
                <hr style="border: 0; border-top: 1px solid #eee; margin: 20px 0;">
                <p style="font-size: 1.2rem; line-height: 1.6;">${tweet.content}</p>
                <div style="margin-top: 20px; color: #888; font-size: 0.9rem;">
                    Posted at ${tweet.timestamp.toLocaleTimeString()} on ${tweet.timestamp.toLocaleDateString()}
                </div>
                <div style="margin-top: 20px; display: flex; gap: 15px;">
                     <button class="load-more-btn" style="padding: 8px 20px; font-size: 0.9rem;">Reply</button>
                     <button class="load-more-btn" style="background: white; color: var(--primary-color); border: 1px solid var(--primary-color);">Share</button>
                </div>
            `;

            modal.style.display = "block";
        }

        function closeModal() {
            document.getElementById('tweetModal').style.display = "none";
        }

        // Interaction
        function likeTweet(btn) {
            const currentText = btn.innerText;
            const currentLikes = parseInt(currentText.split(' ')[1]);

            if(btn.classList.contains('liked')) {
                btn.classList.remove('liked');
                btn.innerText = `❤️ ${currentLikes - 1}`;
                btn.style.color = "#666";
            } else {
                btn.classList.add('liked');
                btn.innerText = `❤️ ${currentLikes + 1}`;
                btn.style.color = "red";
            }
        }
    </script>
</body>
