                        <p style="color: #666; margin-bottom: 5px;">Type: ${room.type}</p>
                        <span class="price">$${room.price} / night</span>
                        <button class="btn" onclick="openBookingModal(${room.id})">Book Now</button>
                    </div>
                `;
                container.appendChild(card);
            });
        }

        // 4. Modal Logic
        const modal = document.getElementById('bookingModal');

        function openBookingModal(roomId) {
            const room = roomsData.find(r => r.id === roomId);
            document.getElementById('modal-room-id').value = room.id;
            document.getElementById('modal-room-name').value = room.name;
            document.getElementById('display-room-name').innerText = `${room.name} ($${room.price})`;

            // Set min date to today
            const today = new Date().toISOString().split('T')[0];
            document.getElementById('check-in').min = today;
            document.getElementById('check-out').min = today;

            modal.style.display = 'block';
        }

        function closeModal() {
            modal.style.display = 'none';
            document.getElementById('bookingForm').reset();
        }

        window.onclick = function(event) {
            if (event.target == modal) {
                closeModal();
            }
        }

        // 5. Booking Logic
        function handleBooking(e) {
            e.preventDefault();

            const guestName = document.getElementById('guest-name').value;
            const checkIn = document.getElementById('check-in').value;
            const checkOut = document.getElementById('check-out').value;
            const roomName = document.getElementById('modal-room-name').value;

            if (new Date(checkOut) <= new Date(checkIn)) {
                showNotification("Check-out date must be after check-in date.");
                return;
            }

            const newBooking = {
                id: Date.now(), // Simple unique ID
                guestName,
                roomName,
                checkIn,
                checkOut,
                status: 'Pending Sync' // Initial status
            };

            bookings.push(newBooking);
            localStorage.setItem('hotelBookings', JSON.stringify(bookings));

            showNotification("Booking Successful! Go to Records to sync.");
            closeModal();
        }

        // 6. Records & Synchronization Logic
        function renderRecords() {
            const tbody = document.getElementById('records-body');
            const noMsg = document.getElementById('no-records-msg');
            tbody.innerHTML = '';

            if (bookings.length === 0) {
                noMsg.style.display = 'block';
                return;
            }
            noMsg.style.display = 'none';

            // Sort by latest
            bookings.sort((a,b) => b.id - a.id).forEach(booking => {
                const tr = document.createElement('tr');
                const isSynced = booking.status === 'Synced';
                const statusClass = isSynced ? 'status-synced' : 'status-pending';
                const statusIcon = isSynced ? '✔' : '⏳';

                tr.innerHTML = `
                    <td>#${booking.id.toString().slice(-4)}</td>
                    <td>${booking.guestName}</td>
                    <td>${booking.roomName}</td>
                    <td>${booking.checkIn} to ${booking.checkOut}</td>
                    <td><span class="status-badge ${statusClass}">${statusIcon} ${booking.status}</span></td>
                    <td>
                        <button class="sync-btn" 
                                onclick="syncRecord(${booking.id})" 
                                ${isSynced ? 'disabled' : ''}>
                            ${isSynced ? 'Done' : 'Sync Info'}
                        </button>
                    </td>
                `;
                tbody.appendChild(tr);
            });
        }

        function syncRecord(bookingId) {
            const btn = event.target;
            const originalText = btn.innerText;
            btn.innerText = "Syncing...";
            btn.disabled = true;

            // Simulate Network Request with Timeout
            setTimeout(() => {
                const index = bookings.findIndex(b => b.id === bookingId);
                if (index !== -1) {
                    bookings[index].status = 'Synced';
                    localStorage.setItem('hotelBookings', JSON.stringify(bookings));
                    renderRecords(); // Refresh table (real-time update)
                    showNotification(`Record #${bookingId.toString().slice(-4)} synchronized successfully!`);
                }
            }, 1500);
        }

        function syncAll() {
            const pending = bookings.filter(b => b.status !== 'Synced');
            if(pending.length === 0) {
                showNotification("All records are already synchronized.");
                return;
            }

            showNotification(`Syncing ${pending.length} records...`);

            // Simulate batch sync
            setTimeout(() => {
                bookings.forEach(b => b.status = 'Synced');
                localStorage.setItem('hotelBookings', JSON.stringify(bookings));
                renderRecords();
                showNotification("All records synchronized!");
            }, 2000);
        }

        // 7. Notification Helper
        function showNotification(message) {
            const container = document.getElementById('notification-area');
            const toast = document.createElement('div');
            toast.className = 'toast';
            toast.innerText = message;
            container.appendChild(toast);

            // Remove after 3 seconds
            setTimeout(() => {
                toast.style.opacity = '0';
                setTimeout(() => toast.remove(), 500);
            }, 3000);
        }

        // Initialize
        document.addEventListener('DOMContentLoaded', () => {
            renderRooms();
        });

    </script>
</body>
</html>
