                    let moodMatch = (mood === 'all' || category === mood);
                    let textMatch = (input === '' || textContent.includes(input));

                    if (moodMatch && textMatch) {
                        card.style.display = 'block';
                        card.style.animation = 'slideIn 0.5s ease';
                        count++;
                    } else {
                        card.style.display = 'none';
                    }
                });

