    <script>
        // --- 1. Dynamic Typing Effect for Hero Section ---
        const texts = ["Explore History.", "See the Pyramids.", "Sail the Nile.", "Relax by the Red Sea."];
        let count = 0;
        let index = 0;
        let currentText = "";
        let letter = "";

        (function type() {
            if (count === texts.length) {
                count = 0;
            }
            currentText = texts[count];
            letter = currentText.slice(0, ++index);

            document.getElementById("typing-text").textContent = letter;

            if (letter.length === currentText.length) {
                count++;
                index = 0;
                setTimeout(type, 2000); // Pause at end of phrase
            } else {
                setTimeout(type, 100); // Typing speed
            }
        })();

        // --- 2. Tab Switching Logic ---
        function openTab(evt, tabName) {
            let i, tabcontent, tablinks;

            // Hide all tab content
            tabcontent = document.getElementsByClassName("tab-content");
            for (i = 0; i < tabcontent.length; i++) {
                tabcontent[i].style.display = "none";
                tabcontent[i].classList.remove("active");
            }

            // Remove active class from buttons
            tablinks = document.getElementsByClassName("tab-btn");
            for (i = 0; i < tablinks.length; i++) {
                tablinks[i].className = tablinks[i].className.replace(" active", "");
            }

            // Show current tab and add active class
            document.getElementById(tabName).style.display = "block";
            // Small timeout to allow display:block to apply before animation class
            setTimeout(() => {
                 document.getElementById(tabName).classList.add("active");
            }, 10);

            evt.currentTarget.className += " active";
        }

        // --- 3. Simulated Weather API ---
        function updateWeather() {
            const temps = [25, 28, 30, 32, 22];
            const conditions = ["Sunny", "Clear Sky", "Partly Cloudy", "Hot"];

            // Randomly select for demo purposes
            const randomTemp = temps[Math.floor(Math.random() * temps.length)];
            const randomCond = conditions[Math.floor(Math.random() * conditions.length)];

            document.getElementById("weather-temp").innerText = `${randomTemp}°C`;
            document.getElementById("weather-desc").innerText = randomCond;
        }

        // Initialize weather on load
        window.onload = updateWeather;

        // --- 4. Interactions ---
        function showDetails(place) {
            alert(`You clicked on ${place}! \n\nWe are redirecting you to the detailed itinerary page (Simulated).`);
        }

        function handleBooking(event, type) {
            event.preventDefault(); // Stop form submission refresh
            alert(`${type} search initiated! \n\nChecking availability in our database...`);
        }

        // Smooth scrolling for anchor links
        document.querySelectorAll('a[href^="#"]').forEach(anchor => {
            anchor.addEventListener('click', function (e) {
                e.preventDefault();
                document.querySelector(this.getAttribute('href')).scrollIntoView({
                    behavior: 'smooth'
                });
            });
        });

    </script>
