    <script>
        // --- Data: Mock Room Data ---
        const roomsData = [
            {
                id: 1,
                name: "Cozy Standard",
                type: "standard",
                price: 150,
                image: "https://images.unsplash.com/photo-1611892440504-42a792e24d32?ixlib=rb-1.2.1&auto=format&fit=crop&w=800&q=80",
