                image: "https://images.unsplash.com/photo-1590490360182-c33d57733427?ixlib=rb-1.2.1&auto=format&fit=crop&w=800&q=80",
                features: ["King Bed", "Ocean View", "Mini Bar", "Bathtub"]
            },
            {
                id: 3,
                name: "Grand Suite",
                type: "suite",
                price: 450,
                image: "https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?ixlib=rb-1.2.1&auto=format&fit=crop&w=800&q=80",
                features: ["Living Area", "King Bed", "Panoramic View", "Jacuzzi"]
            },
            {
                id: 4,
                name: "Twin Standard",
                type: "standard",
                price: 160,
                image: "https://images.unsplash.com/photo-1618773928121-c32242e63f39?ixlib=rb-1.2.1&auto=format&fit=crop&w=800&q=80",
                features: ["2 Twin Beds", "Work Desk", "Shower"]
            },
            {
                id: 5,
                name: "Executive Suite",
                type: "suite",
                price: 550,
                image: "https://images.unsplash.com/photo-1578683010236-d716f9a3f461?ixlib=rb-1.2.1&auto=format&fit=crop&w=800&q=80",
                features: ["Separate Bedroom", "Lounge Access", "Breakfast Included"]
            }
        ];

        // --- Calendar State ---
        let currentDate = new Date();
        let currentMonth = currentDate.getMonth();
        let currentYear = currentDate.getFullYear();

        let checkinDate = null;
        let checkoutDate = null;
        let activeCalendar = null; // 'checkin' or 'checkout'

        const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
        const dayNames = ["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"];

        // --- Initialization ---
        document.addEventListener('DOMContentLoaded', () => {
            renderCalendar('checkin', currentMonth, currentYear);
            renderCalendar('checkout', currentMonth, currentYear);
            displayRooms(roomsData);

            // Close calendars when clicking outside
            document.addEventListener('click', (e) => {
                if (!e.target.closest('.input-group')) {
                    document.getElementById('checkin-calendar').classList.remove('active');
                    document.getElementById('checkout-calendar').classList.remove('active');
                }
            });
        });

        // --- Calendar Logic ---
        function toggleCalendar(type) {
            const calId = type + '-calendar';
            const otherCalId = (type === 'checkin' ? 'checkout' : 'checkin') + '-calendar';

            document.getElementById(otherCalId).classList.remove('active');

            const calendarEl = document.getElementById(calId);
            calendarEl.classList.toggle('active');

            activeCalendar = type;
            // Reset view to selection or current date
            if(type === 'checkin' && checkinDate) {
                 renderCalendar(type, checkinDate.getMonth(), checkinDate.getFullYear());
            } else if (type === 'checkout' && checkoutDate) {
                 renderCalendar(type, checkoutDate.getMonth(), checkoutDate.getFullYear());
            } else {
                 renderCalendar(type, currentMonth, currentYear);
            }
        }

        function changeMonth(step, type) {
            // Need to track view state per calendar, strictly simplifying here for demo
            // In a full app, we'd store viewMonth/viewYear per calendar instance
            let calHeader = document.getElementById(`${type}-month-year`).innerText;
            let parts = calHeader.split(" ");
            let monthIdx = monthNames.indexOf(parts[0]);
            let year = parseInt(parts[1]);

            monthIdx += step;
            if (monthIdx < 0) {
                monthIdx = 11;
                year--;
            } else if (monthIdx > 11) {
                monthIdx = 0;
                year++;
            }
            renderCalendar(type, monthIdx, year);
        }

        function renderCalendar(type, month, year) {
            const container = document.getElementById(`${type}-days`);
            const header = document.getElementById(`${type}-month-year`);

            container.innerHTML = "";
            header.innerText = `${monthNames[month]} ${year}`;

            // Add Day Headers
            dayNames.forEach(day => {
                const div = document.createElement('div');
                div.classList.add('cal-day-name');
                div.innerText = day;
                container.appendChild(div);
            });

            const firstDay = new Date(year, month, 1).getDay();
            const daysInMonth = new Date(year, month + 1, 0).getDate();
            const today = new Date();
            today.setHours(0,0,0,0);

            // Empty slots for previous month
            for (let i = 0; i < firstDay; i++) {
                const div = document.createElement('div');
                container.appendChild(div);
            }

            // Days
            for (let i = 1; i <= daysInMonth; i++) {
                const dateObj = new Date(year, month, i);
                const div = document.createElement('div');
                div.classList.add('cal-day');
                div.innerText = i;

                // Disable past dates
                if (dateObj < today) {
                    div.classList.add('disabled');
                } else {
                    div.onclick = (e) => selectDate(dateObj, type);
                }

                // Highlighting Logic
                if (type === 'checkin' && checkinDate && dateObj.getTime() === checkinDate.getTime()) {
                    div.classList.add('selected');
                }
                if (type === 'checkout' && checkoutDate && dateObj.getTime() === checkoutDate.getTime()) {
                    div.classList.add('selected');
                }

                // Range Highlighting (simple visual cue)
                if (checkinDate && checkoutDate && dateObj > checkinDate && dateObj < checkoutDate) {
                    div.classList.add('in-range');
                }

                // Prevent selecting checkout before checkin
                if (type === 'checkout' && checkinDate && dateObj <= checkinDate) {
                    div.classList.remove('selected');
                    div.classList.add('disabled');
                    div.onclick = null;
                }

                container.appendChild(div);
            }
        }

        function selectDate(date, type) {
            const display = document.getElementById(`${type}-text`);
            const formattedDate = date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

            if (type === 'checkin') {
                checkinDate = date;
                display.innerText = formattedDate;
                document.getElementById('checkin-display').style.borderColor = 'var(--accent-color)';

                // Reset checkout if invalid
                if (checkoutDate && checkoutDate <= checkinDate) {
                    checkoutDate = null;
                    document.getElementById('checkout-text').innerText = "Select Date";
                }
                // Auto open checkout
                setTimeout(() => toggleCalendar('checkout'), 200);

            } else {
                checkoutDate = date;
                display.innerText = formattedDate;
                document.getElementById('checkout-display').style.borderColor = 'var(--accent-color)';
                document.getElementById('checkout-calendar').classList.remove('active');
            }

            // Re-render both to update styling (ranges, disabled dates)
            if(activeCalendar) {
                let calHeader = document.getElementById(`${activeCalendar}-month-year`).innerText.split(" ");
                renderCalendar('checkin', monthNames.indexOf(calHeader[0]), parseInt(calHeader[1]));
                renderCalendar('checkout', monthNames.indexOf(calHeader[0]), parseInt(calHeader[1]));
            }
        }

        // --- Room Filtering & Sorting ---
        function displayRooms(rooms) {
            const list = document.getElementById('room-list');
            const count = document.getElementById('results-count');
            list.innerHTML = '';

            count.innerText = `(${rooms.length} room${rooms.length !== 1 ? 's' : ''} found)`;

            rooms.forEach(room => {
                const card = document.createElement('div');
                card.classList.add('room-card');

                let featuresHtml = room.features.map(f => `<span class="feature-tag">${f}</span>`).join('');

                card.innerHTML = `
                    <div class="room-img">
                        <img src="${room.image}" alt="${room.name}">
                    </div>
                    <div class="room-details">
                        <div class="room-type">${room.type} Collection</div>
                        <h3 class="room-name">${room.name}</h3>
                        <div class="room-price">$${room.price}<span> / night</span></div>
                        <div class="room-features">${featuresHtml}</div>
                        <button class="btn-book" onclick="bookRoom('${room.name}')">Book Now</button>
                    </div>
                `;
                list.appendChild(card);
            });
        }

        function filterRooms() {
            // Validation
            if(!checkinDate || !checkoutDate) {
               // Optional: Alert user to select dates first, but we show rooms anyway for UX
               // alert("Please select check-in and check-out dates.");
            }

            const typeFilter = document.getElementById('room-filter').value;
            const sortOrder = document.getElementById('price-sort').value;

            // 1. Filter
            let filtered = roomsData.filter(room => {
                if (typeFilter === 'all') return true;
                return room.type === typeFilter;
            });

            // 2. Sort
            filtered.sort((a, b) => {
                if (sortOrder === 'asc') return a.price - b.price;
                return b.price - a.price;
            });

            displayRooms(filtered);
        }

        function bookRoom(roomName) {
            if(!checkinDate || !checkoutDate) {
                alert("Please select your check-in and check-out dates first.");
                document.getElementById('checkin-display').scrollIntoView({ behavior: 'smooth' });
                document.getElementById('checkin-display').style.borderColor = 'red';
                setTimeout(() => document.getElementById('checkin-display').style.borderColor = 'var(--highlight-color)', 2000);
            } else {
                const diffTime = Math.abs(checkoutDate - checkinDate);
                const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 
                alert(`You have selected the ${roomName} for ${diffDays} night(s).\nCheck-in: ${checkinDate.toLocaleDateString()}\nCheck-out: ${checkoutDate.toLocaleDateString()}`);
            }
        }

    </script>
</body>
</html>
