            document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));
            document.querySelectorAll('.section').forEach(el => el.classList.remove('active'));

            // Add active class to current selection
            document.getElementById(tabId).classList.add('active');

            // Find the nav item that corresponds to this ID (simple logic for demo)
            const navIndex = ['home', 'spots', 'my-card', 'perks'].indexOf(tabId);
            document.querySelectorAll('.nav-item')[navIndex].classList.add('active');
        }

        // 2. Purchase Logic
        function updatePrice() {
            const type = document.getElementById('cardType').value;
            const container = document.getElementById('dynamic-content');
            if (type === 'individual') {
                container.innerHTML = "<p style='font-size: 0.9rem; margin-top:5px;'>Perfect for solo travelers.</p>";
            } else {
                container.innerHTML = "<p style='font-size: 0.9rem; margin-top:5px;'>Great value! Saves $96 compared to individual.</p>";
            }
        }

        function purchaseCard() {
            const type = document.getElementById('cardType').value;
            alert(`Redirecting to payment gateway for ${type} pass... (Simulation Success)`);
            // Simulating a successful purchase that gives a code
            alert("Payment Successful! Use code 'GOLD123' to activate your card in the 'My Card' tab.");
        }

        // 3. Dropdown Logic
        function toggleDropdown(id) {
            const el = document.getElementById(id);
            if (el.style.display === "block") {
                el.style.display = "none";
            } else {
                el.style.display = "block";
            }
        }

        // 4. Spot Listing & Filter
        function renderSpots(filterText = "") {
            const container = document.getElementById('spotList');
            container.innerHTML = "";

            spotsData.forEach(spot => {
                if (spot.name.toLowerCase().includes(filterText.toLowerCase())) {
                    const div = document.createElement('div');
                    div.className = 'spot-item';

                    let tagsHtml = spot.tags.map(t => `<span class="tag">${t}</span>`).join('');

                    div.innerHTML = `
                        <span>${spot.name}</span>
                        <div>${tagsHtml}</div>
                    `;
                    container.appendChild(div);
                }
            });
        }

        function filterSpots() {
            const text = document.getElementById('searchSpot').value;
            renderSpots(text);
        }

        // 5. Activation Logic
        function activateCard() {
            const code = document.getElementById('activationCode').value;
            if (code === "GOLD123") {
                isCardActive = true;
                document.getElementById('activation-panel').style.display = 'none';
                document.getElementById('card-panel').style.display = 'block';

                // Update card type display based on selection
                const type = document.getElementById('cardType').value;
                document.getElementById('user-card-type').innerText = type === 'individual' ? "Individual Pass" : "Team Pass";

                alert("Activation Successful! Welcome to the club.");
            } else {
                alert("Invalid Code. Please try 'GOLD123'.");
            }
        }

        // 6. QR Code / Entry Logic
        let timerInterval;

        function showQRCode() {
            if (!isCardActive) {
                alert("Please activate your card first.");
                return;
            }
            document.getElementById('qrModal').classList.add('open');
            startTimer();

            // Log a fake usage record
            addUsageRecord("New Park Entry");
        }

        function closeModal(e) {
            if (e.target.id === 'qrModal') {
                closeModalDirect();
            }
        }

        function closeModalDirect() {
            document.getElementById('qrModal').classList.remove('open');
            clearInterval(timerInterval);
        }

        function startTimer() {
            let timeLeft = 30;
            const timerEl = document.getElementById('timer');
            timerEl.innerText = `Refreshes in: ${timeLeft}s`;

            clearInterval(timerInterval);
            timerInterval = setInterval(() => {
                timeLeft--;
                timerEl.innerText = `Refreshes in: ${timeLeft}s`;
                if (timeLeft <= 0) timeLeft = 30; // Reset loop
            }, 1000);
        }

        function addUsageRecord(placeName) {
            const historyList = document.getElementById('history-list');
            const today = new Date();
            const dateStr = today.toLocaleString('default', { month: 'short', day: 'numeric' });

            const div = document.createElement('div');
            div.className = 'record-item';
            div.innerHTML = `<span>${placeName}</span><span class="tag">${dateStr}</span>`;

            // Insert at top
            historyList.insertBefore(div, historyList.firstChild);
        }

        // 7. Coupon Logic
        function generateCoupon() {
            const offers = ["Free Ice Cream", "50% Off Guide", "Buy 1 Get 1 Rental"];
            const randomOffer = offers[Math.floor(Math.random() * offers.length)];

            const container = document.getElementById('coupon-container');
            const div = document.createElement('div');
            div.className = 'coupon';
            div.innerHTML = `<strong>${randomOffer}</strong><br><small>Expires in 24h</small>`;

            container.prepend(div);
        }

        // Initialize
        document.addEventListener('DOMContentLoaded', () => {
            updatePrice();
            renderSpots();
        });

    </script>
</body>
</html>
