<script>
    /* --- JAVASCRIPT LOGIC --- */

    // 1. Mock Data
    const blogPosts = [
        {
            id: 1,
            title: "Why Tomato is a Fruit",
            category: "Botany",
            date: "2023-10-15",
            tags: ["Science", "Food", "Facts"],
            content: "Many people believe tomatoes are vegetables because of their culinary use. However, scientifically speaking, a tomato is the ovary of the flower, containing seeds, which makes it a fruit. This article explores the botanical definition vs the culinary definition."
        },
        {
            id: 2,
            title: "The Sweetness of Melon",
            category: "Culinary",
            date: "2023-10-20",
            tags: ["Recipes", "Summer", "Sweet"],
            content: "Melons are the perfect summer treat. High in water content and rich in vitamins, they provide hydration and sweetness. We discuss the differences between Watermelon, Cantaloupe, and Honeydew in this comprehensive guide."
        },
        {
            id: 3,
            title: "Gardening Tips for Beginners",
            category: "Lifestyle",
            date: "2023-09-05",
            tags: ["Garden", "DIY", "Nature"],
            content: "Starting a garden can be daunting. Start small with herbs or easy-to-grow vegetables like... you guessed it, tomatoes! Ensure you have good soil, adequate sunlight, and a watering schedule."
        },
        {
            id: 4,
            title: "Red vs. Green: Color Theory",
            category: "Design",
