        },
        {
            id: 5,
            title: "Healthy Smoothies",
            category: "Culinary",
            date: "2023-09-12",
            tags: ["Food", "Health", "Recipes"],
            content: "Combine melon, mint, and a dash of lime for a refreshing smoothie. Avoid adding sugar; the natural fructose in the fruit is plenty sweet."
        },
        {
            id: 6,
            title: "The History of Salsa",
            category: "History",
            date: "2023-08-22",
            tags: ["Culture", "Food", "Spicy"],
            content: "Salsa, originating from the Incas, Aztecs, and Mayans, has become a staple worldwide. The base ingredient? The humble tomato."
        }
    ];

    // 2. State Management
    let currentFilters = {
        search: "",
        category: "all",
        tag: "all",
        date: "all"
    };

    // 3. DOM Elements
    const gridEl = document.getElementById('blog-grid');
    const categorySelect = document.getElementById('category-filter');
    const tagSelect = document.getElementById('tag-filter');
    const dateSelect = document.getElementById('date-filter');
    const searchInput = document.getElementById('search-filter');
    const modal = document.getElementById('article-modal');
    const closeModalBtn = document.querySelector('.close-modal');

    // 4. Initialization
    function init() {
        populateFilters();
        renderPosts(blogPosts);
        setupEventListeners();
    }

    // 5. Populate Filter Dropdowns dynamically based on data
    function populateFilters() {
        // Extract unique values
        const categories = [...new Set(blogPosts.map(post => post.category))];
        const tags = [...new Set(blogPosts.flatMap(post => post.tags))];

        // Format dates to Month Year for grouping
        const dates = [...new Set(blogPosts.map(post => {
            const d = new Date(post.date);
            return `${d.toLocaleString('default', { month: 'long' })} ${d.getFullYear()}`;
        }))];

        // Fill Selects
        categories.forEach(cat => {
            const option = document.createElement('option');
            option.value = cat;
            option.textContent = cat;
            categorySelect.appendChild(option);
        });

        tags.forEach(tag => {
            const option = document.createElement('option');
            option.value = tag;
            option.textContent = tag;
            tagSelect.appendChild(option);
        });

        dates.forEach(dateStr => {
            const option = document.createElement('option');
            option.value = dateStr;
            option.textContent = dateStr;
            dateSelect.appendChild(option);
        });
    }

    // 6. Render Posts
    function renderPosts(posts) {
        gridEl.innerHTML = ''; // Clear existing

        if (posts.length === 0) {
            gridEl.innerHTML = '<div class="no-results">No tomatoes or melons found matching your criteria!</div>';
            return;
        }

        posts.forEach(post => {
            const card = document.createElement('div');
            card.className = 'blog-card';

            // Generate HTML for tags
            const tagsHtml = post.tags.map(tag => `<span class="tag">${tag}</span>`).join('');

            card.innerHTML = `
                <div class="blog-meta">
                    <span class="blog-category">${post.category}</span>
                    <span>${new Date(post.date).toLocaleDateString()}</span>
                </div>
                <h2 class="blog-title" onclick="openModal(${post.id})">${post.title}</h2>
                <p>${post.content.substring(0, 80)}...</p>
                <div class="blog-tags">
                    ${tagsHtml}
                </div>
                <button onclick="openModal(${post.id})" 
                        style="margin-top:15px; background:transparent; border:1px solid var(--accent-color); color:var(--accent-color); padding:5px 10px; cursor:pointer; border-radius:4px;">
                    Read More
                </button>
            `;
            gridEl.appendChild(card);
        });
    }

    // 7. Filtering Logic
    function filterPosts() {
        // Update state from inputs
        currentFilters.search = searchInput.value.toLowerCase();
        currentFilters.category = categorySelect.value;
        currentFilters.tag = tagSelect.value;
        currentFilters.date = dateSelect.value;

        const filtered = blogPosts.filter(post => {
            // Search Filter
            const matchesSearch = post.title.toLowerCase().includes(currentFilters.search);

            // Category Filter
            const matchesCategory = currentFilters.category === 'all' || post.category === currentFilters.category;

            // Tag Filter
            const matchesTag = currentFilters.tag === 'all' || post.tags.includes(currentFilters.tag);

            // Date Filter (Convert post date to "Month Year" format to compare)
            const postDateObj = new Date(post.date);
            const postDateStr = `${postDateObj.toLocaleString('default', { month: 'long' })} ${postDateObj.getFullYear()}`;
            const matchesDate = currentFilters.date === 'all' || postDateStr === currentFilters.date;

            return matchesSearch && matchesCategory && matchesTag && matchesDate;
        });

        renderPosts(filtered);
    }

    // 8. Event Listeners
    function setupEventListeners() {
        document.getElementById('apply-filters').addEventListener('click', filterPosts);

        document.getElementById('reset-filters').addEventListener('click', () => {
            searchInput.value = '';
            categorySelect.value = 'all';
            tagSelect.value = 'all';
            dateSelect.value = 'all';
            filterPosts();
        });

        // Search on Enter key
        searchInput.addEventListener('keyup', (e) => {
            if(e.key === 'Enter') filterPosts();
        });

        // Close Modal events
        closeModalBtn.onclick = function() {
            modal.style.display = "none";
        }
        window.onclick = function(event) {
            if (event.target == modal) {
                modal.style.display = "none";
            }
        }
    }

    // 9. Modal Logic (Exposed globally so HTML onclick works)
    window.openModal = function(id) {
        const post = blogPosts.find(p => p.id === id);
        if(!post) return;

        document.getElementById('modal-title').textContent = post.title;
        document.getElementById('modal-date').textContent = new Date(post.date).toLocaleDateString();
        document.getElementById('modal-category').textContent = post.category;
        document.getElementById('modal-body').innerHTML = `<p>${post.content}</p>`;

        const tagsHtml = post.tags.map(tag => `<span class="tag">${tag}</span>`).join('');
        document.getElementById('modal-tags').innerHTML = tagsHtml;

        modal.style.display = "block";
    }

    // Run
    init();

</script>

</body>
</html>
