        <button class="btn" onclick="closeModal()">Keep Brewing</button>
    </div>
</div>

<script>
    /* --- JAVASCRIPT LOGIC --- */

    // State Management
    let entries = [];
    let badgeCount = 0;

    // DOM Elements
    const form = document.getElementById('teaForm');
    const entriesList = document.getElementById('diary-entries');
    const cupsDisplay = document.getElementById('cups-count');
    const badgesDisplay = document.getElementById('badges-count');
    const modal = document.getElementById('rewardModal');
    const emptyState = document.getElementById('empty-state');

    // Handle Form Submission
    form.addEventListener('submit', function(e) {
        e.preventDefault();

        // 1. Gather Data
        const teaType = document.getElementById('teaType').value;
        const waterSource = document.getElementById('waterSource').value;
        const temp = document.getElementById('temp').value || 'N/A';
        const utensil = document.getElementById('utensil').value;
        const notes = document.getElementById('notes').value;
        const date = new Date().toLocaleDateString('en-US', {
            weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit'
        });

        const newEntry = {
            id: Date.now(),
            teaType,
            waterSource,
            temp,
            utensil,
            notes,
            date
        };

        // 2. Add to State
        entries.unshift(newEntry); // Add to beginning of array

        // 3. Render UI
        renderEntries();
        updateStats();

        // 4. Reset Form
        form.reset();
    });

    // Render Entries Function
    function renderEntries() {
        // Clear current list (except empty state, handled by logic)
        entriesList.innerHTML = '';

        if (entries.length === 0) {
            entriesList.appendChild(emptyState);
            emptyState.style.display = 'block';
            return;
        } 

        // Create HTML for each entry
        entries.forEach(entry => {
            const card = document.createElement('div');
            card.className = 'entry-card';
            card.innerHTML = `
                <div class="entry-header">
                    <span class="entry-title">${entry.teaType}</span>
                    <span class="entry-date">${entry.date}</span>
                </div>
                <div class="tags">
                    <span>&#127777; ${entry.temp}°C</span>
                    <span>&#128167; ${entry.waterSource}</span>
                    <span>&#129475; ${entry.utensil}</span>
                </div>
                <p style="margin-top: 15px; font-style: italic;">"${entry.notes}"</p>
                <div style="text-align: right; margin-top: 10px;">
                    <button class="btn share-btn" style="font-size: 0.8rem; padding: 5px 15px;" onclick="shareEntry(${entry.id})">
                        Share & Earn Badge
                    </button>
                </div>
            `;
            entriesList.appendChild(card);
        });
    }

    // Update Statistics
    function updateStats() {
        cupsDisplay.innerText = entries.length;
        badgesDisplay.innerText = badgeCount;
    }

    // Share Functionality (Simulated)
    window.shareEntry = function(id) {
        // Find the entry
        const entry = entries.find(e => e.id === id);

        // Simulate an API call or social intent
        console.log(`Sharing entry for ${entry.teaType}...`);

        // Increase Badge Count
        badgeCount++;
        updateStats();

        // Show Reward Modal
        modal.style.display = 'flex';
    };

    // Close Modal
    window.closeModal = function() {
        modal.style.display = 'none';
    };

    // Close modal if clicking outside content
    window.onclick = function(event) {
        if (event.target == modal) {
            modal.style.display = "none";
        }
    }

</script>

</body>
</html>
