    <style>
        /* --- CSS STYLES --- */

        :root {
            --bg-color: #b0e0e6; /* Powder Blue */
            --primary-color: #4169e1; /* Royal Blue */
            --accent-color: #1e90ff; /* Dodger Blue - lighter accent */
            --text-white: #ffffff;
            --text-dark: #333333;
            --card-bg: #ffffff;
            --shadow: 0 4px 6px rgba(0,0,0,0.1);
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background-color: var(--bg-color);
            margin: 0;
            padding: 20px;
            color: var(--text-dark);
            min-height: 100vh;
            display: flex;
            justify-content: center;
            align-items: flex-start;
        }

        .container {
            width: 100%;
            max-width: 900px;
            background-color: var(--card-bg);
            border-radius: 12px;
            box-shadow: var(--shadow);
            overflow: hidden;
            display: grid;
            grid-template-columns: 1fr;
        }

        /* Header */
        header {
            background-color: var(--primary-color);
            color: var(--text-white);
            padding: 20px;
            text-align: center;
        }

        header h1 {
            margin: 0;
            font-size: 1.8rem;
        }

        header p {
            margin: 5px 0 0;
            opacity: 0.9;
            font-size: 0.9rem;
        }

        /* Layout Grid for Desktop */
        .content-grid {
            display: grid;
            grid-template-columns: 1fr;
            gap: 20px;
            padding: 20px;
        }

        @media (min-width: 768px) {
            .content-grid {
                grid-template-columns: 1fr 1fr;
            }
        }

        /* Section Styling */
        .section-card {
            border: 1px solid #e0e0e0;
            border-radius: 8px;
            padding: 15px;
            background: #fafafa;
        }

        h2 {
            color: var(--primary-color);
            border-bottom: 2px solid var(--bg-color);
            padding-bottom: 8px;
            margin-top: 0;
            font-size: 1.2rem;
        }

        /* Input Forms */
        .form-group {
            margin-bottom: 15px;
        }

        label {
            display: block;
            margin-bottom: 5px;
            font-weight: 600;
            color: var(--primary-color);
        }

        input[type="text"], 
        input[type="number"], 
        select {
            width: 100%;
            padding: 10px;
            border: 2px solid #ddd;
            border-radius: 5px;
            box-sizing: border-box;
            font-size: 1rem;
            transition: border-color 0.3s;
        }

        input:focus, select:focus {
            border-color: var(--primary-color);
            outline: none;
        }

        button {
            background-color: var(--primary-color);
            color: var(--text-white);
            border: none;
            padding: 10px 20px;
            border-radius: 5px;
            cursor: pointer;
            font-weight: bold;
            transition: background-color 0.2s, transform 0.1s;
            width: 100%;
        }

        button:hover {
            background-color: var(--accent-color);
        }

        button:active {
            transform: scale(0.98);
        }

        button.secondary {
            background-color: #6c757d;
            margin-top: 10px;
        }

        /* Order List Table */
        .order-list-container {
            max-height: 250px;
            overflow-y: auto;
            border: 1px solid #eee;
            margin-bottom: 10px;
        }

        table {
            width: 100%;
            border-collapse: collapse;
            font-size: 0.9rem;
        }

        th, td {
            padding: 10px;
            text-align: left;
            border-bottom: 1px solid #eee;
        }

        th {
            background-color: var(--bg-color);
            color: var(--primary-color);
            position: sticky;
            top: 0;
        }

        .remove-btn {
            background-color: #ff4d4d;
            padding: 4px 8px;
            font-size: 0.8rem;
            width: auto;
        }

        /* Statistics & Results */
        .stats-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(120px, 1fr));
            gap: 10px;
            margin-bottom: 15px;
        }

        .stat-box {
            background-color: white;
            border: 1px solid var(--primary-color);
            padding: 10px;
            border-radius: 5px;
            text-align: center;
        }

        .stat-box span {
            display: block;
            font-weight: bold;
            color: var(--primary-color);
        }

        /* Final Results Box */
        .result-box {
            background-color: var(--bg-color);
            border: 2px solid var(--primary-color);
            border-radius: 8px;
            padding: 15px;
            margin-top: 20px;
        }

        .result-row {
            display: flex;
            justify-content: space-between;
            margin-bottom: 8px;
            font-size: 1.1rem;
        }

        .result-row.total {
            font-weight: bold;
            border-top: 1px solid var(--primary-color);
            padding-top: 10px;
            margin-top: 10px;
            font-size: 1.3rem;
            color: var(--primary-color);
        }

        .discount-badge {
            background-color: #28a745;
            color: white;
            padding: 2px 6px;
            border-radius: 4px;
            font-size: 0.8rem;
            margin-left: 5px;
        }

        /* Custom Dropdown Animation */
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(-10px); }
            to { opacity: 1; transform: translateY(0); }
        }

        .animate-fade {
            animation: fadeIn 0.3s ease-out;
        }

    </style>
</head>
<body>

<div class="container">
    <header>
        <h1>Union Meal Ordering System</h1>
        <p>Intelligent Group Ordering & Split Calculation</p>
    </header>

    <div class="content-grid">

        <!-- LEFT COLUMN: INPUTS -->
        <div class="left-col">
            <!-- 1. Add Order -->
            <div class="section-card">
                <h2>1. Place Order</h2>
                <div class="form-group">
                    <label for="userName">Name</label>
                    <input type="text" id="userName" placeholder="Enter colleague's name">
                </div>

                <div class="form-group">
                    <label for="dishSelect">Select Dish</label>
                    <select id="dishSelect">
                        <option value="" disabled selected>-- Choose a Meal --</option>
                        <!-- Options populated via JS -->
                    </select>
                </div>

                <div class="stat-box" id="pricePreview" style="margin-bottom: 10px; display:none;">
                    Price: $<span id="currentPrice" style="display:inline;">0</span>
                </div>

                <button onclick="addOrder()">Add to Order List</button>
            </div>

            <!-- 2. Configure Discounts (Simulation) -->
            <div class="section-card" style="margin-top: 20px;">
                <h2>2. Available Discounts</h2>
                <p style="font-size: 0.85rem; color: #666; margin-bottom: 10px;">The system will automatically apply the best one.</p>

                <div class="form-group">
                    <label>
                        <input type="checkbox" id="disc1" checked disabled> 
                        <strong>Flat $10 off</strong> (Orders over $50)
                    </label>
                </div>
                <div class="form-group">
                    <label>
                        <input type="checkbox" id="disc2" checked disabled> 
                        <strong>15% Off</strong> (Orders over $80)
                    </label>
                </div>
                <div class="form-group">
                    <label>
                        <input type="checkbox" id="disc3" checked disabled> 
                        <strong>20% Off</strong> (Orders over $150)
                    </label>
                </div>
            </div>
        </div>

        <!-- RIGHT COLUMN: DATA & RESULTS -->
        <div class="right-col">

            <!-- 3. Current Orders -->
