                            <tr>
                                <th>Name</th>
                                <th>Dish</th>
                                <th>Price</th>
                                <th>Action</th>
                            </tr>
                        </thead>
                        <tbody id="orderTableBody">
                            <!-- Rows added dynamically -->
                        </tbody>
                    </table>
                </div>
                <div style="text-align: right; color: #666; font-size: 0.9rem;" id="orderCount">Total People: 0</div>
            </div>

            <!-- 4. Dish Counts -->
            <div class="section-card" style="margin-top: 20px;">
                <h2>4. Dish Tally</h2>
