</div>

<script>
    /* --- JAVASCRIPT LOGIC --- */

    // Menu Data
    const menuItems = [
        { id: 1, name: "Kung Pao Chicken", price: 12.50 },
        { id: 2, name: "Beef & Broccoli", price: 14.00 },
        { id: 3, name: "Vegetable Lo Mein", price: 10.50 },
        { id: 4, name: "Sweet & Sour Pork", price: 13.00 },
        { id: 5, name: "Shrimp Fried Rice", price: 15.00 },
        { id: 6, name: "General Tso's Chicken", price: 13.50 }
    ];

    // State
    let orders = [];

    // Initialize
    window.onload = function() {
        populateMenu();
    };

    // 1. Populate Dropdown
    function populateMenu() {
        const select = document.getElementById('dishSelect');
        menuItems.forEach(item => {
            const option = document.createElement('option');
            option.value = item.id;
            option.textContent = `${item.name} ($${item.price.toFixed(2)})`;
            select.appendChild(option);
        });

        // Show price preview on selection
        select.addEventListener('change', function() {
            const item = menuItems.find(i => i.id == this.value);
            if(item) {
                document.getElementById('pricePreview').style.display = 'block';
                document.getElementById('currentPrice').textContent = item.price.toFixed(2);
            }
        });
    }

    // 2. Add Order Function
    function addOrder() {
        const nameInput = document.getElementById('userName');
        const dishSelect = document.getElementById('dishSelect');

        const name = nameInput.value.trim();
        const dishId = dishSelect.value;

        if (!name || !dishId) {
            alert("Please enter a name and select a dish.");
            return;
        }

        const selectedDish = menuItems.find(item => item.id == dishId);

        const newOrder = {
            id: Date.now(), // simple unique ID
            userName: name,
            dishName: selectedDish.name,
            price: selectedDish.price
        };

        orders.push(newOrder);

        // Clear Inputs
        nameInput.value = '';
        dishSelect.value = '';
        document.getElementById('pricePreview').style.display = 'none';

        updateUI();
    }

    // 3. Remove Order
    function removeOrder(id) {
        orders = orders.filter(order => order.id !== id);
        updateUI();
    }

    // 4. Update All UI Components
    function updateUI() {
        renderOrderTable();
        renderDishStats();
        calculateTotals();
    }

    // Render Table
    function renderOrderTable() {
        const tbody = document.getElementById('orderTableBody');
        tbody.innerHTML = '';

        orders.forEach(order => {
            const row = document.createElement('tr');
            row.className = 'animate-fade';
            row.innerHTML = `
                <td>${order.userName}</td>
                <td>${order.dishName}</td>
                <td>$${order.price.toFixed(2)}</td>
                <td><button class="remove-btn" onclick="removeOrder(${order.id})">X</button></td>
            `;
            tbody.appendChild(row);
        });

        document.getElementById('orderCount').textContent = `Total People: ${orders.length}`;
    }

    // Render Dish Tally (Counting Quantity)
    function renderDishStats() {
        const statsContainer = document.getElementById('dishStats');
        statsContainer.innerHTML = '';

        if (orders.length === 0) {
            statsContainer.innerHTML = '<div class="stat-box" style="grid-column: 1 / -1; color: #999;">No dishes added yet.</div>';
            return;
        }

        // Count logic
        const counts = {};
        orders.forEach(order => {
            counts[order.dishName] = (counts[order.dishName] || 0) + 1;
        });

        for (const [dish, count] of Object.entries(counts)) {
            const div = document.createElement('div');
            div.className = 'stat-box animate-fade';
            div.innerHTML = `${dish} <span>x ${count}</span>`;
            statsContainer.appendChild(div);
        }
    }

    // 5. Logic: Calculate Optimal Discount & Split
    function calculateTotals() {
        let subtotal = orders.reduce((sum, order) => sum + order.price, 0);

        // Define Discount Strategies
        const discounts = [
            { 
                name: "None", 
                amount: 0 
            },
            { 
                name: "Flat $10 Off", 
                condition: subtotal > 50, 
                calc: () => 10 
            },
            { 
                name: "15% Off", 
                condition: subtotal > 80, 
                calc: () => subtotal * 0.15 
            },
            { 
                name: "20% Off", 
                condition: subtotal > 150, 
                calc: () => subtotal * 0.20 
            }
        ];

        // Find Best Discount
        let bestDiscount = { name: "None", amount: 0 };

        discounts.forEach(d => {
            if (d.condition || d.name === "None") {
                let amt = d.calc ? d.calc() : 0;
                if (amt > bestDiscount.amount) {
                    bestDiscount = { name: d.name, amount: amt };
                }
            }
        });

        const finalTotal = subtotal - bestDiscount.amount;
        const perPerson = orders.length > 0 ? finalTotal / orders.length : 0;

        // Render Results
        document.getElementById('subtotalDisplay').textContent = `$${subtotal.toFixed(2)}`;
        document.getElementById('discountName').textContent = bestDiscount.amount > 0 ? bestDiscount.name : "None";
        document.getElementById('discountDisplay').textContent = `-$${bestDiscount.amount.toFixed(2)}`;
        document.getElementById('finalTotalDisplay').textContent = `$${finalTotal.toFixed(2)}`;
        document.getElementById('splitAmountDisplay').textContent = `$${perPerson.toFixed(2)}`;
    }

    // Reset
    function resetSystem() {
        if(confirm("Are you sure you want to clear all orders?")) {
            orders = [];
            updateUI();
        }
    }

</script>

</body>
</html>
