                <input type="text" id="userMsg" placeholder="Ask about 'appeal form' or 'timeline'..." onkeypress="handleEnter(event)">
                <button class="btn" onclick="sendMessage()">Send</button>
            </div>
        </div>

    </div>

    <!-- Modal -->
    <div id="successModal" class="modal">
        <div class="modal-content">
            <h2>Congratulations!</h2>
            <p>Your profile recovery process is marked as complete.</p>
            <button class="btn" onclick="closeModal()">Close</button>
        </div>
    </div>

    <script>
        /* --- JAVASCRIPT LOGIC --- */

        // 1. Form Submission & Analysis Logic
        document.getElementById('suspensionForm').addEventListener('submit', function(e) {
            e.preventDefault();

            const reason = document.getElementById('suspensionReason').value;
            const resultDiv = document.getElementById('analysis-result');
            const analysisText = document.getElementById('analysis-text');
            const solutionDiv = document.getElementById('dynamic-solution');
            const checklistDiv = document.getElementById('checklist');

            // Simulate loading
            resultDiv.style.display = 'block';
            analysisText.innerText = "Analyzing content guidelines against your selection...";
            solutionDiv.innerText = "";
            checklistDiv.innerHTML = '<p>Generating checklist...</p>';

            setTimeout(() => {
                // Dynamic Content based on selection
                let analysisMsg = "";
                let solutions = "";
                let checklistItems = "";

                switch(reason) {
                    case 'quality':
                        analysisMsg = "Analysis detected potential keywords in your business name or address discrepancies.";
                        solutions = "Remove keywords from business name. Ensure address matches utility bills exactly.";
                        checklistItems = `
                            <label><input type="checkbox" onclick="checkItem()"> Remove slogans from Business Name</label><br>
                            <label><input type="checkbox" onclick="checkItem()"> Upload permanent signage photo</label><br>
                            <label><input type="checkbox" onclick="checkItem()"> Match address with Secretary of State records</label>
                        `;
                        break;
                    case 'deceptive':
                        analysisMsg = "Flagged for content policy violations regarding reviews or description.";
                        solutions = "Audit recent reviews. Rewrite business description to be purely factual.";
                        checklistItems = `
                            <label><input type="checkbox" onclick="checkItem()"> Remove keyword stuffing in description</label><br>
                            <label><input type="checkbox" onclick="checkItem()"> Report spam reviews</label><br>
                            <label><input type="checkbox" onclick="checkItem()"> Verify website URL is functional</label>
                        `;
                        break;
                    case 'suspicious':
                    case 'unknown':
                        analysisMsg = "Triggered by automated fraud filters or sudden changes in core data.";
                        solutions = "Do not edit profile further. Prepare legal verification documents.";
                        checklistItems = `
                            <label><input type="checkbox" onclick="checkItem()"> Gather Business License PDF</label><br>
                            <label><input type="checkbox" onclick="checkItem()"> Scan Utility Bill (dated within 3 months)</label><br>
                            <label><input type="checkbox" onclick="checkItem()"> Video verification of office interior</label>
                        `;
                        break;
                }

                analysisText.innerText = analysisMsg;
                solutionDiv.innerText = "Recommended Fix: " + solutions;
                checklistDiv.innerHTML = checklistItems;

                // Update Status
                document.getElementById('status-text').innerText = "Analysis Complete - Action Required";
                addBotMessage("Analysis complete. Please check the 'Action Plan' section above for your to-do list.");

            }, 1500); // 1.5 second simulated delay
        });

        // 2. Progress Bar Logic
        function updateProgress(percent) {
            const bar = document.getElementById('progressBar');
            const statusText = document.getElementById('status-text');

            bar.style.width = percent + '%';
            bar.innerText = percent + '%';

            if(percent === 33) statusText.innerText = "Cleanup Phase";
            if(percent === 66) statusText.innerText = "Appeal Submitted - Waiting for Google";

            if(percent === 100) {
                statusText.innerText = "Profile Reinstated";
                bar.style.backgroundColor = "#4CAF50"; // Green for success
                document.getElementById('successModal').style.display = 'flex';
                addBotMessage("Great news! We've marked your case as resolved.");
            }
        }

        function checkItem() {
            // Simple logic to nudge progress slightly when checklist items are clicked
            const currentWidth = parseFloat(document.getElementById('progressBar').style.width) || 0;
            if(currentWidth < 30) {
                updateProgress(currentWidth + 10);
            }
        }

        // 3. Chat Bot Logic
        function handleEnter(e) {
            if (e.key === 'Enter') sendMessage();
        }

        function sendMessage() {
            const input = document.getElementById('userMsg');
            const msgText = input.value.trim();
            if (!msgText) return;

            // Add user message
            const chatBox = document.getElementById('chatBox');
            const userDiv = document.createElement('div');
            userDiv.className = 'message msg-user';
            userDiv.innerText = msgText;
            chatBox.appendChild(userDiv);

            input.value = "";
            chatBox.scrollTop = chatBox.scrollHeight;

            // Simulate Bot Response
            setTimeout(() => {
                let botResponse = "I'm not sure about that. Try selecting a suspension reason above.";
                const lowerMsg = msgText.toLowerCase();

                if(lowerMsg.includes('appeal') || lowerMsg.includes('form')) {
                    botResponse = "The Google Reinstatement form is the only way to appeal. Make sure your documents are ready before clicking submit.";
                } else if (lowerMsg.includes('time') || lowerMsg.includes('long')) {
                    botResponse = "Currently, Google support is taking 3-5 business days to review appeals.";
                } else if (lowerMsg.includes('help') || lowerMsg.includes('support')) {
                    botResponse = "I can help you audit your profile. What seems to be the main error message you received?";
                }

                addBotMessage(botResponse);
            }, 1000);
        }

        function addBotMessage(text) {
            const chatBox = document.getElementById('chatBox');
            const botDiv = document.createElement('div');
            botDiv.className = 'message msg-bot';
            botDiv.innerText = text;
            chatBox.appendChild(botDiv);
            chatBox.scrollTop = chatBox.scrollHeight;
        }

        // Modal Logic
        function closeModal() {
            document.getElementById('successModal').style.display = 'none';
        }

        // Close modal if clicked outside
        window.onclick = function(event) {
            const modal = document.getElementById('successModal');
            if (event.target == modal) {
                modal.style.display = "none";
            }
        }
    </script>
</body>
</html>
