<body>

    <!-- Header Section -->
    <header>
        <div>
            <h1>Installation Workboard</h1>
            <p style="color: #666; margin-top: 5px;">Airtable Custom View Integration</p>
        </div>
        <div class="controls">
            <div>
                <label for="startDate">Start Date:</label>
                <input type="date" id="startDate" class="date-picker">
            </div>
            <div>
                <label for="endDate">End Date:</label>
                <input type="date" id="endDate" class="date-picker">
            </div>
            <button id="loadBtn" onclick="loadWorkboard()">Refresh View</button>
        </div>
    </header>

    <!-- Main Grid -->
    <div class="workboard-container">
        <table id="workboardTable">
            <thead>
                <tr id="tableHeaderRow">
                    <th style="min-width: 150px; z-index: 20; left: 0;">Team Name</th>
                    <!-- Date headers will be injected here via JS -->
                </tr>
            </thead>
            <tbody id="tableBody">
                <!-- Data rows will be injected here via JS -->
            </tbody>
        </table>
    </div>

    <!-- Task Detail Modal -->
    <div id="taskModal" class="modal">
        <div class="modal-content">
            <span class="close" onclick="closeModal()">&times;</span>
            <h2 id="modalTitle" style="color: var(--primary-color);">Task Details</h2>
            <p><strong>Customer:</strong> <span id="modalCustomer"></span></p>
            <p><strong>Description:</strong> <span id="modalDesc"></span></p>
            <p><strong>Hours Allocated:</strong> <span id="modalHours"></span> hrs</p>
            <p><strong>Job Type:</strong> <span id="modalMeta"></span></p>
            <p><strong>Assigned Team:</strong> <span id="modalTeam"></span></p>
            <p><strong>Date:</strong> <span id="modalDate"></span></p>
        </div>
    </div>

    <script>
        // --- 1. MOCK DATA GENERATION (Simulating Airtable API) ---

        const TEAMS = ["Alpha Squad", "Beta Builders", "Gamma Group", "Delta Installers"];

        // Helper to get dates
        function getDatesInRange(startDate, endDate) {
            const date = new Date(startDate);
            const end = new Date(endDate);
            const dates = [];
            while (date <= end) {
                dates.push(new Date(date));
                date.setDate(date.getDate() + 1);
            }
            return dates;
        }

        // Generate random mock tasks
        function generateMockData(dates) {
            const tasks = [];
            const customers = ["Acme Corp", "Globex", "Soylent Corp", "Initech", "Umbrella Corp", "Stark Ind", "Wayne Ent"];
            const descriptions = ["Server Install", "Cabling Phase 1", "Maintenance", "Security Setup", "Inspection", "Hardware Upgrade"];
            const metaData = ["High Priority", "Standard", "Urgent", "Warranty Work"];

            TEAMS.forEach(team => {
                dates.forEach(date => {
                    // Random number of tasks (0 to 5)
                    const numTasks = Math.floor(Math.random() * 6);

                    for(let i=0; i<numTasks; i++) {
                        tasks.push({
                            id: Math.random().toString(36).substr(2, 9),
                            team: team,
                            date: date.toISOString().split('T')[0],
                            customer: customers[Math.floor(Math.random() * customers.length)],
                            description: descriptions[Math.floor(Math.random() * descriptions.length)],
                            hours: Math.floor(Math.random() * 4) + 1, // 1 to 4 hours
                            meta: metaData[Math.floor(Math.random() * metaData.length)]
                        });
                    }
                });
            });
            return tasks;
        }

        // --- 2. CORE LOGIC ---

        function init() {
            // Set default date range (Today + 14 days)
            const today = new Date();
            const twoWeeksLater = new Date();
            twoWeeksLater.setDate(today.getDate() + 13); // 14 days total including today

            document.getElementById('startDate').valueAsDate = today;
            document.getElementById('endDate').valueAsDate = twoWeeksLater;

            loadWorkboard();
        }

        function loadWorkboard() {
            const startVal = document.getElementById('startDate').value;
            const endVal = document.getElementById('endDate').value;

            if (!startVal || !endVal) {
                alert("Please select a valid date range.");
                return;
            }

            if (startVal > endVal) {
                alert("Start date cannot be after end date.");
                return;
            }

            const dates = getDatesInRange(startVal, endVal);

            // Limit range to prevent massive tables if user selects a year
            if (dates.length > 21) {
                alert("Please select a range of 3 weeks or less for optimal viewing.");
                return;
            }

            const tasks = generateMockData(dates);
            renderTable(dates, tasks);
        }

        function renderTable(dates, tasks) {
            const theadRow = document.getElementById('tableHeaderRow');
            const tbody = document.getElementById('tableBody');

            // Clear existing headers (keep first one)
            while (theadRow.children.length > 1) {
                theadRow.removeChild(theadRow.lastChild);
            }
            tbody.innerHTML = '';

            // 1. Build Headers
            dates.forEach(date => {
                const th = document.createElement('th');
                const dayName = date.toLocaleDateString('en-US', { weekday: 'short' });
                const dayDate = date.toLocaleDateString('en-US', { month: 'numeric', day: 'numeric' });
                th.innerHTML = `${dayName}<br><small>${dayDate}</small>`;
                theadRow.appendChild(th);
            });

            // 2. Build Rows per Team
            TEAMS.forEach(team => {
                const tr = document.createElement('tr');

                // Team Name Cell (Sticky)
                const teamHeader = document.createElement('th');
                teamHeader.className = 'team-header';
                teamHeader.textContent = team;
                tr.appendChild(teamHeader);

                // Date Cells
                dates.forEach(date => {
                    const dateStr = date.toISOString().split('T')[0];
                    const td = document.createElement('td');
                    const cellContainer = document.createElement('div');
                    cellContainer.className = 'day-cell';

                    // Filter tasks for this team AND this date
                    const dayTasks = tasks.filter(t => t.team === team && t.date === dateStr);

                    // Cap at 7 tasks per day as requested
                    const tasksToRender = dayTasks.slice(0, 7);

                    // Calculate Total Hours for the day to determine proportions
                    // (Assuming a workday is 8-10 hours, but here we just stack flex items)

                    tasksToRender.forEach(task => {
                        const card = document.createElement('div');
                        card.className = 'task-card';

                        // Set flex grow based on hours (visual proportion)
                        // Adding a base minimum so small tasks don't disappear
                        card.style.flex = `${task.hours} 1 auto`; 

                        card.innerHTML = `
                            <span class="task-hours">${task.hours}h</span>
                            <span class="task-customer">${task.customer}</span>
                            <span class="task-desc">${task.description}</span>
                            <span class="task-meta">${task.meta}</span>
                        `;

                        // Add click event for details
                        card.onclick = () => openModal(task);

                        cellContainer.appendChild(card);
                    });

                    // Add Notes Section at bottom of cell
                    const notesArea = document.createElement('div');
                    notesArea.className = 'notes-area';
                    notesArea.innerHTML = `<textarea class="notes-input" placeholder="Notes..." rows="1"></textarea>`;

                    // Push notes to bottom
                    notesArea.style.marginTop = 'auto'; 
                    cellContainer.appendChild(notesArea);

                    td.appendChild(cellContainer);
                    tr.appendChild(td);
                });

                tbody.appendChild(tr);
            });
        }

        // --- 3. MODAL INTERACTION ---

        function openModal(task) {
            document.getElementById('modalCustomer').textContent = task.customer;
            document.getElementById('modalDesc').textContent = task.description;
            document.getElementById('modalHours').textContent = task.hours;
            document.getElementById('modalMeta').textContent = task.meta;
            document.getElementById('modalTeam').textContent = task.team;
            document.getElementById('modalDate').textContent = task.date;

            const modal = document.getElementById('taskModal');
            modal.style.display = "block";
        }

        function closeModal() {
            document.getElementById('taskModal').style.display = "none";
        }

        // Close modal when clicking outside
        window.onclick = function(event) {
            const modal = document.getElementById('taskModal');
            if (event.target == modal) {
                modal.style.display = "none";
            }
        }

        // --- 4. STARTUP ---
        window.onload = init;

    </script>
</body>
</html>
