            <p class="subtitle">Real-time sorting for upcoming events</p>
        </header>

        <div class="controls">
            <div class="sort-group">
                <label for="sortCriteria">Sort By:</label>
                <select id="sortCriteria">
                    <option value="default" disabled selected>Select Criteria</option>
                    <option value="price">Price ($)</option>
                    <option value="date">Date</option>
                    <option value="location">Location (A-Z)</option>
                </select>

                <label for="sortOrder">Order:</label>
                <select id="sortOrder">
                    <option value="asc">Ascending ⬆️</option>
                    <option value="desc">Descending ⬇️</option>
                </select>
            </div>

            <button id="resetBtn">Reset List</button>
        </div>

        <div class="table-wrapper">
            <table id="ticketTable">
                <thead>
                    <tr>
                        <th>Event Name</th>
                        <th>Location</th>
                        <th>Date</th>
                        <th>Price</th>
                    </tr>
                </thead>
                <tbody id="tableBody">
                    <!-- Rows will be injected here via JavaScript -->
                </tbody>
            </table>
        </div>

        <div style="margin-top: 20px; text-align: right; font-size: 0.8rem; color: #888;">
            <span id="resultCount">0</span> tickets found
        </div>
    </div>

    <script>
        /* --- JAVASCRIPT LOGIC --- */

        // 1. Data Structure: Array of ticket objects
        const initialTickets = [
            { id: 1, event: "Jazz in the Park", location: "Chicago, IL", date: "2023-11-15", price: 45.00 },
            { id: 2, event: "Tech Summit 2023", location: "Austin, TX", date: "2023-12-01", price: 299.99 },
            { id: 3, event: "Winter Symphony", location: "New York, NY", date: "2023-12-24", price: 120.50 },
            { id: 4, event: "Indie Film Festival", location: "Portland, OR", date: "2024-01-10", price: 35.00 },
            { id: 5, event: "Comic Convention", location: "San Diego, CA", date: "2023-10-30", price: 85.00 },
            { id: 6, event: "Charity Gala", location: "Boston, MA", date: "2023-11-05", price: 500.00 },
            { id: 7, event: "Rock Concert", location: "Seattle, WA", date: "2023-10-25", price: 75.00 },
            { id: 8, event: "Food & Wine Expo", location: "Napa Valley, CA", date: "2024-02-14", price: 150.00 },
        ];

        // State management
        let currentTickets = [...initialTickets];

        // DOM Elements
        const tableBody = document.getElementById('tableBody');
        const sortCriteriaSelect = document.getElementById('sortCriteria');
        const sortOrderSelect = document.getElementById('sortOrder');
        const resetBtn = document.getElementById('resetBtn');
        const resultCount = document.getElementById('resultCount');

        // 2. Function to Render the Table
        function renderTable(data) {
            tableBody.innerHTML = ""; // Clear existing rows

            data.forEach(ticket => {
                const row = document.createElement('tr');

                // Format Date for better readability
                const dateObj = new Date(ticket.date);
                const dateStr = dateObj.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });

                row.innerHTML = `
                    <td><strong>${ticket.event}</strong></td>
                    <td>${ticket.location}</td>
                    <td>${dateStr}</td>
                    <td><span class="price-tag">$${ticket.price.toFixed(2)}</span></td>
                `;
                tableBody.appendChild(row);
            });

            // Update count
            resultCount.textContent = data.length;
        }

        // 3. Sorting Logic
        function sortTickets() {
            const criteria = sortCriteriaSelect.value;
            const order = sortOrderSelect.value;

            if (criteria === 'default') return;

            const sorted = [...currentTickets].sort((a, b) => {
                let valA = a[criteria];
                let valB = b[criteria];

                // Check if sorting numbers or strings
                if (criteria === 'price') {
                    // Numeric comparison
                    return order === 'asc' ? valA - valB : valB - valA;
                } else if (criteria === 'date') {
                    // Date comparison
                    const dateA = new Date(valA);
                    const dateB = new Date(valB);
                    return order === 'asc' ? dateA - dateB : dateB - dateA;
                } else {
                    // String comparison (Location)
                    valA = valA.toLowerCase();
                    valB = valB.toLowerCase();
                    if (valA < valB) return order === 'asc' ? -1 : 1;
                    if (valA > valB) return order === 'asc' ? 1 : -1;
                    return 0;
                }
            });

            renderTable(sorted);
        }

        // 4. Reset Logic
        function resetTool() {
            currentTickets = [...initialTickets]; // Reset data
            sortCriteriaSelect.value = 'default'; // Reset dropdown
            sortOrderSelect.value = 'asc'; // Reset order
            renderTable(currentTickets); // Re-render
        }

        // 5. Event Listeners
        sortCriteriaSelect.addEventListener('change', sortTickets);
        sortOrderSelect.addEventListener('change', sortTickets);
        resetBtn.addEventListener('click', resetTool);

        // Initial Render
        renderTable(currentTickets);

    </script>
</body>
</html>
