    <script>
        // --- State Management ---
        let costs = [];
        let revenues = [];

        // --- DOM Elements ---
        const costListEl = document.getElementById('costList');
        const revenueListEl = document.getElementById('revenueList');
        const projectNameInput = document.getElementById('projectName');
        const projectHeader = document.getElementById('projectHeader');

        // Display Elements
        const totalRevEl = document.getElementById('totalRevenueDisplay');
        const totalCostEl = document.getElementById('totalCostDisplay');
        const netProfitEl = document.getElementById('netProfitDisplay');
        const marginBar = document.getElementById('marginBar');
        const marginComment = document.getElementById('marginComment');

        // --- Event Listeners ---
        projectNameInput.addEventListener('input', (e) => {
            projectHeader.textContent = e.target.value || "New Project";
        });

        // --- Core Functions ---

        function formatCurrency(num) {
            return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(num);
        }

        function addCost() {
            const name = document.getElementById('costName').value;
            const amount = parseFloat(document.getElementById('costAmount').value);

            if (name && amount > 0) {
                costs.push({ id: Date.now(), name, amount });
                document.getElementById('costName').value = '';
                document.getElementById('costAmount').value = '';
                renderLists();
                calculateProfitability();
            } else {
                alert("Please enter a valid name and amount.");
            }
        }

        function addRevenue() {
            const name = document.getElementById('revenueName').value;
            const amount = parseFloat(document.getElementById('revenueAmount').value);

            if (name && amount > 0) {
                revenues.push({ id: Date.now(), name, amount });
                document.getElementById('revenueName').value = '';
                document.getElementById('revenueAmount').value = '';
                renderLists();
                calculateProfitability();
            } else {
                alert("Please enter a valid name and amount.");
            }
        }

        function removeItem(type, id) {
            if (type === 'cost') {
                costs = costs.filter(item => item.id !== id);
            } else {
                revenues = revenues.filter(item => item.id !== id);
            }
            renderLists();
            calculateProfitability();
        }

        function renderLists() {
            // Render Costs
            costListEl.innerHTML = '';
            costs.forEach(item => {
                const div = document.createElement('div');
                div.className = 'entry-item';
                div.innerHTML = `
                    <span>${item.name}</span>
                    <div>
                        <strong>${formatCurrency(item.amount)}</strong>
                        <button class="remove-btn" onclick="removeItem('cost', ${item.id})">&times;</button>
                    </div>
                `;
                costListEl.appendChild(div);
            });

            // Render Revenues
            revenueListEl.innerHTML = '';
            revenues.forEach(item => {
                const div = document.createElement('div');
                div.className = 'entry-item';
                div.innerHTML = `
                    <span>${item.name}</span>
                    <div>
                        <strong>${formatCurrency(item.amount)}</strong>
                        <button class="remove-btn" onclick="removeItem('revenue', ${item.id})">&times;</button>
                    </div>
                `;
                revenueListEl.appendChild(div);
            });
        }

        function calculateProfitability() {
            const totalCost = costs.reduce((sum, item) => sum + item.amount, 0);
            const totalRevenue = revenues.reduce((sum, item) => sum + item.amount, 0);
            const profit = totalRevenue - totalCost;

            // Avoid division by zero
            let margin = 0;
            if (totalRevenue > 0) {
                margin = (profit / totalRevenue) * 100;
            }

            // Update UI
            totalRevEl.textContent = formatCurrency(totalRevenue);
            totalCostEl.textContent = formatCurrency(totalCost);
            netProfitEl.textContent = formatCurrency(profit);

            // Update Margin Bar
            // Clamp margin between 0 and 100 for visual bar width, but show real value in text
            let barWidth = margin;
            if (barWidth < 0) barWidth = 0;
            if (barWidth > 100) barWidth = 100;

            marginBar.style.width = `${barWidth}%`;
            marginBar.textContent = `${margin.toFixed(1)}%`;

            // Color coding for profit
            if (profit < 0) {
                netProfitEl.style.color = '#d9534f'; // Red
                marginBar.style.backgroundColor = '#d9534f';
                marginComment.textContent = "Warning: Project is operating at a loss.";
                marginComment.style.color = '#d9534f';
            } else {
                netProfitEl.style.color = 'white'; // White because background is green
                marginBar.style.backgroundColor = '#228B22'; // Forest Green

                if (margin > 30) {
                    marginComment.textContent = "Excellent! High profitability.";
                    marginComment.style.color = '#228B22';
                } else if (margin > 15) {
                    marginComment.textContent = "Good. Healthy margin.";
                    marginComment.style.color = '#228B22';
                } else {
                    marginComment.textContent = "Low margin. Review costs.";
                    marginComment.style.color = '#FFA500'; // Orange
                    marginBar.style.backgroundColor = '#FFA500';
                }
            }
        }

        function generateReport() {
            const x = document.getElementById("toast");
            x.className = "show";
            setTimeout(function(){ x.className = x.className.replace("show", ""); }, 3000);

            console.log({
                project: projectNameInput.value,
                type: document.getElementById('projectType').value,
                costs: costs,
                revenues: revenues,
                timestamp: new Date()
            });
        }

        // Initialize with sample data for demonstration
        function initDemo() {
            costs.push({ id: 1, name: "Lead Consultant (120h)", amount: 18000 });
            costs.push({ id: 2, name: "Travel & Expenses", amount: 2500 });
            revenues.push({ id: 3, name: "Phase 1: Strategy", amount: 35000 });

            document.getElementById('projectName').value = "Alpha Strategy Audit";
            projectHeader.textContent = "Alpha Strategy Audit";

            renderLists();
            calculateProfitability();
        }

        // Run initialization
        initDemo();

    </script>
</body>
