                        <option value="Fall 2023">Fall 2023</option>
                        <option value="Spring 2023">Spring 2023</option>
                    </select>
                    <select id="sortOption">
                        <option value="default">Sort By</option>
                        <option value="scoreDesc">Score (High-Low)</option>
                        <option value="scoreAsc">Score (Low-High)</option>
                        <option value="name">Course Name</option>
                    </select>
                </div>
                <button onclick="applyFilters()" style="width: 100%; padding: 8px;">Update View</button>
            </div>

            <div id="reportsContainer" class="report-grid">
                <!-- Data injected here via JS -->
            </div>

            <div class="action-area">
                <button onclick="exportData()">Download Report (CSV)</button>
                <p style="margin-top: 10px; font-size: 0.8rem; cursor: pointer; text-decoration: underline;" onclick="logout()">Log Out</p>
            </div>
        </section>
