    <script>
        // --- Mock Data ---
        const studentData = {
            id: "S123",
            name: "John Smith",
            courses: [
                { id: 101, name: "Mathematics", score: 92, semester: "Fall 2023", credits: 4 },
                { id: 102, name: "Physics", score: 85, semester: "Fall 2023", credits: 3 },
                { id: 103, name: "History", score: 78, semester: "Spring 2023", credits: 2 },
                { id: 104, name: "Computer Science", score: 98, semester: "Fall 2023", credits: 4 },
                { id: 105, name: "English Lit", score: 88, semester: "Spring 2023", credits: 3 },
                { id: 106, name: "Art", score: 95, semester: "Spring 2023", credits: 2 }
            ]
        };

        // --- State ---
        let currentData = [...studentData.courses];

        // --- DOM Elements ---
        const loginSection = document.getElementById('login-section');
        const dashboardSection = document.getElementById('dashboard-section');
        const loginForm = document.getElementById('loginForm');
        const reportsContainer = document.getElementById('reportsContainer');
        const notification = document.getElementById('notification');

        // --- Initialization ---
        document.getElementById('currentDate').textContent = new Date().toLocaleDateString();

        // --- Functions ---

        // 1. Login Logic
        loginForm.addEventListener('submit', function(e) {
            e.preventDefault();
            const id = document.getElementById('studentId').value;
            // Simple mock validation
            if(id) {
                showToast("Login Successful");
                loginSection.style.display = 'none';
                dashboardSection.style.display = 'block';
                loadDashboard();
            }
        });

        function logout() {
            dashboardSection.style.display = 'none';
            loginSection.style.display = 'flex';
            document.getElementById('studentId').value = '';
            document.getElementById('password').value = '';
        }

        // 2. Render Dashboard
        function loadDashboard() {
            document.getElementById('studentNameDisplay').textContent = studentData.name;
            document.getElementById('studentIdDisplay').textContent = studentData.id;
            renderCourses(currentData);
        }

        function renderCourses(data) {
            reportsContainer.innerHTML = '';

            if(data.length === 0) {
                reportsContainer.innerHTML = '<p style="text-align:center; color:#666;">No records found.</p>';
                return;
            }

            data.forEach(course => {
                const statusClass = course.score >= 60 ? 'status-pass' : 'status-fail';
                const statusText = course.score >= 60 ? 'Passed' : 'Needs Improvement';

                const card = document.createElement('div');
                card.className = 'course-card';
                card.innerHTML = `
                    <div class="course-header">
                        <span class="course-title">${course.name}</span>
                        <span class="course-score">${course.score}</span>
                    </div>
                    <div class="course-details">
                        <p>Semester: ${course.semester}</p>
                        <p>Credits: ${course.credits}</p>
                        <span class="status-badge ${statusClass}">${statusText}</span>
                    </div>
                `;
                reportsContainer.appendChild(card);
            });
        }

        // 3. Filter and Sort Logic
        function applyFilters() {
            const semesterFilter = document.getElementById('filterSemester').value;
            const sortType = document.getElementById('sortOption').value;

            // Reset to original data
            let filtered = [...studentData.courses];

            // Apply Filter
            if (semesterFilter !== 'all') {
                filtered = filtered.filter(c => c.semester === semesterFilter);
            }

            // Apply Sort
            if (sortType === 'scoreDesc') {
                filtered.sort((a, b) => b.score - a.score);
            } else if (sortType === 'scoreAsc') {
                filtered.sort((a, b) => a.score - b.score);
            } else if (sortType === 'name') {
                filtered.sort((a, b) => a.name.localeCompare(b.name));
            }

            currentData = filtered;
            renderCourses(currentData);
            showToast("View Updated");
        }

        // 4. Export Function
        function exportData() {
            const headers = "Course Name,Score,Semester,Credits\n";
            const rows = currentData.map(c => `${c.name},${c.score},${c.semester},${c.credits}`).join("\n");
            const csvContent = "data:text/csv;charset=utf-8," + headers + rows;

            const encodedUri = encodeURI(csvContent);
            const link = document.createElement("a");
            link.setAttribute("href", encodedUri);
            link.setAttribute("download", `${studentData.name}_Learning_Report.csv`);
            document.body.appendChild(link); // Required for FF

            link.click();
            document.body.removeChild(link);
            showToast("Download Started");
        }

        // 5. Utilities
        function showToast(message) {
            notification.textContent = message;
            notification.style.opacity = '1';
            setTimeout(() => {
                notification.style.opacity = '0';
            }, 2000);
        }
    </script>
