                                <span>📍 ${school.city}</span>
                                <span>👥 ${school.students}</span>
                            </div>
                            <div style="margin-bottom:15px; display:flex; gap:5px; flex-wrap:wrap;">
                                ${school.majors.slice(0, 2).map(m => `<span class="tag">${m}</span>`).join('')}
                            </div>
                            <button class="view-btn">View Details</button>
                        </div>
                    `;
                    grid.appendChild(card);
                });
            }
        }

        // Render Ranking Table
        function renderRankingTable(data) {
            const tbody = document.getElementById('rankingTableBody');
            tbody.innerHTML = '';

            // Sort by rank specifically for this table view
            const sortedData = [...data].sort((a, b) => a.rank - b.rank);

            sortedData.forEach(school => {
                const tr = document.createElement('tr');
                tr.innerHTML = `
                    <td><strong>#${school.rank}</strong></td>
                    <td style="font-weight:bold; color:var(--primary-dark);">${school.name}</td>
                    <td>${school.city}, ${school.country}</td>
                    <td>${school.tuition}</td>
                    <td>${school.acceptanceRate}</td>
                    <td><button style="padding:5px 10px; cursor:pointer;" onclick="openModal(${school.id})">Details</button></td>
                `;
                tbody.appendChild(tr);
            });
        }

        // --- 4. Filtering & Sorting Logic ---

        function filterSchools() {
            const searchText = document.getElementById('searchInput').value.toLowerCase();
            const countryVal = document.getElementById('countryFilter').value;

            const filtered = schoolsData.filter(school => {
                // Search Match
                const matchSearch = school.name.toLowerCase().includes(searchText) || 
                                    school.city.toLowerCase().includes(searchText) ||
                                    school.majors.some(m => m.toLowerCase().includes(searchText));

                // Country Match
                const matchCountry = countryVal === 'all' || school.country === countryVal;

                return matchSearch && matchCountry;
            });

            // Apply current sort after filter
            applySort(filtered);
        }

        function sortSchools() {
            // Trigger filter, which calls applySort internally
            filterSchools();
        }

        function applySort(data) {
            const sortVal = document.getElementById('sortFilter').value;

            data.sort((a, b) => {
                if (sortVal === 'rankAsc') return a.rank - b.rank;
                if (sortVal === 'rankDesc') return b.rank - a.rank;
                if (sortVal === 'nameAsc') return a.name.localeCompare(b.name);
                return 0;
            });

            renderSchools(data);
        }

        // --- 5. Navigation & UI Logic ---

        function switchTab(tabName) {
            // Update Nav Styles
            document.querySelectorAll('nav a').forEach(el => el.classList.remove('active'));
            document.getElementById(`nav-${tabName}`).classList.add('active');

            // Toggle Sections
            const libraryView = document.getElementById('library-view');
            const rankingsView = document.getElementById('rankings-view');
            const controls = document.querySelector('.controls-container');

            if (tabName === 'library') {
                libraryView.classList.remove('hidden');
                rankingsView.classList.add('hidden');
                controls.classList.remove('hidden'); // Show filters
            } else {
                libraryView.classList.add('hidden');
                rankingsView.classList.remove('hidden');
                controls.classList.add('hidden'); // Hide filters for ranking view (optional choice)
            }
        }

        // --- 6. Modal Logic ---

        function openModal(id) {
            const school = schoolsData.find(s => s.id === id);
            if (!school) return;

            // Populate Modal
            document.getElementById('modalTitle').innerText = school.name;
            document.getElementById('modalRank').innerText = `#${school.rank}`;
            document.getElementById('modalLocation').innerText = `${school.city}, ${school.country}`;
            document.getElementById('modalDesc').innerText = school.description;
            document.getElementById('modalTuition').innerText = school.tuition;
            document.getElementById('modalRate').innerText = school.acceptanceRate;
            document.getElementById('modalStudents').innerText = school.students;

            const majorsContainer = document.getElementById('modalMajors');
            majorsContainer.innerHTML = school.majors.map(m => `<span class="tag" style="background:#e0e0e0;">${m}</span>`).join('');

            // Show Modal
            const modal = document.getElementById('schoolModal');
            modal.style.display = 'flex';
        }

        function closeModal() {
            document.getElementById('schoolModal').style.display = 'none';
        }

        // Close modal if clicking outside content
        window.onclick = function(event) {
            const modal = document.getElementById('schoolModal');
            if (event.target == modal) {
                closeModal();
            }
        }
    </script>
</body>
</html>
