            const container = document.getElementById('jobsContainer');
            jobs.forEach(job => {
                const item = document.createElement('div');
                item.className = 'job-item';
                item.innerHTML = `
                    <div class="job-info">
                        <h4>${job.title}</h4>
                        <div class="job-meta">
                            <strong>${job.clinic}</strong> &bull; ${job.location} &bull; ${job.type}
                        </div>
                        <div style="color: green; font-weight: 500; margin-top: 5px;">${job.salary}</div>
                    </div>
                    <button onclick="openModal('Job: ${job.title} at ${job.clinic}')" class="cta-button">Apply</button>
                `;
                container.appendChild(item);
            });
        }

        // --- INTERACTION FUNCTIONS ---

        // Mobile Menu Toggle
        function toggleMenu() {
            const navLinks = document.querySelector('.nav-links');
            navLinks.classList.toggle('active');
        }

        // Mobile Dropdown Toggle
        function toggleMobileDropdown(element) {
            if(window.innerWidth <= 768) {
                element.classList.toggle('active');
            }
        }

        // Filter Courses
        function filterCourses(category) {
            renderCourses(category);
            // Close mobile menu if open
            const navLinks = document.querySelector('.nav-links');
            if (navLinks.classList.contains('active')) {
                navLinks.classList.remove('active');
            }
        }

        // Modal Logic
        const modal = document.getElementById("applicationModal");
        const modalTitle = document.getElementById("modalTitle");
        const subjectInput = document.getElementById("applySubject");

        function openModal(subject) {
            modal.style.display = "block";
            modalTitle.innerText = "Apply for " + subject;
            subjectInput.value = subject;
        }

        function closeModal() {
            modal.style.display = "none";
        }

        // Close modal if clicking outside content
        window.onclick = function(event) {
            if (event.target == modal) {
                closeModal();
            }
        }

        // Form Handling
        function handleFormSubmit(e) {
            e.preventDefault();
            const name = document.getElementById('name').value;
            const subject = document.getElementById('applySubject').value;

            alert(`Thank you, ${name}! Your application for "${subject}" has been submitted successfully. We will contact you shortly.`);

            document.getElementById('applyForm').reset();
            closeModal();
        }

        // --- INITIALIZATION ---
        document.addEventListener('DOMContentLoaded', () => {
            renderCourses();
            renderFaculty();
            renderJobs();
        });

    </script>
</body>
</html>
