<script>
    // --- DATA STORE (Simulated Database) ---
    const skills = [
        { id: 1, name: 'Java Programming', category: 'Technical' },
        { id: 2, name: 'Project Management', category: 'Management' }
    ];

    const trainingPlans = [
        { title: 'Java Basics', trainer: 'John Doe', duration: 10, status: 'Active' },
        { title: 'PMP Prep', trainer: 'Jane Smith', duration: 40, status: 'Upcoming' }
    ];

    const employeeTraining = [
        { emp: 'Alice Walker', plan: 'Java Basics', date: '2023-10-01', status: 'In Progress' }
    ];

    const employeeSkills = [
        { emp: 'Alice Walker', skill: 'Java Programming', score: 85 },
        { emp: 'Bob Builder', skill: 'Project Management', score: 92 },
        { emp: 'Charlie Day', skill: 'Java Programming', score: 45 }
    ];

    // --- INITIALIZATION ---
    document.addEventListener('DOMContentLoaded', () => {
        renderSkillsTable();
        renderPlansTable();
        updateDropdowns();
        renderEmpTrainingTable();
        renderQueryTable();
    });

    // --- NAVIGATION LOGIC ---
    function openSection(sectionId) {
        // Hide all sections
        document.querySelectorAll('.section').forEach(sec => {
            sec.classList.remove('active');
        });
        // Show specific section
        document.getElementById(sectionId).classList.add('active');

        // Update tabs styling
        document.querySelectorAll('.tab-btn').forEach(btn => {
            btn.classList.remove('active');
            if(btn.getAttribute('onclick').includes(sectionId)) {
                btn.classList.add('active');
            }
        });
    }

    // --- TOAST NOTIFICATION ---
    function showToast(message) {
        const x = document.getElementById("toast");
        x.textContent = message;
        x.className = "show";
        setTimeout(function(){ x.className = x.className.replace("show", ""); }, 3000);
    }

    // --- BASIC INFO FUNCTIONS ---
    function addSkill() {
        const name = document.getElementById('skillName').value;
        const cat = document.getElementById('skillCategory').value;

        if(!name) { alert("Please enter a skill name."); return; }

        skills.push({ id: skills.length + 1, name: name, category: cat });
        renderSkillsTable();
        updateDropdowns();
        showToast('Skill Added Successfully');
        document.getElementById('skillForm').reset();
    }

    function renderSkillsTable() {
        const tbody = document.querySelector('#skillsTable tbody');
        tbody.innerHTML = '';
        skills.forEach(skill => {
            tbody.innerHTML += `
                <tr>
                    <td>${skill.id}</td>
                    <td>${skill.name}</td>
                    <td>${skill.category}</td>
                    <td><button style="color:red; border:none; background:none; cursor:pointer;">Delete</button></td>
                </tr>`;
        });
    }

    // --- TRAINING SETTING FUNCTIONS ---
    function addTrainingPlan() {
        const title = document.getElementById('trainTitle').value;
        const trainer = document.getElementById('trainTrainer').value;
        const duration = document.getElementById('trainDuration').value;

        if(!title) { alert("Please enter training title."); return; }

        trainingPlans.push({ title, trainer, duration, status: 'Active' });
        renderPlansTable();
        updateDropdowns();
        showToast('Training Plan Created');
    }

    function renderPlansTable() {
        const tbody = document.querySelector('#plansTable tbody');
        tbody.innerHTML = '';
        trainingPlans.forEach(plan => {
            tbody.innerHTML += `
                <tr>
                    <td>${plan.title}</td>
                    <td>${plan.trainer}</td>
                    <td>${plan.duration} hrs</td>
                    <td><span class="badge badge-completed">${plan.status}</span></td>
                </tr>`;
        });
    }

    // --- TRAINING APPLICATION FUNCTIONS ---
    function updateDropdowns() {
        // Update Assign Plan Dropdown
        const planSelect = document.getElementById('assignPlanSelect');
        planSelect.innerHTML = '<option value="">Select a plan...</option>';
        trainingPlans.forEach(p => {
            planSelect.innerHTML += `<option value="${p.title}">${p.title}</option>`;
        });

        // Update Assessment Skill Dropdown
        const skillSelect = document.getElementById('assessSkillSelect');
        skillSelect.innerHTML = '';
        skills.forEach(s => {
            skillSelect.innerHTML += `<option value="${s.name}">${s.name}</option>`;
        });
    }

    function assignTraining() {
        const emp = document.getElementById('assignEmpName').value;
        const plan = document.getElementById('assignPlanSelect').value;

        if(!emp || !plan) { alert("Please fill all fields"); return; }

        employeeTraining.push({
            emp: emp,
            plan: plan,
            date: new Date().toISOString().split('T')[0],
            status: 'Pending'
        });

        renderEmpTrainingTable();
        showToast(`Assigned ${plan} to ${emp}`);
    }

    function renderEmpTrainingTable() {
        const tbody = document.querySelector('#empTrainingTable tbody');
        tbody.innerHTML = '';
        employeeTraining.forEach(et => {
            let badgeClass = et.status === 'Pending' ? 'badge-pending' : 'badge-completed';
            tbody.innerHTML += `
                <tr>
                    <td>${et.emp}</td>
                    <td>${et.plan}</td>
                    <td>${et.date}</td>
                    <td><span class="badge ${badgeClass}">${et.status}</span></td>
                </tr>`;
        });
    }

    function submitAssessment() {
        const emp = document.getElementById('assessEmpName').value;
        const skill = document.getElementById('assessSkillSelect').value;
        const score = document.getElementById('assessScore').value;

        if(!emp || !score) { alert("Please fill all fields"); return; }

        employeeSkills.push({ emp, skill, score });
        renderQueryTable();
        showToast('Assessment Recorded');
    }

    // --- QUERY FUNCTIONS ---
    function getLevel(score) {
        if(score >= 90) return '<span style="color:green; font-weight:bold">Expert</span>';
        if(score >= 75) return '<span style="color:blue; font-weight:bold">Proficient</span>';
        if(score >= 50) return '<span style="color:orange; font-weight:bold">Competent</span>';
        return '<span style="color:red; font-weight:bold">Beginner</span>';
    }

    function renderQueryTable(filterText = '') {
        const tbody = document.querySelector('#queryTable tbody');
        tbody.innerHTML = '';

        const filteredData = employeeSkills.filter(item => 
            item.emp.toLowerCase().includes(filterText.toLowerCase())
        );

        if (filteredData.length === 0) {
            tbody.innerHTML = '<tr><td colspan="4" style="text-align:center;">No records found</td></tr>';
            return;
        }

        filteredData.forEach(es => {
            tbody.innerHTML += `
                <tr>
                    <td>${es.emp}</td>
                    <td>${es.skill}</td>
                    <td>${es.score} / 100</td>
                    <td>${getLevel(es.score)}</td>
                </tr>`;
        });
    }

    function filterSkills() {
        const query = document.getElementById('searchEmployee').value;
        renderQueryTable(query);
    }
</script>

</body>
</html>
