    <script>
        // --- DATA & STATE ---
        let processedData = [];

        // --- DOM ELEMENTS ---
        const form = document.getElementById('locationForm');
        const inputArea = document.getElementById('batchInput');
        const resultsTableBody = document.querySelector('#resultsTable tbody');
        const loader = document.getElementById('loader');
        const processingDiv = document.getElementById('processingStatus');
        const statusText = document.getElementById('statusText');

        // --- MOCK GEOCODING FUNCTION ---
        // In a real application, this would fetch data from Google Maps API, Mapbox, or OpenStreetMap.
        // For this demo, we simulate an API call with random offsets near realistic coordinates.
        const mockGeocode = async (address) => {
            return new Promise((resolve) => {
                setTimeout(() => {
                    // Generate pseudo-random coordinates based on string length to keep it consistent-ish
                    const seed = address.length;
                    const baseLat = 37.0 + (seed % 10); 
                    const baseLng = -95.0 - (seed % 10);

                    resolve({
                        lat: (baseLat + Math.random()).toFixed(6),
                        lng: (baseLng + Math.random()).toFixed(6)
                    });
                }, 800); // Simulate network delay
            });
        };

        // --- EVENT LISTENERS ---
        form.addEventListener('submit', async (e) => {
            e.preventDefault();
            const rawText = inputArea.value.trim();

            if (!rawText) {
                alert("Please enter storefront data.");
                return;
            }

            // UI Updates
            processingDiv.style.display = 'block';
            loader.style.display = 'block';
            statusText.innerText = "Parsing Data...";

            const lines = rawText.split('\n');
            processedData = []; // Reset current batch
            resultsTableBody.innerHTML = ""; // Clear table

            // Process Batch
            for (let i = 0; i < lines.length; i++) {
                const line = lines[i].trim();
                if (line.length === 0) continue;

                // Simple parsing: Assumes first comma separates Name from Address
                const firstCommaIndex = line.indexOf(',');
                let storeName = "Unknown Store";
                let storeAddress = line;

                if (firstCommaIndex !== -1) {
                    storeName = line.substring(0, firstCommaIndex).trim();
                    storeAddress = line.substring(firstCommaIndex + 1).trim();
                }

                // Update Status Text
                statusText.innerText = `Locating: ${storeName}...`;

                // Add placeholder row
                const rowId = `row-${i}`;
                appendRow(rowId, storeName, storeAddress, "Pending...", "Pending...", "pending");

                // "Fetch" Coordinates
                try {
                    const coords = await mockGeocode(storeAddress);

                    // Update Row
                    updateRow(rowId, coords.lat, coords.lng);

                    // Save Data
                    processedData.push({
                        name: storeName,
                        address: storeAddress,
                        lat: coords.lat,
                        lng: coords.lng
                    });

                } catch (error) {
                    console.error(error);
                }
            }

            // Finalize
            loader.style.display = 'none';
            statusText.innerText = "Batch Processing Complete!";
            setTimeout(() => {
                processingDiv.style.display = 'none';
            }, 3000);
        });

        // --- HELPER FUNCTIONS ---

        function appendRow(id, name, address, lat, lng, status) {
            const row = document.createElement('tr');
            row.id = id;

            let statusClass = status === 'pending' ? 'status-pending' : 'status-success';
            let statusLabel = status === 'pending' ? 'Processing' : 'Success';

            row.innerHTML = `
                <td><strong>${name}</strong></td>
                <td>${address}</td>
                <td class="lat-cell">${lat}</td>
                <td class="lng-cell">${lng}</td>
                <td><span class="status-badge ${statusClass}">${statusLabel}</span></td>
            `;

            // If table is empty (has the 'no data' message), clear it first
            if(resultsTableBody.children[0] && resultsTableBody.children[0].children.length === 1) {
                resultsTableBody.innerHTML = '';
            }

            resultsTableBody.appendChild(row);
        }

        function updateRow(id, lat, lng) {
            const row = document.getElementById(id);
            if (row) {
                row.querySelector('.lat-cell').innerText = lat;
                row.querySelector('.lng-cell').innerText = lng;
                const badge = row.querySelector('.status-badge');
                badge.className = 'status-badge status-success';
                badge.innerText = 'Located';

                // Add a flash effect
                row.style.backgroundColor = '#e8f4fd';
                setTimeout(() => {
                    row.style.backgroundColor = 'transparent';
                }, 500);
            }
        }

        function loadSampleData() {
            const sample = "Nike Store, 5th Avenue, New York, NY\nApple Store, 1 Infinite Loop, Cupertino, CA\nWhole Foods, 500 Lamar Blvd, Austin, TX\nMcDonalds, 100 Main St, Chicago, IL";
            inputArea.value = sample;
        }

        function clearAllData() {
            if(confirm("Are you sure you want to clear all inputs and results?")) {
                inputArea.value = "";
                processedData = [];
                resultsTableBody.innerHTML = `<tr><td colspan="5" style="text-align: center; color: #777;">No data processed yet.</td></tr>`;
                processingDiv.style.display = 'none';
            }
        }

        function exportToCSV() {
            if (processedData.length === 0) {
                alert("No data to export!");
                return;
            }

            let csvContent = "data:text/csv;charset=utf-8,";
            csvContent += "Store Name,Address,Latitude,Longitude\n";

            processedData.forEach(function(rowArray) {
                let row = `"${rowArray.name}","${rowArray.address}",${rowArray.lat},${rowArray.lng}`;
                csvContent += row + "\r\n";
            });

            const encodedUri = encodeURI(csvContent);
            const link = document.createElement("a");
            link.setAttribute("href", encodedUri);
            link.setAttribute("download", "storefront_locations.csv");
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }
    </script>
</body>
</html>
