<body>

    <header>
        <h1>TurquoiseScrape</h1>
        <p class="subtitle">Advanced Web Data Extraction & Processing Tool</p>
    </header>

    <div class="container">

        <!-- Section 1: Target Configuration -->
        <div class="card">
            <h2>1. Target Selection</h2>
            <div class="input-group">
                <label for="urlInput">Target Website URL</label>
                <input type="url" id="urlInput" placeholder="https://example.com" required>
            </div>

            <div class="input-group">
                <label for="userAgent">Simulate User Agent</label>
                <select id="userAgent">
                    <option value="chrome">Google Chrome (Desktop)</option>
                    <option value="firefox">Mozilla Firefox (Desktop)</option>
                    <option value="safari">Safari (iPhone)</option>
                    <option value="bot">Googlebot</option>
                </select>
            </div>
        </div>

        <!-- Section 2: Data Selectors -->
        <div class="card">
            <h2>2. Data Extraction</h2>
            <p style="margin-bottom: 10px;">Select data points to scrape:</p>
            <div class="checkbox-group">
                <label class="checkbox-item">
                    <input type="checkbox" value="meta_title" checked> Page Title
                </label>
                <label class="checkbox-item">
                    <input type="checkbox" value="meta_desc"> Meta Description
                </label>
                <label class="checkbox-item">
                    <input type="checkbox" value="h1_headers"> H1 Headers
                </label>
                <label class="checkbox-item">
                    <input type="checkbox" value="emails"> Email Addresses
                </label>
                <label class="checkbox-item">
                    <input type="checkbox" value="images"> Image Links
                </label>
                <label class="checkbox-item">
                    <input type="checkbox" value="links"> External Links
                </label>
            </div>
        </div>

        <!-- Section 3: Action & Status -->
        <div class="card full-width" style="text-align: center;">
            <h2>3. Process Data</h2>
            <button id="scrapeBtn" class="btn" onclick="startScraping()">Initiate Extraction</button>

            <div class="loader-container" id="loader">
                <div class="loader"></div>
                <p id="statusText">Connecting to server...</p>
            </div>
        </div>

        <!-- Section 4: Results Display -->
        <div id="results-area" class="full-width">
            <div class="data-header">
                <h3>Extraction Results</h3>
                <button onclick="copyToClipboard()" style="background:none; border:1px solid var(--accent-color); color:var(--accent-color); padding:5px 10px; border-radius:4px; cursor:pointer;">Copy JSON</button>
            </div>
            <div id="dynamic-content">
                <!-- Results will be injected here -->
            </div>
        </div>

    </div>

    <script>
        /* --- JAVASCRIPT LOGIC --- */

        /**
         * Simulates the scraping process.
         * Note: Real client-side scraping is blocked by CORS policies. 
         * This function simulates the latency and data structure of a real backend scraper.
         */
        function startScraping() {
            const urlInput = document.getElementById('urlInput').value;
            const loader = document.getElementById('loader');
            const btn = document.getElementById('scrapeBtn');
            const resultsArea = document.getElementById('results-area');
            const statusText = document.getElementById('statusText');

            // Validation
            if (!urlInput) {
                alert("Please enter a valid URL.");
                return;
            }

            // Get selected checkboxes
            const checkedBoxes = document.querySelectorAll('.checkbox-group input:checked');
            const selectedFields = Array.from(checkedBoxes).map(cb => cb.value);

            if (selectedFields.length === 0) {
                alert("Please select at least one data point to extract.");
                return;
            }

            // UI Updates: Show loader, disable button, hide previous results
            btn.disabled = true;
            btn.innerText = "Processing...";
            resultsArea.style.display = 'none';
            loader.style.display = 'block';

            // Simulation Steps (Timers)
            updateStatus("Connecting to " + urlInput + "...", 0);
            updateStatus("Parsing HTML structure...", 1000);
            updateStatus("Extracting selected data points...", 2000);
            updateStatus("Formatting JSON output...", 2800);

            // Finish Simulation
            setTimeout(() => {
                const fakeData = generateFakeData(urlInput, selectedFields);
                displayResults(fakeData);

                // Reset UI
                loader.style.display = 'none';
                btn.disabled = false;
                btn.innerText = "Initiate Extraction";
                resultsArea.style.display = 'block';
                // Scroll to results
                resultsArea.scrollIntoView({ behavior: 'smooth' });
            }, 3500);
        }

        // Helper to update status text with delay
        function updateStatus(text, delay) {
            setTimeout(() => {
                document.getElementById('statusText').innerText = text;
            }, delay);
        }

        /**
         * Generates dummy data based on user selection to simulate a result.
         */
        function generateFakeData(url, fields) {
            const data = {
                source: url,
                timestamp: new Date().toISOString(),
                status: 200,
                data: {}
            };

            // Mock Data Generator
            if (fields.includes('meta_title')) data.data.meta_title = "Example Domain - Welcome to the Future";
            if (fields.includes('meta_desc')) data.data.meta_description = "This is a simulated description extracted from the target website meta tags.";
            if (fields.includes('h1_headers')) data.data.h1_headers = ["Welcome", "Our Services", "Contact Us"];
            if (fields.includes('emails')) data.data.emails = ["contact@example.com", "support@example.com"];
            if (fields.includes('images')) data.data.images = [url + "/img/logo.png", url + "/img/hero.jpg", url + "/img/footer.png"];
            if (fields.includes('links')) data.data.links = ["https://twitter.com/example", "https://facebook.com/example", "/about", "/contact"];

            return data;
        }

        /**
         * Renders the JSON data into HTML
         */
        function displayResults(data) {
            const container = document.getElementById('dynamic-content');
            const jsonString = JSON.stringify(data, null, 4);

            // Syntax highlighting logic (simple)
            const html = `
                <div style="margin-bottom: 10px;">
                    <strong>Status:</strong> <span style="color: green;">Success</span><br>
                    <strong>Fields Extracted:</strong> ${Object.keys(data.data).length}
                </div>
                <pre id="jsonOutput">${jsonString}</pre>
            `;

            container.innerHTML = html;
        }

        /**
         * Utility: Copy content to clipboard
         */
        function copyToClipboard() {
            const text = document.getElementById('jsonOutput').innerText;
            navigator.clipboard.writeText(text).then(() => {
                alert("JSON copied to clipboard!");
            }).catch(err => {
                console.error('Failed to copy: ', err);
            });
        }
    </script>
</body>
</html>
